//! Expression type-checker — Phase 3 of TS_PARITY_PLAN.
//!
//! Walks HIR expressions and assigns each one a TypeId, populating
//! the HIR's `types` column. Also drives the cross-statement checks:
//! `let x: T = expr;` verifies `expr`'s type is assignable to `T`.
//!
//! Scope today (Phase 3 expression typing — minimal):
//!   - Literals (number / string / bigint / boolean / null /
//!     undefined) → matching Primitive
//!   - Identifier references — type taken from the binder's symbol
//!     when known, else `Primitive.any` (forgiving for partial input)
//!   - Binary `+` on number+number / string+string → matching
//!     primitive; mixed → string (matches JS coercion)
//!   - Comparison ops → boolean
//!   - Logical `&&`/`||`/`??` → union of branch types
//!   - Conditional `c ? a : b` → union of branches
//!   - Assignment `target = value` → value's type
//!   - VarDecl with annotation: assign annotation to the decl's
//!     type slot, check init assigns to it; else infer from init
//!
//! Out of scope (Phase 3 follow-ups):
//!   - Call type-checking (needs signature lowering)
//!   - Member access / element access (needs object-type lowering)
//!   - Generic instantiation
//!   - Control-flow narrowing
//!   - Class/interface body member resolution

const std = @import("std");
const hir_mod = @import("hir");
const types = @import("types.zig");
const interner = @import("interner.zig");
const relation = @import("relation.zig");
const lower = @import("lower.zig");
const lib = @import("lib.zig");
const string_interner = @import("string_interner");
const binder_mod = @import("binder");

pub const TypeId = types.TypeId;
pub const NodeId = hir_mod.NodeId;
pub const Hir = hir_mod.Hir;

pub const CheckError = error{
    OutOfMemory,
};

pub const Diagnostic = struct {
    node: NodeId,
    /// Optional absolute source byte offset for diagnostics that
    /// belong to trivia rather than an HIR node, such as an unused
    /// `// @ts-expect-error` directive.
    pos: ?u32 = null,
    /// TypeScript-compatible code (e.g. 2322). 0 for uncategorized.
    code: u32 = 0,
    /// `TS` for tsc-compatible codes; `HM` for Home-only codes.
    code_prefix: CodePrefix = .TS,
    message: []const u8,

    pub const CodePrefix = enum { TS, HM };
};

/// External module-resolution hook the checker can delegate to.
///
/// When set via `Checker.setExternalResolver`, the checker will ask
/// this resolver to map a bare/relative module specifier to a
/// resolved file path before falling back to its in-source
/// `@filename:` virtual-section scan. This lets the conformance
/// harness route through `ts_resolver` for `package.json`-aware
/// fixtures (`packageJsonMain*`, `nestedPackageJsonRedirect`,
/// `typesVersions.*`, `untypedModuleImport_*`) instead of having
/// the checker re-implement node resolution against virtual-file
/// markers.
///
/// The vtable shape stays opaque so `ts_checker` does not pull
/// `ts_resolver` in as a build dependency.
pub const ExternalResolver = struct {
    ptr: *anyopaque,
    vtable: *const VTable,

    pub const Resolution = struct {
        /// Resolved file path. Borrowed; lifetime is the resolver's
        /// arena (which must outlive the `Checker`'s
        /// `checkSourceFile` call). The checker never frees it.
        path: []const u8,
        /// True when `path` ends in `.d.ts` / `.d.cts` / `.d.mts`
        /// or `.ts` / `.tsx` / `.mts` / `.cts` — i.e. tsc would
        /// treat the resolution as "typed".
        is_declaration: bool,
    };

    pub const VTable = struct {
        /// Resolve `specifier` from `containing_file`. Returns
        /// `null` when the specifier did not resolve.
        resolve: *const fn (
            self: *anyopaque,
            specifier: []const u8,
            containing_file: []const u8,
        ) ?Resolution,
    };

    pub fn resolve(
        self: ExternalResolver,
        specifier: []const u8,
        containing_file: []const u8,
    ) ?Resolution {
        return self.vtable.resolve(self.ptr, specifier, containing_file);
    }
};

