                        if (u.op == .neg and self.hir.kindOf(u.operand) == .literal_number) {
                            const nv = hir_mod.literalNumberOf(self.hir, u.operand);
                            if (nv > 0) {
                                try self.report(
                                    e.index,
                                    TsCodes.tuple_negative_index,
                                    "A tuple type cannot be indexed with a negative value.",
                                );
                                break :blk types.Primitive.undefined_t;
                            }
                        }
                    }
                    // Tuple literal-index access: `tup[0]` should
                    // pick the per-index member typed under "0", not
                    // the broader number indexer's union. Only fires
                    // when the index is a numeric literal expression.
                    if (self.hir.kindOf(e.index) == .literal_number) {
                        const v = hir_mod.literalNumberOf(self.hir, e.index);
                        // Convert to integer; ignore non-integral
                        // forms (e.g. `tup[0.5]`) and let the indexer
                        // path handle them.
                        const max_u64_float: f64 = @floatFromInt(std.math.maxInt(u64));
                        if (v >= 0 and v == @floor(v) and v <= max_u64_float) {
                            const index: u64 = @intFromFloat(v);
                            var nbuf: [12]u8 = undefined;
                            const k = std.fmt.bufPrint(&nbuf, "{d}", .{index}) catch null;
                            if (k) |key_str| {
                                const key_id = self.string_interner.intern(key_str) catch 0;
                                if (key_id != 0) {
                                    if (self.interner.objectMember(obj_t, key_id)) |t| break :blk try self.optionalChainResult(t, element_is_optional_chain);
                                }
                            }
                            if (self.fixedTupleLength(obj_t)) |length| {
                                if (index >= length) {
                                    try self.reportTupleIndexOutOfBounds(e.index, obj_t, index, length);
                                    const v_idx = self.interner.objectNumberIndex(obj_t);
                                    if (v_idx != types.Primitive.none) break :blk v_idx;
                                    break :blk types.Primitive.any;
                                }
                            }
                        }
                    }
                    var literal_string_key: ?hir_mod.StringId = null;
                    if (self.hir.kindOf(e.index) == .literal_string) {
                        const lit = hir_mod.literalStringOf(self.hir, e.index);
                        literal_string_key = lit.value;
                        // Honor the (obj_name, prop_name) member-narrow
                        // scope when the receiver is a bare identifier,
                        // matching the member_access typing path. This
                        // keeps `if (obj["x"]) { obj["x"]; }` and
                        // `if (obj.x) { obj["x"]; }` typed identically.
                        if (self.hir.kindOf(e.object) == .identifier) {
                            const obj_id_ea = hir_mod.identifierOf(self.hir, e.object);
                            const key: MemberKey = .{ .obj_name = obj_id_ea.name, .prop_name = lit.value };
                            if (self.lookupMemberNarrow(key)) |nt| {
                                break :blk try self.optionalChainResult(nt, element_is_optional_chain);
                            }
                        }
                        if (self.interner.objectMember(obj_t, lit.value)) |t| break :blk try self.optionalChainResult(t, element_is_optional_chain);
                    }
                    if (try self.classMemberNameFromPropertyKey(e.index, true)) |computed_key| {
                        var found_count: usize = 0;
                        var found_t: TypeId = types.Primitive.none;
                        for (self.interner.objectMembers(obj_t)) |member| {
                            if (member.name != computed_key) continue;
                            found_count += 1;
                            found_t = member.type;
                        }
                        if (found_count > 1) break :blk try self.optionalChainResult(types.Primitive.any, element_is_optional_chain);
                        if (found_count == 1) break :blk try self.optionalChainResult(found_t, element_is_optional_chain);
                    }
                    // Index-signature fallback. With
                    // `noUncheckedIndexedAccess`, widen the result
                    // with `undefined` since dynamic indexing may
                    // miss. Tuple positional access above is exempt
                    // because the arity is statically known.
                    const idx_flags = self.interner.pool.flagsOf(idx_t);
                    if (self.typeMaybeStringLike(idx_t)) {
                        const v = self.interner.objectStringIndex(obj_t);
                        if (v != types.Primitive.none) break :blk try self.optionalChainResult(self.maybeWidenWithUndefined(v), element_is_optional_chain);
                        if (try self.functionInterfaceStringIndexForCallableObject(obj_t)) |function_idx| {
                            break :blk try self.optionalChainResult(self.maybeWidenWithUndefined(function_idx), element_is_optional_chain);
                        }
                    }
                    if (self.typeMaybeNumericLike(idx_t)) {
                        const v = self.interner.objectNumberIndex(obj_t);
                        if (v != types.Primitive.none) break :blk try self.optionalChainResult(self.maybeWidenWithUndefined(v), element_is_optional_chain);
                    }
                    if (idx_flags.is_symbol) {
                        const v = self.interner.objectSymbolIndex(obj_t);
                        if (v != types.Primitive.none) break :blk try self.optionalChainResult(self.maybeWidenWithUndefined(v), element_is_optional_chain);
                    }
                    if (literal_string_key) |key_id| {
                        if (self.strict_flags.no_implicit_any and
                            self.interner.objectMembers(obj_t).len != 0 and
                            self.interner.objectStringIndex(obj_t) == types.Primitive.none)
                        {
                            const key = self.string_interner.get(key_id);
                            const msg = try std.fmt.allocPrint(
                                self.diag_arena.allocator(),
                                "Element implicitly has an 'any' type because property '{s}' does not exist on type.",
                                .{key},
                            );
                            try self.diagnostics.append(self.gpa, .{
                                .node = node,
                                .code = TsCodes.element_implicitly_any,
                                .message = msg,
                            });
                        }
                    }
                }
                if (obj_t == types.Primitive.object_t and self.strict_flags.no_implicit_any) {
                    const idx_flags = self.interner.pool.flagsOf(idx_t);
                    if (idx_flags.is_string or idx_flags.is_number or idx_flags.is_symbol) {
                        // tsc renders the broad `object` primitive
                        // as `{}` and includes the index expression
                        // type in the message — see fixture
                        // `nonPrimitiveIndexingWithForInSupressError`.
                        const idx_name = (try self.allocSimpleTypeName(idx_t)) orelse "any";
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Element implicitly has an 'any' type because expression of type '{s}' can't be used to index type '{{}}'.",
                            .{idx_name},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = node,
                            .code = TsCodes.element_implicitly_any,
                            .message = msg,
                        });
                    }
                }
                const loose_untyped_index = self.sourceHasStrictFalseDirective() and
                    idx_t == types.Primitive.undefined_t and
                    self.hir.kindOf(e.index) == .identifier and
                    self.identifierIsUntypedUninitializedVar(e.index);
                if (!loose_untyped_index and !try self.computedPropertyKeyTypeIsValid(idx_t)) {
                    // Prefer tsc's render shape with the inferred type
                    // name when available — `Type 'typeof Foo' cannot
                    // be used as an index type.` — falling back to the
                    // bare form for unnamed types.
                    if (try self.allocSimpleTypeName(idx_t)) |idx_name| {
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Type '{s}' cannot be used as an index type.",
                            .{idx_name},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = e.index,
                            .code = TsCodes.type_cannot_be_used_as_index,
                            .message = msg,
                        });
                    } else {
                        try self.report(e.index, TsCodes.type_cannot_be_used_as_index, "Type cannot be used as an index type.");
                    }
                }
                break :blk try self.optionalChainResult(types.Primitive.any, element_is_optional_chain);
            },
            .as_expr, .type_assertion => blk: {
                // `expr as T` / `<T>expr` — type the inner
                // expression for diagnostics, then return the
                // asserted type. No assignability check: `as` is
                // an explicit override.
                const a = hir_mod.asExpressionOf(self.hir, node);
                const inner_t = try self.checkExpression(a.expr);
                if (a.type_node == hir_mod.none_node_id) break :blk types.Primitive.any;
                // `expr as const` — special form. The parser
                // builds a synthetic `const` type-ref to mark it.
                if (self.isAsConstMarker(a.type_node)) {
                    break :blk self.literalizeForAsConst(a.expr, inner_t) catch inner_t;
                }
                const target_t = try self.lowererLowerWithTypeParams(a.type_node);
                try self.checkTypeAssertionOverlap(node, inner_t, target_t);
                break :blk target_t;
            },
            .satisfies_expr => blk: {
                // `expr satisfies T` — verify that `expr` is
                // assignable to T (TS1360 on miss) but PRESERVE
                // `expr`'s narrower type as the result. Distinct
                // from `as T` which uses T as the result type.
                const a = hir_mod.asExpressionOf(self.hir, node);
                const inner_t = try self.checkExpression(a.expr);
                if (a.type_node == hir_mod.none_node_id) break :blk inner_t;
                const target_t = try self.lowererLowerWithTypeParams(a.type_node);
                var ok = self.engine.isAssignableTo(inner_t, target_t) catch false;
                if (ok and
                    self.hir.kindOf(a.expr) == .object_literal and
                    self.objectLiteralNeedsIndexerValidation(target_t))
                {
                    ok = self.objectLiteralAssignableToTarget(a.expr, inner_t, target_t) catch false;
                }
                if (!ok) {
                    // Prefer tsc's render shape:
                    // `Type 'X' does not satisfy the expected type 'Y'.`
                    // Fall back to the generic constraint wording when
                    // we can't render either side as a simple name
                    // (matches the existing baseline shape).
                    if (try self.allocSimpleTypeName(inner_t)) |src_name| {
                        if (try self.allocSimpleTypeName(target_t)) |dst_name| {
                            const msg = try std.fmt.allocPrint(
                                self.diag_arena.allocator(),
                                "Type '{s}' does not satisfy the expected type '{s}'.",
                                .{ src_name, dst_name },
                            );
                            try self.report(node, TsCodes.satisfies_constraint, msg);
                            break :blk inner_t;
                        }
                    }
                    try self.report(node, TsCodes.satisfies_constraint, "Type does not satisfy the expected constraint.");
                }
                break :blk inner_t;
            },
            .non_null_expr => blk: {
                // `expr!` — postfix non-null assertion. Type the
                // inner expression, then subtract null + undefined
                // from the resulting union. Non-union types pass
                // through (we don't error on a redundant assert).
                const a = hir_mod.asExpressionOf(self.hir, node);
                const inner = try self.checkExpression(a.expr);
                break :blk self.subtractNullUndefined(inner) catch inner;
            },
            .array_literal => blk: {
                const elements = hir_mod.arrayLiteralElements(self.hir, node);
                var elem_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer elem_types.deinit(self.gpa);
                for (elements) |el| {
                    if (el == hir_mod.none_node_id) continue;
                    if (self.hir.kindOf(el) == .spread) {
                        // `...expr` — the spread's element type
                        // contributes to the result. v0: require
                        // the spread operand to be an array type
                        // (number indexer present); fall back to
                        // the spread expression's own type otherwise.
                        const sp = hir_mod.spreadOf(self.hir, el);
                        const inner_t = try self.checkExpression(sp.expression);
                        if (!self.isIterableLikeType(inner_t)) {
                            // Prefer the named TS2488 form
                            // (`Type 'SymbolIterator' must have …`) when the
                            // source type can be named. Mirrors
                            // `iteratorSpreadInArray8` / `iteratorSpreadInArray10`.
                            try self.reportIteratorRequired(sp.expression, inner_t);
                        }
                        const elem_inner = self.interner.objectNumberIndex(inner_t);
                        const contrib = if (elem_inner != types.Primitive.none) elem_inner else try self.iterableElementType(inner_t);
                        try elem_types.append(self.gpa, contrib);
                        continue;
                    }
                    const t = try self.checkExpression(el);
                    try elem_types.append(self.gpa, t);
                }
                const elem_t: TypeId = if (elem_types.items.len == 0)
                    types.Primitive.any
                else if (elem_types.items.len == 1)
                    elem_types.items[0]
                else
                    self.interner.internUnion(elem_types.items) catch return error.OutOfMemory;
                // Build the standard Array<T> shape — `length:
                // number` plus `[i: number]: T`. Lets `arr[0]`
                // and `arr.length` resolve through the existing
                // object-type machinery without a dedicated array
                // TypeKind.
                break :blk self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
            },
            .object_literal => blk: {
                // Type each property and synthesize an object-type
                // mirroring the shape: '{ x: 1 }' -> '{ x: number }'.
                // Spread elements (`...expr`) are stored as raw
                // expression nodes; merge their members in declaration
                // order. Later occurrences override earlier ones,
                // matching TS's "last wins" semantics.
                const props = hir_mod.objectLiteralProps(self.hir, node);
                var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                defer members.deinit(self.gpa);
                var explicit_props: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
                defer explicit_props.deinit(self.gpa);
                var computed_string_value_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer computed_string_value_types.deinit(self.gpa);
                var computed_symbol_value_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer computed_symbol_value_types.deinit(self.gpa);
                var generic_spread_parts: std.ArrayListUnmanaged(TypeId) = .empty;
                defer generic_spread_parts.deinit(self.gpa);
                const upsert = struct {
                    fn run(
                        gpa: std.mem.Allocator,
                        list: *std.ArrayListUnmanaged(types.ObjectMember),
                        m: types.ObjectMember,
                    ) !void {
                        for (list.items) |*existing| {
                            if (existing.name == m.name) {
                                existing.* = m;
                                return;
                            }
                        }
                        try list.append(gpa, m);
                    }
                }.run;
                const upsert_spread = struct {
                    fn run(
                        checker: *Checker,
                        list: *std.ArrayListUnmanaged(types.ObjectMember),
                        m: types.ObjectMember,
                    ) !void {
                        for (list.items) |*existing| {
                            if (existing.name != m.name) continue;
                            if (!existing.is_optional and m.is_optional) {
                                existing.type = checker.interner.internUnion(&.{ existing.type, m.type }) catch return error.OutOfMemory;
                                existing.is_method = existing.is_method and m.is_method;
                                return;
                            }
                            if (existing.is_optional and m.is_optional) {
                                existing.type = checker.interner.internUnion(&.{ existing.type, m.type }) catch return error.OutOfMemory;
                                existing.is_method = existing.is_method and m.is_method;
                                return;
                            }
                            existing.* = m;
                            return;
                        }
                        try list.append(checker.gpa, m);
                    }
                }.run;
                for (props) |p| {
                    if (self.hir.kindOf(p) != .object_property) {
                        // Spread element: type the expression and
                        // merge each of its members. Skip silently
                        // when the spread source isn't an object
                        // type (v0: ignore arrays / strings / any).
                        const spread_expr = if (self.hir.kindOf(p) == .spread) hir_mod.spreadOf(self.hir, p).expression else p;
                        const raw_st = try self.checkExpression(p);
                        const st = try self.objectSpreadEffectiveType(spread_expr, raw_st);
                        if (!try self.objectSpreadSourceIsValid(st)) {
                            try self.report(p, TsCodes.spread_types_object_only, "Spread types may only be created from object types.");
                            continue;
                        }
                        if (self.containsFreeTypeParameter(st)) {
                            try generic_spread_parts.append(self.gpa, st);
                        }
                        const src_members = self.interner.objectMembers(st);
                        const source_is_class_instance = self.class_name_by_instance.contains(st);
                        // Conditional spread expressions like
                        // `...(t ? a : {})` always overwrite *at most*
                        // half the time, so they don't trigger the
                        // TS2783 duplicate-overwrite warning even when
                        // a branch contributes the same property name.
                        // Mirrors `spreadDuplicateExact.ts(20..)` and
                        // `spreadOverwritesPropertyStrict.ts` family.
                        const spread_may_be_empty = self.spreadExpressionMayContributeNothing(spread_expr);
                        for (src_members) |m| {
                            if (source_is_class_instance and (m.is_method or m.is_readonly)) continue;
                            if (!m.is_optional and !spread_may_be_empty) {
                                if (explicit_props.get(m.name)) |prop_node| {
                                    const prop_name = self.string_interner.get(m.name);
                                    const msg = std.fmt.allocPrint(
                                        self.gpa,
                                        "'{s}' is specified more than once, so this usage will be overwritten.",
                                        .{prop_name},
                                    ) catch return error.OutOfMemory;
                                    defer self.gpa.free(msg);
                                    try self.report(prop_node, TsCodes.jsx_attribute_overwritten, msg);
                                }
                            }
                            try upsert_spread(self, &members, m);
                        }
                        continue;
                    }
                    const op = hir_mod.objectPropertyOf(self.hir, p);
                    if (op.is_computed) {
                        if (self.enclosingStaticClassTypeParams(op.key)) |static_class_tps| {
                            if (self.computedNameReferencesTypeParams(op.key, static_class_tps)) {
                                try self.report(op.key, TsCodes.static_member_type_parameter, "Static members cannot reference class type parameters.");
                            }
                        }
                        if (self.expressionContainsSuperCall(op.key) and self.superCallIsInNestedFunctionInsideConstructor(op.key)) {
                            try self.report(op.key, TsCodes.super_in_computed_property_name, "'super' cannot be referenced in a computed property name.");
                        }
                        if (self.expressionContainsThis(op.key) and self.currentThisType() == null) {
                            if (self.nodeHasAncestorKind(op.key, .namespace_decl)) {
                                try self.report(op.key, TsCodes.this_in_namespace_body, "'this' cannot be referenced in a module or namespace body.");
                            }
                            if (!self.sourceHasStrictFalseDirective()) {
                                try self.report(op.key, TsCodes.this_implicitly_any, "'this' implicitly has type 'any' because it does not have a type annotation.");
                            }
                        }
                        const key_t = try self.checkExpression(op.key);
                        if (self.hir.kindOf(op.key) != .yield_expr and !try self.computedPropertyKeyTypeIsValid(key_t)) {
                            try self.report(p, TsCodes.computed_property_name_type, "A computed property name must be of type 'string', 'number', 'symbol', or 'any'.");
                        }
                        if (op.value == hir_mod.none_node_id) continue;
                        const value_kind = self.hir.kindOf(op.value);
                        const op_is_method = op.is_method or
                            ((value_kind == .fn_decl or value_kind == .fn_expr or value_kind == .arrow_fn) and
                                self.memberSourceLooksMethod(p));
                        const raw_vt = try self.checkExpression(op.value);
                        const jsdoc_t = try self.jsDocTypeForLeadingNode(p);
                        if (jsdoc_t) |target_t| {
                            const jsdoc_ok = if (value_kind == .fn_decl or value_kind == .fn_expr or value_kind == .arrow_fn)
                                try self.functionExpressionAssignableToTarget(op.value, target_t)
                            else
                                (try self.literalExpressionAssignableToTarget(op.value, target_t)) or
                                    (self.engine.isAssignableTo(raw_vt, target_t) catch true);
                            if (!jsdoc_ok) {
                                try self.report(p, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
                            }
                        }
                        const vt = self.objectAccessorPropertyType(op.value, jsdoc_t orelse raw_vt);
                        if (try self.classMemberNameFromPropertyKey(op.key, true)) |member_name| {
                            if (!op_is_method and objectMemberListContains(members.items, member_name)) {
                                try self.report(p, TsCodes.object_literal_duplicate_property, "An object literal cannot have multiple properties with the same name.");
                            }
                            try upsert(self.gpa, &members, .{
                                .name = member_name,
                                .type = vt,
                                .is_optional = false,
                                .is_readonly = false,
                                .is_method = op_is_method,
                            });
                        } else if (try self.computedPropertyKeyTypeIsSymbolLike(key_t)) {
                            try computed_symbol_value_types.append(self.gpa, vt);
                        } else if (self.sourceHasCheckJsDirective() and self.hir.kindOf(op.key) == .binary_op) {
                            // tsc does not use non-literal JS computed
                            // property expressions like `['b' + 'ar1']`
                            // to constrain later dot assignments.
                        } else {
                            try computed_string_value_types.append(self.gpa, vt);
                        }
                        continue;
                    }
                    if (op.value == hir_mod.none_node_id) continue;
                    if (self.hir.kindOf(op.key) != .identifier) continue;
                    const k = hir_mod.identifierOf(self.hir, op.key);
                    const value_kind = self.hir.kindOf(op.value);
                    const op_is_method = op.is_method or
                        ((value_kind == .fn_decl or value_kind == .fn_expr or value_kind == .arrow_fn) and
                            self.memberSourceLooksMethod(p));
                    const raw_vt = try self.checkExpression(op.value);
                    if (self.strict_flags.no_implicit_any and
                        (value_kind == .fn_decl or value_kind == .fn_expr or value_kind == .arrow_fn))
                    {
                        const f = hir_mod.fnDeclOf(self.hir, op.value);
                        const params = hir_mod.fnParams(self.hir, op.value);
                        if (f.flags.is_setter and params.len > 0) {
                            const first = hir_mod.parameterOf(self.hir, params[0]);
                            if (first.type_annotation == hir_mod.none_node_id) {
                                try self.reportObjectLiteralSetterImplicitAny(op.key, k.name);
                            }
                        }
                    }
                    if (op.is_shorthand and value_kind == .identifier) {
                        try self.rewriteMissingShorthandPropertyDiagnostic(op.value);
                    }
                    if (self.strict_flags.no_implicit_any and
                        !self.strict_flags.strict_null_checks and
                        value_kind == .literal_null)
                    {
                        try self.reportObjectLiteralPropertyImplicitAny(p, k.name);
                    }
                    const jsdoc_t = try self.jsDocTypeForLeadingNode(p);
                    if (jsdoc_t) |target_t| {
                        const jsdoc_ok = if (value_kind == .fn_decl or value_kind == .fn_expr or value_kind == .arrow_fn)
                            try self.functionExpressionAssignableToTarget(op.value, target_t)
                        else
                            (try self.literalExpressionAssignableToTarget(op.value, target_t)) or
                                (self.engine.isAssignableTo(raw_vt, target_t) catch true);
                        if (!jsdoc_ok) {
                            try self.report(p, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
                        }
                    }
                    const vt = self.objectAccessorPropertyType(op.value, jsdoc_t orelse raw_vt);
                    if (op_is_method and self.objectLiteralHasDuplicateMethodWithLiteralParam(members.items, k.name, op.value)) {
                        try self.reportDuplicateIdentifier(p, k.name);
                    }
                    try explicit_props.put(self.gpa, k.name, p);
                    try upsert(self.gpa, &members, .{
                        .name = k.name,
                        .type = vt,
                        .is_optional = false,
                        .is_readonly = false,
                        .is_method = op_is_method,
                    });
                }
                var string_index: TypeId = types.Primitive.none;
                if (computed_string_value_types.items.len == 1) {
                    string_index = computed_string_value_types.items[0];
                } else if (computed_string_value_types.items.len > 1) {
                    string_index = self.interner.internUnion(computed_string_value_types.items) catch return error.OutOfMemory;
                }
                var symbol_index: TypeId = types.Primitive.none;
                if (computed_symbol_value_types.items.len == 1) {
                    symbol_index = computed_symbol_value_types.items[0];
                } else if (computed_symbol_value_types.items.len > 1) {
                    symbol_index = self.interner.internUnion(computed_symbol_value_types.items) catch return error.OutOfMemory;
                }
                const obj_t = self.interner.internObjectTypeWithIndexAndSymbol(members.items, string_index, types.Primitive.none, symbol_index) catch return error.OutOfMemory;
                if (!self.objectLiteralLikelyHasContextualTarget(node)) {
                    // §4.A.X Phase 4 #11 — when the literal is a return
                    // value, prefer the enclosing function's declared
                    // return type as the contextual target so a
                    // `ThisType<T>` marker on the annotation flips
                    // `this` inside the literal's method bodies.
                    const ctx_t = self.objectLiteralEnclosingReturnTargetType(node) orelse obj_t;
                    try self.checkObjectLiteralMethodBodiesWithThis(node, ctx_t);
                }
                if (generic_spread_parts.items.len > 0) {
                    try generic_spread_parts.append(self.gpa, obj_t);
                    break :blk self.interner.internIntersection(generic_spread_parts.items) catch return error.OutOfMemory;
                }
                break :blk obj_t;
            },
            // Arrow / function expression: lower the signature so the
            // surrounding `let f = (x: T) => U` learns f's signature
            // type. checkFnDecl walks the body too, so all interior
            // typing happens here.
            .fn_decl, .arrow_fn, .fn_expr => blk: {
                try self.checkFnDeclWithFlowBoundary(node);
                break :blk self.hir.typeOf(node);
            },
            .class_decl, .class_expr => blk: {
                try self.checkClassDecl(node);
                if (self.class_static_type_by_node.get(node)) |static_t| {
                    self.hir.setType(node, static_t);
                    break :blk static_t;
                }
                break :blk self.hir.typeOf(node);
            },
            .await_expr => blk: {
                // `await expr` — type-check the operand. When the
                // operand's type is structurally a `Promise<T>` (an
                // object type with a `.then(cb)` method whose callback
                // takes the resolved value as its first parameter),
                // unwrap to `T`. Otherwise pass the operand type
                // through.
                const a = hir_mod.awaitExprOf(self.hir, node);
                const inner_t = try self.checkExpression(a.expr);
                if (self.nodeIsInClassStaticBlockBeforeFunction(node)) {
                    try self.report(node, TsCodes.await_in_class_static_block, "'await' expression cannot be used inside a class static block.");
                }
                // TS1308: `await` is only allowed inside an async
                // function or at the top level of a module. Walk up
                // the parent chain looking for the nearest enclosing
                // function. If found and it isn't async, diagnose.
                // Reaching the root without finding any function is
                // top-level await, which is allowed.
                //
                // Decorators run at class declaration time, NOT inside
                // the function/method they decorate. When the await is
                // inside a decorator expression, the function (or
                // parameter's owning method) the decorator targets is
                // transparent for await scoping — the enclosing
                // function is the one OUTSIDE the decorated class.
                // Mirrors fixture `decoratorOnClassMethodParameter3`
                // where `@dec(await value)` is on an `async method`
                // parameter but the await belongs to the outer
                // non-async `function fn`.
                var inside_decorator = false;
                var cur: hir_mod.NodeId = self.hir.parentOf(node);
                while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
                    const k = self.hir.kindOf(cur);
                    if (k == .decorator) {
                        inside_decorator = true;
                        continue;
                    }
                    if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                        if (inside_decorator) {
                            // Skip this function — decorators run
                            // outside it. The next .decorator boundary
                            // hasn't been crossed yet, so reset and
                            // keep walking.
                            inside_decorator = false;
                            continue;
                        }
                        const fp = hir_mod.fnDeclOf(self.hir, cur);
                        if (!fp.flags.is_async) {
                            try self.report(node, TsCodes.await_only_in_async, "'await' expressions are only allowed within async functions and at the top levels of modules.");
                        }
                        break;
                    }
                }
                if (!self.nodeIsInsideFunctionLike(node) and self.sourceTargetDisallowsTopLevelAwait()) {
                    // Upstream tsc emits TS1378 only on the FIRST
                    // top-level await per source file (the message is a
                    // module-level configuration hint, not a per-await
                    // problem). Mirror that here so fixtures with many
                    // top-level awaits — `topLevelAwait.1`, etc. — match
                    // the baseline exactly.
                    var already_reported = false;
                    for (self.diagnostics.items) |d| {
                        if (d.code == TsCodes.top_level_await_target_module) {
                            already_reported = true;
                            break;
                        }
                    }
                    if (!already_reported) {
                        try self.report(node, TsCodes.top_level_await_target_module, "Top-level 'await' expressions are only allowed when the 'module' option is set to 'es2022', 'esnext', 'system', 'node16', 'node18', 'node20', 'nodenext', or 'preserve', and the 'target' option is set to 'es2017' or higher.");
                    }
                }
                break :blk self.unwrapPromise(inner_t);
            },
            .yield_expr => blk: {
                // `yield expr` / `yield* expr` — type-check the
                // operand as the yielded value. The expression value
                // itself is what the caller sends back into the
                // generator through `.next(value)`, not the yielded
                // operand.
                const y = hir_mod.yieldExprOf(self.hir, node);
                const gen = self.current_generator_info;
                if (y.expr == hir_mod.none_node_id) {
                    if (gen) |info| {
                        if (!(self.engine.isAssignableTo(types.Primitive.undefined_t, info.yield_type) catch true)) {
                            try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to generator yield type.");
                        }
                        break :blk info.next_type;
                    }
                    break :blk types.Primitive.any;
                }
                // Skip operand type-checking when the enclosing function
                // isn't actually a generator — the parser already raised
                // TS1163 ("'yield' is only allowed in a generator body")
                // and tsc suppresses cascading TS2304/TS2363 noise on
                // the operand. Matches fixtures like `YieldExpression11/14/15_es6`
                // and `YieldStarExpression1_es6`.
                //
                // `current_generator_info` alone isn't a sufficient signal:
                // valid generators without a return-type annotation also
                // leave it null (yield type is inferred from body). Walk
                // the parent chain to confirm we're outside any generator
                // fn / method body before suppressing.
                if (gen == null and !self.isInsideGeneratorFunction(node)) {
                    break :blk types.Primitive.any;
                }
                const inner_t = try self.checkExpression(y.expr);
                if (y.type_node != hir_mod.none_node_id) {
                    if (!self.isIterableLikeType(inner_t) and
                        !self.objectLiteralHasSymbolIteratorMethod(y.expr))
                    {
                        try self.reportIteratorRequired(y.expr, inner_t);
                    }
                    const delegated_return = if (self.generator_type_info.get(inner_t)) |delegated|
                        delegated.return_type
                    else
                        types.Primitive.any;
                    if (gen) |info| {
                        const delegated_yield = if (self.generator_type_info.get(inner_t)) |delegated|
                            delegated.yield_type
                        else
                            try self.iterableElementType(inner_t);
                        if (!(self.engine.isAssignableTo(delegated_yield, info.yield_type) catch true)) {
                            try self.report(y.expr, TsCodes.type_not_assignable, "Type is not assignable to generator yield type.");
                        }
                    }
                    break :blk delegated_return;
                }
                if (gen) |info| {
                    if (!(self.engine.isAssignableTo(inner_t, info.yield_type) catch true)) {
                        try self.report(y.expr, TsCodes.type_not_assignable, "Type is not assignable to generator yield type.");
                    }
                    break :blk info.next_type;
                }
                break :blk types.Primitive.any;
            },
            .jsx_element, .jsx_self_closing => try self.checkJsxElement(node),
            .jsx_fragment => blk: {
                const frag = hir_mod.jsxFragmentOf(self.hir, node);
                for (self.hir.childSlice(frag.children_start, frag.children_len)) |child| {
                    _ = try self.checkExpression(child);
                }
                break :blk types.Primitive.any;
            },
            .jsx_expression => blk: {
                const ex = hir_mod.jsxExpressionOf(self.hir, node);
                if (ex.expression != hir_mod.none_node_id) {
                    break :blk try self.checkExpression(ex.expression);
                }
                break :blk types.Primitive.undefined_t;
            },
            else => types.Primitive.any,
        };
        self.hir.setType(node, t);
        return t;
    }

    fn rewriteMissingShorthandPropertyDiagnostic(self: *Checker, value_node: NodeId) CheckError!void {
        if (self.diagnostics.items.len == 0) return;
        const idx = self.diagnostics.items.len - 1;
        var last = &self.diagnostics.items[idx];
        if (last.node != value_node) return;
        if (last.code != TsCodes.cannot_find_name and last.code != TsCodes.cannot_find_name_did_you_mean) return;
        const id = hir_mod.identifierOf(self.hir, value_node);
        const name = self.string_interner.get(id.name);
        last.code = TsCodes.shorthand_property_no_value;
        last.message = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "No value exists in scope for the shorthand property '{s}'. Either declare one or provide an initializer.",
            .{name},
        );
    }

    fn isDynamicImportCallee(self: *Checker, callee: NodeId) bool {
        if (callee == hir_mod.none_node_id or self.hir.kindOf(callee) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, callee);
        return std.mem.eql(u8, self.string_interner.get(id.name), "import");
    }

    fn dynamicImportModuleKindDisallowsImportCall(self: *Checker) bool {
        return self.sourceDirectiveValueMentions("module", "es2015") or
            self.sourceDirectiveValueMentions("module", "es6");
    }

    fn dynamicImportCallHasTypeArgumentSyntax(self: *Checker, call_node: NodeId, callee: NodeId) bool {
        if (hir_mod.callTypeArgs(self.hir, call_node).len > 0) return true;
        const src = self.source orelse return false;
        const callee_span = self.hir.spanOf(callee);
        const call_span = self.hir.spanOf(call_node);
        if (callee_span.end >= src.len or call_span.end > src.len or callee_span.end >= call_span.end) return false;
        const between = src[callee_span.end..call_span.end];
        const open_paren = std.mem.indexOfScalar(u8, between, '(') orelse return false;
        return std.mem.indexOfScalar(u8, between[0..open_paren], '<') != null;
    }

    fn checkJsxElement(self: *Checker, node: NodeId) CheckError!TypeId {
        const el = hir_mod.jsxElementOf(self.hir, node);
        const attrs = hir_mod.jsxAttrs(self.hir, node);
        const children = hir_mod.jsxChildren(self.hir, node);
        const props_t = try self.jsxPropsType(el.tag, attrs.len);

        if (props_t == null and self.jsxTagIsIntrinsic(el.tag)) {
            if (try self.jsxHasIntrinsicElementsDecl(el.tag)) {
                try self.report(el.tag, TsCodes.property_does_not_exist, "Property does not exist on type 'JSX.IntrinsicElements'.");
            } else if (self.strict_flags.no_implicit_any and !self.sourceHasReactJsxReference()) {
                try self.report(el.tag, TsCodes.jsx_element_implicit_any_no_intrinsic, "JSX element implicitly has type 'any' because no interface 'JSX.IntrinsicElements' exists.");
            }
        }
        if (props_t == null and !self.jsxTagIsIntrinsic(el.tag)) {
            const tag_t = try self.checkedExpressionType(el.tag);
            if ((try self.propertyNameFromLiteralType(tag_t)) != null) {
                if (try self.jsxHasIntrinsicElementsDecl(el.tag)) {
                    try self.report(el.tag, TsCodes.property_does_not_exist, "Property does not exist on type 'JSX.IntrinsicElements'.");
                } else if (self.strict_flags.no_implicit_any and !self.sourceHasReactJsxReference()) {
                    try self.report(el.tag, TsCodes.jsx_element_implicit_any_no_intrinsic, "JSX element implicitly has type 'any' because no interface 'JSX.IntrinsicElements' exists.");
                }
            }
        }

        if (!self.jsxTagIsIntrinsic(el.tag) and try self.jsxComponentTypeInvalid(el.tag)) {
            try self.report(el.tag, TsCodes.jsx_element_no_construct_or_call, "JSX element type does not have any construct or call signatures.");
        }

        var has_any_spread = false;
        for (attrs) |attr| {
            if (self.hir.kindOf(attr) != .jsx_spread_attribute) continue;
            const sp = hir_mod.jsxSpreadAttributeOf(self.hir, attr);
            const spread_t = try self.checkedExpressionType(sp.expression);
            if (self.typeIsAnyLike(spread_t)) has_any_spread = true;
        }

        var saw_children_attr = false;
        var attr_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer attr_members.deinit(self.gpa);
        var explicit_attrs: std.ArrayListUnmanaged(NodeId) = .empty;
        defer explicit_attrs.deinit(self.gpa);
        var spread_satisfies_target = false;
        var explicit_value_attr_count: usize = 0;
        for (attrs) |attr| {
            switch (self.hir.kindOf(attr)) {
                .jsx_attribute => {
                    const a = hir_mod.jsxAttributeOf(self.hir, attr);
                    const attr_name = self.string_interner.get(a.name);
                    if (std.mem.eql(u8, attr_name, "children")) saw_children_attr = true;
                    const value_t = try self.checkJsxAttributeValue(a.value);
                    const attr_bag_t = try self.jsxAttributeBagValueType(a.value, value_t);
                    if (!std.mem.eql(u8, attr_name, "key") and !std.mem.startsWith(u8, attr_name, "data-")) {
                        explicit_value_attr_count += 1;
                        try self.appendOrReplaceObjectMember(&attr_members, .{
                            .name = a.name,
                            .type = attr_bag_t,
                            .is_optional = false,
                            .is_readonly = false,
                            .is_method = false,
                        });
                    }
                    if (props_t) |target| {
                        const target_has_free = self.containsFreeTypeParameter(target);
                        if (std.mem.eql(u8, attr_name, "key")) continue;
                        if (try self.lookupObjectMember(target, a.name)) |prop_t| {
                            try self.checkJsxContextualAttributeValue(a.value, prop_t);
                            if (a.value != hir_mod.none_node_id) {
                                const ok = try self.jsxAttributeLiteralAssignable(a.value, prop_t) or
                                    try self.jsxAttributeAssignable(value_t, prop_t);
                                if (!ok) try self.report(attr, TsCodes.type_not_assignable, "JSX attribute value is not assignable to the target property.");
                            }
                        } else if (std.mem.startsWith(u8, attr_name, "data-")) {
                            continue;
                        } else if (!target_has_free and
                            self.jsxPropsTargetHasNamedMembers(target) and
                            !try self.jsxPropsHasNamedMember(target, a.name))
                        {
                            try self.report(attr, TsCodes.object_literal_excess_property, "JSX attribute does not exist on target props.");
                        }
                    }
                    try explicit_attrs.append(self.gpa, attr);
                },
                .jsx_spread_attribute => {
                    const sp = hir_mod.jsxSpreadAttributeOf(self.hir, attr);
                    const spread_t = try self.checkedExpressionType(sp.expression);
                    if (!try self.jsxSpreadTypeIsValid(spread_t)) {
                        try self.report(sp.expression, TsCodes.spread_types_object_only, "Spread types may only be created from object types.");
                    }
                    if (props_t) |target| {
                        if (self.engine.isAssignableTo(spread_t, target) catch false) spread_satisfies_target = true;
                        const constrained_target_param = self.isConstrainedTypeParameter(target);
                        if (self.containsFreeTypeParameter(target) and !constrained_target_param and
                            self.isUnconstrainedTypeParameter(spread_t) and spread_t != target)
                        {
                            try self.report(attr, TsCodes.type_not_assignable, "JSX spread attributes from an unconstrained type parameter are not assignable to the target props.");
                        }
                    }
                    try self.appendJsxSpreadMembers(&attr_members, spread_t);
                    try self.checkJsxSpreadOverwritesExplicitAttrs(spread_t, explicit_attrs.items);
                },
                else => {},
            }
        }

        for (children) |child| _ = try self.checkExpression(child);
        if (children.len > 0 and saw_children_attr) {
            try self.report(node, TsCodes.jsx_attribute_overwritten, "'children' is specified more than once.");
        }
        if (children.len > 0 and props_t != null and !self.typeIsAnyLike(props_t.?) and !saw_children_attr) {
            const children_name = self.string_interner.intern("children") catch return error.OutOfMemory;
            if (try self.lookupObjectMember(props_t.?, children_name)) |children_t| {
                if (children.len > 1 and !self.jsxChildrenTypeAllowsCount(children_t, children.len)) {
                    try self.report(node, TsCodes.type_not_assignable, "JSX element has multiple children but the target props type expects a single child.");
                }
                for (children) |child| {
                    if (self.hir.kindOf(child) == .literal_string and !self.jsxChildrenTypeAllowsString(children_t)) {
                        try self.report(child, TsCodes.jsx_text_child_not_accepted, "JSX text child is not assignable to the target children type.");
                    }
                }
            } else if (self.jsxPropsTargetHasNonChildrenMember(props_t.?)) {
                // Empty object props (`{}`) opts out of excess-property
                // checks just like a regular `{}` target in TS: with no
                // named members at all, JSX children flow in without
                // complaint. Only fire when the target genuinely
                // declares OTHER properties (so the missing `children`
                // signals a structural gap).
                try self.report(node, TsCodes.object_literal_excess_property, "JSX element has children but the target props type has no 'children' property.");
            }
        }
        if (children.len > 0 and !saw_children_attr) {
            const children_name = self.string_interner.intern("children") catch return error.OutOfMemory;
            try self.appendOrReplaceObjectMember(&attr_members, .{
                .name = children_name,
                .type = types.Primitive.any,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }
        if (props_t) |target| {
            if (!has_any_spread and !self.typeIsAnyLike(target)) {
                if (!(spread_satisfies_target and explicit_value_attr_count == 0)) {
                    const attrs_t = self.interner.internObjectType(attr_members.items) catch return error.OutOfMemory;
                    var effective_target = target;
                    if (self.containsFreeTypeParameter(target)) {
                        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                        defer subs.deinit(self.gpa);
                        try self.inferFromPair(target, attrs_t, &subs);
                        if (subs.count() > 0) {
                            effective_target = self.substituteType(target, &subs) catch target;
                        }
                    }
                    const required_props_ok = try self.jsxRequiredPropsAssignable(effective_target, attrs_t);
                    if ((!required_props_ok or !(self.engine.isAssignableTo(attrs_t, effective_target) catch true)) and
                        !try self.jsxAttributesMatchOverload(el.tag, attrs_t, attrs.len) and
                        !(self.containsFreeTypeParameter(target) and try self.jsxRequiredPropsCovered(target, attrs_t)))
                    {
                        try self.report(node, TsCodes.type_not_assignable, "JSX attributes are not assignable to the target props type.");
                    }
                }
            }
        }
        return types.Primitive.any;
    }

    fn checkedExpressionType(self: *Checker, node: NodeId) CheckError!TypeId {
        const existing = self.hir.typeOf(node);
        if (existing != types.Primitive.none) return existing;
        return try self.checkExpression(node);
    }

    fn appendOrReplaceObjectMember(
        self: *Checker,
        members: *std.ArrayListUnmanaged(types.ObjectMember),
        member: types.ObjectMember,
    ) CheckError!void {
        for (members.items) |*existing| {
            if (existing.name == member.name) {
                existing.* = member;
                return;
            }
        }
        try members.append(self.gpa, member);
    }

    fn appendJsxSpreadMembers(
        self: *Checker,
        members: *std.ArrayListUnmanaged(types.ObjectMember),
        spread_t: TypeId,
    ) CheckError!void {
        if (spread_t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(spread_t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(spread_t) orelse return;
            if (constraint != spread_t) try self.appendJsxSpreadMembers(members, constraint);
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(spread_t)) |member_t| {
                try self.appendJsxSpreadMembers(members, member_t);
            }
            return;
        }
        if (flags.is_union) return;
        if (!flags.is_object_type) return;
        for (self.interner.objectMembers(spread_t)) |member| {
            try self.appendOrReplaceObjectMember(members, member);
        }
    }

    fn jsxSpreadTypeIsValid(self: *Checker, t: TypeId) CheckError!bool {
        if (self.typeIsAnyLike(t)) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_never or flags.is_null or flags.is_undefined or flags.is_void) return false;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!try self.jsxSpreadTypeIsValid(member)) return false;
            }
            return true;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (try self.jsxSpreadTypeIsValid(member)) return true;
            }
            return false;
        }
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return true;
            if (constraint == t) return false;
            return try self.jsxSpreadTypeIsValid(constraint);
        }
        return flags.is_object_type or flags.is_object or flags.is_signature;
    }

    fn objectSpreadSourceIsValid(self: *Checker, t: TypeId) CheckError!bool {
        if (self.typeIsAnyLike(t)) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_never) return true;
        // For unions/intersections, the OR'd flags include
        // is_null/is_undefined/is_void from constituents — defer to the
        // dedicated union/intersection branches below which inspect
        // each member individually. Only reject the bare nullish
        // primitives outright. Mirrors `spreadUnion2.ts(o1..o5)` where
        // `{ a: number } | undefined` is a valid spread source.
        if (!flags.is_union and !flags.is_intersection) {
            if (flags.is_null or flags.is_undefined or flags.is_void) return false;
        }
        if (flags.is_boolean and (t == types.Primitive.boolean_t or t == types.Primitive.false_lit)) return true;
        if (flags.is_union) {
            var saw_spreadable = false;
            for (self.interner.unionMembers(t)) |member| {
                if (member == types.Primitive.null_t or member == types.Primitive.undefined_t or member == types.Primitive.false_lit) continue;
                // Type parameters constrained to nullish-only types
                // (`T extends undefined`, `T extends null`) collapse to
                // their constraint within the union — TS does NOT
                // report TS2698 if the rest of the union is spreadable.
                // Mirrors `spreadObjectOrFalsy.ts(f4/f5/f6)`.
                if (member < self.interner.pool.typeCount()) {
                    const mflags = self.interner.pool.flagsOf(member);
                    if (mflags.is_type_parameter) {
                        if (self.typeParameterConstraint(member)) |constraint| {
                            if (constraint != member and constraint < self.interner.pool.typeCount()) {
                                const cflags = self.interner.pool.flagsOf(constraint);
                                if (cflags.is_undefined or cflags.is_null or cflags.is_void) continue;
                            }
                        }
                    }
                    // Intersections that include `undefined` / `null` /
                    // `void` reduce to `never` at runtime — also skip
                    // them inside a union (mirrors `f2: T | T & undefined`).
                    if (mflags.is_intersection) {
                        var has_nullish = false;
                        for (self.interner.intersectionMembers(member)) |im| {
                            if (im == types.Primitive.null_t or
                                im == types.Primitive.undefined_t or
                                im == types.Primitive.void_t)
                            {
                                has_nullish = true;
                                break;
                            }
                        }
                        if (has_nullish) continue;
                    }
                }
                if (!try self.objectSpreadSourceIsValid(member)) return false;
                saw_spreadable = true;
            }
            // A union composed entirely of nullish/falsy members
            // (`null | undefined`, `null | undefined | false`) has no
            // spreadable inhabitant and must surface TS2698. Mirrors
            // `spreadUnion3.ts(19/20)`'s `nullAndUndefinedUnion`.
            return saw_spreadable;
        }
        if (flags.is_intersection) {
            // TS2698 wave-2: an intersection that includes a hard
            // nullish member (`null`, `undefined`, `void`) collapses
            // to `never` in upstream's relation engine — `T &
            // undefined` has no inhabitants, so spreading it must
            // surface as TS2698 rather than silently passing because
            // a sibling type-parameter member happened to clear the
            // per-member check. Mirrors `spreadObjectOrFalsy.ts`
            // lines 5/13 (`f1<T>(a: T & undefined)`,
            // `f3<T extends undefined>(a: T)`).
            for (self.interner.intersectionMembers(t)) |member| {
                if (member == types.Primitive.null_t or
                    member == types.Primitive.undefined_t or
                    member == types.Primitive.void_t)
                {
                    return false;
                }
            }
            for (self.interner.intersectionMembers(t)) |member| {
                if (try self.objectSpreadSourceIsValid(member)) return true;
            }
            return false;
        }
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return true;
            if (constraint == t) return true;
            return try self.objectSpreadSourceIsValid(constraint);
        }
        return flags.is_object_type or flags.is_object or flags.is_signature;
    }

    fn objectSpreadEffectiveType(self: *Checker, expr: NodeId, fallback: TypeId) CheckError!TypeId {
        if (expr == hir_mod.none_node_id) return fallback;
        const k = self.hir.kindOf(expr);
        if (k == .logical_op) {
            const l = hir_mod.logicalOf(self.hir, expr);
            if (l.op != .@"and") return fallback;
            const rhs_t = if (self.hir.typeOf(l.rhs) != types.Primitive.none)
                self.hir.typeOf(l.rhs)
            else
                try self.checkExpression(l.rhs);
            if (try self.objectSpreadSourceIsValid(rhs_t)) return rhs_t;
            return fallback;
        }
        if (k == .conditional) {
            // For `cond ? thenExpr : elseExpr` we use whichever branch
            // is a valid spread source — at least one nullish branch
            // is OK (matches `objectSpreadIndexSignature.ts(14)`'s
            // `...b ? indexed3 : undefined`).
            const c = hir_mod.conditionalOf(self.hir, expr);
            const tt = if (self.hir.typeOf(c.then_branch) != types.Primitive.none)
                self.hir.typeOf(c.then_branch)
            else
                try self.checkExpression(c.then_branch);
            const ff = if (self.hir.typeOf(c.else_branch) != types.Primitive.none)
                self.hir.typeOf(c.else_branch)
            else
                try self.checkExpression(c.else_branch);
            const tt_ok = try self.objectSpreadSourceIsValid(tt);
            const ff_ok = try self.objectSpreadSourceIsValid(ff);
            if (tt_ok and ff_ok) return fallback;
            if (tt_ok) return tt;
            if (ff_ok) return ff;
            return fallback;
        }
        return fallback;
    }

    /// Returns true when the spread expression might contribute no
    /// members at runtime, e.g. `...(t ? a : {})` or `...(x && a)`.
    /// In those cases TS2783 (duplicate-property overwrite) should not
    /// fire even when an explicit property earlier shares a name with
    /// one of the spread's possible members — the spread is not
    /// guaranteed to overwrite. Walks through type assertions and
    /// parenthesized expressions so source-level grouping is
    /// transparent.
    fn spreadExpressionMayContributeNothing(self: *Checker, expr: NodeId) bool {
        var cur = expr;
        while (cur != hir_mod.none_node_id) {
            switch (self.hir.kindOf(cur)) {
                .conditional => return true,
                .logical_op => {
                    const l = hir_mod.logicalOf(self.hir, cur);
                    // `a && b` (LHS may be falsy → spread evaluates `a`).
                    // `a || b` and `a ?? b` similarly may pick either side.
                    _ = l;
                    return true;
                },
                .type_assertion, .as_expr, .satisfies_expr, .non_null_expr => {
                    const inner = hir_mod.asExpressionOf(self.hir, cur);
                    cur = inner.expr;
                },
                else => return false,
            }
        }
        return false;
    }

    fn jsxAttributeAssignable(self: *Checker, value_t: TypeId, prop_t: TypeId) CheckError!bool {
        if (self.firstSignatureType(value_t)) |value_sig| {
            if (self.containsFreeTypeParameter(prop_t)) return true;
            if (self.firstSignatureType(prop_t)) |prop_sig| {
                const value_params = self.interner.signatureParams(value_sig);
                const prop_params = self.interner.signatureParams(prop_sig);
                if (value_params.len <= prop_params.len) {
                    var i: usize = 0;
                    while (i < value_params.len) : (i += 1) {
                        if (prop_params[i] < self.interner.pool.typeCount()) {
                            const pf = self.interner.pool.flagsOf(prop_params[i]);
                            if (pf.is_type_parameter or pf.is_any or pf.is_unknown) continue;
                        }
                        if (!(self.engine.isAssignableTo(prop_params[i], value_params[i]) catch true)) return false;
                    }
                    return true;
                }
            }
        }
        return self.engine.isAssignableTo(value_t, prop_t) catch true;
    }

    fn jsxAttributeLiteralAssignable(self: *Checker, value: NodeId, prop_t: TypeId) CheckError!bool {
        if (value == hir_mod.none_node_id) return false;
        var inner = value;
        if (self.hir.kindOf(value) == .jsx_expression) {
            const ex = hir_mod.jsxExpressionOf(self.hir, value);
            if (ex.expression == hir_mod.none_node_id) return false;
            inner = ex.expression;
        }
        return try self.literalExpressionAssignableToTarget(inner, prop_t);
    }

    fn jsxAttributesMatchOverload(self: *Checker, tag: NodeId, attrs_t: TypeId, attr_count: usize) CheckError!bool {
        if (tag == hir_mod.none_node_id or self.hir.kindOf(tag) != .identifier) return false;
        const tag_name = hir_mod.identifierOf(self.hir, tag).name;
        const overload_list = self.overloads.get(tag_name) orelse return false;
        const has_impl = self.overload_has_implementation.contains(tag_name);
        const visible_len = if (has_impl and overload_list.items.len > 0) overload_list.items.len - 1 else overload_list.items.len;
        for (overload_list.items[0..visible_len]) |sig| {
            const params = self.interner.signatureParams(sig);
            if (params.len == 0) {
                if (attr_count == 0) return true;
                continue;
            }
            var target = params[0];
            const target_had_free = self.containsFreeTypeParameter(target);
            if (target_had_free) {
                var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                defer subs.deinit(self.gpa);
                try self.inferFromPair(target, attrs_t, &subs);
                if (subs.count() > 0) {
                    target = self.substituteType(target, &subs) catch target;
                }
            }
            if (self.engine.isAssignableTo(attrs_t, target) catch false) return true;
            if (target_had_free and try self.jsxRequiredPropsAssignable(target, attrs_t)) return true;
        }
        return false;
    }

    fn jsxRequiredPropsAssignable(self: *Checker, target: TypeId, attrs_t: TypeId) CheckError!bool {
        if (target >= self.interner.pool.typeCount()) return true;
        const flags = self.interner.pool.flagsOf(target);
        if (flags.is_type_parameter) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(target)) |member| {
                if (try self.jsxRequiredPropsAssignable(member, attrs_t)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target)) |member| {
                if (!try self.jsxRequiredPropsAssignable(member, attrs_t)) return false;
            }
            return true;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(target)) |member| {
            if (member.is_optional) continue;
            const attr_t = self.interner.objectMember(attrs_t, member.name) orelse return false;
            if (self.containsFreeTypeParameter(member.type)) continue;
            if (!try self.jsxAttributeAssignable(attr_t, member.type)) return false;
        }
        return true;
    }

    fn jsxRequiredPropsCovered(self: *Checker, target: TypeId, attrs_t: TypeId) CheckError!bool {
        if (target >= self.interner.pool.typeCount()) return true;
        const flags = self.interner.pool.flagsOf(target);
        if (flags.is_type_parameter) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(target)) |member| {
                if (try self.jsxRequiredPropsCovered(member, attrs_t)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target)) |member| {
                if (!try self.jsxRequiredPropsCovered(member, attrs_t)) return false;
            }
            return true;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(target)) |member| {
            if (member.is_optional) continue;
            if (self.interner.objectMember(attrs_t, member.name) == null) return false;
        }
        return true;
    }

    fn checkJsxSpreadOverwritesExplicitAttrs(self: *Checker, spread_t: TypeId, attrs: []const NodeId) CheckError!void {
        if (spread_t >= self.interner.pool.typeCount()) return;
        for (attrs) |attr| {
            if (self.hir.kindOf(attr) != .jsx_attribute) continue;
            const a = hir_mod.jsxAttributeOf(self.hir, attr);
            if ((try self.lookupObjectMember(spread_t, a.name)) != null) {
                try self.report(attr, TsCodes.jsx_attribute_overwritten, "JSX attribute is specified more than once, so this usage will be overwritten.");
            }
        }
    }

    /// Returns true when the props target carries at least one named
    /// member that ISN'T `children`. Empty `{}` and a props type that
    /// only declares `children` both return false — the former opts
    /// out of excess-property checks entirely, the latter is already
    /// handled by the dedicated `children`-member lookup. Mirrors
    /// `checkJsxChildrenProperty10` baseline where `props: {}` doesn't
    /// trigger TS2353 on the JSX children block.
    fn jsxPropsTargetHasNonChildrenMember(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return self.jsxPropsTargetHasNonChildrenMember(constraint);
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.jsxPropsTargetHasNonChildrenMember(member)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.jsxPropsTargetHasNonChildrenMember(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(t)) |m| {
            const name = self.string_interner.get(m.name);
            if (!std.mem.eql(u8, name, "children")) return true;
        }
        return false;
    }

    fn jsxPropsTargetHasNamedMembers(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return self.jsxPropsTargetHasNamedMembers(constraint);
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.jsxPropsTargetHasNamedMembers(member)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.jsxPropsTargetHasNamedMembers(member)) return true;
            }
            return false;
        }
        return flags.is_object_type;
    }

    fn jsxPropsHasNamedMember(self: *Checker, t: TypeId, name: hir_mod.StringId) CheckError!bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return try self.jsxPropsHasNamedMember(constraint, name);
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (try self.jsxPropsHasNamedMember(member, name)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (try self.jsxPropsHasNamedMember(member, name)) return true;
            }
            return false;
        }
        return self.interner.objectMember(t, name) != null;
    }

    fn jsxChildrenTypeAllowsCount(self: *Checker, t: TypeId, count: usize) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_any) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.jsxChildrenTypeAllowsCount(member, count)) return true;
            }
            return false;
        }
        if (self.fixedTupleLength(t)) |length| return count <= length;
        if (flags.is_object_type and self.interner.objectNumberIndex(t) != types.Primitive.none) return true;
        return count <= 1;
    }

    fn jsxChildrenTypeAllowsString(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_any or flags.is_string) return true;
        if (flags.is_literal and flags.is_string) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.jsxChildrenTypeAllowsString(member)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.jsxChildrenTypeAllowsString(member)) return true;
            }
            return false;
        }
        const elem_t = self.interner.objectNumberIndex(t);
        return elem_t != types.Primitive.none and self.jsxChildrenTypeAllowsString(elem_t);
    }

    fn checkJsxAttributeValue(self: *Checker, value: NodeId) CheckError!TypeId {
        if (value == hir_mod.none_node_id) return types.Primitive.true_lit;
        if (self.hir.kindOf(value) == .jsx_expression) {
            const ex = hir_mod.jsxExpressionOf(self.hir, value);
            if (ex.expression == hir_mod.none_node_id) return types.Primitive.undefined_t;
            return try self.checkExpression(ex.expression);
        }
        return try self.checkExpression(value);
    }

    fn jsxAttributeBagValueType(self: *Checker, value: NodeId, fallback: TypeId) CheckError!TypeId {
        if (value == hir_mod.none_node_id) return types.Primitive.true_lit;
        var inner = value;
        if (self.hir.kindOf(value) == .jsx_expression) {
            const ex = hir_mod.jsxExpressionOf(self.hir, value);
            if (ex.expression == hir_mod.none_node_id) return types.Primitive.undefined_t;
            inner = ex.expression;
        }
        return try self.flowTypeForAssignmentValue(inner, fallback);
    }

    fn checkJsxContextualAttributeValue(self: *Checker, value: NodeId, prop_t: TypeId) CheckError!void {
        if (value == hir_mod.none_node_id) return;
        if (self.hir.kindOf(value) != .jsx_expression) return;
        const ex = hir_mod.jsxExpressionOf(self.hir, value);
        if (ex.expression == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(ex.expression);
        if (k != .arrow_fn and k != .fn_expr and k != .fn_decl) return;
        const sig = self.firstSignatureType(prop_t) orelse return;
        try self.checkFunctionWithContextualSignature(ex.expression, sig);
    }

    fn firstSignatureType(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_signature) return t;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.firstSignatureType(member)) |sig| return sig;
            }
        }
        return null;
    }

    fn checkFunctionWithContextualSignature(self: *Checker, fn_node: NodeId, sig: TypeId) CheckError!void {
        const params = hir_mod.fnParams(self.hir, fn_node);
        const param_ts = self.interner.signatureParams(sig);
        try self.pushNarrowScope();
        defer self.popNarrowScope();
        const n = @min(params.len, param_ts.len);
        for (0..n) |i| {
            const pp = hir_mod.parameterOf(self.hir, params[i]);
            if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, pp.name);
            try self.recordNarrow(id.name, param_ts[i]);
            self.hir.setType(params[i], param_ts[i]);
            self.hir.setType(pp.name, param_ts[i]);
        }
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.body == hir_mod.none_node_id) return;
        self.function_body_depth += 1;
        defer self.function_body_depth -= 1;
        if (self.hir.kindOf(f.body) == .block_stmt) {
            for (hir_mod.blockStmts(self.hir, f.body)) |s| try self.checkStatement(s);
        } else {
            _ = try self.checkExpression(f.body);
        }
    }

    fn jsxPropsType(self: *Checker, tag: NodeId, attr_count: usize) CheckError!?TypeId {
        if (tag == hir_mod.none_node_id) return null;
        if (self.jsxTagIsIntrinsic(tag)) {
            const id = hir_mod.identifierOf(self.hir, tag);
            return try self.jsxIntrinsicPropsType(tag, id.name);
        }
        if (self.jsxClassInstanceTypeForTag(tag)) |instance_t| {
            const props_name = self.string_interner.intern("props") catch return error.OutOfMemory;
            if (try self.lookupObjectMember(instance_t, props_name)) |props_t| return props_t;
        }
        if (self.hir.kindOf(tag) == .identifier) {
            const tag_name = hir_mod.identifierOf(self.hir, tag).name;
            if (self.overloads.get(tag_name)) |overload_list| {
                const has_impl = self.overload_has_implementation.contains(tag_name);
                const visible_len = if (has_impl and overload_list.items.len > 0) overload_list.items.len - 1 else overload_list.items.len;
                var prop_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer prop_types.deinit(self.gpa);
                var saw_zero_param = false;
                for (overload_list.items[0..visible_len]) |sig| {
                    const params = self.interner.signatureParams(sig);
                    if (params.len == 0) {
                        saw_zero_param = true;
                        continue;
                    }
                    try prop_types.append(self.gpa, params[0]);
                }
                if (saw_zero_param and attr_count == 0) return types.Primitive.any;
                if (prop_types.items.len > 0) {
                    if (prop_types.items.len == 1) return prop_types.items[0];
                    return self.interner.internUnion(prop_types.items) catch return error.OutOfMemory;
                }
            }
            if (try self.jsxLogicalComponentPropsType(tag, tag_name)) |props_t| return props_t;
            if (try self.jsxForwardFunctionPropsType(tag, tag_name)) |props_t| return props_t;
        }
        const tag_t = try self.checkExpression(tag);
        if (try self.propertyNameFromLiteralType(tag_t)) |intrinsic_name| {
            return try self.jsxIntrinsicPropsType(tag, intrinsic_name);
        }
        if (try self.lookupObjectMember(tag_t, self.string_interner.intern("props") catch return error.OutOfMemory)) |props_t| {
            return props_t;
        }
        var construct_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer construct_sigs.deinit(self.gpa);
        try self.collectConstructSignatures(tag_t, &construct_sigs);
        if (construct_sigs.items.len > 0) {
            const params = self.interner.signatureParams(construct_sigs.items[0]);
            if (params.len > 0) return params[0];
            return types.Primitive.any;
        }
        var call_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer call_sigs.deinit(self.gpa);
        try self.collectCallSignatures(tag_t, &call_sigs);
        if (call_sigs.items.len > 0) {
            const params = self.interner.signatureParams(call_sigs.items[0]);
            if (params.len > 0) return params[0];
            return types.Primitive.any;
        }
        return null;
    }

    fn jsxForwardFunctionPropsType(self: *Checker, anchor: NodeId, tag_name: hir_mod.StringId) CheckError!?TypeId {
        return try self.jsxNamedFunctionPropsType(anchor, tag_name);
    }

    fn jsxNamedFunctionPropsType(self: *Checker, anchor: NodeId, tag_name: hir_mod.StringId) CheckError!?TypeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
            if (decl == hir_mod.none_node_id or self.hir.kindOf(decl) != .fn_decl) continue;
            const f = hir_mod.fnDeclOf(self.hir, decl);
            if (f.name == hir_mod.none_node_id or self.hir.kindOf(f.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, f.name).name != tag_name) continue;
            const params = hir_mod.fnParams(self.hir, decl);
            if (params.len == 0) return self.interner.internObjectType(&.{}) catch return error.OutOfMemory;
            const first = hir_mod.parameterOf(self.hir, params[0]);
            if (first.type_annotation == hir_mod.none_node_id) return types.Primitive.any;
            try self.ensureTypeRefDeclChecked(first.type_annotation, root);
            return try self.lowererLowerWithTypeParams(first.type_annotation);
        }
        return null;
    }

    fn jsxLogicalComponentPropsType(self: *Checker, anchor: NodeId, tag_name: hir_mod.StringId) CheckError!?TypeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
            if (decl == hir_mod.none_node_id) continue;
            const dk = self.hir.kindOf(decl);
            if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, decl);
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, v.name).name != tag_name) continue;
            if (v.init == hir_mod.none_node_id or self.hir.kindOf(v.init) != .logical_op) return null;
            var prop_types: std.ArrayListUnmanaged(TypeId) = .empty;
            defer prop_types.deinit(self.gpa);
            try self.collectJsxLogicalComponentProps(anchor, v.init, &prop_types);
            if (prop_types.items.len == 0) return null;
            if (prop_types.items.len == 1) return prop_types.items[0];
            return self.interner.internIntersection(prop_types.items) catch return error.OutOfMemory;
        }
        return null;
    }

    fn collectJsxLogicalComponentProps(
        self: *Checker,
        anchor: NodeId,
        node: NodeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        if (self.hir.kindOf(node) == .logical_op) {
            const l = hir_mod.logicalOf(self.hir, node);
            try self.collectJsxLogicalComponentProps(anchor, l.lhs, out);
            try self.collectJsxLogicalComponentProps(anchor, l.rhs, out);
            return;
        }
        if (self.hir.kindOf(node) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, node);
        const props_t = (try self.jsxNamedFunctionPropsType(anchor, id.name)) orelse
            self.jsxClassPropsTypeForName(id.name) orelse
            return;
        try out.append(self.gpa, props_t);
    }

    fn jsxClassPropsTypeForName(self: *Checker, tag_name: hir_mod.StringId) ?TypeId {
        const instance_t = self.class_instance_types.get(tag_name) orelse return null;
        const props_name = self.string_interner.intern("props") catch return null;
        return self.lookupObjectMember(instance_t, props_name) catch null;
    }

    fn ensureTypeRefDeclChecked(self: *Checker, type_node: NodeId, root: NodeId) CheckError!void {
        switch (self.hir.kindOf(type_node)) {
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, type_node);
                if (r.qualifier_len != 0) return;
                if (self.type_names.contains(r.name) or self.generic_aliases.contains(r.name)) return;
                for (hir_mod.blockStmts(self.hir, root)) |stmt| {
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    switch (self.hir.kindOf(decl)) {
                        .interface_decl => {
                            const it = hir_mod.interfaceOf(self.hir, decl);
                            if (it.name != hir_mod.none_node_id and
                                self.hir.kindOf(it.name) == .identifier and
                                hir_mod.identifierOf(self.hir, it.name).name == r.name)
                            {
                                try self.checkInterfaceDecl(decl);
                                return;
                            }
                        },
                        .type_alias_decl => {
                            const ta = hir_mod.typeAliasOf(self.hir, decl);
                            if (ta.name != hir_mod.none_node_id and
                                self.hir.kindOf(ta.name) == .identifier and
                                hir_mod.identifierOf(self.hir, ta.name).name == r.name)
                            {
                                try self.checkTypeAliasDecl(decl);
                                return;
                            }
                        },
                        else => {},
                    }
                }
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, type_node)) |member| try self.ensureTypeRefDeclChecked(member, root),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, type_node)) |member| try self.ensureTypeRefDeclChecked(member, root),
            .array_type => try self.ensureTypeRefDeclChecked(hir_mod.arrayTypeOf(self.hir, type_node).element, root),
            else => {},
        }
    }

    fn jsxTagIsIntrinsic(self: *Checker, tag: NodeId) bool {
        if (tag == hir_mod.none_node_id or self.hir.kindOf(tag) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, tag);
        const name = self.string_interner.get(id.name);
        if (std.mem.eql(u8, name, "this")) return false;
        return name.len > 0 and std.ascii.isLower(name[0]);
    }

    fn jsxComponentTypeInvalid(self: *Checker, tag: NodeId) CheckError!bool {
        if (tag == hir_mod.none_node_id) return false;
        if (self.jsxClassInstanceTypeForTag(tag)) |_| return false;
        const tag_t = try self.checkedExpressionType(tag);
        return !(try self.jsxComponentTypeIsValid(tag_t));
    }

    fn jsxClassInstanceTypeForTag(self: *Checker, tag: NodeId) ?TypeId {
        if (tag == hir_mod.none_node_id or self.hir.kindOf(tag) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, tag);
        return self.class_instance_types.get(id.name);
    }

    fn jsxComponentTypeIsValid(self: *Checker, t: TypeId) CheckError!bool {
        if (self.typeIsAnyLike(t)) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_string) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!try self.jsxComponentTypeIsValid(member)) return false;
            }
            return true;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (try self.jsxComponentTypeIsValid(member)) return true;
            }
            return false;
        }
        if (flags.is_signature) {
            const ret = self.interner.signatureReturn(t) orelse types.Primitive.any;
            if (self.strict_flags.strict_null_checks and
                (ret == types.Primitive.undefined_t or ret == types.Primitive.void_t))
            {
                return false;
            }
            return true;
        }
        if (!flags.is_object_type) return false;
        const props_name = self.string_interner.intern("props") catch return error.OutOfMemory;
        if ((try self.lookupObjectMember(t, props_name)) != null) return true;
        var construct_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer construct_sigs.deinit(self.gpa);
        try self.collectConstructSignatures(t, &construct_sigs);
        if (construct_sigs.items.len > 0) return true;
        var call_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer call_sigs.deinit(self.gpa);
        try self.collectCallSignatures(t, &call_sigs);
        return call_sigs.items.len > 0;
    }

    fn jsxIntrinsicPropsType(self: *Checker, anchor: NodeId, tag_name: hir_mod.StringId) CheckError!?TypeId {
        const jsx_name = self.string_interner.intern("JSX") catch return error.OutOfMemory;
        const intrinsic_name = self.string_interner.intern("IntrinsicElements") catch return error.OutOfMemory;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const ns_node = self.findNamespaceByPath(hir_mod.blockStmts(self.hir, root), &[_]hir_mod.StringId{jsx_name}) orelse {
            if (self.sourceHasReactJsxReference()) return types.Primitive.any;
            return null;
        };
        const decl = self.findNamedTypeDeclInNamespace(ns_node, intrinsic_name) orelse return null;
        if (self.hir.kindOf(decl) == .interface_decl) {
            for (hir_mod.interfaceMembers(self.hir, decl)) |member| {
                if (self.hir.kindOf(member) != .interface_member) continue;
                const im = hir_mod.interfaceMemberOf(self.hir, member);
                if (im.name != tag_name) continue;
                if (im.type_node != hir_mod.none_node_id) {
                    return try self.lowererLowerWithTypeParams(im.type_node);
                }
                return types.Primitive.any;
            }
        }
        var intrinsic_t = self.hir.typeOf(decl);
        if (intrinsic_t == types.Primitive.none or intrinsic_t == types.Primitive.unknown) {
            if (self.hir.kindOf(decl) == .interface_decl) try self.checkInterfaceDecl(decl);
            intrinsic_t = self.hir.typeOf(decl);
        }
        if (intrinsic_t == types.Primitive.none or intrinsic_t == types.Primitive.unknown) return null;
        if (try self.lookupObjectMember(intrinsic_t, tag_name)) |props_t| return props_t;
        const string_idx = self.interner.objectStringIndex(intrinsic_t);
        if (string_idx != types.Primitive.none) return string_idx;
        const number_idx = self.interner.objectNumberIndex(intrinsic_t);
        if (number_idx != types.Primitive.none and self.isNumericStringId(tag_name)) return number_idx;
        return null;
    }

    fn jsxHasIntrinsicElementsDecl(self: *Checker, anchor: NodeId) CheckError!bool {
        const jsx_name = self.string_interner.intern("JSX") catch return error.OutOfMemory;
        const intrinsic_name = self.string_interner.intern("IntrinsicElements") catch return error.OutOfMemory;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        const ns_node = self.findNamespaceByPath(hir_mod.blockStmts(self.hir, root), &[_]hir_mod.StringId{jsx_name}) orelse return false;
        return self.findNamedTypeDeclInNamespace(ns_node, intrinsic_name) != null;
    }

    fn jsxHasNamespaceDecl(self: *Checker, anchor: NodeId) CheckError!bool {
        const jsx_name = self.string_interner.intern("JSX") catch return error.OutOfMemory;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        return self.findNamespaceByPath(hir_mod.blockStmts(self.hir, root), &[_]hir_mod.StringId{jsx_name}) != null;
    }

    fn nodeIsSuperReference(self: *Checker, node: NodeId) bool {
        const kind = self.hir.kindOf(node);
        if (kind == .super_expr) return true;
        if (kind == .identifier) {
            const id = hir_mod.identifierOf(self.hir, node);
            return std.mem.eql(u8, self.string_interner.get(id.name), "super");
        }
        return false;
    }

    /// Walks parents of `node` and returns the enclosing class
    /// declaration whose lexical static `super` binding governs this
    /// node — or `none_node_id` if the node is not inside a static
    /// member that inherits super. Crossing a non-arrow function or a
    /// nested class breaks the static-super chain (mirrors JS arrow
    /// lexical inheritance: `super` flows through arrows, not through
    /// `function () {}` or `class {}` bodies). Static `{ … }` blocks
    /// declared as class members are detected by checking whether the
    /// block is one of the parent class's `members` slice.
    fn enclosingStaticSuperClass(self: *Checker, node: NodeId) NodeId {
        var prev: NodeId = node;
        var cur = self.hir.parentOf(node);
        var saw_static_member = false;
        while (cur != hir_mod.none_node_id) {
            const k = self.hir.kindOf(cur);
            switch (k) {
                .object_property => {
                    const op = hir_mod.objectPropertyOf(self.hir, cur);
                    if (op.is_static) saw_static_member = true;
                },
                .fn_decl, .fn_expr => {
                    const fp = hir_mod.fnDeclOf(self.hir, cur);
                    if (fp.flags.is_static) saw_static_member = true;
                    if (!fp.flags.is_arrow) return hir_mod.none_node_id;
                },
                .arrow_fn => {},
                .class_decl, .class_expr => {
                    // `static { … }` blocks are stored as bare
                    // `block_stmt` nodes in `classMembers`. Detect
                    // by scanning the members slice — if the last
                    // child we walked through (prev) is one of them
                    // and is a block_stmt, this access lives inside
                    // a static block.
                    if (!saw_static_member and self.hir.kindOf(prev) == .block_stmt) {
                        for (hir_mod.classMembers(self.hir, cur)) |m| {
                            if (m == prev) {
                                saw_static_member = true;
                                break;
                            }
                        }
                    }
                    if (!saw_static_member) return hir_mod.none_node_id;
                    return cur;
                },
                else => {},
            }
            prev = cur;
            cur = self.hir.parentOf(cur);
        }
        return hir_mod.none_node_id;
    }

    /// TS2340 — `Only public and protected methods of the base class
    /// are accessible via the 'super' keyword.` Fires for `super.X`
    /// where the access is in a static initializer / static method of
    /// a derived class, `X` is a data property (not a method) on the
    /// base class, and the emit target is ES5. Mirrors tsc fixtures
    /// `typeOfThisInStaticMembers{3,4,7,9,10,11}` and `classStaticBlock5`.
    fn reportSuperPropertyNotMethodInStatic(
        self: *Checker,
        super_obj_node: NodeId,
        super_t: TypeId,
        member_node: NodeId,
        member_name: hir_mod.StringId,
    ) CheckError!void {
        if (!self.sourceTargetMentionsEs5()) return;
        if (super_t >= self.interner.pool.typeCount()) return;
        if (!self.interner.pool.flagsOf(super_t).is_object_type) return;
        // Anchor must live inside a derived class — both static AND
        // instance contexts qualify under target=es5 (tsc emits
        // TS2340 for `super.X` data-property access regardless of
        // static-ness when the lowering target predates `Reflect.get`).
        const enclosing = self.enclosingSuperClass(super_obj_node);
        if (enclosing == hir_mod.none_node_id) return;
        if (self.hir.kindOf(enclosing) != .class_decl and self.hir.kindOf(enclosing) != .class_expr) return;
        const c = hir_mod.classOf(self.hir, enclosing);
        if (c.extends == hir_mod.none_node_id) return;
        const obj_members = self.interner.objectMembers(super_t);
        var found_member: ?types.ObjectMember = null;
        for (obj_members) |om| {
            if (om.name == member_name) {
                found_member = om;
                break;
            }
        }
        const om = found_member orelse return;
        if (om.is_method) return;
        const member_span = self.hir.spanOf(member_node);
        const name_str = self.string_interner.get(member_name);
        const name_pos: ?u32 = if (member_span.end >= name_str.len)
            member_span.end - @as(u32, @intCast(name_str.len))
        else
            null;
        try self.diagnostics.append(self.gpa, .{
            .node = member_node,
            .pos = name_pos,
            .code = TsCodes.super_only_methods_accessible,
            .message = "Only public and protected methods of the base class are accessible via the 'super' keyword.",
        });
    }

    /// Same as `enclosingStaticSuperClass` but accepts either static
    /// or instance member contexts — provided we stay within a class
    /// whose lexical super chain hasn't been broken by a non-arrow
    /// function or nested class boundary.
    fn enclosingSuperClass(self: *Checker, node: NodeId) NodeId {
        var prev: NodeId = node;
        var cur = self.hir.parentOf(node);
        var saw_member = false;
        while (cur != hir_mod.none_node_id) {
            const k = self.hir.kindOf(cur);
            switch (k) {
                .object_property => {
                    saw_member = true;
                },
                .fn_decl, .fn_expr => {
                    const fp = hir_mod.fnDeclOf(self.hir, cur);
                    const is_class_member = fp.flags.is_method or fp.flags.is_constructor or
                        fp.flags.is_getter or fp.flags.is_setter;
                    if (is_class_member) {
                        saw_member = true;
                        // Class member methods anchor the super chain
                        // — keep walking to find the enclosing class.
                    } else if (!fp.flags.is_arrow) {
                        // Bare function expression / declaration breaks
                        // the lexical super chain (`function () { super.x }`
                        // doesn't see the enclosing class's super).
                        return hir_mod.none_node_id;
                    }
                },
                .arrow_fn => {},
                .class_decl, .class_expr => {
                    if (!saw_member and self.hir.kindOf(prev) == .block_stmt) {
                        for (hir_mod.classMembers(self.hir, cur)) |m| {
                            if (m == prev) {
                                saw_member = true;
                                break;
                            }
                        }
                    }
                    if (!saw_member) return hir_mod.none_node_id;
                    return cur;
                },
                else => {},
            }
            prev = cur;
            cur = self.hir.parentOf(cur);
        }
        return hir_mod.none_node_id;
    }

    fn pushNarrowScope(self: *Checker) !void {
        const empty: std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId) = .empty;
        try self.narrow_scopes.append(self.gpa, empty);
        const empty_mem: std.AutoHashMapUnmanaged(MemberKey, TypeId) = .empty;
        try self.member_narrow_scopes.append(self.gpa, empty_mem);
    }

    fn popNarrowScope(self: *Checker) void {
        if (self.narrow_scopes.items.len == 0) return;
        var top = self.narrow_scopes.items[self.narrow_scopes.items.len - 1];
        top.deinit(self.gpa);
        _ = self.narrow_scopes.pop();
        if (self.member_narrow_scopes.items.len == 0) return;
        var mtop = self.member_narrow_scopes.items[self.member_narrow_scopes.items.len - 1];
        mtop.deinit(self.gpa);
        _ = self.member_narrow_scopes.pop();
    }

    /// Look up the topmost narrowed type for a member access keyed
    /// by `(obj_name, prop_name)`. Walks the scope stack inner →
    /// outer.
    fn lookupMemberNarrow(self: *Checker, key: MemberKey) ?TypeId {
        var i = self.member_narrow_scopes.items.len;
        const floor = @min(self.narrow_lookup_floor, i);
        while (i > floor) {
            i -= 1;
            if (self.member_narrow_scopes.items[i].get(key)) |t| return t;
        }
        return null;
    }

    fn recordMemberNarrow(self: *Checker, key: MemberKey, t: TypeId) !void {
        if (self.member_narrow_scopes.items.len == 0) return;
        var top = &self.member_narrow_scopes.items[self.member_narrow_scopes.items.len - 1];
        try top.put(self.gpa, key, t);
    }

    fn recordMemberPredicatesForReceiver(
        self: *Checker,
        receiver_t: TypeId,
        predicates: *const std.AutoHashMapUnmanaged(hir_mod.StringId, FnPredicate),
    ) !void {
        var it = predicates.iterator();
        while (it.next()) |entry| {
            try self.recordMemberPredicate(receiver_t, entry.key_ptr.*, entry.value_ptr.*);
        }
    }

    fn recordMemberPredicate(
        self: *Checker,
        receiver_t: TypeId,
        member_name: hir_mod.StringId,
        pred: FnPredicate,
    ) !void {
        try self.member_predicates.put(self.gpa, .{
            .receiver_type = receiver_t,
            .member_name = member_name,
        }, pred);
    }

    fn copyMemberPredicatesFromReceiver(
        self: *Checker,
        receiver_t: TypeId,
        parent_t: TypeId,
    ) !void {
        if (parent_t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(parent_t);
        if (flags.is_type_parameter) {
            if (self.typeParameterConstraint(parent_t)) |constraint| {
                if (constraint != parent_t) try self.copyMemberPredicatesFromReceiver(receiver_t, constraint);
            }
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(parent_t)) |member| {
                try self.copyMemberPredicatesFromReceiver(receiver_t, member);
            }
            return;
        }
        if (!flags.is_object_type) return;
        for (self.interner.objectMembers(parent_t)) |member| {
            if (self.member_predicates.contains(.{ .receiver_type = receiver_t, .member_name = member.name })) continue;
            if (self.lookupMemberPredicate(parent_t, member.name)) |pred| {
                try self.recordMemberPredicate(receiver_t, member.name, pred);
            }
        }
    }

    fn lookupMemberPredicate(
        self: *Checker,
        receiver_t: TypeId,
        member_name: hir_mod.StringId,
    ) ?FnPredicate {
        if (self.member_predicates.get(.{ .receiver_type = receiver_t, .member_name = member_name })) |pred| {
            return pred;
        }
        if (receiver_t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(receiver_t);
        if (flags.is_type_parameter) {
            if (self.typeParameterConstraint(receiver_t)) |constraint| {
                if (constraint != receiver_t) return self.lookupMemberPredicate(constraint, member_name);
            }
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(receiver_t)) |member| {
                if (self.lookupMemberPredicate(member, member_name)) |pred| return pred;
            }
        }
        if (flags.is_union) {
            var found: ?FnPredicate = null;
            for (self.interner.unionMembers(receiver_t)) |member| {
                const pred = self.lookupMemberPredicate(member, member_name) orelse return null;
                if (found) |prior| {
                    if (prior.target_type != pred.target_type or prior.target_node != pred.target_node or
                        prior.param_index != pred.param_index or prior.is_asserts != pred.is_asserts)
                    {
                        return null;
                    }
                } else {
                    found = pred;
                }
            }
            return found;
        }
        return null;
    }

    /// Look up the topmost narrowed type for `name`, walking the
    /// scope stack from inner-most to outer-most.
    fn lookupNarrow(self: *Checker, name: hir_mod.StringId) ?TypeId {
        var i = self.narrow_scopes.items.len;
        const floor = @min(self.narrow_lookup_floor, i);
        while (i > floor) {
            i -= 1;
            if (self.narrow_scopes.items[i].get(name)) |t| return t;
        }
        while (i > 0) {
            i -= 1;
            if (self.narrow_scopes.items[i].get(name)) |t| {
                const name_str = self.string_interner.get(name);
                if (std.mem.eql(u8, name_str, "this") or std.mem.eql(u8, name_str, "super")) return t;
                if (t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(t).is_type_parameter) return t;
            }
        }
        return null;
    }

    fn typeOfIdentifierDeclared(self: *Checker, node: NodeId) TypeId {
        const old_floor = self.narrow_lookup_floor;
        const old_declared_lookup = self.declared_identifier_lookup;
        self.narrow_lookup_floor = self.narrow_scopes.items.len;
        self.declared_identifier_lookup = true;
        defer {
            self.narrow_lookup_floor = old_floor;
            self.declared_identifier_lookup = old_declared_lookup;
        }
        return self.typeOfIdentifier(node);
    }

    fn visibleAnnotatedIdentifierType(self: *Checker, node: NodeId) ?TypeId {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, node);
        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                for (hir_mod.fnParams(self.hir, cur)) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, pp.name).name != id.name) continue;
                    if (pp.type_annotation == hir_mod.none_node_id) return null;
                    return self.lowerValueTypeAnnotation(id.name, pp.type_annotation) catch types.Primitive.any;
                }
            }
            const stmts: ?[]const NodeId = switch (k) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => null,
            };
            if (stmts) |items| {
                for (items) |stmt| {
                    if (self.hir.spanOf(stmt).start > use_start) break;
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    const dk = self.hir.kindOf(decl);
                    if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, v.name).name != id.name) continue;
                    if (v.type_annotation == hir_mod.none_node_id) return null;
                    return self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                }
            }
        }
        if (self.module) |module| {
            if (module.root.lookup(id.name)) |sym| {
                if (sym.decls.items.len == 0) return null;
                const decl = sym.decls.items[0];
                const dk = self.hir.kindOf(decl);
                if (dk != .var_decl and dk != .let_decl and dk != .const_decl) return null;
                const v = hir_mod.varDeclOf(self.hir, decl);
                if (v.type_annotation == hir_mod.none_node_id) return null;
                return self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
            }
        }
        return null;
    }

    /// Detect simple type guards in `cond` and write their
    /// narrowing into the current scope.
    ///
    /// Recognized:
    ///   typeof X === "string" / "number" / "boolean" / "bigint" /
    ///                "symbol" / "undefined" / "object"
    ///     and the !== negation (with `when_true` flipped)
    ///   X === null / X !== null
    ///   X === undefined / X !== undefined
    /// True if `sig` accepts the given `arg_types` — i.e., the call
    /// would type-check without TS2554 / TS2345. Used by overload
    /// resolution to pick the first applicable signature.
    fn signatureAccepts(self: *Checker, sig: TypeId, args: []const NodeId, arg_types: []const TypeId) !bool {
        const params = self.interner.signatureParams(sig);
        const is_variadic = self.rest_signatures.contains(sig) and params.len > 0;
        const fixed_count: usize = if (is_variadic) params.len - 1 else params.len;
        // Required-arg count = params not including a trailing run
        // that includes `undefined`.
        var min_required: usize = self.signatureMinRequiredArgs(sig, params);
        min_required = @min(min_required, fixed_count);
        if (arg_types.len < min_required) return false;
        if (!is_variadic and arg_types.len > params.len) return false;
        const n = @min(arg_types.len, fixed_count);
        for (0..n) |i| {
            if (self.interner.pool.flagsOf(params[i]).is_type_parameter) continue;
            if (i < args.len and try self.literalExpressionAssignableToTarget(args[i], params[i])) continue;
            if (i < args.len and try self.templateExpressionAssignableToType(args[i], params[i])) continue;
            const ok = self.engine.isAssignableTo(arg_types[i], params[i]) catch false;
            if (!ok) return false;
        }
        if (is_variadic) {
            const rest_arr_t = params[params.len - 1];
            if (rest_arr_t >= self.interner.pool.typeCount()) return true;
            const elem_t = self.interner.objectNumberIndex(rest_arr_t);
            const target_t = if (elem_t == types.Primitive.none) rest_arr_t else elem_t;
            if (target_t >= self.interner.pool.typeCount()) return true;
            if (self.interner.pool.flagsOf(target_t).is_type_parameter) return true;
            if (arg_types.len > fixed_count) {
                for (arg_types[fixed_count..], fixed_count..) |arg_t, arg_i| {
                    if (arg_i < args.len and try self.literalExpressionAssignableToTarget(args[arg_i], target_t)) continue;
                    if (arg_i < args.len and try self.templateExpressionAssignableToType(args[arg_i], target_t)) continue;
                    if (!(try self.restArgumentAssignable(arg_t, target_t))) return false;
                }
            }
        }
        return true;
    }

    fn signatureIsConstruct(self: *Checker, sig: TypeId) bool {
        if (!self.interner.isSignature(sig)) return false;
        const payload_idx = self.interner.pool.payloadOf(sig);
        if (payload_idx >= self.interner.pool.signature_payloads.items.len) return false;
        return self.interner.pool.signature_payloads.items[payload_idx].is_construct;
    }

    fn collectConstructSignatures(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_signature) {
            if (self.signatureIsConstruct(t)) try out.append(self.gpa, t);
            return;
        }
        if (flags.is_type_parameter) {
            if (self.typeParameterConstraint(t)) |constraint| {
                if (constraint != t) try self.collectConstructSignatures(constraint, out);
            }
            return;
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                try self.collectConstructSignatures(member, out);
            }
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                try self.collectConstructSignatures(member, out);
            }
            return;
        }
        if (!flags.is_object_type) return;

        const construct_member_id = self.string_interner.intern("__construct") catch return error.OutOfMemory;
        for (self.interner.objectMembers(t)) |member| {
            if (member.name == construct_member_id and self.interner.isSignature(member.type)) {
                try out.append(self.gpa, member.type);
            }
        }
    }

    fn checkNewConstructSignatures(
        self: *Checker,
        node: NodeId,
        callee_node: NodeId,
        callee_t: TypeId,
        args: []const NodeId,
        arg_types: []const TypeId,
    ) CheckError!?TypeId {
        var construct_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer construct_sigs.deinit(self.gpa);
        try self.collectConstructSignatures(callee_t, &construct_sigs);
        // Splice in any declared *overload* constructor signatures for
        // the named class so the overload-resolution loop below can
        // pick a matching overload before falling back to the
        // implementation's stricter arity. The implementation signature
        // is the one that ends up in the static type's `__construct`
        // member; the overloads only live in
        // `class_constructor_overload_sigs`.
        if (callee_node != hir_mod.none_node_id and self.hir.kindOf(callee_node) == .identifier) {
            const callee_id = hir_mod.identifierOf(self.hir, callee_node);
            if (self.class_constructor_overload_sigs.get(callee_id.name)) |overload_list| {
                // Insert overloads at the FRONT so they're considered
                // first — mirrors tsc's left-to-right overload-match
                // walk for `new ClassName(...)`.
                var combined: std.ArrayListUnmanaged(TypeId) = .empty;
                defer combined.deinit(self.gpa);
                try combined.appendSlice(self.gpa, overload_list.items);
                try combined.appendSlice(self.gpa, construct_sigs.items);
                construct_sigs.clearRetainingCapacity();
                try construct_sigs.appendSlice(self.gpa, combined.items);
            }
        }
        if (construct_sigs.items.len == 0) return null;

        const type_arg_nodes = hir_mod.callTypeArgs(self.hir, node);
        var selected_sig: TypeId = construct_sigs.items[0];
        var found_applicable = false;
        var saw_generic_record = false;

        for (construct_sigs.items) |sig| {
            var effective_sig = sig;
            if (type_arg_nodes.len > 0) {
                var used_explicit_type_args = false;
                effective_sig = try self.instantiateSignatureWithExplicitTypeArgs(node, sig, type_arg_nodes, &used_explicit_type_args);
                if (self.generic_signature_params.get(sig) != null) saw_generic_record = true;
            } else {
                effective_sig = try self.instantiateSignatureFromArgs(sig, args, arg_types);
            }

            if (try self.signatureAccepts(effective_sig, args, arg_types)) {
                selected_sig = effective_sig;
                found_applicable = true;
                break;
            }
            if (selected_sig == construct_sigs.items[0]) selected_sig = effective_sig;
        }

        if (type_arg_nodes.len > 0 and !saw_generic_record and !self.newCalleeAcceptsTypeArguments(callee_node)) {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Expected 0 type arguments, but got {d}.",
                .{type_arg_nodes.len},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = node,
                .code = TsCodes.expected_n_type_arguments,
                .message = msg,
            });
        }

        if (!found_applicable and construct_sigs.items.len > 1) {
            try self.report(node, TsCodes.no_overload_matches, "No overload matches this call.");
        } else if (!self.newCalleeIsAbstractClass(callee_node)) {
            // Skip arg-arity / arg-type checks (TS2554/TS2345) when
            // constructing an abstract class — tsc reports only
            // TS2511 in that case. See `classAbstractInstantiations1`.
            try self.checkArgsAgainstSignature(node, args, arg_types, selected_sig);
        }

        return self.interner.signatureReturn(selected_sig) orelse types.Primitive.any;
    }

    fn newCalleeIsAbstractClass(self: *Checker, callee_node: NodeId) bool {
        if (callee_node == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(callee_node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, callee_node);
        return self.abstract_classes.contains(id.name);
    }

    fn newCalleeAcceptsTypeArguments(self: *Checker, callee_node: NodeId) bool {
        if (callee_node == hir_mod.none_node_id or self.hir.kindOf(callee_node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, callee_node);
        return self.generic_aliases.contains(id.name);
    }

    fn inferPromiseConstructorPayload(self: *Checker, args: []const NodeId) CheckError!?TypeId {
        if (self.promiseConstructorResolvedArgument(args)) |resolved| {
            return try self.checkExpression(resolved);
        }
        return null;
    }

    fn promiseConstructorResolvedArgumentFromExpr(self: *Checker, expr: NodeId) ?NodeId {
        if (expr == hir_mod.none_node_id or self.hir.kindOf(expr) != .new_expr) return null;
        const c = hir_mod.callOf(self.hir, expr);
        if (self.hir.kindOf(c.callee) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, c.callee);
        if (!std.mem.eql(u8, self.string_interner.get(id.name), "Promise")) return null;
        return self.promiseConstructorResolvedArgument(hir_mod.callArgs(self.hir, expr));
    }

    fn promiseConstructorResolvedArgument(self: *Checker, args: []const NodeId) ?NodeId {
        if (args.len == 0) return null;
        const executor = args[0];
        const k = self.hir.kindOf(executor);
        if (k != .arrow_fn and k != .fn_expr and k != .fn_decl) return null;
        const f = hir_mod.fnDeclOf(self.hir, executor);
        const params = hir_mod.fnParams(self.hir, executor);
        if (params.len == 0) return null;
        const first_param = hir_mod.parameterOf(self.hir, params[0]);
        if (first_param.name == hir_mod.none_node_id or self.hir.kindOf(first_param.name) != .identifier) return null;
        const resolve_name = hir_mod.identifierOf(self.hir, first_param.name).name;
        return self.firstCallArgumentNodeToIdentifier(f.body, resolve_name);
    }

    fn firstCallArgumentToIdentifier(self: *Checker, node: NodeId, callee_name: hir_mod.StringId) CheckError!?TypeId {
        if (self.firstCallArgumentNodeToIdentifier(node, callee_name)) |arg| {
            return try self.checkExpression(arg);
        }
        return null;
    }

    fn firstCallArgumentNodeToIdentifier(self: *Checker, node: NodeId, callee_name: hir_mod.StringId) ?NodeId {
        if (node == hir_mod.none_node_id) return null;
        switch (self.hir.kindOf(node)) {
            .call_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.hir.kindOf(c.callee) == .identifier and
                    hir_mod.identifierOf(self.hir, c.callee).name == callee_name)
                {
                    const args = hir_mod.callArgs(self.hir, node);
                    if (args.len > 0) return args[0];
                    return null;
                }
                if (self.firstCallArgumentNodeToIdentifier(c.callee, callee_name)) |arg| return arg;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.firstCallArgumentNodeToIdentifier(arg, callee_name)) |found| return found;
                }
                return null;
            },
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                return self.firstCallArgumentNodeToIdentifier(r.value, callee_name);
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                    if (self.firstCallArgumentNodeToIdentifier(stmt, callee_name)) |arg| return arg;
                }
                return null;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                if (self.firstCallArgumentNodeToIdentifier(i.then_branch, callee_name)) |arg| return arg;
                return self.firstCallArgumentNodeToIdentifier(i.else_branch, callee_name);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                if (self.firstCallArgumentNodeToIdentifier(l.lhs, callee_name)) |arg| return arg;
                return self.firstCallArgumentNodeToIdentifier(l.rhs, callee_name);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                if (self.firstCallArgumentNodeToIdentifier(c.then_branch, callee_name)) |arg| return arg;
                return self.firstCallArgumentNodeToIdentifier(c.else_branch, callee_name);
            },
            else => return null,
        }
    }

    fn collectCallSignatures(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_signature) {
            if (!self.signatureIsConstruct(t)) try out.append(self.gpa, t);
            return;
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                try self.collectCallSignatures(member, out);
            }
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                try self.collectCallSignatures(member, out);
            }
            return;
        }
        if (!flags.is_object_type) return;

        const call_member_id = self.string_interner.intern("__call") catch return error.OutOfMemory;
        for (self.interner.objectMembers(t)) |member| {
            if (member.name == call_member_id and self.interner.isSignature(member.type)) {
                try out.append(self.gpa, member.type);
            }
        }
    }

    fn collectNamedMemberSignatures(
        self: *Checker,
        t: TypeId,
        name: hir_mod.StringId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                try self.collectNamedMemberSignatures(member, name, out);
            }
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                try self.collectNamedMemberSignatures(member, name, out);
            }
            return;
        }
        if (!flags.is_object_type) return;
        for (self.interner.objectMembers(t)) |member| {
            if (member.name == name) {
                try self.collectCallSignatures(member.type, out);
            }
        }
    }

    fn resolveOverloadedObjectCall(
        self: *Checker,
        call_node: NodeId,
        callee: NodeId,
        callee_t: TypeId,
        args: []const NodeId,
        arg_types: []const TypeId,
        call_is_optional_chain: bool,
    ) CheckError!?TypeId {
        var sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer sigs.deinit(self.gpa);
        if (self.hir.kindOf(callee) == .member_access) {
            const m = hir_mod.memberOf(self.hir, callee);
            const receiver_t = try self.checkExpression(m.object);
            try self.collectNamedMemberSignatures(receiver_t, m.name, &sigs);
        } else {
            try self.collectCallSignatures(callee_t, &sigs);
        }
        if (sigs.items.len <= 1) return null;
        for (sigs.items) |sig| {
            if (try self.signatureAccepts(sig, args, arg_types)) {
                try self.checkArgsAgainstSignature(call_node, args, arg_types, sig);
                const ret = self.interner.signatureReturn(sig) orelse types.Primitive.any;
                const param_ts = self.interner.signatureParams(sig);
                var instantiated = self.instantiateReturn(param_ts, arg_types, ret) catch ret;
                instantiated = try self.instantiateMemberThisReturn(callee, instantiated);
                return try self.optionalChainResult(instantiated, call_is_optional_chain);
            }
        }
        try self.report(call_node, TsCodes.no_overload_matches, "No overload matches this call.");
        var ret = self.interner.signatureReturn(sigs.items[0]) orelse types.Primitive.any;
        ret = try self.instantiateMemberThisReturn(callee, ret);
        return try self.optionalChainResult(ret, call_is_optional_chain);
    }

    fn checkMethodThisCompatibility(self: *Checker, call_node: NodeId, callee: NodeId, callee_t: TypeId) CheckError!void {
        if (self.hir.kindOf(callee) != .member_access) return;
        const m = hir_mod.memberOf(self.hir, callee);
        const receiver_t = try self.checkExpression(m.object);
        var saw_this_param = false;
        var unmet_this: std.ArrayListUnmanaged(TypeId) = .empty;
        defer unmet_this.deinit(self.gpa);
        // When the receiver is a union of method-bearing types each
        // declaring its own `this: this`, the per-signature `this`
        // type is keyed on the (interned) signature TypeId — which
        // collides across union branches that share an identical
        // shape. Walk the union explicitly so each branch contributes
        // its own `this` type to the unmet set.
        const receiver_is_union = receiver_t >= types.Primitive.first_dynamic and
            receiver_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(receiver_t).is_union;
        if (receiver_is_union) {
            for (self.interner.unionMembers(receiver_t)) |branch| {
                var branch_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
                defer branch_sigs.deinit(self.gpa);
                try self.collectNamedMemberSignatures(branch, m.name, &branch_sigs);
                for (branch_sigs.items) |sig| {
                    const this_t = self.signature_this_params.get(sig) orelse continue;
                    saw_this_param = true;
                    var effective_this: TypeId = this_t;
                    // The signature_this_params map is keyed only on
                    // signature TypeId, so when two union members
                    // share an identical method signature shape only
                    // the last branch's `this`-type is retained. If
                    // the cached `this_t` matches one of the union
                    // members (suggesting `this: this`/`this: <self>`),
                    // use the current branch as its effective `this`
                    // so each branch contributes its own type to the
                    // unmet set.
                    if (this_t != branch) {
                        var this_t_is_union_member = false;
                        for (self.interner.unionMembers(receiver_t)) |other| {
                            if (other == this_t) {
                                this_t_is_union_member = true;
                                break;
                            }
                        }
                        if (this_t_is_union_member) effective_this = branch;
                    }
                    // Check the actual receiver (the union) against
                    // the effective `this`-type for this branch.
                    if (self.engine.isAssignableTo(receiver_t, effective_this) catch false) continue;
                    var seen = false;
                    for (unmet_this.items) |existing| {
                        if (existing == effective_this) {
                            seen = true;
                            break;
                        }
                    }
                    if (!seen) try unmet_this.append(self.gpa, effective_this);
                }
            }
            if (!saw_this_param) return;
            if (unmet_this.items.len == 0) return;
        } else {
            var call_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
            defer call_sigs.deinit(self.gpa);
            try self.collectCallSignatures(callee_t, &call_sigs);
            for (call_sigs.items) |sig| {
                const this_t = self.signature_this_params.get(sig) orelse continue;
                saw_this_param = true;
                if (self.engine.isAssignableTo(receiver_t, this_t) catch false) return;
                // Track unique unmet `this` types — when the receiver is
                // a union of method-bearing types each requiring its own
                // `this`, upstream tsc intersects them in the diagnostic.
                var seen = false;
                for (unmet_this.items) |existing| {
                    if (existing == this_t) {
                        seen = true;
                        break;
                    }
                }
                if (!seen) try unmet_this.append(self.gpa, this_t);
            }
            if (!saw_this_param) return;
        }
        // Prefer the upstream-shaped TS2684 with both `of type 'X'`
        // and `of type 'Y'` clauses when we can name both sides.
        // Falls back to the generic wording when the engine lacks a
        // simple type name for either side.
        if (unmet_this.items.len > 0) {
            const recv_name = try self.allocSimpleTypeName(receiver_t);
            const this_name: ?[]const u8 = blk: {
                if (unmet_this.items.len == 1) {
                    break :blk try self.allocSimpleTypeName(unmet_this.items[0]);
                }
                var buf: std.ArrayListUnmanaged(u8) = .empty;
                const arena = self.diag_arena.allocator();
                for (unmet_this.items, 0..) |this_t, i| {
                    const part = (try self.allocSimpleTypeName(this_t)) orelse break :blk null;
                    if (i > 0) try buf.appendSlice(arena, " & ");
                    try buf.appendSlice(arena, part);
                }
                break :blk buf.items;
            };
            if (recv_name != null and this_name != null) {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "The 'this' context of type '{s}' is not assignable to method's 'this' of type '{s}'.",
                    .{ recv_name.?, this_name.? },
                );
                try self.report(call_node, TsCodes.this_context_not_assignable, msg);
                return;
            }
        }
        try self.report(call_node, TsCodes.this_context_not_assignable, "The 'this' context is not assignable to method's 'this' type.");
    }

    fn checkBareCallThisCompatibility(
        self: *Checker,
        call_node: NodeId,
        callee_t: TypeId,
        args: []const NodeId,
        arg_types: []const TypeId,
    ) CheckError!void {
        var call_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer call_sigs.deinit(self.gpa);
        try self.collectCallSignatures(callee_t, &call_sigs);

        var expected_this: TypeId = types.Primitive.none;
        for (call_sigs.items) |sig| {
            if (!try self.signatureAccepts(sig, args, arg_types)) continue;
            const this_t = self.signature_this_params.get(sig) orelse continue;
            if (expected_this == types.Primitive.none) {
                expected_this = this_t;
                continue;
            }
            if (self.engine.isIdenticalTo(expected_this, this_t) catch false) continue;
            expected_this = types.Primitive.never;
            break;
        }
        if (expected_this == types.Primitive.none) return;
        if (self.engine.isAssignableTo(types.Primitive.void_t, expected_this) catch false) return;
        // If a union of call signatures had at least one declared
        // `this: T` plus another with no compatible `this`, tsc
        // reports the conflict as a `never` intersection. Detect
        // that by re-walking and looking for a second declared
        // `this` that's both not-`void`-assignable AND not
        // identical to `expected_this`. This catches fixture
        // `unionTypeCallSignatures5` where the union of `(this: void, ...)`
        // and `(this: number, ...)` should report `never` rather
        // than the first matching sig's `this`.
        if (expected_this != types.Primitive.never) {
            for (call_sigs.items) |sig| {
                if (!try self.signatureAccepts(sig, args, arg_types)) continue;
                const this_t = self.signature_this_params.get(sig) orelse continue;
                if (this_t == expected_this) continue;
                if (self.engine.isIdenticalTo(this_t, expected_this) catch false) continue;
                expected_this = types.Primitive.never;
                break;
            }
        }
        if (try self.allocSimpleTypeName(expected_this)) |this_name| {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "The 'this' context of type 'void' is not assignable to method's 'this' of type '{s}'.",
                .{this_name},
            );
            try self.report(call_node, TsCodes.this_context_not_assignable, msg);
            return;
        }
        try self.report(call_node, TsCodes.this_context_not_assignable, "The 'this' context of type 'void' is not assignable to method's 'this' type.");
    }

    fn callCalleeHasSyntacticThisReceiver(self: *Checker, callee: NodeId) bool {
        var cur = callee;
        while (true) {
            switch (self.hir.kindOf(cur)) {
                .member_access, .element_access => return true,
                .non_null_expr => {
                    cur = hir_mod.asExpressionOf(self.hir, cur).expr;
                    continue;
                },
                else => return false,
            }
        }
    }

    fn callCalleeAlreadyHasUnresolvedNameDiagnostic(self: *Checker, callee: NodeId) bool {
        const root = self.calleeRootIdentifier(callee) orelse return false;
        for (self.diagnostics.items) |d| {
            if (d.node != root) continue;
            switch (d.code) {
                TsCodes.cannot_find_name,
                TsCodes.cannot_find_name_did_you_mean,
                TsCodes.cannot_find_node_name,
                TsCodes.cannot_find_jquery_name,
                2868,
                => return true,
                else => {},
            }
        }
        return false;
    }

    /// When the call's member-access callee already triggered a TS2339
    /// ("Property 'x' does not exist on type 'Y'."), suppress the
    /// follow-on TS2347 — tsc emits only the property-existence error
    /// in that case. Matches `parserSuperExpression3`.
    fn callCalleeAlreadyHasMissingPropertyDiagnostic(self: *Checker, callee: NodeId) bool {
        if (self.hir.kindOf(callee) != .member_access and
            self.hir.kindOf(callee) != .element_access) return false;
        for (self.diagnostics.items) |d| {
            if (d.node != callee) continue;
            if (d.code == TsCodes.property_does_not_exist) return true;
        }
        return false;
    }

    fn calleeRootIdentifier(self: *Checker, callee: NodeId) ?NodeId {
        var cur = callee;
        while (true) {
            switch (self.hir.kindOf(cur)) {
                .identifier => return cur,
                .member_access => {
                    cur = hir_mod.memberOf(self.hir, cur).object;
                    continue;
                },
                .element_access => {
                    cur = hir_mod.elementOf(self.hir, cur).object;
                    continue;
                },
                .non_null_expr => {
                    cur = hir_mod.asExpressionOf(self.hir, cur).expr;
                    continue;
                },
                .call_expr => {
                    if (self.isInstantiationExpressionCall(cur)) {
                        cur = hir_mod.callOf(self.hir, cur).callee;
                        continue;
                    }
                    return null;
                },
                else => return null,
            }
        }
    }

    fn instantiateSignatureWithExplicitTypeArgs(
        self: *Checker,
        call_node: NodeId,
        sig: TypeId,
        type_arg_nodes: []const NodeId,
        used_explicit_type_args: *bool,
    ) CheckError!TypeId {
        used_explicit_type_args.* = false;
        if (type_arg_nodes.len == 0) return sig;
        const type_params = self.generic_signature_params.get(sig) orelse return sig;
        if (type_arg_nodes.len != type_params.len) {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Expected {d} type arguments, but got {d}.",
                .{ type_params.len, type_arg_nodes.len },
            );
            try self.diagnostics.append(self.gpa, .{
                .node = call_node,
                .code = TsCodes.expected_n_type_arguments,
                .message = msg,
            });
        }
        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);
        const n = @min(type_params.len, type_arg_nodes.len);
        for (0..n) |i| {
            const explicit_t = self.lowererLowerWithTypeParams(type_arg_nodes[i]) catch types.Primitive.unknown;
            // TS2344: Verify the explicit type arg satisfies the
            // parameter's `extends` constraint. Mirrors upstream
            // `nonPrimitiveInGeneric.ts(25,8)` where
            // `bound2<number>()` violates `T extends object`.
            try self.checkTypeArgSatisfiesConstraint(type_arg_nodes[i], type_params[i], explicit_t);
            try subs.put(self.gpa, type_params[i], explicit_t);
        }
        if (subs.count() == 0) return sig;
        used_explicit_type_args.* = true;
        return self.substituteType(sig, &subs) catch sig;
    }

    fn instantiateSignatureFromArgs(
        self: *Checker,
        sig: TypeId,
        args: []const NodeId,
        arg_types: []const TypeId,
    ) CheckError!TypeId {
        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);
        try self.inferCallSubstitutions(sig, args, arg_types, &subs);
        if (subs.count() == 0) return sig;
        return self.substituteType(sig, &subs) catch sig;
    }

    /// Post-statement narrowing for logical assignments. Recognizes
    /// the lowered shape `target = target <op> value` produced by
    /// the parser for `??=`, `||=`, and `&&=`. After `x ??= "default"`
    /// narrows `x` to its non-nullish type unioned with the rhs's
    /// type. For `||=` and `&&=` we use a v0 approximation: subtract
    /// `null | undefined` from the lhs and union with rhs's type.
    /// This handles the common `string | null | undefined` cases
    /// that motivate the operators; richer truthy/falsy partitioning
    /// is deferred until the relation engine models truthiness.
    fn applyLogicalAssignmentFlow(self: *Checker, stmt: NodeId) !void {
        if (self.hir.kindOf(stmt) != .assignment) return;
        const a = hir_mod.assignmentOf(self.hir, stmt);
        if (a.op != null) return; // arithmetic compound assignment
        if (self.hir.kindOf(a.target) != .identifier) return;
        if (self.hir.kindOf(a.value) != .logical_op) return;
        const target_id = hir_mod.identifierOf(self.hir, a.target);
        const l = hir_mod.logicalOf(self.hir, a.value);
        // Only act when the operator's lhs is the same identifier as
        // the assignment target — that's the lowered `x = x ?? rhs`
        // shape produced by `parseLogicalAssign`.
        if (self.hir.kindOf(l.lhs) != .identifier) return;
        const lhs_id = hir_mod.identifierOf(self.hir, l.lhs);
        if (lhs_id.name != target_id.name) return;
        switch (l.op) {
            .nullish => {
                // For `??=` reuse the assignment value's type — it's
                // already `(target minus null|undefined) | rhs_type`
                // because checkLogical specially handles `??`.
                const value_t = self.hir.typeOf(a.value);
                if (value_t == types.Primitive.none) return;
                try self.recordNarrow(target_id.name, value_t);
            },
            .@"or", .@"and" => {
                // checkLogical produces `lhs | rhs` for `||`/`&&`,
                // which doesn't actually narrow. Compute a v0
                // approximation: drop null/undefined from the lhs
                // and union with the rhs. That covers the common
                // `string | null | undefined` shapes without modeling
                // full truthiness.
                const lhs_t = self.hir.typeOf(l.lhs);
                const rhs_t = self.hir.typeOf(l.rhs);
                if (lhs_t == types.Primitive.none or rhs_t == types.Primitive.none) return;
                const lhs_non_null = self.subtractNullUndefined(lhs_t) catch lhs_t;
                const narrowed = self.interner.internUnion(&.{ lhs_non_null, rhs_t }) catch return;
                try self.recordNarrow(target_id.name, narrowed);
            },
        }
    }

    const NullishGuardKind = enum { null_only, undefined_only, null_or_undefined };

    const NullishGuard = struct {
        name: hir_mod.StringId,
        ident_node: NodeId,
        kind: NullishGuardKind,
    };

    const DiscriminantTarget = struct {
        name: hir_mod.StringId,
        t: TypeId,
    };

    fn applyNullishGuardAssignmentFlow(self: *Checker, cond: NodeId, then_branch: NodeId) !void {
        const guard = self.nullishEqualityGuard(cond) orelse return;
        const value_node = self.singleAssignmentValueToIdentifier(then_branch, guard.name) orelse return;
        var assigned_t = self.hir.typeOf(value_node);
        if (assigned_t == types.Primitive.none) assigned_t = try self.checkExpression(value_node);
        const current = self.lookupNarrow(guard.name) orelse self.typeOfIdentifier(guard.ident_node);
        const false_t = try self.subtractNullishGuardedType(current, guard.kind);
        const narrowed = if (false_t == types.Primitive.never)
            assigned_t
        else if (assigned_t == types.Primitive.never)
            false_t
        else
            self.interner.internUnion(&.{ false_t, assigned_t }) catch return error.OutOfMemory;
        try self.recordNarrow(guard.name, narrowed);
    }

    fn nullishEqualityGuard(self: *Checker, cond: NodeId) ?NullishGuard {
        if (self.hir.kindOf(cond) != .binary_op) return null;
        const b = hir_mod.binopOf(self.hir, cond);
        if (b.op != .eq and b.op != .eq_strict) return null;
        if (self.hir.kindOf(b.lhs) == .identifier) {
            if (self.nullishGuardKindForNode(b.rhs, b.op)) |kind| {
                return .{ .name = hir_mod.identifierOf(self.hir, b.lhs).name, .ident_node = b.lhs, .kind = kind };
            }
        }
        if (self.hir.kindOf(b.rhs) == .identifier) {
            if (self.nullishGuardKindForNode(b.lhs, b.op)) |kind| {
                return .{ .name = hir_mod.identifierOf(self.hir, b.rhs).name, .ident_node = b.rhs, .kind = kind };
            }
        }
        return null;
    }

    fn nullishGuardKindForNode(self: *Checker, node: NodeId, op: hir_mod.BinOp) ?NullishGuardKind {
        return switch (self.hir.kindOf(node)) {
            .literal_null => if (op == .eq) .null_or_undefined else .null_only,
            .literal_undefined => if (op == .eq) .null_or_undefined else .undefined_only,
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, node);
                if (!std.mem.eql(u8, self.string_interner.get(id.name), "undefined")) break :blk null;
                break :blk if (op == .eq) .null_or_undefined else .undefined_only;
            },
            else => null,
        };
    }

    fn singleAssignmentValueToIdentifier(self: *Checker, node: NodeId, name: hir_mod.StringId) ?NodeId {
        const stmt = if (self.hir.kindOf(node) == .block_stmt) blk: {
            const stmts = hir_mod.blockStmts(self.hir, node);
            if (stmts.len != 1) return null;
            break :blk stmts[0];
        } else node;
        if (self.hir.kindOf(stmt) != .assignment) return null;
        const a = hir_mod.assignmentOf(self.hir, stmt);
        if (a.op != null or self.hir.kindOf(a.target) != .identifier) return null;
        if (hir_mod.identifierOf(self.hir, a.target).name != name) return null;
        return a.value;
    }

    fn subtractNullishGuardedType(self: *Checker, t: TypeId, kind: NullishGuardKind) !TypeId {
        return switch (kind) {
            .null_only => self.subtractType(t, types.Primitive.null_t) catch t,
            .undefined_only => self.subtractType(t, types.Primitive.undefined_t) catch t,
            .null_or_undefined => try self.subtractNullUndefined(t),
        };
    }

    /// Assertion-function flow narrowing. If `stmt` is a call to a
    /// function whose return type is `asserts arg is T`, record
    /// `arg -> T` in the surrounding narrow scope so subsequent
    /// statements in the same block see the narrowed type.
    fn applyAssertionFlow(self: *Checker, stmt: NodeId) !void {
        const k = self.hir.kindOf(stmt);
        if (k != .call_expr) return;
        const c = hir_mod.callOf(self.hir, stmt);
        if (self.hir.kindOf(c.callee) != .identifier) return;
        const callee_id = hir_mod.identifierOf(self.hir, c.callee);
        const pred = self.fn_predicates.get(callee_id.name) orelse return;
        if (!pred.is_asserts) return;
        const args = hir_mod.callArgs(self.hir, stmt);
        if (pred.param_index >= args.len) return;
        const arg = args[pred.param_index];
        if (self.hir.kindOf(arg) != .identifier) return;
        const arg_id = hir_mod.identifierOf(self.hir, arg);
        // Predicate-less `asserts arg` (no `is T`): narrow to a
        // truthy approximation by subtracting `null | undefined`
        // from the current type.
        if (pred.target_type == types.Primitive.unknown or pred.target_type == types.Primitive.none) {
            const current = self.lookupNarrow(arg_id.name) orelse self.typeOfIdentifier(arg);
            const narrowed = self.subtractNullUndefined(current) catch current;
            try self.recordNarrow(arg_id.name, narrowed);
            return;
        }
        const current = self.lookupNarrow(arg_id.name) orelse self.typeOfIdentifier(arg);
        const target = try self.instantiatePredicateTarget(stmt, pred);
        try self.recordNarrow(arg_id.name, try self.narrowTypeByPredicate(current, target));
    }

    fn resolvePredicateTarget(self: *Checker, pred: FnPredicate) CheckError!TypeId {
        if (pred.target_type != types.Primitive.unknown or pred.target_node == hir_mod.none_node_id) return pred.target_type;
        return self.lowererLowerWithTypeParams(pred.target_node) catch pred.target_type;
    }

    fn instantiatePredicateTarget(self: *Checker, call_node: NodeId, pred: FnPredicate) CheckError!TypeId {
        const base_target = try self.resolvePredicateTarget(pred);
        if (!self.containsFreeTypeParameter(base_target)) return base_target;
        if (self.hir.kindOf(call_node) != .call_expr) return base_target;
        const c = hir_mod.callOf(self.hir, call_node);
        var callee_t = self.hir.typeOf(c.callee);
        if (callee_t == types.Primitive.none) callee_t = try self.checkExpression(c.callee);
        const call_member_id = self.string_interner.intern("__call") catch return error.OutOfMemory;
        if (!self.interner.isSignature(callee_t)) {
            if (self.interner.objectMember(callee_t, call_member_id)) |call_member_t| {
                callee_t = call_member_t;
            }
        }
        if (!self.interner.isSignature(callee_t)) return base_target;
        const args = hir_mod.callArgs(self.hir, call_node);
        var arg_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer arg_types.deinit(self.gpa);
        for (args) |arg| {
            var arg_t = self.hir.typeOf(arg);
            if (arg_t == types.Primitive.none) arg_t = try self.checkExpression(arg);
            try arg_types.append(self.gpa, arg_t);
        }
        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);
        try self.inferPredicateCallSubstitutions(callee_t, args, arg_types.items, base_target, &subs);
        if (subs.count() == 0) return base_target;
        return self.substituteType(base_target, &subs) catch base_target;
    }

    fn inferPredicateCallSubstitutions(
        self: *Checker,
        sig: TypeId,
        args: []const NodeId,
        arg_types: []const TypeId,
        predicate_target: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !void {
        if (!self.interner.isSignature(sig)) return;
        const param_ts = self.interner.signatureParams(sig);
        const n = @min(param_ts.len, arg_types.len);
        for (0..n) |i| {
            const param_t = param_ts[i];
            if (param_t >= self.interner.pool.typeCount()) continue;
            const param_flags = self.interner.pool.flagsOf(param_t);
            if (param_flags.is_signature and self.containsFreeTypeParameter(param_t)) {
                if (try self.inferFromPredicateSignatureArgument(param_t, null, args[i], arg_types[i], subs)) continue;
                if (self.interner.signatureReturn(param_t)) |param_ret| {
                    if (param_ret != types.Primitive.boolean_t) {
                        if (self.interner.signatureReturn(arg_types[i])) |arg_ret| {
                            try self.inferFromPair(param_ret, arg_ret, subs);
                        }
                    }
                }
            } else if (!param_flags.is_signature) {
                try self.inferFromArgument(param_t, arg_types[i], args[i], subs);
            }
        }
        if (subs.count() != 0) return;
        const target_tp = self.firstFreeTypeParameter(predicate_target) orelse return;
        for (args) |arg| {
            if (self.hir.kindOf(arg) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, arg);
            const arg_pred = self.fn_predicates.get(id.name) orelse continue;
            if (self.containsFreeTypeParameter(arg_pred.target_type)) continue;
            try subs.put(self.gpa, target_tp, arg_pred.target_type);
            return;
        }
    }

    fn inferFromPredicateSignatureArgument(
        self: *Checker,
        param_sig: TypeId,
        param_pred_override: ?FnPredicate,
        arg_node: NodeId,
        arg_t: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !bool {
        const param_pred = param_pred_override orelse (self.signature_predicates.get(param_sig) orelse return false);
        if (!self.containsFreeTypeParameter(param_pred.target_type)) return false;
        var arg_target: ?TypeId = null;
        if (self.hir.kindOf(arg_node) == .identifier) {
            const arg_id = hir_mod.identifierOf(self.hir, arg_node);
            if (self.fn_predicates.get(arg_id.name)) |arg_pred| {
                arg_target = arg_pred.target_type;
            }
        }
        if (arg_target == null) {
            if (self.signature_predicates.get(arg_t)) |arg_pred| {
                arg_target = arg_pred.target_type;
            }
        }
        const target = arg_target orelse return false;
        if (self.containsFreeTypeParameter(target)) return false;
        try self.inferFromPair(param_pred.target_type, target, subs);
        return true;
    }

    fn recordPredicateNarrowForExpression(self: *Checker, expr: NodeId, target: TypeId, when_true: bool) !bool {
        if (self.hir.kindOf(expr) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, expr);
            const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(expr);
            const narrowed = if (when_true)
                try self.narrowTypeByPredicate(current, target)
            else
                (self.subtractTypeByPredicate(current, target) catch current);
            try self.recordNarrow(id.name, narrowed);
            return true;
        }
        if (self.hir.kindOf(expr) == .member_access) {
            const m = hir_mod.memberOf(self.hir, expr);
            if (self.hir.kindOf(m.object) != .identifier) return false;
            const obj_id = hir_mod.identifierOf(self.hir, m.object);
            const key: MemberKey = .{ .obj_name = obj_id.name, .prop_name = m.name };
            const obj_t = self.lookupNarrow(obj_id.name) orelse self.typeOfIdentifier(m.object);
            const current = self.lookupMemberNarrow(key) orelse
                ((try self.lookupObjectMember(obj_t, m.name)) orelse self.hir.typeOf(expr));
            if (current == types.Primitive.none) return false;
            const narrowed = if (when_true)
                try self.narrowTypeByPredicate(current, target)
            else
                (self.subtractTypeByPredicate(current, target) catch current);
            try self.recordMemberNarrow(key, narrowed);
            return true;
        }
        return false;
    }

    const TypeofComparison = struct {
        name: hir_mod.StringId,
        node: NodeId,
        target: TypeId,
        is_equal: bool,
    };

    fn typeofNarrowType(self: *Checker, lit_str: []const u8, fallback: TypeId) CheckError!TypeId {
        if (std.mem.eql(u8, lit_str, "function")) {
            return self.lowerBuiltinObjectType("Function") orelse fallback;
        }
        return fallback;
    }

    fn identifierHasNarrowableValueBinding(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        if (self.isNodeCommonJsGlobalName(id.name)) {
            if (self.sourceHasVarDeclarationText(id.name)) return true;
            if (self.globalAugmentedValueType(id.name, node) catch null != null) return true;
            if (self.module) |module| {
                if (module.root.lookup(id.name) != null) return true;
            }
            return false;
        }
        if (self.isBuiltinName(id.name)) return true;
        if (self.sourceHasVarDeclarationText(id.name)) return true;
        if (self.globalAugmentedValueType(id.name, node) catch null != null) return true;
        if (self.module) |module| {
            if (module.root.lookup(id.name) != null) return true;
        }

        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const kind = self.hir.kindOf(cur);
            if (kind == .fn_decl or kind == .fn_expr or kind == .arrow_fn) {
                for (hir_mod.fnParams(self.hir, cur)) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, pp.name).name == id.name) return true;
                }
            } else if (kind == .try_stmt) {
                const ts = hir_mod.tryOf(self.hir, cur);
                if (ts.catch_param != hir_mod.none_node_id and self.hir.kindOf(ts.catch_param) == .identifier) {
                    if (hir_mod.identifierOf(self.hir, ts.catch_param).name == id.name) return true;
                }
            }

            const stmts: ?[]const NodeId = switch (kind) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => null,
            };
            if (stmts) |items| {
                for (items) |stmt| {
                    if (self.hir.spanOf(stmt).start >= use_start) break;
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    switch (self.hir.kindOf(decl)) {
                        .var_decl, .let_decl, .const_decl => {
                            const v = hir_mod.varDeclOf(self.hir, decl);
                            if (v.name != hir_mod.none_node_id and
                                self.hir.kindOf(v.name) == .identifier and
                                hir_mod.identifierOf(self.hir, v.name).name == id.name)
                            {
                                return true;
                            }
                        },
                        .fn_decl, .fn_expr => {
                            const f = hir_mod.fnDeclOf(self.hir, decl);
                            if (f.name != hir_mod.none_node_id and
                                self.hir.kindOf(f.name) == .identifier and
                                hir_mod.identifierOf(self.hir, f.name).name == id.name)
                            {
                                return true;
                            }
                        },
                        .class_decl, .class_expr => {
                            const c = hir_mod.classOf(self.hir, decl);
                            if (c.name != hir_mod.none_node_id and
                                self.hir.kindOf(c.name) == .identifier and
                                hir_mod.identifierOf(self.hir, c.name).name == id.name)
                            {
                                return true;
                            }
                        },
                        .import_decl => if (self.importDeclBindsLocal(decl, id.name)) return true,
                        else => {},
                    }
                }
            }
        }
        return false;
    }

    fn typeofComparison(self: *Checker, node: NodeId) CheckError!?TypeofComparison {
        if (self.hir.kindOf(node) != .binary_op) return null;
        const b = hir_mod.binopOf(self.hir, node);
        const is_equal = b.op == .eq_strict or b.op == .eq;
        const is_not_equal = b.op == .neq_strict or b.op == .neq;
        if (!is_equal and !is_not_equal) return null;
        if (self.hir.kindOf(b.lhs) != .unary_op) return null;
        const u = hir_mod.unaryOf(self.hir, b.lhs);
        if (u.op != .typeof or self.hir.kindOf(u.operand) != .identifier) return null;
        const type_name = (try self.staticStringValue(b.rhs)) orelse return null;
        const lit_str = self.string_interner.get(type_name);
        const base = typeOfTypeofString(lit_str) orelse return null;
        return .{
            .name = hir_mod.identifierOf(self.hir, u.operand).name,
            .node = u.operand,
            .target = try self.typeofNarrowType(lit_str, base),
            .is_equal = is_equal,
        };
    }

    fn collectTypeofChainTargets(
        self: *Checker,
        node: NodeId,
        op: hir_mod.LogicalOp,
        want_equal: bool,
        name: *?hir_mod.StringId,
        first_node: *NodeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!bool {
        if (self.hir.kindOf(node) == .logical_op) {
            const l = hir_mod.logicalOf(self.hir, node);
            if (l.op != op) return false;
            return (try self.collectTypeofChainTargets(l.lhs, op, want_equal, name, first_node, out)) and
                (try self.collectTypeofChainTargets(l.rhs, op, want_equal, name, first_node, out));
        }
        const cmp = (try self.typeofComparison(node)) orelse return false;
        if (cmp.is_equal != want_equal) return false;
        if (name.*) |existing| {
            if (existing != cmp.name) return false;
        } else {
            name.* = cmp.name;
            first_node.* = cmp.node;
        }
        try out.append(self.gpa, cmp.target);
        return true;
    }

    fn applyTypeofTargetUnion(self: *Checker, name: hir_mod.StringId, node: NodeId, targets: []const TypeId) CheckError!bool {
        if (targets.len == 0) return false;
        const target = if (targets.len == 1)
            targets[0]
        else
            self.interner.internUnion(targets) catch return error.OutOfMemory;
        const current = self.lookupNarrow(name) orelse self.typeOfIdentifier(node);
        const narrowed = try self.narrowTypeByPredicate(current, target);
        try self.recordNarrow(name, narrowed);
        return true;
    }

    fn applyTrueOrTypeofChain(self: *Checker, lhs: NodeId, rhs: NodeId) CheckError!bool {
        var targets: std.ArrayListUnmanaged(TypeId) = .empty;
        defer targets.deinit(self.gpa);
        var name: ?hir_mod.StringId = null;
        var first_node: NodeId = hir_mod.none_node_id;
        if (!try self.collectTypeofChainTargets(lhs, .@"or", true, &name, &first_node, &targets)) return false;
        if (!try self.collectTypeofChainTargets(rhs, .@"or", true, &name, &first_node, &targets)) return false;
        return try self.applyTypeofTargetUnion(name orelse return false, first_node, targets.items);
    }

    fn applyFalseAndTypeofChain(self: *Checker, lhs: NodeId, rhs: NodeId) CheckError!bool {
        var targets: std.ArrayListUnmanaged(TypeId) = .empty;
        defer targets.deinit(self.gpa);
        var name: ?hir_mod.StringId = null;
        var first_node: NodeId = hir_mod.none_node_id;
        if (!try self.collectTypeofChainTargets(lhs, .@"and", false, &name, &first_node, &targets)) return false;
        if (!try self.collectTypeofChainTargets(rhs, .@"and", false, &name, &first_node, &targets)) return false;
        return try self.applyTypeofTargetUnion(name orelse return false, first_node, targets.items);
    }

    fn nodeIsNullLiteralish(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) == .literal_null) return true;
        if (self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        return std.mem.eql(u8, self.string_interner.get(id.name), "null");
    }

    fn applyTypeGuard(self: *Checker, cond: NodeId, when_true: bool) !void {
        // Aliased conditional narrowing: `if (cond)` where `cond`
        // was bound to a guard expression. Expand the alias and
        // recurse on the original expression so all the existing
        // guard logic applies.
        if (self.hir.kindOf(cond) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, cond);
            if (self.cond_aliases.get(id.name)) |aliased| {
                return self.applyTypeGuard(aliased, when_true);
            }
        }
        // `if (Array.isArray(x))` — built-in narrowing for the
        // canonical array predicate. We don't yet have a fully-shaped
        // `Array<any>` reference type wired up here, so we narrow the
        // argument to `Primitive.object_t` (arrays are objects). This
        // mirrors the approximation used elsewhere (e.g. `instanceof`)
        // and lets `let arr = x` after the guard pick up an object
        // type rather than the original `any`/union.
        if (self.hir.kindOf(cond) == .call_expr) {
            const c = hir_mod.callOf(self.hir, cond);
            if (self.hir.kindOf(c.callee) == .member_access) {
                const m = hir_mod.memberOf(self.hir, c.callee);
                if (self.hir.kindOf(m.object) == .identifier) {
                    const obj_id = hir_mod.identifierOf(self.hir, m.object);
                    const obj_name = self.string_interner.get(obj_id.name);
                    const prop_name = self.string_interner.get(m.name);
                    if (std.mem.eql(u8, obj_name, "Array") and
                        std.mem.eql(u8, prop_name, "isArray"))
                    {
                        const args = hir_mod.callArgs(self.hir, cond);
                        if (args.len >= 1 and self.hir.kindOf(args[0]) == .identifier) {
                            const arg_id = hir_mod.identifierOf(self.hir, args[0]);
                            if (when_true) {
                                try self.recordNarrow(arg_id.name, types.Primitive.object_t);
                            } else {
                                const current = self.lookupNarrow(arg_id.name) orelse self.typeOfIdentifier(args[0]);
                                const narrowed = self.subtractType(current, types.Primitive.object_t) catch current;
                                try self.recordNarrow(arg_id.name, narrowed);
                            }
                            return;
                        }
                    }
                }
            }
        }
        // `if (obj.isFoo())` where the method return type is
        // `this is Foo`. Predicate metadata is attached to the
        // method's signature, so narrow the receiver expression.
        if (self.hir.kindOf(cond) == .call_expr) {
            const c = hir_mod.callOf(self.hir, cond);
            if (self.hir.kindOf(c.callee) == .member_access) {
                const m = hir_mod.memberOf(self.hir, c.callee);
                var receiver_t = self.hir.typeOf(m.object);
                if (receiver_t == types.Primitive.none) receiver_t = try self.checkExpression(m.object);
                if (self.lookupMemberPredicate(receiver_t, m.name)) |pred| {
                    if (pred.param_index == 0xFFFF) {
                        const target = try self.resolvePredicateTarget(pred);
                        if (try self.recordPredicateNarrowForExpression(m.object, target, when_true)) return;
                    }
                }
                var callee_t = self.hir.typeOf(c.callee);
                if (callee_t == types.Primitive.none) callee_t = try self.checkExpression(c.callee);
                if (self.signature_predicates.get(callee_t)) |pred| {
                    if (pred.param_index == 0xFFFF) {
                        const target = try self.resolvePredicateTarget(pred);
                        if (try self.recordPredicateNarrowForExpression(m.object, target, when_true)) return;
                    }
                }
                if (self.fn_predicates.get(m.name)) |pred| {
                    if (pred.param_index == 0xFFFF) {
                        const target = try self.resolvePredicateTarget(pred);
                        if (try self.recordPredicateNarrowForExpression(m.object, target, when_true)) return;
                    }
                }
            }
        }
        // `if (isFoo(x))` — type-predicate call narrowing. When the
        // condition is a call to a predicate function and the argument
        // at the predicate's parameter index is an identifier, narrow
        // the identifier in the then-branch to the predicate's target
        // type (or subtract it in the else-branch).
        if (self.hir.kindOf(cond) == .call_expr) {
            const c = hir_mod.callOf(self.hir, cond);
            if (self.hir.kindOf(c.callee) == .identifier) {
                const callee_id = hir_mod.identifierOf(self.hir, c.callee);
                if (self.fn_predicates.get(callee_id.name)) |pred| {
                    const args = hir_mod.callArgs(self.hir, cond);
                    if (pred.param_index < args.len) {
                        const arg = args[pred.param_index];
                        if (self.hir.kindOf(arg) == .identifier) {
                            const arg_id = hir_mod.identifierOf(self.hir, arg);
                            const target = try self.instantiatePredicateTarget(cond, pred);
                            if (when_true) {
                                const current = self.lookupNarrow(arg_id.name) orelse self.typeOfIdentifier(arg);
                                try self.recordNarrow(arg_id.name, try self.narrowTypeByPredicate(current, target));
                            } else {
                                const current = self.lookupNarrow(arg_id.name) orelse self.typeOfIdentifier(arg);
                                const narrowed = self.subtractTypeByPredicate(current, target) catch current;
                                try self.recordNarrow(arg_id.name, narrowed);
                            }
                            return;
                        }
                    }
                }
            }
        }
        // Bare-identifier truthy narrowing: `if (x)` / `x ? a : b`.
        // In the truthy branch, subtract `null | undefined` from `x`'s
        // current type — the v0 approximation that handles the
        // canonical `string | null` → `string` case. (TS also strips
        // `false | 0 | ""` from the truthy branch, but we don't yet
        // model unit-falsy types here.) The falsy branch is left
        // un-narrowed since broad falsy partitioning needs the
        // discriminated-union machinery.
        if (self.hir.kindOf(cond) == .identifier and when_true) {
            const id = hir_mod.identifierOf(self.hir, cond);
            const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(cond);
            const narrowed = if (current == types.Primitive.unknown)
                types.Primitive.object_t
            else
                self.subtractNullUndefined(current) catch current;
            if (narrowed != current) try self.recordNarrow(id.name, narrowed);
            return;
        }
        if (self.hir.kindOf(cond) == .member_access) {
            try self.applyTruthyDiscriminantGuard(cond, when_true);
            return;
        }
        if (self.hir.kindOf(cond) == .logical_op) {
            const l = hir_mod.logicalOf(self.hir, cond);
            switch (l.op) {
                .@"and" => {
                    if (when_true) {
                        try self.applyTypeGuard(l.lhs, true);
                        try self.applyTypeGuard(l.rhs, true);
                    } else if (try self.applyFalseAndTypeofChain(l.lhs, l.rhs)) {
                        return;
                    }
                    return;
                },
                .@"or" => {
                    if (when_true) {
                        if (try self.applyTrueOrTypeofChain(l.lhs, l.rhs)) return;
                    } else {
                        try self.applyTypeGuard(l.lhs, false);
                        try self.applyTypeGuard(l.rhs, false);
                    }
                    return;
                },
                .nullish => return,
            }
        }
        // Same shape but via element_access with a string-literal
        // index: `if (obj["x"])` / `obj["x"] && rhs`. The
        // (obj_name, prop_name) MemberKey is identical to the dot
        // form, so any later `obj.x` access inside the branch picks
        // up the same narrow — and vice versa.
        if (self.hir.kindOf(cond) == .element_access and when_true) {
            const e = hir_mod.elementOf(self.hir, cond);
            if (self.hir.kindOf(e.object) == .identifier and
                self.hir.kindOf(e.index) == .literal_string)
            {
                const obj_id = hir_mod.identifierOf(self.hir, e.object);
                const lit = hir_mod.literalStringOf(self.hir, e.index);
                const key: MemberKey = .{ .obj_name = obj_id.name, .prop_name = lit.value };
                const obj_t = self.lookupNarrow(obj_id.name) orelse self.typeOfIdentifier(e.object);
                const looked_up = (try self.lookupObjectMember(obj_t, lit.value));
                const current = self.lookupMemberNarrow(key) orelse (looked_up orelse types.Primitive.none);
                if (current != types.Primitive.none) {
                    const narrowed = self.subtractNullUndefined(current) catch current;
                    if (narrowed != current) try self.recordMemberNarrow(key, narrowed);
                }
                return;
            }
        }
        if (self.hir.kindOf(cond) == .unary_op) {
            const u = hir_mod.unaryOf(self.hir, cond);
            if (u.op == .not) return self.applyTypeGuard(u.operand, !when_true);
        }
        if (self.hir.kindOf(cond) != .binary_op) return;
        const b = hir_mod.binopOf(self.hir, cond);

        // `x instanceof Foo` — narrows `x` to the class's instance
        // type when `Foo` resolves to a declared class; otherwise
        // falls back to the broad object predicate. The false branch
        // subtracts object-like constituents from unions, which is
        // the common primitive/object partitioning used by TS.
        if (b.op == .instanceof and self.hir.kindOf(b.lhs) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, b.lhs);
            var target: TypeId = types.Primitive.object_t;
            var rhs_is_array = false;
            if (self.hir.kindOf(b.rhs) == .identifier) {
                const rhs_id = hir_mod.identifierOf(self.hir, b.rhs);
                if (self.class_instance_types.get(rhs_id.name)) |inst| {
                    target = inst;
                } else {
                    const rhs_name = self.string_interner.get(rhs_id.name);
                    if (std.mem.eql(u8, rhs_name, "Array") or std.mem.eql(u8, rhs_name, "ReadonlyArray")) {
                        rhs_is_array = true;
                    }
                }
            }
            const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(b.lhs);
            // `x instanceof Array` — narrow union to its array
            // constituents (and the false branch keeps non-array
            // constituents). Falls through to the object-predicate
            // path when no array constituents are present so the
            // existing partitioning behavior applies.
            if (rhs_is_array) {
                const cur_flags = self.interner.pool.flagsOf(current);
                if (cur_flags.is_union) {
                    var kept: std.ArrayListUnmanaged(TypeId) = .empty;
                    defer kept.deinit(self.gpa);
                    var subtracted: std.ArrayListUnmanaged(TypeId) = .empty;
                    defer subtracted.deinit(self.gpa);
                    for (self.interner.unionMembers(current)) |member| {
                        const elem = self.interner.objectNumberIndex(member);
                        if (elem != types.Primitive.none) {
                            try kept.append(self.gpa, member);
                        } else {
                            try subtracted.append(self.gpa, member);
                        }
                    }
                    if (when_true and kept.items.len > 0) {
                        const narrowed = if (kept.items.len == 1)
                            kept.items[0]
                        else
                            self.interner.internUnion(kept.items) catch current;
                        try self.recordNarrow(id.name, narrowed);
                        return;
                    } else if (!when_true and subtracted.items.len > 0 and kept.items.len > 0) {
                        const narrowed = if (subtracted.items.len == 1)
                            subtracted.items[0]
                        else
                            self.interner.internUnion(subtracted.items) catch current;
                        try self.recordNarrow(id.name, narrowed);
                        return;
                    }
                } else if (when_true and self.interner.objectNumberIndex(current) != types.Primitive.none) {
                    // Already an array — keep as-is.
                    try self.recordNarrow(id.name, current);
                    return;
                }
            }
            if (when_true) {
                const narrowed = self.narrowTypeByPredicate(current, target) catch target;
                try self.recordNarrow(id.name, narrowed);
            } else {
                const narrowed = self.subtractTypeByPredicate(current, target) catch current;
                try self.recordNarrow(id.name, narrowed);
            }
            return;
        }

        // `"foo" in x` — narrows `x` to the variants of its union
        // that declare `foo`. The else-branch keeps the variants
        // that *don't* declare it. LHS must be a string literal
        // (TS only narrows when the property name is statically
        // known); RHS must be an identifier we can record against.
        if (b.op == .in and self.hir.kindOf(b.rhs) == .identifier) {
            const property_name = (try self.staticStringValue(b.lhs)) orelse return;
            const rhs_id = hir_mod.identifierOf(self.hir, b.rhs);
            const current = self.lookupNarrow(rhs_id.name) orelse self.typeOfIdentifier(b.rhs);
            const narrowed = self.narrowByPropertyPresence(current, property_name, when_true) catch current;
            if (narrowed != current) try self.recordNarrow(rhs_id.name, narrowed);
            return;
        }

        const equality_op = b.op == .eq_strict or b.op == .neq_strict or b.op == .eq or b.op == .neq;
        if (!equality_op) return;
        // `positive` = "this branch represents the equality
        // matching" (i.e. `===` in then, `!==` in else).
        const positive = (b.op == .eq_strict or b.op == .eq) == when_true;

        // Discriminated union narrowing: `x.kind === "circle"`.
        // LHS is a member access, RHS is a literal. We walk the
        // member access's object's static type — if it's a union of
        // object types, keep the variants whose discriminant prop's
        // type matches the RHS literal.
        if (self.hir.kindOf(b.lhs) == .member_access) {
            if (try self.expressionNarrowLiteralType(b.rhs)) |rhs_lit_t| {
                try self.applyDiscriminatedNarrowWithLiteralType(b.lhs, rhs_lit_t, positive);
            }
            // Don't return — fall through so other guards still try
            // to match (rare overlap, but keeps the logic
            // additive).
        }
        // typeof X === "kind"
        if (self.hir.kindOf(b.lhs) == .unary_op) {
            const u = hir_mod.unaryOf(self.hir, b.lhs);
            if (u.op == .typeof) {
                if (try self.applyTypeofPropertyGuard(u.operand, b.rhs, positive)) return;
            }
            if (u.op == .typeof and self.hir.kindOf(u.operand) == .identifier) {
                const id = hir_mod.identifierOf(self.hir, u.operand);
                const type_name = (try self.staticStringValue(b.rhs)) orelse return;
                const lit_str = self.string_interner.get(type_name);
                if (typeOfTypeofString(lit_str)) |narrowed| {
                    const target = try self.typeofNarrowType(lit_str, narrowed);
                    if (!self.identifierHasNarrowableValueBinding(u.operand)) return;
                    if (positive) {
                        const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(u.operand);
                        const next = if (std.mem.eql(u8, lit_str, "object") and self.typeIncludesNull(current))
                            self.objectOrNullType()
                        else
                            try self.narrowTypeByPredicate(current, target);
                        try self.recordNarrow(id.name, next);
                    } else {
                        // Negative branch: subtract `narrowed` from
                        // the variable's current type. Works for
                        // unions of primitives (`string | number`
                        // minus `string` → `number`). Falls through
                        // to `never` for the bare-equality case.
                        const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(u.operand);
                        const subbed = self.subtractTypeByPredicate(current, target) catch current;
                        try self.recordNarrow(id.name, subbed);
                    }
                }
                return;
            }
        }
        // X === <literal> / X !== <literal> — narrow X to the
        // literal type in the positive branch, subtract it in the
        // negative branch. Covers `s === "hello"`, `n === 42`,
        // `b === true`, `x === 42n`, `x === -42n` (parsed as
        // `unary_op(neg, literal_bigint(42))`). Discriminated-union
        // narrowing above handles the member-access case
        // (`x.kind === "circle"`); this branch handles the
        // bare-identifier case.
        const rhs_is_neg_bigint = blk: {
            if (self.hir.kindOf(b.rhs) != .unary_op) break :blk false;
            const u = hir_mod.unaryOf(self.hir, b.rhs);
            break :blk u.op == .neg and self.hir.kindOf(u.operand) == .literal_bigint;
        };
        if (self.hir.kindOf(b.lhs) == .identifier and
            ((try self.expressionNarrowLiteralType(b.rhs)) != null or
                self.hir.kindOf(b.rhs) == .literal_bigint or
                rhs_is_neg_bigint))
        {
            const id = hir_mod.identifierOf(self.hir, b.lhs);
            const lit_t: TypeId = blk: {
                if (rhs_is_neg_bigint) {
                    const u = hir_mod.unaryOf(self.hir, b.rhs);
                    const lit = hir_mod.literalBigIntOf(self.hir, u.operand);
                    const digits_str = self.string_interner.get(lit.digits);
                    // Build "-<digits>" so the rendered literal is
                    // `-<digits>n` and equality of TypeIds tracks
                    // sign + magnitude.
                    var buf: [64]u8 = undefined;
                    if (digits_str.len + 1 > buf.len) return;
                    buf[0] = '-';
                    @memcpy(buf[1 .. 1 + digits_str.len], digits_str);
                    const neg_digits_id = self.string_interner.intern(buf[0 .. 1 + digits_str.len]) catch return;
                    break :blk self.interner.internBigIntLiteral(neg_digits_id) catch return;
                }
                if (try self.expressionNarrowLiteralType(b.rhs)) |lit| break :blk lit;
                switch (self.hir.kindOf(b.rhs)) {
                    .literal_bigint => {
                        const lit = hir_mod.literalBigIntOf(self.hir, b.rhs);
                        break :blk self.interner.internBigIntLiteral(lit.digits) catch return;
                    },
                    else => unreachable,
                }
            };
            if (positive) {
                try self.recordNarrow(id.name, lit_t);
            } else {
                const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(b.lhs);
                const narrowed = self.subtractType(current, lit_t) catch current;
                try self.recordNarrow(id.name, narrowed);
            }
            return;
        }
        // X === null / X !== null / X == null / X != null
        if (self.hir.kindOf(b.lhs) == .identifier and
            self.nodeIsNullLiteralish(b.rhs))
        {
            const id = hir_mod.identifierOf(self.hir, b.lhs);
            if (positive) {
                try self.recordNarrow(id.name, types.Primitive.null_t);
            } else {
                // X !== null in then-branch → subtract null from X's
                // current static type. If X was `string | null`, the
                // narrowed type is `string`. If X was just `null`,
                // the narrowed type is `never` (unreachable).
                const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(b.lhs);
                const without_null = if (current == types.Primitive.unknown)
                    types.Primitive.object_t
                else
                    self.subtractType(current, types.Primitive.null_t) catch current;
                const narrowed = if (b.op == .eq or b.op == .neq)
                    self.subtractType(without_null, types.Primitive.undefined_t) catch without_null
                else
                    without_null;
                try self.recordNarrow(id.name, narrowed);
            }
            return;
        }
        if (self.hir.kindOf(b.rhs) == .identifier and
            self.nodeIsNullLiteralish(b.lhs))
        {
            const id = hir_mod.identifierOf(self.hir, b.rhs);
            if (positive) {
                try self.recordNarrow(id.name, types.Primitive.null_t);
            } else {
                const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(b.rhs);
                const without_null = if (current == types.Primitive.unknown)
                    types.Primitive.object_t
                else
                    self.subtractType(current, types.Primitive.null_t) catch current;
                const narrowed = if (b.op == .eq or b.op == .neq)
                    self.subtractType(without_null, types.Primitive.undefined_t) catch without_null
                else
                    without_null;
                try self.recordNarrow(id.name, narrowed);
            }
            return;
        }
        // X === undefined / X !== undefined / X == undefined / X != undefined (literal_undefined +
        // identifier 'undefined' both occur in source code).
        if (self.hir.kindOf(b.lhs) == .identifier and
            self.hir.kindOf(b.rhs) == .identifier)
        {
            const lhs = hir_mod.identifierOf(self.hir, b.lhs);
            const rhs = hir_mod.identifierOf(self.hir, b.rhs);
            const rhs_name = self.string_interner.get(rhs.name);
            if (std.mem.eql(u8, rhs_name, "undefined")) {
                if (positive) {
                    try self.recordNarrow(lhs.name, types.Primitive.undefined_t);
                } else {
                    const current = self.lookupNarrow(lhs.name) orelse self.typeOfIdentifier(b.lhs);
                    const without_undefined = if (current == types.Primitive.unknown)
                        types.Primitive.object_t
                    else
                        self.subtractType(current, types.Primitive.undefined_t) catch current;
                    const narrowed = if (b.op == .eq or b.op == .neq)
                        self.subtractType(without_undefined, types.Primitive.null_t) catch without_undefined
                    else
                        without_undefined;
                    try self.recordNarrow(lhs.name, narrowed);
                }
                return;
            }
        }
        if (self.hir.kindOf(b.rhs) == .identifier and
            self.hir.kindOf(b.lhs) == .identifier)
        {
            const lhs = hir_mod.identifierOf(self.hir, b.lhs);
            const lhs_name = self.string_interner.get(lhs.name);
            if (std.mem.eql(u8, lhs_name, "undefined")) {
                const rhs = hir_mod.identifierOf(self.hir, b.rhs);
                if (positive) {
                    try self.recordNarrow(rhs.name, types.Primitive.undefined_t);
                } else {
                    const current = self.lookupNarrow(rhs.name) orelse self.typeOfIdentifier(b.rhs);
                    const without_undefined = if (current == types.Primitive.unknown)
                        types.Primitive.object_t
                    else
                        self.subtractType(current, types.Primitive.undefined_t) catch current;
                    const narrowed = if (b.op == .eq or b.op == .neq)
                        self.subtractType(without_undefined, types.Primitive.null_t) catch without_undefined
                    else
                        without_undefined;
                    try self.recordNarrow(rhs.name, narrowed);
                }
                return;
            }
        }

        // Member-access narrowing on an identifier-rooted access:
        //   obj.x === null / obj.x !== null
        //   obj.x === undefined / obj.x !== undefined
        //   obj.x === <literal> / obj.x !== <literal>
        // The narrow is keyed by `(obj_name, prop_name)` so the
        // `member_access` typing path sees it inside the branch.
        if (self.hir.kindOf(b.lhs) == .member_access) {
            const m = hir_mod.memberOf(self.hir, b.lhs);
            if (self.hir.kindOf(m.object) == .identifier) {
                const obj_id = hir_mod.identifierOf(self.hir, m.object);
                const key: MemberKey = .{ .obj_name = obj_id.name, .prop_name = m.name };
                // RHS == null
                if (self.hir.kindOf(b.rhs) == .literal_null) {
                    if (positive) {
                        try self.recordMemberNarrow(key, types.Primitive.null_t);
                    } else {
                        const obj_t = self.typeOfIdentifier(m.object);
                        const current = self.lookupMemberNarrow(key) orelse
                            (self.interner.objectMember(obj_t, m.name) orelse types.Primitive.any);
                        const narrowed = self.subtractType(current, types.Primitive.null_t) catch current;
                        try self.recordMemberNarrow(key, narrowed);
                    }
                    return;
                }
                // RHS == identifier 'undefined'
                if (self.hir.kindOf(b.rhs) == .identifier) {
                    const rhs2 = hir_mod.identifierOf(self.hir, b.rhs);
                    const rhs2_name = self.string_interner.get(rhs2.name);
                    if (std.mem.eql(u8, rhs2_name, "undefined")) {
                        if (positive) {
                            try self.recordMemberNarrow(key, types.Primitive.undefined_t);
                        } else {
                            const obj_t = self.typeOfIdentifier(m.object);
                            const current = self.lookupMemberNarrow(key) orelse
                                (self.interner.objectMember(obj_t, m.name) orelse types.Primitive.any);
                            const narrowed = self.subtractType(current, types.Primitive.undefined_t) catch current;
                            try self.recordMemberNarrow(key, narrowed);
                        }
                        return;
                    }
                }
                // RHS == primitive literal (string/number/bool).
                // The discriminated-union path above narrows the
                // whole object when its type is a union; this
                // records a property-level narrow so non-union
                // object roots also see the literal type.
                if (try self.expressionNarrowLiteralType(b.rhs)) |lit_t| {
                    if (positive) {
                        try self.recordMemberNarrow(key, lit_t);
                    } else {
                        const obj_t = self.typeOfIdentifier(m.object);
                        const current = self.lookupMemberNarrow(key) orelse
                            (self.interner.objectMember(obj_t, m.name) orelse types.Primitive.any);
                        const narrowed = self.subtractType(current, lit_t) catch current;
                        try self.recordMemberNarrow(key, narrowed);
                    }
                    return;
                }
            }
        }
    }

    fn applyTypeofPropertyGuard(self: *Checker, operand: NodeId, rhs: NodeId, positive: bool) CheckError!bool {
        const type_name = (try self.staticStringValue(rhs)) orelse return false;
        const lit_str = self.string_interner.get(type_name);
        const narrowed = typeOfTypeofString(lit_str) orelse return false;
        const target = try self.memberNarrowTargetFromAccess(operand) orelse return false;
        const current = self.lookupMemberNarrow(target.key) orelse target.current;
        if (current == types.Primitive.none) return false;
        const next = if (positive)
            narrowed
        else
            (self.subtractType(current, narrowed) catch current);
        try self.recordMemberNarrow(target.key, next);
        return true;
    }

    const MemberNarrowTarget = struct {
        key: MemberKey,
        current: TypeId,
    };

    fn memberNarrowTargetFromAccess(self: *Checker, access: NodeId) CheckError!?MemberNarrowTarget {
        switch (self.hir.kindOf(access)) {
            .member_access => {
                const m = hir_mod.memberOf(self.hir, access);
                if (self.hir.kindOf(m.object) != .identifier) return null;
                const obj_id = hir_mod.identifierOf(self.hir, m.object);
                const key: MemberKey = .{ .obj_name = obj_id.name, .prop_name = m.name };
                const obj_t = self.lookupNarrow(obj_id.name) orelse self.typeOfIdentifier(m.object);
                const current = (try self.lookupObjectMember(obj_t, m.name)) orelse self.hir.typeOf(access);
                return .{ .key = key, .current = current };
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, access);
                if (self.hir.kindOf(e.object) != .identifier) return null;
                const prop_name = (try self.staticStringValue(e.index)) orelse return null;
                const obj_id = hir_mod.identifierOf(self.hir, e.object);
                const key: MemberKey = .{ .obj_name = obj_id.name, .prop_name = prop_name };
                const obj_t = self.lookupNarrow(obj_id.name) orelse self.typeOfIdentifier(e.object);
                const current = (try self.lookupObjectMember(obj_t, prop_name)) orelse self.hir.typeOf(access);
                return .{ .key = key, .current = current };
            },
            else => return null,
        }
    }

    fn staticStringValue(self: *Checker, node: NodeId) CheckError!?hir_mod.StringId {
        return switch (self.hir.kindOf(node)) {
            .literal_string => hir_mod.literalStringOf(self.hir, node).value,
            .template_literal => try self.templateLiteralConcreteString(node),
            else => null,
        };
    }

    /// Discriminated-union narrowing. `lhs` is a member access
    /// `obj.disc`; `rhs_lit` is the literal we're comparing against.
    /// If `obj` is a union of object types and one of its members'
    /// `disc` field matches `rhs_lit`, we narrow `obj` to that member.
    fn applyDiscriminatedNarrow(self: *Checker, lhs: NodeId, rhs_lit: NodeId, positive: bool) !void {
        const lit_t = (try self.expressionNarrowLiteralType(rhs_lit)) orelse return;
        try self.applyDiscriminatedNarrowWithLiteralType(lhs, lit_t, positive);
    }

    fn applyDiscriminatedNarrowWithLiteralType(self: *Checker, lhs: NodeId, lit_t: TypeId, positive: bool) !void {
        const m = hir_mod.memberOf(self.hir, lhs);
        if (self.hir.kindOf(m.object) != .identifier) return;
        const obj_id = hir_mod.identifierOf(self.hir, m.object);
        const static_t = self.typeOfIdentifier(m.object);
        // If accumulated narrowing already produced `never`, there's
        // nothing left to subtract — leave the narrow alone.
        if (static_t == types.Primitive.never) return;
        const is_union = self.interner.pool.flagsOf(static_t).is_union;
        const is_object = self.interner.pool.flagsOf(static_t).is_object_type;
        if (!is_union and !is_object) return;

        try self.applyDiscriminatedNarrowByType(obj_id.name, static_t, m.name, lit_t, positive);
    }

    fn applyTruthyDiscriminantGuard(self: *Checker, member_node: NodeId, when_true: bool) !void {
        const m = hir_mod.memberOf(self.hir, member_node);
        const target: DiscriminantTarget = switch (self.hir.kindOf(m.object)) {
            .identifier => blk: {
                const obj_id = hir_mod.identifierOf(self.hir, m.object);
                break :blk .{ .name = obj_id.name, .t = self.typeOfIdentifier(m.object) };
            },
            .assignment => blk: {
                const a = hir_mod.assignmentOf(self.hir, m.object);
                if (a.op != null or self.hir.kindOf(a.target) != .identifier) return;
                const target_id = hir_mod.identifierOf(self.hir, a.target);
                var assigned_t = self.hir.typeOf(m.object);
                if (assigned_t == types.Primitive.none) assigned_t = try self.checkExpression(m.object);
                break :blk .{ .name = target_id.name, .t = assigned_t };
            },
            else => return,
        };
        const true_lit = self.interner.internBooleanLiteral(true);
        try self.applyDiscriminatedNarrowByType(target.name, target.t, m.name, true_lit, when_true);
    }

    fn applyDiscriminatedNarrowByType(
        self: *Checker,
        obj_name: hir_mod.StringId,
        static_t: TypeId,
        prop_name: hir_mod.StringId,
        lit_t: TypeId,
        positive: bool,
    ) !void {
        // Treat a single-object narrow as a one-element union so the
        // exhaustion logic below collapses it to `never` when the
        // last remaining variant is also subtracted (the
        // exhaustiveness-marker pattern in switch defaults).
        if (static_t == types.Primitive.never) return;
        const flags = self.interner.pool.flagsOf(static_t);
        const is_union = flags.is_union;
        const is_object = flags.is_object_type;
        if (!is_union and !is_object) return;
        const single_buf = [_]TypeId{static_t};
        const members: []const TypeId = if (is_union)
            self.interner.unionMembers(static_t)
        else
            single_buf[0..];
        var keep: std.ArrayListUnmanaged(TypeId) = .empty;
        defer keep.deinit(self.gpa);
        for (members) |variant| {
            if (!self.interner.pool.flagsOf(variant).is_object_type) continue;
            const disc_t = self.interner.objectMember(variant, prop_name) orelse continue;
            // Match: the variant's discriminant is exactly the literal.
            if (try self.discriminantTypeMatchesLiteral(disc_t, lit_t)) {
                if (positive) {
                    try keep.append(self.gpa, variant);
                }
            } else {
                if (!positive) {
                    try keep.append(self.gpa, variant);
                }
            }
        }
        const narrowed: TypeId = if (keep.items.len == 0)
            // Exhausted: every variant was excluded. The discriminant
            // is `never` — TS uses this for exhaustiveness checks
            // (e.g. `let x: never = s` in a switch's default branch
            // after every case is covered).
            types.Primitive.never
        else if (keep.items.len == 1)
            keep.items[0]
        else
            self.interner.internUnion(keep.items) catch return;
        try self.recordNarrow(obj_name, narrowed);
    }

    fn discriminantTypeMatchesLiteral(self: *Checker, disc_t: TypeId, lit_t: TypeId) CheckError!bool {
        if (disc_t == lit_t) return true;
        if (self.engine.isAssignableTo(lit_t, disc_t) catch false) return true;
        if (self.engine.isAssignableTo(disc_t, lit_t) catch false) return true;
        if (lit_t >= types.Primitive.first_dynamic and lit_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(lit_t).is_literal)
        {
            switch (self.interner.literalOf(lit_t)) {
                .string_lit => |sid| return try self.stringLiteralAssignableToType(sid, disc_t),
                else => {},
            }
        }
        return false;
    }

    fn recordNarrow(self: *Checker, name: hir_mod.StringId, t: TypeId) !void {
        if (self.narrow_scopes.items.len == 0) return;
        var top = &self.narrow_scopes.items[self.narrow_scopes.items.len - 1];
        try top.put(self.gpa, name, t);
    }

    /// Resolve the type of a binding identifier inside a destructuring
    /// pattern. `pattern_node` is the `object_pattern` / `array_pattern`
    /// HIR node that stands in for the parameter or var-decl name.
    /// `container_t` is the lowered type of the parameter / initializer.
    /// `target_name` is the identifier whose type we want.
    ///
    /// For object patterns: looks up `target_name` as a member of
    /// `container_t`. The property's optionality (`a?: number`) shows
    /// up either as an `is_optional` ObjectMember flag or as `T |
    /// undefined` already; if the binding has a default expression,
    /// strip `undefined` from the result so `{ a = 1 }: { a?: T }`
    /// types `a` as `T`.
    ///
    /// For array patterns: looks up the matching tuple element by
    /// position. Optional/rest elements receive the same default
    /// stripping treatment.
    fn typeOfPatternBinding(
        self: *Checker,
        pattern_node: NodeId,
        container_t: TypeId,
        target_name: hir_mod.StringId,
    ) ?TypeId {
        const pk = self.hir.kindOf(pattern_node);
        const elements = hir_mod.patternElements(self.hir, pattern_node);
        if (pk == .object_pattern) {
            for (elements) |e| {
                if (self.hir.kindOf(e) != .parameter) continue;
                const ep = hir_mod.parameterOf(self.hir, e);
                if (ep.name == hir_mod.none_node_id) continue;
                const name_kind = self.hir.kindOf(ep.name);
                if (name_kind == .identifier) {
                    const eid = hir_mod.identifierOf(self.hir, ep.name);
                    if (eid.name != target_name) continue;
                    // Found the binding. Look up the property in
                    // `container_t`. The lowered type for `{ a?: T }`
                    // marks the member optional but stores T directly;
                    // union with `undefined` to reflect callers passing
                    // `{}`.
                    var member_t: TypeId = types.Primitive.any;
                    if (ep.flags.is_computed_binding_key and ep.default_value != hir_mod.none_node_id) {
                        member_t = (self.objectPropertyTypeForComputedKeyNode(container_t, ep.default_value) catch null) orelse types.Primitive.any;
                    } else if (self.interner.objectMemberInfo(container_t, eid.name)) |info| {
                        member_t = info.type;
                        if (info.is_optional) {
                            member_t = self.unionWithUndefined(member_t) catch member_t;
                        }
                    }
                    if (ep.default_value != hir_mod.none_node_id) {
                        member_t = self.subtractType(member_t, types.Primitive.undefined_t) catch member_t;
                    }
                    return member_t;
                }
                if (name_kind == .object_pattern or name_kind == .array_pattern) {
                    var nested_container_t: TypeId = types.Primitive.any;
                    if (self.objectBindingElementKeyName(e, ep.name) catch null) |key_name| {
                        nested_container_t = self.objectPropertyTypeByName(container_t, key_name) orelse types.Primitive.any;
                    }
                    if (self.typeOfPatternBinding(ep.name, nested_container_t, target_name)) |bt| {
                        return bt;
                    }
                }
            }
            return null;
        }
        if (pk == .array_pattern) {
            // Walk elements in order, tracking the tuple index. Rest
            // elements are skipped for v0 (no slice typing).
            const flags = self.interner.pool.flagsOf(container_t);
            var idx: u32 = 0;
            for (elements) |e| {
                if (self.hir.kindOf(e) != .parameter) continue;
                const ep = hir_mod.parameterOf(self.hir, e);
                if (ep.name == hir_mod.none_node_id) continue;
                const name_kind = self.hir.kindOf(ep.name);
                if (name_kind == .object_pattern or name_kind == .array_pattern) {
                    var elem_container_t: TypeId = types.Primitive.any;
                    if (!ep.flags.is_rest) {
                        const tuple_t = self.tupleElementType(container_t, idx);
                        if (tuple_t != types.Primitive.none) {
                            elem_container_t = tuple_t;
                        } else if (flags.is_tuple) {
                            const payload = self.interner.pool.tuple_payloads.items[self.interner.pool.payloadOf(container_t)];
                            const elems = self.interner.pool.tuple_element_pool.items[payload.elements_start .. payload.elements_start + payload.elements_len];
                            if (idx < elems.len) elem_container_t = elems[idx].type;
                        }
                    }
                    if (ep.default_value != hir_mod.none_node_id) {
                        const default_t = if (self.nodeContainsIdentifier(ep.default_value, target_name))
                            types.Primitive.any
                        else
                            self.checkExpression(ep.default_value) catch types.Primitive.any;
                        elem_container_t = if (elem_container_t == types.Primitive.any)
                            default_t
                        else
                            self.destructuringSourceWithDefault(elem_container_t, default_t) catch elem_container_t;
                    }
                    if (self.typeOfPatternBinding(ep.name, elem_container_t, target_name)) |bt| {
                        return bt;
                    }
                    if (!ep.flags.is_rest) idx += 1;
                    continue;
                }
                if (name_kind != .identifier) {
                    if (!ep.flags.is_rest) idx += 1;
                    continue;
                }
                const eid = hir_mod.identifierOf(self.hir, ep.name);
                if (eid.name != target_name) {
                    if (!ep.flags.is_rest) idx += 1;
                    continue;
                }
                if (ep.flags.is_rest) return types.Primitive.any;
                var elem_t: TypeId = types.Primitive.any;
                if (flags.is_tuple) {
                    const payload = self.interner.pool.tuple_payloads.items[self.interner.pool.payloadOf(container_t)];
                    const elems = self.interner.pool.tuple_element_pool.items[payload.elements_start .. payload.elements_start + payload.elements_len];
                    if (idx < elems.len) {
                        const te = elems[idx];
                        elem_t = te.type;
                        if (te.is_optional) {
                            elem_t = self.unionWithUndefined(elem_t) catch elem_t;
                        }
                    }
                }
                if (ep.default_value != hir_mod.none_node_id) {
                    const default_t = if (self.nodeContainsIdentifier(ep.default_value, target_name))
                        types.Primitive.any
                    else
                        self.checkExpression(ep.default_value) catch types.Primitive.any;
                    elem_t = self.destructuringSourceWithDefault(elem_t, default_t) catch elem_t;
                }
                return elem_t;
            }
            return null;
        }
        return null;
    }

    fn widenNullishBindingElementType(self: *Checker, source_node: NodeId, elem_t: TypeId) TypeId {
        if (self.strict_flags.strict_null_checks) return elem_t;
        if (source_node != hir_mod.none_node_id) {
            const k = self.hir.kindOf(source_node);
            if (k == .literal_null or k == .literal_undefined) return types.Primitive.any;
        }
        if (elem_t == types.Primitive.null_t or elem_t == types.Primitive.undefined_t) {
            return types.Primitive.any;
        }
        return elem_t;
    }

    fn typeOfPatternBindingFromSource(
        self: *Checker,
        pattern_node: NodeId,
        source_node: NodeId,
        source_t: TypeId,
        target_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        if (pattern_node == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(pattern_node)) {
            .array_pattern => blk: {
                const source_elements: []const NodeId = if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .array_literal)
                    hir_mod.arrayLiteralElements(self.hir, source_node)
                else
                    &.{};
                const fallback_elem_t = try self.iterableElementType(source_t);
                for (hir_mod.patternElements(self.hir, pattern_node), 0..) |elem, i| {
                    if (self.hir.kindOf(elem) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, elem);
                    if (p.name == hir_mod.none_node_id) continue;
                    var elem_node: NodeId = hir_mod.none_node_id;
                    var elem_t: TypeId = types.Primitive.any;
                    if (i < source_elements.len and source_elements[i] != hir_mod.none_node_id) {
                        elem_node = source_elements[i];
                        elem_t = self.hir.typeOf(elem_node);
                        if (elem_t == types.Primitive.none and self.nodeContainsIdentifier(elem_node, target_name)) {
                            elem_t = types.Primitive.any;
                        } else if (elem_t == types.Primitive.none and self.hir.kindOf(elem_node) != .identifier) {
                            elem_t = try self.checkExpression(elem_node);
                        }
                    } else if (p.default_value != hir_mod.none_node_id) {
                        elem_node = p.default_value;
                        elem_t = self.hir.typeOf(elem_node);
                        if (elem_t == types.Primitive.none and self.nodeContainsIdentifier(elem_node, target_name)) {
                            elem_t = types.Primitive.any;
                        } else if (elem_t == types.Primitive.none and self.hir.kindOf(elem_node) != .identifier) {
                            elem_t = try self.checkExpression(elem_node);
                        }
                    } else {
                        const tuple_t = self.tupleElementType(source_t, i);
                        elem_t = if (tuple_t != types.Primitive.none) tuple_t else fallback_elem_t;
                    }
                    if (p.flags.is_rest) {
                        elem_t = try self.arrayRestSourceType(source_node, i, elem_t);
                    }
                    elem_t = self.widenNullishBindingElementType(elem_node, elem_t);
                    if (elem_t == types.Primitive.none or elem_t == types.Primitive.any or elem_t == types.Primitive.unknown) continue;
                    switch (self.hir.kindOf(p.name)) {
                        .identifier => if (hir_mod.identifierOf(self.hir, p.name).name == target_name) break :blk elem_t,
                        .array_pattern, .object_pattern => {
                            if (try self.typeOfPatternBindingFromSource(p.name, elem_node, elem_t, target_name)) |bt| break :blk bt;
                        },
                        .assignment => {
                            const a = hir_mod.assignmentOf(self.hir, p.name);
                            if (try self.typeOfPatternBindingFromSource(a.target, elem_node, elem_t, target_name)) |bt| break :blk bt;
                        },
                        else => {},
                    }
                }
                break :blk null;
            },
            .array_literal => blk: {
                const target_elements = hir_mod.arrayLiteralElements(self.hir, pattern_node);
                const source_elements: []const NodeId = if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .array_literal)
                    hir_mod.arrayLiteralElements(self.hir, source_node)
                else
                    &.{};
                const fallback_elem_t = try self.iterableElementType(source_t);
                for (target_elements, 0..) |target, i| {
                    if (target == hir_mod.none_node_id) continue;
                    var elem_node: NodeId = hir_mod.none_node_id;
                    var elem_t: TypeId = types.Primitive.any;
                    if (i < source_elements.len and source_elements[i] != hir_mod.none_node_id) {
                        elem_node = source_elements[i];
                        elem_t = self.hir.typeOf(elem_node);
                        if (elem_t == types.Primitive.none and self.nodeContainsIdentifier(elem_node, target_name)) {
                            elem_t = types.Primitive.any;
                        } else if (elem_t == types.Primitive.none and self.hir.kindOf(elem_node) != .identifier) {
                            elem_t = try self.checkExpression(elem_node);
                        }
                    } else {
                        const tuple_t = self.tupleElementType(source_t, i);
                        elem_t = if (tuple_t != types.Primitive.none) tuple_t else fallback_elem_t;
                    }
                    elem_t = self.widenNullishBindingElementType(elem_node, elem_t);
                    if (elem_t == types.Primitive.none or elem_t == types.Primitive.any or elem_t == types.Primitive.unknown) continue;
                    switch (self.hir.kindOf(target)) {
                        .identifier => if (hir_mod.identifierOf(self.hir, target).name == target_name) break :blk elem_t,
                        .array_literal, .object_literal, .array_pattern, .object_pattern => {
                            if (try self.typeOfPatternBindingFromSource(target, elem_node, elem_t, target_name)) |bt| break :blk bt;
                        },
                        .assignment => {
                            const a = hir_mod.assignmentOf(self.hir, target);
                            var default_t = self.hir.typeOf(a.value);
                            if (default_t == types.Primitive.none and self.nodeContainsIdentifier(a.value, target_name)) {
                                default_t = types.Primitive.any;
                            } else if (default_t == types.Primitive.none and self.hir.kindOf(a.value) != .identifier) {
                                default_t = try self.checkExpression(a.value);
                            }
                            if (default_t == types.Primitive.none) default_t = types.Primitive.any;
                            const effective_t = try self.destructuringSourceWithDefault(elem_t, default_t);
                            if (try self.typeOfPatternBindingFromSource(a.target, a.value, effective_t, target_name)) |bt| break :blk bt;
                        },
                        else => {},
                    }
                }
                break :blk null;
            },
            .object_pattern => blk: {
                for (hir_mod.patternElements(self.hir, pattern_node)) |elem| {
                    if (self.hir.kindOf(elem) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, elem);
                    if (p.name == hir_mod.none_node_id or p.flags.is_rest) continue;
                    var prop_t: TypeId = types.Primitive.any;
                    if (p.flags.is_computed_binding_key and p.default_value != hir_mod.none_node_id) {
                        prop_t = (try self.objectPropertyTypeForComputedKeyNode(source_t, p.default_value)) orelse types.Primitive.any;
                    } else if (try self.objectBindingElementKeyName(elem, p.name)) |key_name| {
                        prop_t = self.objectPropertyTypeByName(source_t, key_name) orelse types.Primitive.any;
                    }
                    if (prop_t == types.Primitive.any or prop_t == types.Primitive.unknown or prop_t == types.Primitive.none) continue;
                    switch (self.hir.kindOf(p.name)) {
                        .identifier => if (hir_mod.identifierOf(self.hir, p.name).name == target_name) break :blk prop_t,
                        .array_pattern, .object_pattern => {
                            if (try self.typeOfPatternBindingFromSource(p.name, hir_mod.none_node_id, prop_t, target_name)) |bt| break :blk bt;
                        },
                        .assignment => {
                            const a = hir_mod.assignmentOf(self.hir, p.name);
                            if (try self.typeOfPatternBindingFromSource(a.target, hir_mod.none_node_id, prop_t, target_name)) |bt| break :blk bt;
                        },
                        else => {},
                    }
                }
                break :blk null;
            },
            .object_literal => blk: {
                for (hir_mod.objectLiteralProps(self.hir, pattern_node)) |prop_node| {
                    if (self.hir.kindOf(prop_node) != .object_property) continue;
                    const op = hir_mod.objectPropertyOf(self.hir, prop_node);
                    if (op.value == hir_mod.none_node_id) continue;
                    var prop_t: TypeId = types.Primitive.any;
                    if (op.is_computed) {
                        prop_t = (try self.objectPropertyTypeForComputedKeyNode(source_t, op.key)) orelse types.Primitive.any;
                    } else if (self.propertyNameFromKeyNode(op.key)) |key_name| {
                        prop_t = self.objectPropertyTypeByName(source_t, key_name) orelse types.Primitive.any;
                    }
                    if (prop_t == types.Primitive.any or prop_t == types.Primitive.unknown or prop_t == types.Primitive.none) continue;
                    switch (self.hir.kindOf(op.value)) {
                        .identifier => if (hir_mod.identifierOf(self.hir, op.value).name == target_name) break :blk prop_t,
                        .array_literal, .object_literal, .array_pattern, .object_pattern => {
                            if (try self.typeOfPatternBindingFromSource(op.value, hir_mod.none_node_id, prop_t, target_name)) |bt| break :blk bt;
                        },
                        .assignment => {
                            const a = hir_mod.assignmentOf(self.hir, op.value);
                            if (try self.typeOfPatternBindingFromSource(a.target, hir_mod.none_node_id, prop_t, target_name)) |bt| break :blk bt;
                        },
                        else => {},
                    }
                }
                break :blk null;
            },
            .identifier => if (hir_mod.identifierOf(self.hir, pattern_node).name == target_name) source_t else null,
            .assignment => blk: {
                const a = hir_mod.assignmentOf(self.hir, pattern_node);
                break :blk try self.typeOfPatternBindingFromSource(a.target, source_node, source_t, target_name);
            },
            else => null,
        };
    }

    /// Resolve an identifier reference's type. Walks up the HIR
    /// parent chain looking for an enclosing function whose
    /// parameter list declares this name; then falls back to the
    /// binder's module-level scope. This is a Phase 3 simplification
    /// — proper lexical scoping per the binder's Scope graph lands
    /// in a follow-up; this covers the high-frequency patterns
    /// (function parameter use, top-level decl reference).
    fn typeOfIdentifier(self: *Checker, node: NodeId) TypeId {
        const id = hir_mod.identifierOf(self.hir, node);
        const name_str = self.string_interner.get(id.name);
        if (std.mem.eql(u8, name_str, "this") and
            self.sourceHasStrictFalseDirective() and
            self.thisInsideNonArrowPlainFunction(node))
        {
            return types.Primitive.any;
        }

        // Narrowed binding from an enclosing type-guard takes
        // precedence over the static type.
        if (self.lookupNarrow(id.name)) |t| return t;
        if (self.resolving_value_types.contains(id.name)) return types.Primitive.any;

        if (std.mem.eql(u8, name_str, "this")) {
            if (self.isDeclNameSlot(node) or self.nodeIsThisParameterName(node) or self.thisInsideDecoratorInitializerCallback(node)) return types.Primitive.any;
            if (self.nodeInsideAmbientVarInitializer(node)) return types.Primitive.any;
            if (self.nodeHasAncestorKind(node, .decorator)) return types.Primitive.any;
            if (self.thisInsideCheckJsConstructorFunction(node)) return types.Primitive.any;
            if (self.thisInsideCheckJsPrototypeAssignmentFunction(node)) return types.Primitive.any;
            if (self.thisInsideCheckJsFunctionWithThisTag(node)) return types.Primitive.any;
            if (self.thisInsideCheckJsCallbackWithThis(node)) return types.Primitive.any;
            // TS2331: `this` referenced directly inside a namespace
            // body (without an intervening function/class frame) is
            // illegal — mirrors upstream tsc for `thisTypeErrors.ts(36)`
            // (`namespace N1 { export var y = this; }`). Pairs with
            // the implicit-any TS2683 below.
            if (self.thisDirectlyInsideNamespaceBody(node)) {
                self.report(node, TsCodes.this_in_namespace_body, "'this' cannot be referenced in a module or namespace body.") catch {};
            }
            if (self.thisIsGlobalScriptThis(node)) return self.bareGlobalThisType() catch types.Primitive.any;
            if (!self.sourceHasStrictFalseDirective() and
                !self.identifierThisIsArrowCaptured(node) and
                !self.thisInsideObjectLiteralMethod(node))
            {
                self.report(node, TsCodes.this_implicitly_any, "'this' implicitly has type 'any' because it does not have a type annotation.") catch {};
            }
            return types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "new.target")) {
            return types.Primitive.any;
        }
        // `arguments` referenced from an arrow function (no enclosing
        // `function` body to bind it to) is invalid for ES5 — tsc
        // emits TS2496 explaining the down-emit can't synthesize an
        // `arguments` slot inside the resulting `function () { … }`.
        // This check has to run BEFORE the regular
        // `hasNonArrowFunctionAncestor` early-return: that helper
        // considers any non-arrow ancestor sufficient to bind
        // `arguments`, but tsc fires TS2496 whenever the *innermost*
        // enclosing function is an arrow regardless of what's above.
        if (std.mem.eql(u8, name_str, "arguments") and
            self.argumentsInsideArrowOnlyChain(node) and
            self.sourceTargetMentionsEs5() and
            !self.argumentsResolvesToLocalBinding(node, id.name))
        {
            const msg = self.diag_arena.allocator().dupe(u8, "The 'arguments' object cannot be referenced in an arrow function in ES5. Consider using a standard function expression.") catch return types.Primitive.any;
            self.diagnostics.append(self.gpa, .{
                .node = node,
                .code = TsCodes.arguments_in_arrow_es5,
                .message = msg,
            }) catch return types.Primitive.any;
            return types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "arguments") and self.hasNonArrowFunctionAncestor(node)) {
            return types.Primitive.any;
        }
        if (!self.isDeclNameSlot(node) and !self.nodeHasAncestorKind(node, .typeof_type) and !self.isComputedKeyInAmbientClassMember(node) and self.typeOnlyImportLocal(id.name, node)) {
            const msg = std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "'{s}' cannot be used as a value because it was imported using 'import type'.",
                .{name_str},
            ) catch return types.Primitive.any;
            self.diagnostics.append(self.gpa, .{
                .node = node,
                .code = TsCodes.type_only_import_used_as_value,
                .message = msg,
            }) catch return types.Primitive.any;
            return types.Primitive.any;
        }
        // Walk up the parent chain searching for parameters or
        // sibling let/const/var decls in scope.
        var cur: hir_mod.NodeId = self.hir.parentOf(node);
        var saw_namespace_scope = false;
        while (cur != hir_mod.none_node_id) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                // Walk parameters and check the same name.
                const params = hir_mod.fnParams(self.hir, cur);
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id) continue;
                    const pn_kind = self.hir.kindOf(pp.name);
                    if (pn_kind == .identifier) {
                        const pid = hir_mod.identifierOf(self.hir, pp.name);
                        if (pid.name == id.name) return self.hir.typeOf(p);
                    } else if (pn_kind == .object_pattern or pn_kind == .array_pattern) {
                        // Destructuring parameter binding. Walk the
                        // pattern's elements: each element is a
                        // `parameter` whose own `name` is the bound
                        // identifier. When it matches, resolve the
                        // property's type through the parameter's
                        // annotation (object: by key; array: by
                        // index) and strip `undefined` if a default
                        // expression is present.
                        if (self.typeOfPatternBinding(pp.name, self.hir.typeOf(p), id.name)) |bt| {
                            return bt;
                        }
                    }
                }
                // Don't continue past the function — outer scopes
                // would shadow but we still want module-level
                // fallback below.
            }
            if (k == .for_stmt) {
                const fr = hir_mod.forStmtOf(self.hir, cur);
                if (fr.init != hir_mod.none_node_id) {
                    const init_kind = self.hir.kindOf(fr.init);
                    if (init_kind == .var_decl or init_kind == .let_decl or init_kind == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, fr.init);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            if (vid.name == id.name) {
                                if (self.declared_identifier_lookup and v.type_annotation != hir_mod.none_node_id) {
                                    const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                                    self.hir.setType(fr.init, declared_t);
                                    self.hir.setType(v.name, declared_t);
                                    return declared_t;
                                }
                                const t = self.hir.typeOf(fr.init);
                                if (t != types.Primitive.none) return t;
                                if (v.type_annotation != hir_mod.none_node_id) {
                                    const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                                    self.hir.setType(fr.init, declared_t);
                                    self.hir.setType(v.name, declared_t);
                                    return declared_t;
                                }
                            }
                        } else if (v.name != hir_mod.none_node_id) {
                            const vk = self.hir.kindOf(v.name);
                            if (vk == .object_pattern or vk == .array_pattern) {
                                const container_t = if (self.hir.typeOf(fr.init) != types.Primitive.none)
                                    self.hir.typeOf(fr.init)
                                else
                                    types.Primitive.any;
                                if (self.typeOfPatternBinding(v.name, container_t, id.name)) |bt| {
                                    return bt;
                                }
                            }
                        }
                    }
                }
            }
            if (k == .block_stmt) {
                // Look for a sibling var_decl/let_decl/const_decl
                // before this node.
                const stmts = hir_mod.blockStmts(self.hir, cur);
                for (stmts) |s| {
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            if (vid.name == id.name) {
                                if (self.declared_identifier_lookup and v.type_annotation != hir_mod.none_node_id) {
                                    const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                                    self.hir.setType(s, declared_t);
                                    self.hir.setType(v.name, declared_t);
                                    return declared_t;
                                }
                                const t = self.hir.typeOf(s);
                                if (t != types.Primitive.none) return t;
                                if (v.type_annotation != hir_mod.none_node_id) {
                                    const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                                    self.hir.setType(s, declared_t);
                                    self.hir.setType(v.name, declared_t);
                                    return declared_t;
                                }
                            }
                        } else if (v.name != hir_mod.none_node_id) {
                            const vk = self.hir.kindOf(v.name);
                            if (vk == .object_pattern or vk == .array_pattern or vk == .object_literal or vk == .array_literal) {
                                const container_t = if (self.hir.typeOf(s) != types.Primitive.none)
                                    self.hir.typeOf(s)
                                else
                                    types.Primitive.any;
                                if (v.init != hir_mod.none_node_id) {
                                    if (self.typeOfPatternBindingFromSource(v.name, v.init, container_t, id.name) catch null) |bt| {
                                        return bt;
                                    }
                                }
                                if (self.typeOfPatternBinding(v.name, container_t, id.name)) |bt| {
                                    return bt;
                                }
                            }
                        }
                    } else if (sk == .fn_decl or sk == .fn_expr) {
                        const fp = hir_mod.fnDeclOf(self.hir, s);
                        if (fp.name != hir_mod.none_node_id and self.hir.kindOf(fp.name) == .identifier) {
                            const fid = hir_mod.identifierOf(self.hir, fp.name);
                            if (fid.name == id.name) {
                                if (self.overloadedFunctionValueType(id.name) catch null) |overload_t| return overload_t;
                                const t = self.hir.typeOf(s);
                                if (t != types.Primitive.none) return t;
                            }
                        }
                    } else if (sk == .class_decl or sk == .class_expr) {
                        const cp = hir_mod.classOf(self.hir, s);
                        if (cp.name != hir_mod.none_node_id and self.hir.kindOf(cp.name) == .identifier) {
                            const cid = hir_mod.identifierOf(self.hir, cp.name);
                            if (cid.name == id.name) {
                                if (self.class_static_types.get(id.name)) |static_t| return static_t;
                                const t = self.hir.typeOf(s);
                                if (t != types.Primitive.none) return t;
                            }
                        }
                    } else if (sk == .import_decl) {
                        if (self.importDeclBindsLocal(s, id.name)) {
                            if (self.moduleNamespaceTypeForLocalImport(id.name, node) catch null) |ns_t| return ns_t;
                            return types.Primitive.any;
                        }
                    }
                }
            }
            if (k == .namespace_decl) {
                saw_namespace_scope = true;
                const stmts = hir_mod.namespaceBody(self.hir, cur);
                for (stmts) |s| {
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            if (vid.name == id.name) {
                                if (self.declared_identifier_lookup and v.type_annotation != hir_mod.none_node_id) {
                                    const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                                    self.hir.setType(s, declared_t);
                                    self.hir.setType(v.name, declared_t);
                                    return declared_t;
                                }
                                const t = self.hir.typeOf(s);
                                if (t != types.Primitive.none) return t;
                                if (self.declared_identifier_lookup and v.type_annotation != hir_mod.none_node_id) {
                                    const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                                    self.hir.setType(s, declared_t);
                                    self.hir.setType(v.name, declared_t);
                                    return declared_t;
                                }
                            }
                        }
                    } else if (sk == .fn_decl or sk == .fn_expr) {
                        const fp = hir_mod.fnDeclOf(self.hir, s);
                        if (fp.name != hir_mod.none_node_id and self.hir.kindOf(fp.name) == .identifier) {
                            const fid = hir_mod.identifierOf(self.hir, fp.name);
                            if (fid.name == id.name) {
                                if (self.overloadedFunctionValueType(id.name) catch null) |overload_t| return overload_t;
                                const t = self.hir.typeOf(s);
                                if (t != types.Primitive.none) return t;
                            }
                        }
                    } else if (sk == .class_decl or sk == .class_expr) {
                        const cp = hir_mod.classOf(self.hir, s);
                        if (cp.name != hir_mod.none_node_id and self.hir.kindOf(cp.name) == .identifier) {
                            const cid = hir_mod.identifierOf(self.hir, cp.name);
                            if (cid.name == id.name) {
                                if (self.class_static_types.get(id.name)) |static_t| return static_t;
                                const t = self.hir.typeOf(s);
                                if (t != types.Primitive.none) return t;
                            }
                        }
                    } else if (sk == .import_decl) {
                        if (self.importDeclBindsLocal(s, id.name)) {
                            if (self.moduleNamespaceTypeForLocalImport(id.name, node) catch null) |ns_t| return ns_t;
                            return types.Primitive.any;
                        }
                    }
                }
            }
            if (k == .for_in_stmt or k == .for_of_stmt) {
                // The loop binding lives directly on the for node;
                // it isn't a sibling in any block. Match against
                // the binding's name slot if it's a let/const/var
                // form, or directly when it's a bare identifier
                // (the parser emits this for `for (let n of ...)`).
                const fr = hir_mod.forInOf(self.hir, cur);
                if (fr.target != hir_mod.none_node_id) {
                    const tk = self.hir.kindOf(fr.target);
                    if (tk == .var_decl or tk == .let_decl or tk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, fr.target);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            if (vid.name == id.name) {
                                const t = self.hir.typeOf(fr.target);
                                if (t != types.Primitive.none) return t;
                            }
                        }
                    } else if (tk == .identifier) {
                        const vid = hir_mod.identifierOf(self.hir, fr.target);
                        if (vid.name == id.name) {
                            if (!self.declared_identifier_lookup) {
                                const t = self.hir.typeOf(fr.target);
                                if (t != types.Primitive.none) return t;
                            }
                        }
                    } else if (tk == .object_pattern or tk == .array_pattern) {
                        const container_t = if (self.hir.typeOf(fr.target) != types.Primitive.none)
                            self.hir.typeOf(fr.target)
                        else
                            types.Primitive.any;
                        if (self.typeOfPatternBinding(fr.target, container_t, id.name)) |bt| {
                            return bt;
                        }
                    }
                }
            }
            if (k == .try_stmt) {
                const ts = hir_mod.tryOf(self.hir, cur);
                if (ts.catch_param != hir_mod.none_node_id) {
                    const ck = self.hir.kindOf(ts.catch_param);
                    if (ck == .identifier) {
                        const cid = hir_mod.identifierOf(self.hir, ts.catch_param);
                        if (cid.name == id.name) {
                            return if (self.strict_flags.use_unknown_in_catch_variables)
                                types.Primitive.unknown
                            else
                                types.Primitive.any;
                        }
                    } else if (ck == .object_pattern or ck == .array_pattern) {
                        if (self.typeOfPatternBinding(ts.catch_param, types.Primitive.any, id.name)) |bt| {
                            return bt;
                        }
                    }
                }
            }
            cur = self.hir.parentOf(cur);
        }

        if (saw_namespace_scope and !self.report_unresolved_in_namespace_scope) {
            if (!self.isDeclNameSlot(node) and self.namespaceScopeHasErrantModifierAssignmentTarget(node, id.name)) {
                self.reportCannotFindNamePlainOnce(node, id.name) catch {};
            }
            return types.Primitive.any;
        }

        if (self.moduleNamespaceTypeForLocalImport(id.name, node) catch null) |ns_t| return ns_t;
        if (self.virtualImportTypeForLocal(id.name, node) catch null) |import_t| return import_t;
        if (self.virtualDefaultImportTypeForLocal(id.name, node) catch null) |import_t| return import_t;
        if (self.globalAugmentedValueType(id.name, node) catch null) |global_t| return global_t;
        if (self.checkJsTopLevelThisExpandoName(id.name, node)) return types.Primitive.any;
        if (!self.isDeclNameSlot(node)) {
            if (self.overloadedFunctionValueType(id.name) catch null) |overload_t| return overload_t;
        }
        if (self.enumDeclForNameAt(id.name, node)) |decl| {
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none) return t;
            return types.Primitive.number_t;
        }
        if (!self.isDeclNameSlot(node) and self.sourceHasVarDeclarationText(id.name)) return types.Primitive.any;

        // Module-level fallback.
        if (self.module) |module| {
            if (!self.isDeclNameSlot(node) and self.moduleNameIsNamespaceOnlyValue(module, id.name)) {
                // `export = N;` where `N` is a namespace is the
                // CommonJS namespace-export form; tsc does not
                // flag it with TS2708 since the assignment targets
                // the module shape, not a runtime value slot.
                if (!self.identifierIsExportEqualsTarget(node)) {
                    std.debug.print("TS2708-fire node={} parent={} parent_kind={any}\n", .{ node, self.hir.parentOf(node), if (self.hir.parentOf(node) != hir_mod.none_node_id) self.hir.kindOf(self.hir.parentOf(node)) else .none });
                    self.reportNamespaceAsValue(node, id.name) catch {};
                }
                return types.Primitive.any;
            }
            if (module.root.lookup(id.name)) |sym| {
                if (sym.decls.items.len > 0) {
                    const decl = sym.decls.items[0];
                    if (self.hir.kindOf(decl) == .import_specifier) {
                        const parent = self.hir.parentOf(decl);
                        if (parent != hir_mod.none_node_id and self.hir.kindOf(parent) == .import_decl) {
                            const imp = hir_mod.importOf(self.hir, parent);
                            const spec_text = self.string_interner.get(imp.module);
                            const sp = hir_mod.importSpecifierOf(self.hir, decl);
                            if (self.virtualBareModuleExportType(parent, spec_text, sp.imported) catch null) |import_t| return import_t;
                        }
                    }
                    if (self.moduleNamespaceTypeForImportBinding(decl) catch null) |ns_t| return ns_t;
                    if (self.hir.kindOf(decl) == .class_decl or self.hir.kindOf(decl) == .class_expr) {
                        if (self.class_static_types.get(id.name)) |static_t| return static_t;
                    }
                    if (self.hir.kindOf(decl) == .fn_decl or self.hir.kindOf(decl) == .fn_expr) {
                        if (self.overloadedFunctionValueType(id.name) catch null) |overload_t| return overload_t;
                    }
                    const dk = self.hir.kindOf(decl);
                    if (dk == .var_decl or dk == .let_decl or dk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, decl);
                        if (self.declared_identifier_lookup and v.type_annotation != hir_mod.none_node_id) {
                            const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                            self.hir.setType(decl, declared_t);
                            if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, declared_t);
                            return declared_t;
                        }
                    }
                    const t = self.hir.typeOf(decl);
                    if (t != types.Primitive.none) return t;
                    if (dk == .var_decl or dk == .let_decl or dk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, decl);
                        if (v.type_annotation != hir_mod.none_node_id) {
                            const declared_t = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch types.Primitive.any;
                            self.hir.setType(decl, declared_t);
                            if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, declared_t);
                            return declared_t;
                        }
                    }
                }
                return types.Primitive.any;
            }
            // Module is bound and the name is unknown — emit TS2304
            // unless the identifier is a recognized built-in (e.g.
            // `console`, `undefined`, global constructors). Skip
            // declaration name slots to avoid flagging the very
            // identifier that introduces the name.
            if (!self.isDeclNameSlot(node) and self.isNodeCommonJsGlobalName(id.name)) {
                if (self.rootHasVarDeclarationNamed(node, id.name) or self.sourceHasVarDeclarationText(id.name)) return types.Primitive.any;
                if (self.moduleHasRuntimeNamespacePrefix(module, id.name)) return types.Primitive.any;
                if (self.identifierNamesEnclosingClassExpression(node, id.name)) return types.Primitive.any;
                // In JS-like source files (`.js` / `.jsx` / `.mjs` /
                // `.cjs`) `module` / `require` are part of the implicit
                // CommonJS environment under tsc's `--allowJs` policy
                // and never surface TS2591. Suppress here to mirror
                // upstream baselines (`bug27342.js`, `mod1.js`,
                // `cls.js`, etc. across the 3000-4000 slice).
                if (self.virtualSectionIsJsLike(node)) return types.Primitive.any;
                self.reportCannotFindNodeName(node, id.name) catch {};
                return types.Primitive.any;
            }
            if (!self.isDeclNameSlot(node) and self.isBunRuntimeGlobalName(id.name)) {
                if (self.rootHasVarDeclarationNamed(node, id.name) or self.sourceHasVarDeclarationText(id.name)) return types.Primitive.any;
                if (self.moduleHasRuntimeNamespacePrefix(module, id.name)) return types.Primitive.any;
                if (self.identifierNamesEnclosingClassExpression(node, id.name)) return types.Primitive.any;
                if (self.virtualSectionIsJsLike(node)) return types.Primitive.any;
                self.reportCannotFindBunName(node, id.name) catch {};
                return types.Primitive.any;
            }
            if (!self.isDeclNameSlot(node) and !self.isBuiltinName(id.name)) {
                if (self.rootHasVarDeclarationNamed(node, id.name) or self.sourceHasVarDeclarationText(id.name)) return types.Primitive.any;
                if (self.moduleHasRuntimeNamespacePrefix(module, id.name)) return types.Primitive.any;
                if (self.identifierNamesEnclosingClassExpression(node, id.name)) return types.Primitive.any;
                self.reportCannotFindName(node, id.name) catch {};
            }
        }
        // Lib globals — `Object` carries the keys/values/entries/
        // assign namespace. `NaN` / `Infinity` are number-typed values.
        // `isNaN` / `isFinite` / `parseFloat` / `parseInt` get loose
        // signatures so call sites typecheck (e.g. `const b: boolean =
        // isNaN(1);`). Other globals fall through to `any` for now
        // (full lib.d.ts wiring is a follow-up).
        if (std.mem.eql(u8, name_str, "Object")) {
            if (lib.objectGlobal(&self.lib_cache, self.interner, self.string_interner)) |og| {
                return og;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "Array")) {
            if (lib.arrayGlobal(&self.lib_cache, self.interner, self.string_interner)) |ag| {
                return ag;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "Math")) {
            if (lib.mathGlobal(&self.lib_cache, self.interner, self.string_interner, self.gpa, &self.rest_signatures)) |mg| {
                return mg;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "console")) {
            if (lib.consoleGlobal(&self.lib_cache, self.interner, self.string_interner, self.gpa, &self.rest_signatures)) |cg| {
                return cg;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "Number")) {
            if (lib.numberGlobal(&self.lib_cache, self.interner, self.string_interner)) |ng| {
                return ng;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "RegExp")) {
            const regexp_t = self.lowerBuiltinObjectType("RegExp") orelse types.Primitive.any;
            const escape_sig = self.interner.internSignature(&[_]TypeId{types.Primitive.string_t}, types.Primitive.string_t, false) catch
                return types.Primitive.any;
            const construct_sig = self.interner.internSignature(&[_]TypeId{ types.Primitive.any, types.Primitive.string_t }, regexp_t, true) catch
                return types.Primitive.any;
            self.recordSignatureMinArgs(construct_sig, &.{ true, true }) catch return types.Primitive.any;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("escape") catch return types.Primitive.any,
                    .type = escape_sig,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("__construct") catch return types.Primitive.any,
                    .type = construct_sig,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "Symbol")) {
            return self.symbolGlobalType() catch types.Primitive.any;
        }
        // Conservative seeded shapes for common JS/Node/DOM globals.
        // Each helper returns an object type whose members are typed
        // loosely (any-typed args/returns) — the goal is to suppress
        // spurious TS2339 ("Property does not exist on type") emits
        // when fixtures touch members like `Promise.resolve`,
        // `JSON.stringify`, `Reflect.get`, `e.message`, etc.
        // `Map` / `Set` / `WeakMap` / `WeakSet` are intentionally
        // NOT routed here — checker tests exercise `new Map([…])`
        // element-type inference whose semantics assume the bare
        // identifier falls through to `any`.
        if (std.mem.eql(u8, name_str, "JSON")) {
            return self.jsonGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "Promise")) {
            return self.promiseGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "Reflect")) {
            return self.reflectGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "Proxy")) {
            return self.proxyGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "Error") or
            std.mem.eql(u8, name_str, "TypeError") or
            std.mem.eql(u8, name_str, "RangeError") or
            std.mem.eql(u8, name_str, "SyntaxError") or
            std.mem.eql(u8, name_str, "ReferenceError") or
            std.mem.eql(u8, name_str, "EvalError") or
            std.mem.eql(u8, name_str, "URIError"))
        {
            return self.errorConstructorGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "process")) {
            return self.processGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "window")) {
            return self.windowGlobalType() catch types.Primitive.any;
        }
        if (std.mem.eql(u8, name_str, "NaN") or std.mem.eql(u8, name_str, "Infinity")) {
            return types.Primitive.number_t;
        }
        if (std.mem.eql(u8, name_str, "undefined")) {
            return types.Primitive.undefined_t;
        }
        if (std.mem.eql(u8, name_str, "isNaN") or std.mem.eql(u8, name_str, "isFinite")) {
            // `(n: number): boolean`
            if (self.interner.internSignature(
                &[_]types.TypeId{types.Primitive.number_t},
                types.Primitive.boolean_t,
                false,
            )) |sig| {
                return sig;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "parseFloat")) {
            // `(s: string): number`
            if (self.interner.internSignature(
                &[_]types.TypeId{types.Primitive.string_t},
                types.Primitive.number_t,
                false,
            )) |sig| {
                return sig;
            } else |_| {}
        }
        if (std.mem.eql(u8, name_str, "parseInt")) {
            // `(s: string, radix?: number): number` — modeled as
            // `(s: string): number`; arity check accepts >= required.
            if (self.interner.internSignature(
                &[_]types.TypeId{types.Primitive.string_t},
                types.Primitive.number_t,
                false,
            )) |sig| {
                return sig;
            } else |_| {}
        }
        if (self.module == null and !self.isDeclNameSlot(node) and self.isNodeCommonJsGlobalName(id.name)) {
            // Mirror the bound-module path: `.js` / `.jsx` / `.mjs` /
            // `.cjs` source files don't surface TS2591 for `module` /
            // `require` (implicit CommonJS environment under
            // `--allowJs`).
            if (self.virtualSectionIsJsLike(node)) return types.Primitive.any;
            if (!self.identifierNamesEnclosingClassExpression(node, id.name)) {
                self.reportCannotFindNodeName(node, id.name) catch {};
            }
            return types.Primitive.any;
        }
        if (self.module == null and !self.isDeclNameSlot(node) and self.isBunRuntimeGlobalName(id.name)) {
            if (self.virtualSectionIsJsLike(node)) return types.Primitive.any;
            if (!self.identifierNamesEnclosingClassExpression(node, id.name)) {
                self.reportCannotFindBunName(node, id.name) catch {};
            }
            return types.Primitive.any;
        }
        if (self.module == null and !self.isDeclNameSlot(node) and !self.isBuiltinName(id.name)) {
            if (!self.identifierNamesEnclosingClassExpression(node, id.name)) {
                self.reportCannotFindName(node, id.name) catch {};
            }
        }
        return types.Primitive.any;
    }

    fn identifierNamesEnclosingClassExpression(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .class_decl and k != .class_expr) continue;
            const c = hir_mod.classOf(self.hir, cur);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, c.name).name == name) return true;
        }
        return false;
    }

    fn checkJsTopLevelThisExpandoName(self: *Checker, name: hir_mod.StringId, node: NodeId) bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        if (self.isDeclNameSlot(node)) return false;
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.topLevelThisAssignmentName(stmt)) |assigned| {
                if (assigned == name) return true;
            }
        }
        return false;
    }

    fn topLevelThisAssignmentName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        const local = self.unwrapExportDecl(node);
        if (local == hir_mod.none_node_id or self.hir.kindOf(local) != .assignment) return null;
        const a = hir_mod.assignmentOf(self.hir, local);
        if (a.target == hir_mod.none_node_id or self.hir.kindOf(a.target) != .member_access) return null;
        const m = hir_mod.memberOf(self.hir, a.target);
        if (m.object == hir_mod.none_node_id or self.hir.kindOf(m.object) != .identifier) return null;
        const obj = hir_mod.identifierOf(self.hir, m.object);
        if (!std.mem.eql(u8, self.string_interner.get(obj.name), "this")) return null;
        return m.name;
    }

    fn moduleNameIsNamespaceOnlyValue(
        self: *Checker,
        module: *const binder_mod.Module,
        name: hir_mod.StringId,
    ) bool {
        _ = module.root.namespaces.get(name) orelse return false;
        const value_sym = module.root.values.get(name) orelse return true;
        for (value_sym.decls.items) |decl| {
            if (self.hir.kindOf(decl) != .namespace_decl) return false;
            if (self.namespaceHasRuntimeValue(decl)) return false;
        }
        return true;
    }

    fn moduleHasRuntimeNamespacePrefix(
        self: *Checker,
        module: *const binder_mod.Module,
        name: hir_mod.StringId,
    ) bool {
        const prefix = self.string_interner.get(name);
        var it = module.root.namespaces.iterator();
        while (it.next()) |entry| {
            const ns_name = self.string_interner.get(entry.key_ptr.*);
            if (ns_name.len <= prefix.len) continue;
            if (!std.mem.startsWith(u8, ns_name, prefix)) continue;
            if (ns_name[prefix.len] != '.') continue;
            const sym = entry.value_ptr.*;
            for (sym.decls.items) |decl| {
                if (self.namespaceHasRuntimeValue(decl)) return true;
            }
        }
        return false;
    }

    fn namespaceHasRuntimeValue(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) return false;
        if (self.declarationSourceHasLeadingDeclare(node) or self.virtualSectionIsDeclarationFile(node)) return true;
        for (hir_mod.namespaceBody(self.hir, node)) |raw| {
            const s = self.unwrapExportDecl(raw);
            switch (self.hir.kindOf(s)) {
                .var_decl,
                .let_decl,
                .const_decl,
                .fn_decl,
                .fn_expr,
                .class_decl,
                .class_expr,
                .enum_decl,
                => return true,
                .block_stmt => return true,
                .namespace_decl => if (self.namespaceHasRuntimeValue(s)) return true,
                else => {},
            }
        }
        return false;
    }

    fn reportNamespaceAsValue(
        self: *Checker,
        node: NodeId,
        name: hir_mod.StringId,
    ) !void {
        const name_str = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot use namespace '{s}' as a value.",
            .{name_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.namespace_as_value,
            .message = msg,
        });
    }

    /// True when `node` is the target identifier of an
    /// `export = <ident>;` statement. The parser models export
    /// assignment as an `export_decl` whose `decl` slot points
    /// directly at the assigned expression (no `from` module,
    /// no named specifiers). Used to suppress TS2708 — a CJS
    /// namespace export is allowed even when the named binding
    /// has no runtime value.
    fn identifierIsExportEqualsTarget(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(parent) != .export_decl) return false;
        const ex = hir_mod.exportOf(self.hir, parent);
        if (ex.decl != node) return false;
        if (ex.named_len != 0) return false;
        if (ex.is_default) return false;
        const module_str = self.string_interner.get(ex.module);
        return module_str.len == 0;
    }

    /// Does this name refer to a class declaration with one or more
    /// type parameters in the current source? Used by the `new C<...>()`
    /// validity check to short-circuit TS2347 when the class is generic
    /// but its constructor sig hasn't been recorded (the class member
    /// pass and call-expr pass aren't ordered, and a class without an
    /// explicit constructor never lands in `class_constructor_sigs`).
    fn classNameRefersToGenericDecl(self: *Checker, name: hir_mod.StringId, ctx_node: NodeId) bool {
        const root = self.rootBlockFor(ctx_node);
        if (self.hir.kindOf(root) != .block_stmt) return false;
        const stmts = hir_mod.blockStmts(self.hir, root);
        for (stmts) |s| {
            const k = self.hir.kindOf(s);
            const decl = if (k == .class_decl) s else blk: {
                if (k != .export_decl) break :blk hir_mod.none_node_id;
                const ex = hir_mod.exportOf(self.hir, s);
                if (ex.decl == hir_mod.none_node_id) break :blk hir_mod.none_node_id;
                if (self.hir.kindOf(ex.decl) != .class_decl) break :blk hir_mod.none_node_id;
                break :blk ex.decl;
            };
            if (decl == hir_mod.none_node_id) continue;
            const c = hir_mod.classOf(self.hir, decl);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, c.name).name != name) continue;
            if (c.type_params_len > 0) return true;
        }
        return false;
    }

    /// Recognize a small set of common globals that should not
    /// trigger TS2304 even though we don't have a real lib.d.ts
    /// loaded yet. The list intentionally errs on the conservative
    /// side; expand as more globals are encountered.
    fn isBuiltinName(self: *const Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.get(name);
        const builtins = [_][]const u8{
            // Core globals / values.
            "console",              "undefined",        "NaN",
            "Infinity",             "globalThis",       "this",
            "new.target",           "window",           "document",
            "Element",              "Node",             "HTMLElement",
            "HTMLBodyElement",      "HTMLDivElement",   "HTMLAnchorElement",
            "HTMLImageElement",     "HTMLInputElement", "HTMLSpanElement",
            "HTMLButtonElement",    "HTMLFormElement",  "Event",
            "EventTarget",          "MouseEvent",       "KeyboardEvent",
            "FocusEvent",           "Document",         "Window",
            "Location",             "Navigator",        "History",
            "Storage",              "URL",              "URLSearchParams",
            "Blob",                 "File",             "FileReader",
            "FormData",             "Headers",          "Request",
            "Response",
            // Constructors / namespaces.
                        "Math",             "JSON",
            "Object",               "Array",            "String",
            "Number",               "Boolean",          "Symbol",
            "BigInt",               "Error",            "TypeError",
            "RangeError",           "SyntaxError",      "Promise",
            "Map",                  "Set",              "WeakMap",
            "WeakSet",              "Date",             "RegExp",
            "Function",             "Proxy",            "Reflect",
            "TemplateStringsArray", "ArrayBuffer",      "Uint8Array",
            "Uint8ClampedArray",    "Int8Array",        "Uint16Array",
            "Int16Array",           "Uint32Array",      "Int32Array",
            "Float16Array",         "Float32Array",     "Float64Array",
            "BigUint64Array",       "BigInt64Array",    "SharedArrayBuffer",
            "Atomics",              "Intl",
            // Global functions.
                        "parseInt",
            "parseFloat",           "isNaN",            "isFinite",
            "encodeURI",            "decodeURI",        "encodeURIComponent",
            "decodeURIComponent",
            // Timers / scheduling.
              "setTimeout",       "clearTimeout",
            "setInterval",          "clearInterval",    "setImmediate",
            "clearImmediate",       "queueMicrotask",
            // Node.js / CommonJS.
              "process",
            "Buffer",               "require",          "module",
            "exports",              "__dirname",        "__filename",
            // Dynamic `import("…")` parses the keyword as an
            // identifier callee — exempt it from TS2304.
            "import",
            // Common ambient names emitted by the parser for
            // module / class shapes that don't have full
            // resolution wired up yet.
                          "super",
        };
        for (builtins) |b| {
            if (std.mem.eql(u8, s, b)) return true;
        }
        return false;
    }

    fn isNodeCommonJsGlobalName(self: *const Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.get(name);
        const names = [_][]const u8{
            "module",
            "require",
        };
        for (names) |n| {
            if (std.mem.eql(u8, s, n)) return true;
        }
        return false;
    }

    fn hasNonArrowFunctionAncestor(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const f = hir_mod.fnDeclOf(self.hir, cur);
            if (!f.flags.is_arrow) return true;
        }
        return false;
    }

    /// True when the nearest enclosing function-like ancestor of
    /// `node` is an arrow function (i.e. `arguments` here would
    /// resolve through the lexical chain instead of binding to a
    /// local `arguments` slot). Used to gate TS2496 (`arguments` in
    /// arrow function in ES5): tsc rejects every `arguments`
    /// reference whose innermost containing function is an arrow,
    /// regardless of whether further out there's a real function —
    /// the down-emit can't synthesize an `arguments` slot inside the
    /// resulting `function () { … }`. Top-level `() => arguments`
    /// also matches: `cur` is `none_node_id` after the arrow, so the
    /// `saw_arrow` flag still answers "yes, I was inside an arrow".
    fn argumentsInsideArrowOnlyChain(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const f = hir_mod.fnDeclOf(self.hir, cur);
            return f.flags.is_arrow;
        }
        return false;
    }

    /// True when the identifier reference (e.g. `arguments`) resolves
    /// to a parameter of the *immediate* enclosing function/arrow,
    /// rather than the runtime `arguments` object. Used to suppress
    /// TS2496 only for `(arguments) => arguments` where the inner
    /// reference shadows the slot directly via its own arrow's
    /// parameter list. A reference one level out (e.g.
    /// `(arguments) => () => arguments` — fixture 07) must still emit
    /// TS2496 because the inner arrow has no `arguments` parameter
    /// and the down-emit cannot synthesize a slot for it. Mirrors
    /// `emitArrowFunctionWhenUsingArguments08` (suppress) vs
    /// `…07` (emit).
    fn argumentsResolvesToLocalBinding(self: *Checker, node: NodeId, name_id: hir_mod.StringId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const params = hir_mod.fnParams(self.hir, cur);
            for (params) |p| {
                if (self.hir.kindOf(p) != .parameter) continue;
                const pp = hir_mod.parameterOf(self.hir, p);
                if (pp.name == hir_mod.none_node_id) continue;
                if (self.hir.kindOf(pp.name) != .identifier) continue;
                const pid = hir_mod.identifierOf(self.hir, pp.name);
                if (pid.name == name_id) return true;
            }
            // Only inspect the innermost enclosing function — references
            // that escape it via the lexical chain still want TS2496
            // when the surrounding ES5 emit can't synthesize a slot.
            return false;
        }
        return false;
    }

    const MapEntryTypes = struct {
        key: TypeId,
        value: TypeId,
        invalid_mixed_value_entries: bool = false,
    };

    fn inferMapEntryTypes(self: *Checker, args: []const NodeId) CheckError!MapEntryTypes {
        if (args.len == 0 or self.hir.kindOf(args[0]) != .array_literal) {
            return .{ .key = types.Primitive.any, .value = types.Primitive.any };
        }
        var key_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer key_types.deinit(self.gpa);
        var value_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer value_types.deinit(self.gpa);
        var first_value_t: TypeId = types.Primitive.none;
        var invalid_mixed_value_entries = false;
        for (hir_mod.arrayLiteralElements(self.hir, args[0])) |entry_node| {
            if (entry_node == hir_mod.none_node_id or self.hir.kindOf(entry_node) != .array_literal) continue;
            const entry_elems = hir_mod.arrayLiteralElements(self.hir, entry_node);
            if (entry_elems.len < 2) continue;
            try key_types.append(self.gpa, try self.checkExpression(entry_elems[0]));
            const value_t = try self.checkExpression(entry_elems[1]);
            try value_types.append(self.gpa, value_t);
            if (first_value_t == types.Primitive.none) {
                first_value_t = value_t;
            } else if (!(self.engine.isAssignableTo(value_t, first_value_t) catch true)) {
                invalid_mixed_value_entries = true;
            }
        }
        return .{
            .key = try self.unionOrAny(key_types.items),
            .value = try self.unionOrAny(value_types.items),
            .invalid_mixed_value_entries = invalid_mixed_value_entries,
        };
    }

    fn unionOrAny(self: *Checker, items: []const TypeId) CheckError!TypeId {
        if (items.len == 0) return types.Primitive.any;
        if (items.len == 1) return items[0];
        return self.interner.internUnion(items) catch return error.OutOfMemory;
    }

    fn symbolGlobalType(self: *Checker) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        const include_declared_augmentations = !self.symbol_global_building;
        if (include_declared_augmentations) self.symbol_global_building = true;
        defer if (include_declared_augmentations) {
            self.symbol_global_building = false;
        };

        const empty_params = [_]types.TypeId{};
        const symbol_ctor = self.interner.internSignature(&empty_params, types.Primitive.symbol_t, false) catch return error.OutOfMemory;
