    fn appendDeclaredInterfaceMembers(
        self: *Checker,
        members: *std.ArrayListUnmanaged(types.ObjectMember),
        name: []const u8,
    ) CheckError!void {
        const module = self.module orelse return;
        const name_id = self.string_interner.intern(name) catch return error.OutOfMemory;
        const sym = module.root.types.get(name_id) orelse return;
        for (sym.decls.items) |decl| {
            if (self.hir.kindOf(decl) != .interface_decl) continue;
            var iface_t = self.hir.typeOf(decl);
            if (iface_t == types.Primitive.none or iface_t == types.Primitive.unknown) {
                try self.checkInterfaceDecl(decl);
                iface_t = self.hir.typeOf(decl);
            }
            if (iface_t == types.Primitive.none or iface_t == types.Primitive.unknown) continue;
            for (self.interner.objectMembers(iface_t)) |member| {
                if (objectMemberListContains(members.items, member.name)) continue;
                try members.append(self.gpa, member);
            }
        }
    }

    fn objectMemberListContains(members: []const types.ObjectMember, name: hir_mod.StringId) bool {
        for (members) |member| {
            if (member.name == name) return true;
        }
        return false;
    }

    fn memberNameIsEcmaPrivate(self: *Checker, name: hir_mod.StringId) bool {
        return std.mem.startsWith(u8, self.string_interner.get(name), "#");
    }

    fn objectLiteralHasDuplicateMethodWithLiteralParam(
        self: *Checker,
        members: []const types.ObjectMember,
        name: hir_mod.StringId,
        value: NodeId,
    ) bool {
        var saw_method = false;
        for (members) |member| {
            if (member.name == name and member.is_method) {
                saw_method = true;
                break;
            }
        }
        return saw_method and self.fnLikeHasLiteralParameterType(value);
    }

    fn fnLikeHasLiteralParameterType(self: *Checker, value: NodeId) bool {
        return switch (self.hir.kindOf(value)) {
            .fn_decl, .fn_expr, .arrow_fn => blk: {
                const f = hir_mod.fnDeclOf(self.hir, value);
                for (self.hir.childSlice(f.params_start, @intCast(f.params_len))) |param| {
                    if (self.hir.kindOf(param) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, param);
                    if (self.typeNodeIsLiteralType(p.type_annotation)) break :blk true;
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn typeNodeIsLiteralType(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(node)) {
            .type_literal => true,
            .union_type => blk: {
                for (hir_mod.unionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeIsLiteralType(member)) break :blk true;
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn builtinMapInstanceType(self: *Checker, key_t: TypeId, value_t: TypeId) CheckError!TypeId {
        var entry_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer entry_members.deinit(self.gpa);
        const zero_id = self.string_interner.intern("0") catch return error.OutOfMemory;
        const one_id = self.string_interner.intern("1") catch return error.OutOfMemory;
        const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
        try entry_members.append(self.gpa, .{ .name = zero_id, .type = key_t, .is_optional = false, .is_readonly = false, .is_method = false });
        try entry_members.append(self.gpa, .{ .name = one_id, .type = value_t, .is_optional = false, .is_readonly = false, .is_method = false });
        const length_t = self.interner.internNumberLiteral(2) catch types.Primitive.number_t;
        try entry_members.append(self.gpa, .{ .name = length_id, .type = length_t, .is_optional = false, .is_readonly = true, .is_method = false });
        const entry_union = self.interner.internUnion(&.{ key_t, value_t }) catch types.Primitive.any;
        const entry_t = self.interner.internObjectTypeWithIndex(entry_members.items, types.Primitive.none, entry_union) catch return error.OutOfMemory;

        var map_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer map_members.deinit(self.gpa);
        const iterator_id = self.string_interner.intern("Symbol.iterator") catch return error.OutOfMemory;
        const values_id = self.string_interner.intern("values") catch return error.OutOfMemory;
        const keys_id = self.string_interner.intern("keys") catch return error.OutOfMemory;
        const entries_id = self.string_interner.intern("entries") catch return error.OutOfMemory;
        const value_iter_t = self.interner.internArrayType(self.string_interner, value_t) catch return error.OutOfMemory;
        const key_iter_t = self.interner.internArrayType(self.string_interner, key_t) catch return error.OutOfMemory;
        const entry_iter_t = self.interner.internArrayType(self.string_interner, entry_t) catch return error.OutOfMemory;
        const sig_values = self.interner.internSignature(&[_]TypeId{}, value_iter_t, false) catch return error.OutOfMemory;
        const sig_keys = self.interner.internSignature(&[_]TypeId{}, key_iter_t, false) catch return error.OutOfMemory;
        const sig_entries = self.interner.internSignature(&[_]TypeId{}, entry_iter_t, false) catch return error.OutOfMemory;
        try map_members.append(self.gpa, .{ .name = iterator_id, .type = sig_entries, .is_optional = false, .is_readonly = false, .is_method = true });
        try map_members.append(self.gpa, .{ .name = values_id, .type = sig_values, .is_optional = false, .is_readonly = false, .is_method = true });
        try map_members.append(self.gpa, .{ .name = keys_id, .type = sig_keys, .is_optional = false, .is_readonly = false, .is_method = true });
        try map_members.append(self.gpa, .{ .name = entries_id, .type = sig_entries, .is_optional = false, .is_readonly = false, .is_method = true });
        return self.interner.internObjectTypeWithIndex(map_members.items, types.Primitive.none, entry_t) catch return error.OutOfMemory;
    }

    fn builtinSetInstanceType(self: *Checker, value_t: TypeId) CheckError!TypeId {
        const entry_union = value_t;
        var entry_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer entry_members.deinit(self.gpa);
        const zero_id = self.string_interner.intern("0") catch return error.OutOfMemory;
        const one_id = self.string_interner.intern("1") catch return error.OutOfMemory;
        const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
        try entry_members.append(self.gpa, .{ .name = zero_id, .type = value_t, .is_optional = false, .is_readonly = false, .is_method = false });
        try entry_members.append(self.gpa, .{ .name = one_id, .type = value_t, .is_optional = false, .is_readonly = false, .is_method = false });
        const length_t = self.interner.internNumberLiteral(2) catch types.Primitive.number_t;
        try entry_members.append(self.gpa, .{ .name = length_id, .type = length_t, .is_optional = false, .is_readonly = true, .is_method = false });
        const entry_t = self.interner.internObjectTypeWithIndex(entry_members.items, types.Primitive.none, entry_union) catch return error.OutOfMemory;
        const value_iter_t = self.interner.internArrayType(self.string_interner, value_t) catch return error.OutOfMemory;
        const entry_iter_t = self.interner.internArrayType(self.string_interner, entry_t) catch return error.OutOfMemory;
        const sig_values = self.interner.internSignature(&[_]TypeId{}, value_iter_t, false) catch return error.OutOfMemory;
        const sig_entries = self.interner.internSignature(&[_]TypeId{}, entry_iter_t, false) catch return error.OutOfMemory;
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        try members.append(self.gpa, .{ .name = self.string_interner.intern("Symbol.iterator") catch return error.OutOfMemory, .type = sig_values, .is_optional = false, .is_readonly = false, .is_method = true });
        try members.append(self.gpa, .{ .name = self.string_interner.intern("values") catch return error.OutOfMemory, .type = sig_values, .is_optional = false, .is_readonly = false, .is_method = true });
        try members.append(self.gpa, .{ .name = self.string_interner.intern("keys") catch return error.OutOfMemory, .type = sig_values, .is_optional = false, .is_readonly = false, .is_method = true });
        try members.append(self.gpa, .{ .name = self.string_interner.intern("entries") catch return error.OutOfMemory, .type = sig_entries, .is_optional = false, .is_readonly = false, .is_method = true });
        return self.interner.internObjectTypeWithIndex(members.items, types.Primitive.none, value_t) catch return error.OutOfMemory;
    }

    fn builtinWeakMapInstanceType(self: *Checker, key_t: TypeId, value_t: TypeId) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        const get_id = self.string_interner.intern("get") catch return error.OutOfMemory;
        const set_id = self.string_interner.intern("set") catch return error.OutOfMemory;
        const has_id = self.string_interner.intern("has") catch return error.OutOfMemory;
        const delete_id = self.string_interner.intern("delete") catch return error.OutOfMemory;
        const get_sig = self.interner.internSignature(&[_]TypeId{key_t}, value_t, false) catch return error.OutOfMemory;
        const set_sig = self.interner.internSignature(&[_]TypeId{ key_t, value_t }, types.Primitive.any, false) catch return error.OutOfMemory;
        const bool_sig = self.interner.internSignature(&[_]TypeId{key_t}, types.Primitive.boolean_t, false) catch return error.OutOfMemory;
        try members.append(self.gpa, .{ .name = get_id, .type = get_sig, .is_optional = false, .is_readonly = false, .is_method = true });
        try members.append(self.gpa, .{ .name = set_id, .type = set_sig, .is_optional = false, .is_readonly = false, .is_method = true });
        try members.append(self.gpa, .{ .name = has_id, .type = bool_sig, .is_optional = false, .is_readonly = false, .is_method = true });
        try members.append(self.gpa, .{ .name = delete_id, .type = bool_sig, .is_optional = false, .is_readonly = false, .is_method = true });
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn isBuiltinObjectConstructor(self: *const Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.get(name);
        const builtins = [_][]const u8{
            "Map",          "Set",         "WeakMap",      "WeakSet",
            "Date",         "RegExp",      "Error",        "TypeError",
            "RangeError",   "SyntaxError", "Float16Array", "Float32Array",
            "Float64Array",
        };
        for (builtins) |b| {
            if (std.mem.eql(u8, s, b)) return true;
        }
        return false;
    }

    fn reportCannotFindName(
        self: *Checker,
        node: NodeId,
        name: hir_mod.StringId,
    ) !void {
        const name_str = self.string_interner.get(name);
        if (std.mem.eql(u8, name_str, "$")) {
            try self.reportCannotFindJQueryName(node, name);
            return;
        }

        // Collect in-scope candidate names and find the closest one
        // by Levenshtein distance. We accept a suggestion only if the
        // distance is ≤ max(2, name.len/4) — matches tsc behavior of
        // suggesting only "obvious" typos.
        const Best = struct { name: []const u8 = "", dist: usize = std.math.maxInt(usize) };
        var best: Best = .{};

        // Skip spelling suggestions for qualified-name lookups
        // (`Z.foo`, `M2.Point`, …) — tsc routes those through
        // namespace resolution and never offers a "Did you mean
        // 'foo'?" hint that crosses the dot. Mirrors fixtures like
        // `typeofAnExportedType` and `typeofANonExportedType`.
        const skip_suggestions = std.mem.indexOfScalar(u8, name_str, '.') != null;

        const considerCandidate = struct {
            fn call(typo: []const u8, cand_str: []const u8, b: *Best) void {
                if (cand_str.len == 0) return;
                if (std.mem.eql(u8, cand_str, typo)) return;
                // Quick reject mirrors tsc's `getSpellingSuggestion`
                // length gate: `maximumLengthDifference = max(2,
                // floor(typo.len * 0.34))`. Any candidate whose length
                // differs by more than that cannot survive the
                // Levenshtein threshold either, so we skip it without
                // running the (more expensive) distance computation.
                const ll = if (cand_str.len > typo.len) cand_str.len - typo.len else typo.len - cand_str.len;
                const regexp_suffix_candidate = std.mem.eql(u8, cand_str, "RegExp") and
                    lowerAsciiIdentifierEndsWith(typo, "regexp");
                const max_len_diff: usize = @max(@as(usize, 2), (typo.len * 34) / 100);
                if (!regexp_suffix_candidate and ll > max_len_diff) return;
                // tsc's `getSpellingSuggestion` does case-insensitive
                // comparison so `$ERROR` → `Error` (parserS7.3_A1.1_T2)
                // and `mY_Var` → `my_var` are recognized. Mirror
                // that with an ASCII case-folded distance.
                const d = levenshteinIcase(typo, cand_str);
                if (d < b.dist) b.* = .{ .name = cand_str, .dist = d };
            }
        }.call;

        // Walk the HIR parent chain and collect parameter / local
        // decl names — mirrors the lookup in `typeOfIdentifier`.
        var cur: hir_mod.NodeId = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                const params = hir_mod.fnParams(self.hir, cur);
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id) continue;
                    if (self.hir.kindOf(pp.name) != .identifier) continue;
                    const pid = hir_mod.identifierOf(self.hir, pp.name);
                    considerCandidate(name_str, self.string_interner.get(pid.name), &best);
                }
            } else if (k == .block_stmt) {
                const stmts = hir_mod.blockStmts(self.hir, cur);
                for (stmts) |s| {
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            considerCandidate(name_str, self.string_interner.get(vid.name), &best);
                        }
                    } else if (sk == .fn_decl or sk == .fn_expr) {
                        const fp = hir_mod.fnDeclOf(self.hir, s);
                        if (fp.name != hir_mod.none_node_id and self.hir.kindOf(fp.name) == .identifier) {
                            const fid = hir_mod.identifierOf(self.hir, fp.name);
                            considerCandidate(name_str, self.string_interner.get(fid.name), &best);
                        }
                    }
                }
            }
            cur = self.hir.parentOf(cur);
        }

        // Module-level symbol names (value / type / namespace spaces).
        if (self.module) |module| {
            inline for (.{ "values", "types", "namespaces" }) |field_name| {
                var it = @field(module.root, field_name).iterator();
                while (it.next()) |entry| {
                    const cand_id = entry.key_ptr.*;
                    considerCandidate(name_str, self.string_interner.get(cand_id), &best);
                }
            }
        }

        // Built-in globals — without a real lib.d.ts loaded these
        // names aren't in `module.root`, but tsc's `Did you mean
        // '<x>'?` suggestion still walks them. Mirrors fixtures like
        // `parserS7.3_A1.1_T2` where `$ERROR` should suggest
        // `Error`.
        const builtin_suggestions = [_][]const u8{
            "console",     "undefined",     "NaN",          "Infinity",
            "globalThis",  "window",        "document",     "Element",
            "Math",        "JSON",          "Object",       "Array",
            "String",      "Number",        "Boolean",      "Symbol",
            "BigInt",      "Error",         "TypeError",    "RangeError",
            "SyntaxError", "Promise",       "Map",          "Set",
            "WeakMap",     "WeakSet",       "Date",         "RegExp",
            "Function",    "Proxy",         "Reflect",      "ArrayBuffer",
            "Uint8Array",  "Int8Array",     "Uint16Array",  "Int16Array",
            "Uint32Array", "Int32Array",    "Float32Array", "Float64Array",
            "parseInt",    "parseFloat",    "isNaN",        "isFinite",
            "encodeURI",   "decodeURI",     "setTimeout",   "clearTimeout",
            "setInterval", "clearInterval",
        };
        for (builtin_suggestions) |b| {
            considerCandidate(name_str, b, &best);
        }

        // Threshold mirrors tsc's `getSpellingSuggestion`:
        // `min(floor(name.length * 0.4), 4)`. For very short names
        // (1-2 chars) the threshold collapses to 0 / 1 so we suppress
        // suggestions like "Did you mean 'x'?" for `b` — matching
        // baselines such as objectTypesIdentityWithCallSignatures3
        // which expect bare TS2304 in that case.
        const threshold: usize = @min((name_str.len * 4) / 10, @as(usize, 4));
        const regexp_suffix_suggestion = !skip_suggestions and
            std.mem.eql(u8, best.name, "RegExp") and
            lowerAsciiIdentifierEndsWith(name_str, "regexp");
        const has_suggestion = !skip_suggestions and
            ((best.dist <= threshold and best.name.len > 0) or regexp_suffix_suggestion);
        const suggestion_name: []const u8 = if (regexp_suffix_suggestion) "RegExp" else best.name;

        const msg = if (has_suggestion)
            try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find name '{s}'. Did you mean '{s}'?",
                .{ name_str, suggestion_name },
            )
        else
            try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find name '{s}'.",
                .{name_str},
            );

        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = if (has_suggestion) TsCodes.cannot_find_name_did_you_mean else TsCodes.cannot_find_name,
            .message = msg,
        });
    }

    fn lowerAsciiIdentifierEndsWith(value: []const u8, suffix: []const u8) bool {
        if (suffix.len > value.len) return false;
        for (value) |c| {
            if (c < 'a' or c > 'z') return false;
        }
        return std.mem.eql(u8, value[value.len - suffix.len ..], suffix);
    }

    fn reportCannotFindNamePlain(self: *Checker, node: NodeId, name: hir_mod.StringId) !void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find name '{s}'.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_name,
            .message = msg,
        });
    }

    fn reportCannotFindNamePlainOnce(self: *Checker, node: NodeId, name: hir_mod.StringId) !void {
        for (self.diagnostics.items) |d| {
            if (d.node == node and d.code == TsCodes.cannot_find_name) return;
        }
        try self.reportCannotFindNamePlain(node, name);
    }

    fn reportCannotFindNameAtPosOnce(self: *Checker, node: NodeId, pos: u32, name: hir_mod.StringId) !void {
        for (self.diagnostics.items) |d| {
            if (d.code == TsCodes.cannot_find_name and d.pos != null and d.pos.? == pos) return;
        }
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find name '{s}'.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .pos = pos,
            .code = TsCodes.cannot_find_name,
            .message = msg,
        });
    }

    fn reportCannotFindNameOnce(self: *Checker, node: NodeId, name: hir_mod.StringId) !void {
        for (self.diagnostics.items) |d| {
            if (d.node != node) continue;
            if (d.code == TsCodes.cannot_find_name or d.code == TsCodes.cannot_find_name_did_you_mean) return;
        }
        try self.reportCannotFindName(node, name);
    }

    fn reportCannotFindNodeName(self: *Checker, node: NodeId, name: hir_mod.StringId) !void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find name '{s}'. Do you need to install type definitions for node? Try `npm i --save-dev @types/node` and then add 'node' to the types field in your tsconfig.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_node_name,
            .message = msg,
        });
    }

    fn reportCannotFindJQueryName(self: *Checker, node: NodeId, name: hir_mod.StringId) !void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find name '{s}'. Do you need to install type definitions for jQuery? Try `npm i --save-dev @types/jquery` and then add 'jquery' to the types field in your tsconfig.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_jquery_name,
            .message = msg,
        });
    }

    /// TS2868 — `Cannot find name 'Bun'. Do you need to install type
    /// definitions for Bun? Try `npm i --save-dev @types/bun`...`
    /// Mirrors the upstream Bun typings suggestion (fixtures
    /// `typingsSuggestionBun1` / `typingsSuggestionBun2`). The
    /// trigger is identical to the node-typings path — an unbound
    /// identifier whose name matches a known runtime global.
    fn reportCannotFindBunName(self: *Checker, node: NodeId, name: hir_mod.StringId) !void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find name '{s}'. Do you need to install type definitions for Bun? Try `npm i --save-dev @types/bun` and then add 'bun' to the types field in your tsconfig.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = 2868,
            .message = msg,
        });
    }

    fn isBunRuntimeGlobalName(self: *const Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.get(name);
        return std.mem.eql(u8, s, "Bun");
    }

    /// Classic two-row Levenshtein edit distance. Computes the
    /// minimum number of single-character insertions, deletions, or
    /// substitutions to transform `a` into `b`. O(|a|·|b|) time,
    /// O(min(|a|,|b|)) space. Used for "did you mean?" suggestions.
    fn levenshtein(a: []const u8, b: []const u8) usize {
        if (a.len == 0) return b.len;
        if (b.len == 0) return a.len;
        // Bound the DP arrays — identifier names rarely exceed 128
        // bytes; anything over the cap is treated as max-distance to
        // avoid heap allocation in the hot diagnostic path.
        const cap: usize = 128;
        if (a.len + 1 > cap or b.len + 1 > cap) return std.math.maxInt(usize);
        var prev: [cap]usize = undefined;
        var curr: [cap]usize = undefined;
        var j: usize = 0;
        while (j <= b.len) : (j += 1) prev[j] = j;
        var i: usize = 1;
        while (i <= a.len) : (i += 1) {
            curr[0] = i;
            var k: usize = 1;
            while (k <= b.len) : (k += 1) {
                const cost: usize = if (a[i - 1] == b[k - 1]) 0 else 1;
                const del = prev[k] + 1;
                const ins = curr[k - 1] + 1;
                const sub = prev[k - 1] + cost;
                var m = del;
                if (ins < m) m = ins;
                if (sub < m) m = sub;
                curr[k] = m;
            }
            std.mem.copyForwards(usize, prev[0 .. b.len + 1], curr[0 .. b.len + 1]);
        }
        return prev[b.len];
    }

    /// Case-insensitive (ASCII) Levenshtein. Mirrors the
    /// `equateStringsCaseInsensitive` flag tsc passes to its
    /// `getSpellingSuggestion` helper — substitutions that differ
    /// only in ASCII case cost 0, so `$ERROR` → `Error` measures
    /// distance 1 (the leading `$`), well within the threshold.
    fn levenshteinIcase(a: []const u8, b: []const u8) usize {
        if (a.len == 0) return b.len;
        if (b.len == 0) return a.len;
        const cap: usize = 128;
        if (a.len + 1 > cap or b.len + 1 > cap) return std.math.maxInt(usize);
        var prev: [cap]usize = undefined;
        var curr: [cap]usize = undefined;
        var j: usize = 0;
        while (j <= b.len) : (j += 1) prev[j] = j;
        var i: usize = 1;
        while (i <= a.len) : (i += 1) {
            curr[0] = i;
            var k: usize = 1;
            while (k <= b.len) : (k += 1) {
                const ai = std.ascii.toLower(a[i - 1]);
                const bk = std.ascii.toLower(b[k - 1]);
                const cost: usize = if (ai == bk) 0 else 1;
                const del = prev[k] + 1;
                const ins = curr[k - 1] + 1;
                const sub = prev[k - 1] + cost;
                var m = del;
                if (ins < m) m = ins;
                if (sub < m) m = sub;
                curr[k] = m;
            }
            std.mem.copyForwards(usize, prev[0 .. b.len + 1], curr[0 .. b.len + 1]);
        }
        return prev[b.len];
    }

    /// Returns true when the identifier reference resolves to a
    /// `const`-declared symbol at the source — used by TS2588 to
    /// flag assignment to a constant. Walks the same parent-chain
    /// as `typeOfIdentifier` but checks the *kind* of declaration
    /// rather than its type.
    fn identifierResolvesToConst(self: *Checker, node: NodeId) bool {
        const id = hir_mod.identifierOf(self.hir, node);
        var cur: hir_mod.NodeId = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) {
            const k = self.hir.kindOf(cur);
            // Parameter binding shadows outer const decls; if a
            // parameter with this name is in scope, it isn't const.
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                const params = hir_mod.fnParams(self.hir, cur);
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id) continue;
                    if (self.hir.kindOf(pp.name) != .identifier) continue;
                    const pid = hir_mod.identifierOf(self.hir, pp.name);
                    if (pid.name == id.name) return false;
                }
            }
            if (k == .block_stmt) {
                const stmts = hir_mod.blockStmts(self.hir, cur);
                for (stmts) |s| {
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            if (vid.name == id.name) return sk == .const_decl;
                        }
                    }
                }
            }
            cur = self.hir.parentOf(cur);
        }
        // Module-level fallback via the binder's symbol table.
        if (self.module) |module| {
            if (module.root.lookup(id.name)) |sym| {
                return sym.flags.is_const;
            }
        }
        return false;
    }

    /// True when `node` is an identifier whose name resolves to a
    /// `namespace`/`module` declaration AND has no value-side binding
    /// (e.g. `var M = …` redeclaring the namespace name). tsc fires
    /// TS2631 for `M = x;` only on namespace-only identifiers.
    fn identifierResolvesToNamespaceOnly(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        // Local shadow: a `var`/`let`/`const`/parameter with the same
        // name in scope means the identifier is a value, not the
        // namespace.
        var cur: hir_mod.NodeId = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                const params = hir_mod.fnParams(self.hir, cur);
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id) continue;
                    if (self.hir.kindOf(pp.name) != .identifier) continue;
                    const pid = hir_mod.identifierOf(self.hir, pp.name);
                    if (pid.name == id.name) return false;
                }
            }
            if (k == .block_stmt) {
                for (hir_mod.blockStmts(self.hir, cur)) |s| {
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                            const vid = hir_mod.identifierOf(self.hir, v.name);
                            if (vid.name == id.name) return false;
                        }
                    } else if (sk == .fn_decl) {
                        const fd = hir_mod.fnDeclOf(self.hir, s);
                        if (fd.name != hir_mod.none_node_id and self.hir.kindOf(fd.name) == .identifier) {
                            const fid = hir_mod.identifierOf(self.hir, fd.name);
                            if (fid.name == id.name) return false;
                        }
                    } else if (sk == .class_decl) {
                        const cd = hir_mod.classOf(self.hir, s);
                        if (cd.name != hir_mod.none_node_id and self.hir.kindOf(cd.name) == .identifier) {
                            const cid = hir_mod.identifierOf(self.hir, cd.name);
                            if (cid.name == id.name) return false;
                        }
                    }
                }
            }
            cur = self.hir.parentOf(cur);
        }
        // Module-level: a namespace decl exists, and there is no
        // value-binding shadow (var/let/const/fn/class with the same
        // name).
        const module = self.module orelse return false;
        if (module.root.namespaces.get(id.name) == null) return false;
        if (module.root.values.get(id.name)) |sym| {
            for (sym.decls.items) |decl| {
                const dk = self.hir.kindOf(decl);
                // namespace_decl entries are also recorded in `values`
                // when they have runtime members, so we must not bail
                // on those — only on real value-side declarations.
                if (dk == .namespace_decl or dk == .module_decl) continue;
                return false;
            }
        }
        return true;
    }

    /// Conservative gate for TS2367: return true only when both
    /// sides look like concrete primitives (string / number / boolean
    /// / bigint / symbol) or literals of those. Nullish equality
    /// probes are intentionally exempt: TS's comparable relation
    /// permits `x === null` / `x === undefined` style checks even
    /// when `x` is currently a non-nullish primitive under
    /// `strictNullChecks`. Skips unions, intersections, object
    /// types, type parameters, any/unknown/never, and other compound
    /// shapes — TS allows many of those comparisons even when they
    /// look unrelated, and our `isComparableTo` is too coarse to
    /// reproduce TS's `comparableRelation` exactly.
    fn shouldCheckNoOverlap(self: *Checker, a: TypeId, b: TypeId) bool {
        if (self.isNullishType(a) or self.isNullishType(b)) return false;
        return self.isConcretePrimitiveLike(a) and self.isConcretePrimitiveLike(b);
    }

    fn typesHaveComparableOverlap(self: *Checker, a: TypeId, b: TypeId) CheckError!bool {
        return self.typesHaveComparableOverlapLimit(a, b, 0);
    }

    fn typesHaveComparableOverlapLimit(self: *Checker, a: TypeId, b: TypeId, depth: u8) CheckError!bool {
        if (a == b) return true;
        if (depth > 32) return true;
        if (self.typeIsAnyLike(a) or self.typeIsAnyLike(b)) return true;
        if (self.isNullishType(a) or self.isNullishType(b)) return true;
        if (self.enumNumberLiteralOverlap(a, b)) |ok| return ok;
        if (self.enumNumberLiteralOverlap(b, a)) |ok| return ok;
        if (a >= self.interner.pool.typeCount() or b >= self.interner.pool.typeCount()) return true;

        const af = self.interner.pool.flagsOf(a);
        const bf = self.interner.pool.flagsOf(b);
        if (af.is_union) {
            for (self.interner.unionMembers(a)) |member| {
                if (try self.typesHaveComparableOverlapLimit(member, b, depth + 1)) return true;
            }
            return false;
        }
        if (bf.is_union) {
            for (self.interner.unionMembers(b)) |member| {
                if (try self.typesHaveComparableOverlapLimit(a, member, depth + 1)) return true;
            }
            return false;
        }
        if (af.is_intersection) {
            var saw_concrete = false;
            for (self.interner.intersectionMembers(a)) |member| {
                if (!self.isConcretePrimitiveLike(member)) continue;
                saw_concrete = true;
                if (!try self.typesHaveComparableOverlapLimit(member, b, depth + 1)) return false;
            }
            if (saw_concrete) return true;
            if (self.intersectionContainsObjectLike(a)) {
                return self.engine.isComparableTo(a, b) catch true;
            }
            for (self.interner.intersectionMembers(a)) |member| {
                if (try self.typesHaveComparableOverlapLimit(member, b, depth + 1)) return true;
            }
            return false;
        }
        if (bf.is_intersection) {
            var saw_concrete = false;
            for (self.interner.intersectionMembers(b)) |member| {
                if (!self.isConcretePrimitiveLike(member)) continue;
                saw_concrete = true;
                if (!try self.typesHaveComparableOverlapLimit(a, member, depth + 1)) return false;
            }
            if (saw_concrete) return true;
            if (self.intersectionContainsObjectLike(b)) {
                return self.engine.isComparableTo(a, b) catch true;
            }
            for (self.interner.intersectionMembers(b)) |member| {
                if (try self.typesHaveComparableOverlapLimit(a, member, depth + 1)) return true;
            }
            return false;
        }
        if (self.weakObjectPrimitiveMayOverlap(a, b) or self.weakObjectPrimitiveMayOverlap(b, a)) return true;
        if (self.objectPrimitiveHasNoOverlap(a, b) or self.objectPrimitiveHasNoOverlap(b, a)) return false;
        if (self.isConcretePrimitiveLike(a) and self.isConcretePrimitiveLike(b)) {
            return self.engine.isComparableTo(a, b) catch true;
        }
        if (af.is_object_type and bf.is_object_type) {
            if (try self.objectTypesHaveIndependentOverlap(a, b, depth + 1)) return true;
        }
        if (self.isObjectLikeType(a) or self.isObjectLikeType(b)) {
            return self.engine.isComparableTo(a, b) catch true;
        }
        // Two distinct type parameters with no relating constraint
        // have no provable overlap — tsc emits TS2367 for `t == u`
        // where T and U are sibling type parameters. Mirrors fixtures
        // like comparisonOperatorWithTypeParameter.ts.
        if (af.is_type_parameter and bf.is_type_parameter and a != b) {
            if (!self.typeParameterConstraintsRelate(a, b)) return false;
        }
        return true;
    }

    fn typeParameterConstraintsRelate(self: *Checker, a: TypeId, b: TypeId) bool {
        // Allow comparison when one parameter's constraint chain
        // reaches the other (e.g., `U extends T`), or when they share
        // a common ancestor constraint type.
        if (self.typeParameterConstraintReaches(a, b)) return true;
        if (self.typeParameterConstraintReaches(b, a)) return true;
        return false;
    }

    fn typeParameterConstraintReaches(self: *Checker, from: TypeId, target: TypeId) bool {
        var cur = from;
        var depth: u8 = 0;
        while (depth < 16) : (depth += 1) {
            const constraint = self.typeParameterConstraint(cur) orelse return false;
            if (constraint == target) return true;
            if (constraint == cur) return false;
            const cf = self.interner.pool.flagsOf(constraint);
            if (!cf.is_type_parameter) return false;
            cur = constraint;
        }
        return false;
    }

    fn enumNumberLiteralOverlap(self: *Checker, enum_t: TypeId, lit_t: TypeId) ?bool {
        const enum_name = self.enumNameFromNominal(enum_t) orelse return null;
        const value = self.numberLiteralValueFromType(lit_t) orelse return null;
        var it = self.enum_member_values.iterator();
        while (it.next()) |entry| {
            if (entry.key_ptr.obj_name == enum_name and entry.value_ptr.* == value) return true;
        }
        return false;
    }

    fn numberLiteralValueFromType(self: *Checker, t: TypeId) ?f64 {
        if (t >= self.interner.pool.typeCount()) return null;
        const f = self.interner.pool.flagsOf(t);
        if (!f.is_literal or !f.is_number) return null;
        return switch (self.interner.literalOf(t)) {
            .number_lit => |bits| @as(f64, @bitCast(bits)),
            else => null,
        };
    }

    fn objectPrimitiveHasNoOverlap(self: *Checker, maybe_obj: TypeId, maybe_prim: TypeId) bool {
        if (!self.isConcretePrimitiveLike(maybe_prim)) return false;
        return self.assertionObjectConstituentHasNoPrimitiveOverlap(maybe_obj, maybe_prim);
    }

    fn weakObjectPrimitiveMayOverlap(self: *Checker, maybe_obj: TypeId, maybe_prim: TypeId) bool {
        if (!self.isConcretePrimitiveLike(maybe_prim)) return false;
        return self.objectTypeIsWeak(maybe_obj);
    }

    fn isObjectLikeType(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        return f.is_object_type or f.is_signature or f.is_tuple;
    }

    fn objectTypeIsWeak(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (!f.is_object_type) return false;
        if (self.interner.objectStringIndex(t) != types.Primitive.none or
            self.interner.objectNumberIndex(t) != types.Primitive.none or
            self.interner.objectSymbolIndex(t) != types.Primitive.none)
        {
            return false;
        }
        for (self.interner.objectMembers(t)) |member| {
            if (!member.is_optional) return false;
        }
        return true;
    }

    fn objectTypesHaveIndependentOverlap(self: *Checker, a: TypeId, b: TypeId, depth: u8) CheckError!bool {
        var saw_common = false;
        for (self.interner.objectMembers(a)) |am| {
            const bm = self.interner.objectMemberInfo(b, am.name) orelse continue;
            saw_common = true;
            if (am.is_optional or bm.is_optional) continue;
            if (!try self.typesHaveComparableOverlapLimit(am.type, bm.type, depth + 1)) return false;
        }
        return saw_common or self.objectTypeIsWeak(a) or self.objectTypeIsWeak(b);
    }

    fn intersectionContainsObjectLike(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (!f.is_intersection) return false;
        for (self.interner.intersectionMembers(t)) |member| {
            if (self.isObjectLikeType(member)) return true;
        }
        return false;
    }

    fn templateTypesHaveNoOverlap(self: *Checker, a: TypeId, b: TypeId) bool {
        if (a >= self.interner.pool.typeCount() or b >= self.interner.pool.typeCount()) return false;
        const af = self.interner.pool.flagsOf(a);
        const bf = self.interner.pool.flagsOf(b);
        if (!af.is_template_literal or !bf.is_template_literal) return false;
        const a_texts = self.interner.templateLiteralTexts(a);
        const b_texts = self.interner.templateLiteralTexts(b);
        if (a_texts.len == 0 or b_texts.len == 0) return false;
        const a_prefix = self.string_interner.get(a_texts[0]);
        const b_prefix = self.string_interner.get(b_texts[0]);
        if (a_prefix.len > 0 and b_prefix.len > 0 and
            !std.mem.startsWith(u8, a_prefix, b_prefix) and
            !std.mem.startsWith(u8, b_prefix, a_prefix))
        {
            return true;
        }
        const a_suffix = self.string_interner.get(a_texts[a_texts.len - 1]);
        const b_suffix = self.string_interner.get(b_texts[b_texts.len - 1]);
        if (a_suffix.len > 0 and b_suffix.len > 0 and
            !std.mem.endsWith(u8, a_suffix, b_suffix) and
            !std.mem.endsWith(u8, b_suffix, a_suffix))
        {
            return true;
        }
        return false;
    }

    fn isNullishType(self: *Checker, t: TypeId) bool {
        const f = self.interner.pool.flagsOf(t);
        return f.is_null or f.is_undefined;
    }

    fn isConcretePrimitiveLike(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.any or
            t == types.Primitive.unknown or
            t == types.Primitive.never or
            t == types.Primitive.void_t)
        {
            return false;
        }
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union or f.is_intersection or
            f.is_object_type or f.is_object or
            f.is_signature or f.is_tuple or
            f.is_type_parameter or f.is_instantiation or
            f.is_conditional or f.is_mapped or
            f.is_indexed_access or f.is_keyof or
            f.is_typeof or f.is_infer or
            f.is_template_literal)
        {
            return false;
        }
        return f.is_string or f.is_number or f.is_boolean or
            f.is_bigint or f.is_symbol;
    }

    fn typeContainsSymbol(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_object_type or f.is_signature or f.is_tuple or f.is_type_parameter) return false;
        if (f.is_symbol) return true;
        if (!f.is_union) return false;
        for (self.interner.unionMembers(t)) |member| {
            if (self.typeContainsSymbol(member)) return true;
        }
        return false;
    }

    /// Mirrors tsc's `checkRightHandSideOfForOf` for `for-in`: the
    /// right-hand side must be `any`, an object type, or a type
    /// parameter (after stripping null/undefined). Returns true when
    /// the type is definitely invalid (a non-object primitive,
    /// enum-literal, void, or never), so the caller can fire TS2407.
    /// Conservative: returns false for unions/intersections whose
    /// members include any valid for-in source, and false for unknown
    /// constructions we can't classify (no over-firing).
    fn forInSourceIsInvalid(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.any or
            t == types.Primitive.unknown or
            t == types.Primitive.object_t or
            t == types.Primitive.null_t or
            t == types.Primitive.undefined_t)
        {
            // null/undefined alone would error TS2532 elsewhere; do
            // not double-fire TS2407 on them. `unknown` is permitted.
            return false;
        }
        if (t == types.Primitive.string_t or
            t == types.Primitive.number_t or
            t == types.Primitive.boolean_t or
            t == types.Primitive.bigint_t or
            t == types.Primitive.void_t or
            t == types.Primitive.never or
            t == types.Primitive.true_lit or
            t == types.Primitive.false_lit)
        {
            return true;
        }
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_object_type or f.is_signature or f.is_tuple or f.is_type_parameter) return false;
        if (f.is_intersection) {
            // An intersection is valid as long as ANY component is a
            // valid for-in source.
            for (self.interner.intersectionMembers(t)) |member| {
                if (!self.forInSourceIsInvalid(member)) return false;
            }
            return true;
        }
        if (f.is_union) {
            // A union is invalid only when EVERY member is invalid.
            for (self.interner.unionMembers(t)) |member| {
                if (!self.forInSourceIsInvalid(member)) return false;
            }
            return true;
        }
        if (f.is_keyof or f.is_indexed_access or f.is_conditional or
            f.is_typeof or f.is_infer or f.is_template_literal)
        {
            return false;
        }
        // Literals and enum-literals — invalid (cannot enumerate).
        return f.is_string or f.is_number or f.is_boolean or
            f.is_bigint or f.is_symbol;
    }

    fn computedPropertyKeyTypeIsValid(self: *Checker, t: TypeId) CheckError!bool {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!try self.computedPropertyKeyTypeIsValid(member)) return false;
            }
            return true;
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (try self.computedPropertyKeyTypeIsValid(member)) return true;
            }
            return false;
        }
        if (f.is_void) return true;
        if (f.is_string or f.is_number or f.is_symbol) return true;
        if (f.is_keyof) return true;
        if (f.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return try self.computedPropertyKeyTypeIsValid(constraint);
        }
        return false;
    }

    fn typeParameterConstraint(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_type_parameter) return null;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return null;
        const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
        if (tp.constraint == types.Primitive.none or tp.constraint == types.Primitive.unknown) return null;
        return tp.constraint;
    }

    /// TS2344: Type 'X' does not satisfy the constraint 'Y'.
    /// Conservative: only emit when both `arg_t` and the parameter's
    /// constraint render as simple, fully-resolved type names AND the
    /// arg is provably not assignable to the constraint. Skips
    /// any/unknown/never/error placeholders, free type-parameters,
    /// and generic instantiations whose body still contains a
    /// type parameter — those need full inference machinery to
    /// classify correctly.
    fn checkTypeArgSatisfiesConstraint(
        self: *Checker,
        arg_node: NodeId,
        param_t: TypeId,
        arg_t: TypeId,
    ) CheckError!void {
        if (arg_node == hir_mod.none_node_id) return;
        if (arg_t == types.Primitive.any or arg_t == types.Primitive.unknown or arg_t == types.Primitive.never) return;
        if (param_t >= self.interner.pool.typeCount()) return;
        if (!self.interner.pool.flagsOf(param_t).is_type_parameter) return;
        const constraint = self.typeParameterConstraint(param_t) orelse return;
        if (constraint == types.Primitive.any or constraint == types.Primitive.unknown) return;
        if (constraint == arg_t) return;
        if (self.containsFreeTypeParameter(constraint)) return;
        // Free type parameters as type-arguments (e.g. `infer U`,
        // a generic alias body referring to its own outer
        // parameters) need full inference machinery to classify;
        // upstream defers the constraint check until a concrete
        // instantiation appears. Skip to avoid spurious TS2344
        // noise on `inferTypesWithExtends1.ts(136)` and similar
        // conditional-type alias bodies.
        if (self.containsFreeTypeParameter(arg_t)) return;
        const arg_text = (try self.simpleDiagnosticTypeName(arg_t)) orelse return;
        const constraint_text = (try self.simpleDiagnosticTypeName(constraint)) orelse return;
        // Special-case the upstream wording for `extends object`:
        // null and undefined are excluded from the `object` type even
        // though they pass our default `isAssignableTo` heuristic.
        const constraint_is_object = constraint == types.Primitive.object_t;
        const arg_is_nullish = arg_t == types.Primitive.null_t or arg_t == types.Primitive.undefined_t;
        if (!constraint_is_object) {
            if (self.engine.isAssignableTo(arg_t, constraint) catch true) return;
        } else {
            if (!arg_is_nullish and (self.engine.isAssignableTo(arg_t, constraint) catch true)) return;
            if (arg_t == types.Primitive.object_t) return;
            if (arg_t < self.interner.pool.typeCount()) {
                const af = self.interner.pool.flagsOf(arg_t);
                if (af.is_object_type and !arg_is_nullish) return;
            }
            if (self.namedTypeForId(arg_t) != null and !arg_is_nullish and
                !(arg_t == types.Primitive.string_t or arg_t == types.Primitive.number_t or
                    arg_t == types.Primitive.boolean_t or arg_t == types.Primitive.bigint_t or
                    arg_t == types.Primitive.symbol_t))
            {
                return;
            }
        }
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Type '{s}' does not satisfy the constraint '{s}'.",
            .{ arg_text, constraint_text },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = arg_node,
            .code = TsCodes.type_does_not_satisfy_constraint,
            .message = msg,
        });
    }

    /// True when `source` and `target` are both type parameters with
    /// distinct ids and `source` does not transitively reach `target`
    /// through its constraint chain — the upstream
    /// `typeParameterAssignability.ts` shape that should surface
    /// TS2322 instead of relying on the relation engine's permissive
    /// inference-slot acceptance.
    fn unrelatedTypeParameterAssignment(self: *Checker, source: TypeId, target: TypeId) bool {
        if (source == target) return false;
        if (source >= self.interner.pool.typeCount() or target >= self.interner.pool.typeCount()) return false;
        const sf = self.interner.pool.flagsOf(source);
        const tf = self.interner.pool.flagsOf(target);
        if (!sf.is_type_parameter or !tf.is_type_parameter) return false;
        var cur: TypeId = source;
        var hops: u32 = 0;
        while (hops < 16) : (hops += 1) {
            const c = self.typeParameterConstraint(cur) orelse return true;
            if (c == target) return false;
            if (c == cur) return true;
            const cf = self.interner.pool.flagsOf(c);
            if (!cf.is_type_parameter) return true;
            cur = c;
        }
        return true;
    }

    fn parameterDefaultInvalid(self: *Checker, source: TypeId, target: TypeId) bool {
        if (source == target) return false;
        if (target >= self.interner.pool.typeCount()) return false;
        const tf = self.interner.pool.flagsOf(target);
        if (!tf.is_type_parameter) return false;
        if (source < self.interner.pool.typeCount() and self.interner.pool.flagsOf(source).is_type_parameter) {
            return self.unrelatedTypeParameterAssignment(source, target);
        }
        return true;
    }

    fn typeParameterConstraintAssignableTo(self: *Checker, t: TypeId, target: TypeId) bool {
        const constraint = self.typeParameterConstraint(t) orelse return false;
        if (constraint == t) return false;
        return constraint == target or (self.engine.isAssignableTo(constraint, target) catch false);
    }

    fn computedClassPropertyKeyIsSimpleLiteral(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        return f.is_literal and (f.is_string or f.is_number);
    }

    fn computedKeyIsUnresolvedIdentifier(self: *Checker, key: NodeId) bool {
        if (key == hir_mod.none_node_id or self.hir.kindOf(key) != .identifier) return false;
        return !self.identifierHasNarrowableValueBinding(key);
    }

    /// Returns the source text for a computed key when it is a simple
    /// identifier (e.g. `[e2]` -> `"e2"`). Walks the source forward
    /// from the key span end up to (but not including) the closing
    /// `]`, preserving inner whitespace so the rendered text matches
    /// the source — e.g. `[public ]` keeps its trailing space. Falls
    /// back to the interned name when source isn't available.
    /// Returns null when the key is not a bare identifier.
    fn computedKeyIdentifierText(self: *Checker, key: NodeId) ?[]const u8 {
        if (key == hir_mod.none_node_id) return null;
        if (self.hir.kindOf(key) != .identifier) return null;
        const src = self.source orelse {
            const id = hir_mod.identifierOf(self.hir, key);
            return self.string_interner.get(id.name);
        };
        const span = self.hir.spanOf(key);
        if (span.start >= src.len) return null;
        var end: usize = @min(@as(usize, span.end), src.len);
        while (end < src.len and src[end] != ']' and src[end] != '\n') : (end += 1) {}
        return src[@intCast(span.start)..end];
    }

    /// Returns true when a type annotation contains any bare type-ref
    /// that doesn't resolve to a visible type declaration, builtin,
    /// or type parameter. Used to suppress TS2564 for computed class
    /// fields like `[e]: Type` where `Type` is unresolved — tsc skips
    /// TS2564 since the field's type cannot be analyzed. Mirrors
    /// `parserComputedPropertyName9`.
    fn typeAnnotationContainsUnresolvedRef(self: *Checker, type_node: NodeId) bool {
        if (type_node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(type_node)) {
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, type_node);
                for (hir_mod.typeRefArgs(self.hir, type_node)) |arg| {
                    if (self.typeAnnotationContainsUnresolvedRef(arg)) break :blk true;
                }
                if (r.qualifier_len != 0 or r.args_len != 0) break :blk false;
                if (self.typeRefNameExists(r.name) or self.visibleTypeDeclarationExistsAt(type_node, r.name)) break :blk false;
                const raw = self.string_interner.get(r.name);
                if (self.lowerBuiltinObjectType(raw) != null) break :blk false;
                if (std.mem.eql(u8, raw, "any") or
                    std.mem.eql(u8, raw, "unknown") or
                    std.mem.eql(u8, raw, "never") or
                    std.mem.eql(u8, raw, "void") or
                    std.mem.eql(u8, raw, "null") or
                    std.mem.eql(u8, raw, "undefined") or
                    std.mem.eql(u8, raw, "string") or
                    std.mem.eql(u8, raw, "number") or
                    std.mem.eql(u8, raw, "boolean") or
                    std.mem.eql(u8, raw, "bigint") or
                    std.mem.eql(u8, raw, "symbol") or
                    std.mem.eql(u8, raw, "object") or
                    self.isBuiltinName(r.name))
                {
                    break :blk false;
                }
                break :blk true;
            },
            .array_type => self.typeAnnotationContainsUnresolvedRef(hir_mod.arrayTypeOf(self.hir, type_node).element),
            .union_type => for (hir_mod.unionTypeMembers(self.hir, type_node)) |member| {
                if (self.typeAnnotationContainsUnresolvedRef(member)) break true;
            } else false,
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, type_node)) |member| {
                if (self.typeAnnotationContainsUnresolvedRef(member)) break true;
            } else false,
            else => false,
        };
    }

    fn computedClassPropertyKeyIsSimpleLiteralNode(self: *Checker, key: NodeId, t: TypeId) bool {
        switch (self.hir.kindOf(key)) {
            .literal_string, .literal_number => return true,
            .member_access => {
                const m = hir_mod.memberOf(self.hir, key);
                if (self.hir.kindOf(m.object) == .identifier) {
                    const obj = hir_mod.identifierOf(self.hir, m.object);
                    if (std.mem.eql(u8, self.string_interner.get(obj.name), "Symbol")) return true;
                }
                return self.computedClassPropertyKeyIsSimpleLiteral(t);
            },
            .identifier => {
                const raw = self.string_interner.get(hir_mod.identifierOf(self.hir, key).name);
                if (self.sourceHasUniqueSymbolDeclaration(raw) or self.sourceHasDirectConstSymbolInit(raw)) return true;
                if ((self.sourceConstSymbolMemberName(raw) catch null) != null) return true;
                return self.computedClassPropertyKeyIsSimpleLiteral(t);
            },
            else => return self.computedClassPropertyKeyIsSimpleLiteral(t),
        }
    }

    fn computedPropertyKeyTypeIsSymbolLike(self: *Checker, t: TypeId) CheckError!bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_symbol) return true;
        if (f.is_union) {
            var saw = false;
            for (self.interner.unionMembers(t)) |member| {
                if (!try self.computedPropertyKeyTypeIsSymbolLike(member)) return false;
                saw = true;
            }
            return saw;
        }
        return false;
    }

    fn computedPropertyKeyTypeIsNumberLike(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_number) return true;
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.computedPropertyKeyTypeIsNumberLike(member)) return false;
            }
            return true;
        }
        return false;
    }

    fn checkComputedIndexSignatureCompatibility(
        self: *Checker,
        node: NodeId,
        key_t: TypeId,
        member_t: TypeId,
        string_idx: TypeId,
        number_idx: TypeId,
        symbol_idx: TypeId,
    ) CheckError!void {
        _ = symbol_idx;
        if (member_t == types.Primitive.any or key_t == types.Primitive.any or key_t == types.Primitive.unknown) return;
        const key_is_symbol = try self.computedPropertyKeyTypeIsSymbolLike(key_t);
        if (!key_is_symbol and string_idx != types.Primitive.none and string_idx != types.Primitive.any) {
            if (!(self.engine.isAssignableTo(member_t, string_idx) catch true)) {
                try self.report(node, TsCodes.property_not_assignable_to_index_type, "Property is not assignable to string index type.");
            }
        }
        if (self.computedPropertyKeyTypeIsNumberLike(key_t) and
            number_idx != types.Primitive.none and
            number_idx != types.Primitive.any)
        {
            if (!(self.engine.isAssignableTo(member_t, number_idx) catch true)) {
                try self.report(node, TsCodes.property_not_assignable_to_index_type, "Property is not assignable to number index type.");
            }
        }
    }

    fn expressionContainsThis(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .this_expr => return true,
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                return std.mem.eql(u8, self.string_interner.get(id.name), "this");
            },
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                return self.expressionContainsThis(m.object);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                return self.expressionContainsThis(e.object) or self.expressionContainsThis(e.index);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.expressionContainsThis(c.callee)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.expressionContainsThis(arg)) return true;
                }
                return false;
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.expressionContainsThis(b.lhs) or self.expressionContainsThis(b.rhs);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                return self.expressionContainsThis(l.lhs) or self.expressionContainsThis(l.rhs);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                return self.expressionContainsThis(c.cond) or
                    self.expressionContainsThis(c.then_branch) or
                    self.expressionContainsThis(c.else_branch);
            },
            .unary_op => return self.expressionContainsThis(hir_mod.unaryOf(self.hir, node).operand),
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                return self.expressionContainsThis(a.target) or self.expressionContainsThis(a.value);
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| {
                    if (self.expressionContainsThis(s)) return true;
                }
                return false;
            },
            .return_stmt => return self.expressionContainsThis(hir_mod.returnOf(self.hir, node).value),
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                    if (self.expressionContainsThis(el)) return true;
                }
                return false;
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |p| {
                    if (self.hir.kindOf(p) == .object_property) {
                        const op = hir_mod.objectPropertyOf(self.hir, p);
                        if (self.expressionContainsThis(op.key) or self.expressionContainsThis(op.value)) return true;
                    } else if (self.expressionContainsThis(p)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn expressionContainsSuper(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .super_expr => return true,
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                return std.mem.eql(u8, self.string_interner.get(id.name), "super");
            },
            .member_access => return self.expressionContainsSuper(hir_mod.memberOf(self.hir, node).object),
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                return self.expressionContainsSuper(e.object) or self.expressionContainsSuper(e.index);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.expressionContainsSuper(c.callee)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.expressionContainsSuper(arg)) return true;
                }
                return false;
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.expressionContainsSuper(b.lhs) or self.expressionContainsSuper(b.rhs);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                return self.expressionContainsSuper(l.lhs) or self.expressionContainsSuper(l.rhs);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                return self.expressionContainsSuper(c.cond) or
                    self.expressionContainsSuper(c.then_branch) or
                    self.expressionContainsSuper(c.else_branch);
            },
            .unary_op => return self.expressionContainsSuper(hir_mod.unaryOf(self.hir, node).operand),
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                return self.expressionContainsSuper(a.target) or self.expressionContainsSuper(a.value);
            },
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                    if (self.expressionContainsSuper(el)) return true;
                }
                return false;
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |p| {
                    if (self.hir.kindOf(p) == .object_property) {
                        const op = hir_mod.objectPropertyOf(self.hir, p);
                        if (self.expressionContainsSuper(op.key) or self.expressionContainsSuper(op.value)) return true;
                    } else if (self.expressionContainsSuper(p)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn expressionContainsSuperCall(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .call_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.hir.kindOf(c.callee) == .super_expr) return true;
                if (self.hir.kindOf(c.callee) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, c.callee);
                    if (std.mem.eql(u8, self.string_interner.get(id.name), "super")) return true;
                }
                if (self.expressionContainsSuperCall(c.callee)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.expressionContainsSuperCall(arg)) return true;
                }
                return false;
            },
            .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.expressionContainsSuperCall(c.callee)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.expressionContainsSuperCall(arg)) return true;
                }
                return false;
            },
            .member_access => return self.expressionContainsSuperCall(hir_mod.memberOf(self.hir, node).object),
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                return self.expressionContainsSuperCall(e.object) or self.expressionContainsSuperCall(e.index);
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.expressionContainsSuperCall(b.lhs) or self.expressionContainsSuperCall(b.rhs);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                return self.expressionContainsSuperCall(l.lhs) or self.expressionContainsSuperCall(l.rhs);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                return self.expressionContainsSuperCall(c.cond) or
                    self.expressionContainsSuperCall(c.then_branch) or
                    self.expressionContainsSuperCall(c.else_branch);
            },
            .unary_op => return self.expressionContainsSuperCall(hir_mod.unaryOf(self.hir, node).operand),
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                return self.expressionContainsSuperCall(a.target) or self.expressionContainsSuperCall(a.value);
            },
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                    if (self.expressionContainsSuperCall(el)) return true;
                }
                return false;
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |p| {
                    if (self.hir.kindOf(p) == .object_property) {
                        const op = hir_mod.objectPropertyOf(self.hir, p);
                        if (self.expressionContainsSuperCall(op.key) or self.expressionContainsSuperCall(op.value)) return true;
                    } else if (self.expressionContainsSuperCall(p)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn superCallIsInNestedFunctionInsideConstructor(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        var saw_nested_function = false;
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const f = hir_mod.fnDeclOf(self.hir, cur);
            if (f.flags.is_constructor) return saw_nested_function;
            saw_nested_function = true;
        }
        return false;
    }

    fn computedNameReferencesTypeParams(self: *Checker, node: NodeId, type_params: []const NodeId) bool {
        if (node == hir_mod.none_node_id or type_params.len == 0) return false;
        switch (self.hir.kindOf(node)) {
            .type_ref => return self.typeParamNameMatches(hir_mod.typeRefOf(self.hir, node).name, type_params),
            .call_expr, .new_expr => {
                for (hir_mod.callTypeArgs(self.hir, node)) |ta| {
                    if (self.computedNameReferencesTypeParams(ta, type_params)) return true;
                }
                const c = hir_mod.callOf(self.hir, node);
                if (self.computedNameReferencesTypeParams(c.callee, type_params)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.computedNameReferencesTypeParams(arg, type_params)) return true;
                }
                return false;
            },
            .member_access => return self.computedNameReferencesTypeParams(hir_mod.memberOf(self.hir, node).object, type_params),
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                return self.computedNameReferencesTypeParams(e.object, type_params) or
                    self.computedNameReferencesTypeParams(e.index, type_params);
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.computedNameReferencesTypeParams(b.lhs, type_params) or
                    self.computedNameReferencesTypeParams(b.rhs, type_params);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                return self.computedNameReferencesTypeParams(l.lhs, type_params) or
                    self.computedNameReferencesTypeParams(l.rhs, type_params);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                return self.computedNameReferencesTypeParams(c.cond, type_params) or
                    self.computedNameReferencesTypeParams(c.then_branch, type_params) or
                    self.computedNameReferencesTypeParams(c.else_branch, type_params);
            },
            .unary_op => return self.computedNameReferencesTypeParams(hir_mod.unaryOf(self.hir, node).operand, type_params),
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                return self.computedNameReferencesTypeParams(a.target, type_params) or
                    self.computedNameReferencesTypeParams(a.value, type_params);
            },
            else => return false,
        }
    }

    fn currentThisType(self: *Checker) ?TypeId {
        const this_id = self.string_interner.intern("this") catch return null;
        return self.lookupNarrow(this_id);
    }

    fn objectLiteralLikelyHasContextualTarget(self: *Checker, node: NodeId) bool {
        var cur = node;
        while (true) {
            const parent = self.hir.parentOf(cur);
            if (parent == hir_mod.none_node_id) return false;
            switch (self.hir.kindOf(parent)) {
                .var_decl, .let_decl, .const_decl => {
                    const v = hir_mod.varDeclOf(self.hir, parent);
                    return v.init == cur and v.type_annotation != hir_mod.none_node_id;
                },
                .assignment => {
                    const a = hir_mod.assignmentOf(self.hir, parent);
                    return a.value == cur;
                },
                .call_expr, .new_expr => {
                    const c = hir_mod.callOf(self.hir, parent);
                    for (hir_mod.callArgs(self.hir, parent)) |arg| {
                        if (arg == cur) return true;
                    }
                    return c.callee == cur;
                },
                .object_property => {
                    cur = parent;
                    continue;
                },
                .object_literal => {
                    cur = parent;
                    continue;
                },
                .as_expr, .satisfies_expr => return true,
                else => return false,
            }
        }
    }

    /// Phase 4 #11 — when an object literal is the return value of a
    /// function with a declared return type, return that declared
    /// return type. Used as the contextual target for
    /// `checkObjectLiteralMethodBodiesWithThis` so a `ThisType<T>`
    /// marker on the return-type annotation flips `this` inside the
    /// returned object literal's methods (Vue-style pattern with
    /// explicit return type instead of explicit param/var annotation).
    ///
    /// Returns `null` when the literal isn't a return value, the
    /// enclosing function lacks a declared return type, or the
    /// declared return type fails to lower.
    fn objectLiteralEnclosingReturnTargetType(self: *Checker, node: NodeId) ?TypeId {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id) return null;
        if (self.hir.kindOf(parent) != .return_stmt) return null;
        var cur = self.hir.parentOf(parent);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                const f = hir_mod.fnDeclOf(self.hir, cur);
                if (f.return_type == hir_mod.none_node_id) return null;
                return self.lowererLowerWithTypeParams(f.return_type) catch null;
            }
        }
        return null;
    }

    fn memberAccessIsContextualObjectLiteralThis(self: *Checker, object_node: NodeId) bool {
        if (object_node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(object_node)) {
            .this_expr => {},
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, object_node);
                if (!std.mem.eql(u8, self.string_interner.get(id.name), "this")) return false;
            },
            else => return false,
        }
        var cur = self.hir.parentOf(object_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            switch (self.hir.kindOf(cur)) {
                .object_literal => return true,
                .fn_decl, .fn_expr, .arrow_fn, .block_stmt, .object_property, .member_access, .binary_op, .assignment, .logical_op, .if_stmt, .return_stmt => {},
                else => {},
            }
        }
        return false;
    }

    fn checkThisExpression(self: *Checker, node: NodeId) CheckError!TypeId {
        if (self.nodeIsThisParameterName(node)) return types.Primitive.any;
        if (self.thisInsideDecoratorInitializerCallback(node)) return types.Primitive.any;
        if (self.nodeInsideAmbientVarInitializer(node)) return types.Primitive.any;
        if (self.sourceHasStrictFalseDirective() and self.thisInsideNonArrowPlainFunction(node)) return types.Primitive.any;
        if (self.thisInsideCheckJsConstructorFunction(node)) return types.Primitive.any;
        if (self.thisInsideCheckJsPrototypeAssignmentFunction(node)) return types.Primitive.any;
        if (self.thisInsideCheckJsFunctionWithThisTag(node)) return types.Primitive.any;
        if (self.thisInsideCheckJsCallbackWithThis(node)) return types.Primitive.any;
        if (self.currentThisType()) |this_t| return this_t;
        if (self.nodeHasAncestorKind(node, .decorator)) return types.Primitive.any;
        if (self.thisIsGlobalScriptThis(node)) return try self.bareGlobalThisType();
        if (!self.sourceHasStrictFalseDirective() and !self.thisInsideObjectLiteralMethod(node)) {
            try self.report(node, TsCodes.this_implicitly_any, "'this' implicitly has type 'any' because it does not have a type annotation.");
        }
        return types.Primitive.any;
    }

    fn thisIsGlobalScriptThis(self: *Checker, node: NodeId) bool {
        if (self.sourceHasStrictFalseDirective()) return false;
        if (self.rootHasTopLevelExternalModuleMarker(node)) return false;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            switch (self.hir.kindOf(cur)) {
                .fn_decl, .fn_expr, .class_decl, .class_expr, .object_literal => return false,
                .arrow_fn => {},
                else => {},
            }
        }
        return true;
    }

    fn memberAccessObjectIsGlobalThisThis(self: *Checker, object_node: NodeId) bool {
        switch (self.hir.kindOf(object_node)) {
            .this_expr => return self.thisIsGlobalScriptThis(object_node),
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, object_node);
                return std.mem.eql(u8, self.string_interner.get(id.name), "this") and self.thisIsGlobalScriptThis(object_node);
            },
            else => return false,
        }
    }

    fn reportGlobalThisNoIndexSignature(self: *Checker, node: NodeId) CheckError!void {
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .pos = self.memberAccessNamePos(node),
            .code = TsCodes.global_this_no_index_signature,
            .message = "Element implicitly has an 'any' type because type 'typeof globalThis' has no index signature.",
        });
    }

    fn nodeInsideAmbientVarInitializer(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const kind = self.hir.kindOf(cur);
            if (kind != .var_decl and kind != .let_decl and kind != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, cur);
            return v.is_ambient and v.init != hir_mod.none_node_id;
        }
        return false;
    }

    /// True when `node` is lexically inside a `namespace M { ... }`
    /// (or `module M { ... }`) body without any intervening
    /// function-like or class frame. Used by TS2331 / `this` checks
    /// to mirror upstream `isInsideStaticOrModule`.
    fn thisDirectlyInsideNamespaceBody(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn or
                k == .class_decl or k == .class_expr) return false;
            if (k == .namespace_decl or k == .module_decl) return true;
        }
        return false;
    }

    fn nodeIsThisParameterName(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id or self.hir.kindOf(parent) != .parameter) return false;
        const p = hir_mod.parameterOf(self.hir, parent);
        return p.name == node and self.isThisParameter(parent);
    }

    fn thisInsideDecoratorInitializerCallback(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr) continue;
            var p = self.hir.parentOf(cur);
            while (p != hir_mod.none_node_id) : (p = self.hir.parentOf(p)) {
                if (self.hir.kindOf(p) != .call_expr) continue;
                const call = hir_mod.callOf(self.hir, p);
                var is_arg = false;
                for (hir_mod.callArgs(self.hir, p)) |arg| {
                    if (arg == cur) {
                        is_arg = true;
                        break;
                    }
                }
                if (!is_arg) continue;
                if (self.hir.kindOf(call.callee) != .member_access) continue;
                const member = hir_mod.memberOf(self.hir, call.callee);
                if (std.mem.eql(u8, self.string_interner.get(member.name), "addInitializer")) return true;
            }
            return false;
        }
        return false;
    }

    fn thisInsideCheckJsConstructorFunction(self: *Checker, node: NodeId) bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .arrow_fn) return false;
            if (k != .fn_decl and k != .fn_expr) continue;
            const f = hir_mod.fnDeclOf(self.hir, cur);
            if (f.flags.is_method or f.flags.is_constructor) return false;
            return self.fnLooksLikeCheckJsConstructor(cur);
        }
        return false;
    }

    fn thisInsideCheckJsPrototypeAssignmentFunction(self: *Checker, node: NodeId) bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        const src = self.source orelse return false;
        var fn_node = hir_mod.none_node_id;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .arrow_fn) return false;
            if (k == .fn_expr or k == .fn_decl) {
                fn_node = cur;
                break;
            }
        }
        if (fn_node == hir_mod.none_node_id) return false;
        const fn_span = self.hir.spanOf(fn_node);
        cur = self.hir.parentOf(fn_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .block_stmt) break;
            const sp = self.hir.spanOf(cur);
            if (sp.start >= fn_span.start or fn_span.start > src.len) continue;
            const prefix = src[sp.start..fn_span.start];
            if (std.mem.indexOf(u8, prefix, ".prototype.") != null) return true;
        }
        return false;
    }

    fn thisInsideCheckJsFunctionWithThisTag(self: *Checker, node: NodeId) bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        const src = self.source orelse return false;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .arrow_fn) return false;
            if (k != .fn_decl and k != .fn_expr) continue;

            var owner = cur;
            while (owner != hir_mod.none_node_id) : (owner = self.hir.parentOf(owner)) {
                const owner_kind = self.hir.kindOf(owner);
                if (owner_kind == .block_stmt or owner_kind == .class_decl or owner_kind == .class_expr) break;
                const span = self.hir.spanOf(owner);
                const body = self.leadingJsDocBody(src, span.start) orelse continue;
                if (std.mem.indexOf(u8, body, "@this") != null) return true;
            }
            return false;
        }
        return false;
    }

    fn thisInsideCheckJsCallbackWithThis(self: *Checker, node: NodeId) bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        const src = self.source orelse return false;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .arrow_fn) return false;
            if (k != .fn_expr and k != .fn_decl) continue;
            const parent = self.hir.parentOf(cur);
            if (parent == hir_mod.none_node_id) return false;
            const pk = self.hir.kindOf(parent);
            if (pk != .var_decl and pk != .let_decl and pk != .const_decl) return false;
            const v = hir_mod.varDeclOf(self.hir, parent);
            if (v.init != cur) return false;
            const span = self.hir.spanOf(parent);
            const body = self.leadingJsDocBody(src, span.start) orelse return false;
            const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return false;
            defer self.gpa.free(tags);
            for (tags) |tag| {
                if (tag.kind != .type_tag) continue;
                const base = jsDocTypeBaseName(tag.type_text);
                if (base.len == 0) continue;
                if (self.jsDocCallbackHasThis(src, base)) return true;
            }
            return false;
        }
        return false;
    }

    fn jsDocCallbackHasThis(self: *Checker, src: []const u8, wanted_name: []const u8) bool {
        _ = self;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return false;
            defer search_start = end + 2;
            const body = src[body_start..end];
            if (!jsDocBlockHasNamedTag(body, "@callback", wanted_name)) continue;
            if (std.mem.indexOf(u8, body, "@this") != null) return true;
        }
        return false;
    }

    fn fnLooksLikeCheckJsConstructor(self: *Checker, fn_node: NodeId) bool {
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, f.name);
            if (self.identifierNameStartsUppercase(id.name)) return true;
        }
        if (self.leadingJsDocBody(self.source orelse "", self.hir.spanOf(fn_node).start)) |body| {
            if (std.mem.indexOf(u8, body, "@class") != null or
                std.mem.indexOf(u8, body, "@constructor") != null) return true;
        }
        const parent = self.hir.parentOf(fn_node);
        if (parent != hir_mod.none_node_id) {
            const pk = self.hir.kindOf(parent);
            if (pk == .var_decl or pk == .let_decl or pk == .const_decl) {
                const v = hir_mod.varDeclOf(self.hir, parent);
                if (v.init == fn_node and
                    v.name != hir_mod.none_node_id and
                    self.hir.kindOf(v.name) == .identifier and
                    self.identifierNameStartsUppercase(hir_mod.identifierOf(self.hir, v.name).name))
                {
                    return true;
                }
            }
        }
        if (parent != hir_mod.none_node_id and self.hir.kindOf(parent) == .assignment) {
            const a = hir_mod.assignmentOf(self.hir, parent);
            if (a.value == fn_node and self.assignmentTargetIsPrototypeMember(a.target)) return true;
            if (a.value == fn_node and self.assignmentTargetLastNameStartsUppercase(a.target)) return true;
        }
        return false;
    }

    fn identifierNameStartsUppercase(self: *Checker, name: hir_mod.StringId) bool {
        const text = self.string_interner.get(name);
        if (text.len == 0) return false;
        return text[0] >= 'A' and text[0] <= 'Z';
    }

    fn assignmentTargetIsPrototypeMember(self: *Checker, target: NodeId) bool {
        if (target == hir_mod.none_node_id or self.hir.kindOf(target) != .member_access) return false;
        const m = hir_mod.memberOf(self.hir, target);
        if (m.object == hir_mod.none_node_id or self.hir.kindOf(m.object) != .member_access) return false;
        const parent_member = hir_mod.memberOf(self.hir, m.object);
        return std.mem.eql(u8, self.string_interner.get(parent_member.name), "prototype");
    }

    /// `.js` files with `// @ts-check` accept `/** @type {T} */
    /// C.prototype = expr` as a declaration that pins the prototype
    /// slot to T. Returns T when the assignment statement carries a
    /// leading `@type` JSDoc and the target is `<Ctor>.prototype`
    /// (a 2-level member access whose tail name is `prototype` and
    /// whose object is an identifier — typically a constructor
    /// function or class). The override is restricted to
    /// constructor-shaped LHS names to avoid touching unrelated
    /// `obj.prototype = …` patterns where the member-access
    /// structural shape is the right declared type. Mirrors
    /// `typeTagPrototypeAssignment` upstream.
    fn jsDocTypeForPrototypeAssignmentTarget(
        self: *Checker,
        assignment_node: NodeId,
        target: NodeId,
    ) CheckError!?TypeId {
        if (target == hir_mod.none_node_id) return null;
        if (self.hir.kindOf(target) != .member_access) return null;
        const m = hir_mod.memberOf(self.hir, target);
        if (!std.mem.eql(u8, self.string_interner.get(m.name), "prototype")) return null;
        if (m.object == hir_mod.none_node_id or self.hir.kindOf(m.object) != .identifier) return null;
        const obj_id = hir_mod.identifierOf(self.hir, m.object);
        // Treat as a real constructor when:
        //  - the checker has already registered the name as a class
        //    instance type, OR
        //  - the binder identifies it as a function/class symbol, OR
        //  - the same source declares a `function <id>()` or
        //    `class <id>` at the top level (the binder isn't always
        //    attached, e.g. inside checker unit-test setups).
        var is_constructor_like = self.class_instance_types.contains(obj_id.name);
        if (!is_constructor_like) {
            if (self.module) |module| {
                if (module.root.lookup(obj_id.name)) |sym| {
                    is_constructor_like = sym.flags.is_function or sym.flags.is_class;
                }
            }
        }
        if (!is_constructor_like) {
            is_constructor_like = self.rootHasFunctionOrClassDeclNamed(assignment_node, obj_id.name);
        }
        if (!is_constructor_like) return null;
        // Pull `@type` from the leading JSDoc on the assignment's
        // enclosing expression statement (where the comment actually
        // lives), falling back to the assignment node itself.
        const parent = self.hir.parentOf(assignment_node);
        const anchor = if (parent != hir_mod.none_node_id and
            self.hir.kindOf(parent) == .expression_stmt)
            parent
        else
            assignment_node;
        return try self.jsDocTypeForLeadingNode(anchor);
    }

    /// Returns true when the source-file root block contains a
    /// `function <name>()` or `class <name>` declaration. Used as a
    /// binder-free constructor-shape probe for `Ctor.prototype = …`
    /// detection in the JSDoc `@type` override. The anchor is any
    /// node inside the source file — we walk to its root block.
    fn rootHasFunctionOrClassDeclNamed(
        self: *Checker,
        anchor: NodeId,
        wanted: hir_mod.StringId,
    ) bool {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const k = self.hir.kindOf(stmt);
            if (k == .fn_decl) {
                const f = hir_mod.fnDeclOf(self.hir, stmt);
                if (f.name == hir_mod.none_node_id) continue;
                if (self.hir.kindOf(f.name) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, f.name).name == wanted) return true;
            } else if (k == .class_decl) {
                const c = hir_mod.classOf(self.hir, stmt);
                if (c.name == hir_mod.none_node_id) continue;
                if (self.hir.kindOf(c.name) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, c.name).name == wanted) return true;
            }
        }
        return false;
    }

    fn assignmentTargetLastNameStartsUppercase(self: *Checker, target: NodeId) bool {
        if (target == hir_mod.none_node_id or self.hir.kindOf(target) != .member_access) return false;
        const m = hir_mod.memberOf(self.hir, target);
        return self.identifierNameStartsUppercase(m.name);
    }

    fn thisInsideNonArrowPlainFunction(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .arrow_fn) return false;
            if (k == .fn_decl or k == .fn_expr) {
                const f = hir_mod.fnDeclOf(self.hir, cur);
                return !f.flags.is_method and !f.flags.is_constructor;
            }
        }
        return false;
    }

    fn identifierThisIsArrowCaptured(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .arrow_fn) return true;
            if (k == .fn_decl or k == .fn_expr) return false;
        }
        return false;
    }

    fn thisInsideObjectLiteralMethod(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const fn_parent = self.hir.parentOf(cur);
            if (fn_parent == hir_mod.none_node_id or self.hir.kindOf(fn_parent) != .object_property) return false;
            const op = hir_mod.objectPropertyOf(self.hir, fn_parent);
            return op.value == cur and (op.is_method or self.memberSourceLooksMethod(fn_parent) or k == .fn_expr or k == .fn_decl);
        }
        return false;
    }

    fn optionalChainResult(self: *Checker, t: TypeId, is_optional_chain: bool) CheckError!TypeId {
        if (!is_optional_chain) return t;
        return self.unionWithUndefined(t) catch return error.OutOfMemory;
    }

    fn expressionIsOptionalChain(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(node)) {
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, node);
                break :blk m.optional or self.expressionIsOptionalChain(m.object);
            },
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, node);
                break :blk e.optional or self.expressionIsOptionalChain(e.object);
            },
            .call_expr => blk: {
                const c = hir_mod.callOf(self.hir, node);
                break :blk c.optional or self.expressionIsOptionalChain(c.callee);
            },
            else => false,
        };
    }

    fn classThisType(self: *Checker, instance_t: TypeId) CheckError!TypeId {
        const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
        return self.interner.internFreshTypeParameterWithFlags(
            this_id,
            instance_t,
            types.Primitive.none,
            .bivariant,
            false,
        ) catch return error.OutOfMemory;
    }

    fn checkObjectLiteralMethodBodiesWithThis(self: *Checker, node: NodeId, obj_t: TypeId) CheckError!void {
        const props = hir_mod.objectLiteralProps(self.hir, node);
        const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
        var this_t = self.contextualObjectLiteralThisType(obj_t);
        if (self.ancestorObjectLiteralDataReturnType(node)) |data_t| {
            this_t = self.interner.internIntersection(&.{ data_t, this_t }) catch this_t;
        }
        for (props) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            if (op.value == hir_mod.none_node_id) continue;
            const value_kind = self.hir.kindOf(op.value);
            if (value_kind != .fn_decl and value_kind != .fn_expr and value_kind != .arrow_fn) continue;
            const op_is_method = op.is_method or self.memberSourceLooksMethod(p);
            if (!op_is_method and value_kind != .fn_expr and value_kind != .fn_decl) continue;
            if (!self.functionContainsThis(op.value)) continue;
            try self.pushNarrowScope();
            try self.recordNarrow(this_id, this_t);
            try self.checkFnDecl(op.value);
            self.popNarrowScope();
        }
    }

    fn contextualObjectLiteralThisType(self: *Checker, t: TypeId) TypeId {
        if (self.thisTypeMarkerConstraint(t)) |this_t| return this_t;
        return t;
    }

    fn thisTypeMarkerConstraint(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        if (self.this_type_markers.get(t)) |this_t| return this_t;
        if (self.isThisTypeParameter(t)) return self.typeParameterConstraint(t) orelse types.Primitive.any;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_intersection) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return null;
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.thisTypeMarkerConstraint(member)) |this_t| return this_t;
            }
        }
        if (flags.is_union) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.union_payloads.items.len) return null;
            for (self.interner.unionMembers(t)) |member| {
                if (self.thisTypeMarkerConstraint(member)) |this_t| return this_t;
            }
        }
        return null;
    }

    fn ancestorObjectLiteralDataReturnType(self: *Checker, node: NodeId) ?TypeId {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) != .object_literal) continue;
            for (hir_mod.objectLiteralProps(self.hir, cur)) |prop_node| {
                if (self.hir.kindOf(prop_node) != .object_property) continue;
                const op = hir_mod.objectPropertyOf(self.hir, prop_node);
                if (op.key == hir_mod.none_node_id or self.hir.kindOf(op.key) != .identifier) continue;
                const key = hir_mod.identifierOf(self.hir, op.key).name;
                if (!std.mem.eql(u8, self.string_interner.get(key), "data")) continue;
                if (op.value == hir_mod.none_node_id) return null;
                const value_kind = self.hir.kindOf(op.value);
                if (value_kind == .object_literal) return self.hir.typeOf(op.value);
                if (value_kind != .fn_decl and value_kind != .fn_expr and value_kind != .arrow_fn) return null;
                const f = hir_mod.fnDeclOf(self.hir, op.value);
                if (f.body == hir_mod.none_node_id) return null;
                if (self.hir.kindOf(f.body) == .object_literal) {
                    const body_t = self.hir.typeOf(f.body);
                    return if (body_t != types.Primitive.none) body_t else null;
                }
                if (self.hir.kindOf(f.body) == .block_stmt) {
                    for (hir_mod.blockStmts(self.hir, f.body)) |stmt| {
                        if (self.hir.kindOf(stmt) != .return_stmt) continue;
                        const r = hir_mod.returnOf(self.hir, stmt);
                        if (r.value == hir_mod.none_node_id or self.hir.kindOf(r.value) != .object_literal) continue;
                        const ret_t = self.hir.typeOf(r.value);
                        return if (ret_t != types.Primitive.none) ret_t else null;
                    }
                }
                return null;
            }
        }
        return null;
    }

    fn objectAccessorPropertyType(self: *Checker, value_node: NodeId, raw_t: TypeId) TypeId {
        if (value_node == hir_mod.none_node_id) return raw_t;
        const kind = self.hir.kindOf(value_node);
        if (kind != .fn_decl and kind != .fn_expr and kind != .arrow_fn) return raw_t;
        const fnp = hir_mod.fnDeclOf(self.hir, value_node);
        if (fnp.flags.is_getter) {
            return self.interner.signatureReturn(raw_t) orelse types.Primitive.any;
        }
        if (fnp.flags.is_setter) {
            const params = self.interner.signatureParams(raw_t);
            return if (params.len > 0) params[0] else types.Primitive.any;
        }
        return raw_t;
    }

    fn functionContainsThis(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        const kind = self.hir.kindOf(node);
        if (kind != .fn_decl and kind != .fn_expr and kind != .arrow_fn) return self.expressionContainsThis(node);
        const f = hir_mod.fnDeclOf(self.hir, node);
        for (hir_mod.fnParams(self.hir, node)) |p| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (self.expressionContainsThis(pp.default_value)) return true;
        }
        return self.expressionContainsThis(f.body);
    }

    fn reportSymbolOperator(self: *Checker, node: NodeId, op: []const u8) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "The '{s}' operator cannot be applied to type 'symbol'.",
            .{op},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.symbol_operator_not_allowed,
            .message = msg,
        });
    }

    /// Like `reportSymbolOperator` but anchors at an explicit byte
    /// position (used for parenthesized operands so the diagnostic
    /// column matches tsc, which anchors at the opening `(`).
    fn reportSymbolOperatorAt(self: *Checker, node: NodeId, pos: ?u32, op: []const u8) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "The '{s}' operator cannot be applied to type 'symbol'.",
            .{op},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .pos = pos,
            .code = TsCodes.symbol_operator_not_allowed,
            .message = msg,
        });
    }

    /// Walk back over any immediately-preceding `(` characters so the
    /// anchor for symbol-operator diagnostics on parenthesized
    /// operands lands at the opening paren (matching tsc's column).
    fn symbolOperandAnchorPos(self: *Checker, node: NodeId) ?u32 {
        const src = self.source orelse return null;
        const span = self.hir.spanOf(node);
        if (span.start == 0 or span.start > src.len) return null;
        var i: usize = span.start;
        while (i > 0 and src[i - 1] == '(') : (i -= 1) {}
        if (i == span.start) return null;
        return @intCast(i);
    }

    fn reportArithmeticOperand(
        self: *Checker,
        node: NodeId,
        code: u32,
        msg: []const u8,
    ) CheckError!void {
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = code,
            .message = msg,
        });
    }

    fn checkTemplateLiteralExpression(self: *Checker, node: NodeId) CheckError!TypeId {
        const exprs = hir_mod.templateLiteralExprs(self.hir, node);
        for (exprs) |e| _ = try self.checkExpression(e);
        if (try self.templateLiteralConcreteString(node)) |sid| {
            return self.interner.internStringLiteral(sid) catch types.Primitive.string_t;
        }
        return types.Primitive.string_t;
    }

    fn templateExpressionAssignableToType(self: *Checker, node: NodeId, target_t: TypeId) CheckError!bool {
        var expr_node = node;
        while (true) {
            switch (self.hir.kindOf(expr_node)) {
                .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => {
                    expr_node = hir_mod.asExpressionOf(self.hir, expr_node).expr;
                    continue;
                },
                else => {},
            }
            break;
        }
        if (self.hir.kindOf(expr_node) != .template_literal) return false;
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const target_flags = self.interner.pool.flagsOf(target_t);
        if (!target_flags.is_template_literal) return false;
        const source_text_nodes = hir_mod.templateLiteralTexts(self.hir, expr_node);
        const source_exprs = hir_mod.templateLiteralExprs(self.hir, expr_node);
        const target_texts = self.interner.templateLiteralTexts(target_t);
        const target_parts = self.interner.templateLiteralTypes(target_t);
        if (source_text_nodes.len != target_texts.len or source_exprs.len != target_parts.len) return false;
        for (source_text_nodes, target_texts) |source_text_node, target_sid| {
            if (self.hir.kindOf(source_text_node) != .literal_string) return false;
            const source_sid = hir_mod.literalStringOf(self.hir, source_text_node).value;
            if (!try self.cookedStringIdEquals(source_sid, target_sid)) return false;
        }
        for (source_exprs, target_parts) |source_expr, target_part| {
            const source_t = self.hir.typeOf(source_expr);
            if (source_t == types.Primitive.none) return false;
            if (self.engine.isAssignableTo(source_t, target_part) catch false) continue;
            if (target_part >= types.Primitive.first_dynamic and target_part < self.interner.pool.typeCount() and
                self.interner.pool.flagsOf(target_part).is_type_parameter)
            {
                if (self.typeParameterConstraint(target_part)) |constraint| {
                    if (constraint == target_part or (self.engine.isAssignableTo(source_t, constraint) catch false)) continue;
                }
            }
            return false;
        }
        return true;
    }

    fn templateLiteralConcreteString(self: *Checker, node: NodeId) CheckError!?hir_mod.StringId {
        const texts = hir_mod.templateLiteralTexts(self.hir, node);
        const exprs = hir_mod.templateLiteralExprs(self.hir, node);
        if (texts.len != exprs.len + 1) return null;
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        defer buf.deinit(self.gpa);
        for (texts, 0..) |text_node, i| {
            if (self.hir.kindOf(text_node) != .literal_string) return null;
            const text = hir_mod.literalStringOf(self.hir, text_node);
            try self.appendCookedStringText(self.string_interner.get(text.value), &buf);
            if (i < exprs.len) {
                if (!try self.appendTemplateSubstitutionString(exprs[i], &buf)) return null;
            }
        }
        return self.string_interner.intern(buf.items) catch return error.OutOfMemory;
    }

    fn appendTemplateSubstitutionString(
        self: *Checker,
        node: NodeId,
        out: *std.ArrayListUnmanaged(u8),
    ) CheckError!bool {
        switch (self.hir.kindOf(node)) {
            .literal_string => {
                const lit = hir_mod.literalStringOf(self.hir, node);
                try self.appendCookedStringText(self.string_interner.get(lit.value), out);
                return true;
            },
            .literal_number => {
                const v = hir_mod.literalNumberOf(self.hir, node);
                if (@trunc(v) == v and v >= @as(f64, @floatFromInt(std.math.minInt(i64))) and v <= @as(f64, @floatFromInt(std.math.maxInt(i64)))) {
                    const as_int: i64 = @intFromFloat(v);
                    const text = try std.fmt.allocPrint(self.gpa, "{d}", .{as_int});
                    defer self.gpa.free(text);
                    try out.appendSlice(self.gpa, text);
                } else {
                    const text = try std.fmt.allocPrint(self.gpa, "{d}", .{v});
                    defer self.gpa.free(text);
                    try out.appendSlice(self.gpa, text);
                }
                return true;
            },
            .literal_bigint => {
                const lit = hir_mod.literalBigIntOf(self.hir, node);
                try out.appendSlice(self.gpa, self.string_interner.get(lit.digits));
                return true;
            },
            .literal_bool => {
                try out.appendSlice(self.gpa, if (hir_mod.literalBoolOf(self.hir, node)) "true" else "false");
                return true;
            },
            .literal_null => {
                try out.appendSlice(self.gpa, "null");
                return true;
            },
            .literal_undefined => {
                try out.appendSlice(self.gpa, "undefined");
                return true;
            },
            .unary_op => {
                const u = hir_mod.unaryOf(self.hir, node);
                if (u.op == .neg and self.hir.kindOf(u.operand) == .literal_number) {
                    try out.append(self.gpa, '-');
                    return try self.appendTemplateSubstitutionString(u.operand, out);
                }
                return false;
            },
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                if (self.hir.kindOf(m.object) != .identifier) return false;
                const obj = hir_mod.identifierOf(self.hir, m.object);
                const lit_t = self.constEnumLiteralAccess(obj.name, m.name, node) orelse
                    self.enumMemberStringLiteralAccess(obj.name, m.name, node) orelse
                    return false;
                if (lit_t < types.Primitive.first_dynamic or lit_t >= self.interner.pool.typeCount()) return false;
                const flags = self.interner.pool.flagsOf(lit_t);
                if (!flags.is_literal) return false;
                switch (self.interner.literalOf(lit_t)) {
                    .string_lit => |sid| try self.appendCookedStringText(self.string_interner.get(sid), out),
                    .number_lit => |bits| {
                        const v = @as(f64, @bitCast(bits));
                        const text = try std.fmt.allocPrint(self.gpa, "{d}", .{v});
                        defer self.gpa.free(text);
                        try out.appendSlice(self.gpa, text);
                    },
                    .boolean_lit => |b| try out.appendSlice(self.gpa, if (b) "true" else "false"),
                    .bigint_lit => return false,
                }
                return true;
            },
            .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => {
                const a = hir_mod.asExpressionOf(self.hir, node);
                return try self.appendTemplateSubstitutionString(a.expr, out);
            },
            else => return false,
        }
    }

    fn isArithmeticOperandAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.isArithmeticOperandAllowed(member)) return false;
            }
            return true;
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.isArithmeticOperandAllowed(member)) return true;
            }
            return false;
        }
        if (!self.strict_flags.strict_null_checks and (f.is_null or f.is_undefined)) return true;
        return f.is_number or f.is_bigint;
    }

    fn compoundAdditionAllowsNullish(self: *Checker, lhs: TypeId) bool {
        if (self.typeIsAnyLike(lhs) or self.typeMaybeStringLike(lhs)) return true;
        const f = self.interner.pool.flagsOf(lhs);
        if (f.is_union) {
            for (self.interner.unionMembers(lhs)) |member| {
                if (!self.compoundAdditionAllowsNullish(member)) return false;
            }
            return true;
        }
        return self.isArithmeticOperandAllowed(lhs);
    }

    fn compoundAdditionAssignableBack(self: *Checker, result_t: TypeId, target_t: TypeId) CheckError!bool {
        if (self.typeIsAnyLike(result_t) or self.typeIsAnyLike(target_t)) return true;
        if (result_t == types.Primitive.string_t) return self.typeMaybeStringLike(target_t);
        if (result_t == types.Primitive.number_t and self.isArithmeticOperandAllowed(target_t)) return true;
        return self.engine.isAssignableTo(result_t, target_t) catch true;
    }

    fn checkCompoundAdditionAssignment(
        self: *Checker,
        node: NodeId,
        target: NodeId,
        value: NodeId,
        target_t: TypeId,
        value_t: TypeId,
    ) CheckError!void {
        if (self.typeContainsSymbol(target_t) or self.typeContainsSymbol(value_t)) {
            try self.reportSymbolOperator(node, "+");
            return;
        }
        if (self.typeIsExactNullish(value_t) and !self.compoundAdditionAllowsNullish(target_t)) {
            try self.reportNullishRelationalOperand(value, value_t);
            return;
        }

        const result_t: TypeId = blk: {
            if (self.typeIsAnyLike(target_t) or self.typeIsAnyLike(value_t)) break :blk types.Primitive.any;
            if (self.typeMaybeStringLike(target_t) or self.typeMaybeStringLike(value_t)) break :blk types.Primitive.string_t;
            if (self.isArithmeticOperandAllowed(target_t) and self.isArithmeticOperandAllowed(value_t)) break :blk types.Primitive.number_t;
            // Prefer tsc's type-rich form
            // `Operator '+=' cannot be applied to types 'A' and 'B'.`
            // when both endpoints have a simple display name; fall
            // back to the generic `…to these operand types.` form.
            // Mirrors `compoundAdditionAssignmentWithInvalidOperands.ts`.
            if (try self.simpleDiagnosticTypeName(target_t)) |t_name| {
                if (try self.simpleDiagnosticTypeName(value_t)) |v_name| {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Operator '+=' cannot be applied to types '{s}' and '{s}'.",
                        .{ t_name, v_name },
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.operator_cannot_be_applied,
                        .message = msg,
                    });
                    return;
                }
            }
            try self.report(node, TsCodes.operator_cannot_be_applied, "Operator '+=' cannot be applied to these operand types.");
            return;
        };

        if (!try self.compoundAdditionAssignableBack(result_t, target_t)) {
            try self.reportTypeNotAssignable(target, result_t, target_t, "Type is not assignable to target type.");
        }
    }

    /// Locate the `=` token inside an `x = <init>` assignment node used
    /// as the spread element of `[..."x = init"]`. Returns the byte
    /// offset of the `=` so TS1186 anchors at the operator (matching
    /// `restElementWithInitializer2.ts(3,7)`), or null when source
    /// isn't available / the scan fails so callers fall back to the
    /// assignment span start.
    fn restElementInitializerEqualPos(self: *Checker, assign_node: NodeId) ?u32 {
        if (self.source == null) return null;
        if (self.hir.kindOf(assign_node) != .assignment) return null;
        const a = hir_mod.assignmentOf(self.hir, assign_node);
        const src = self.source.?;
        const target_span = self.hir.spanOf(a.target);
        const value_span = self.hir.spanOf(a.value);
        const scan_start: usize = @intCast(target_span.end);
        const scan_end: usize = @min(src.len, @as(usize, @intCast(value_span.start)));
        if (scan_start >= scan_end) return null;
        var i = scan_start;
        while (i < scan_end) : (i += 1) {
            if (src[i] == '=') return @intCast(i);
        }
        return null;
    }

    fn reportPropertyDoesNotExist(self: *Checker, node: NodeId, name: hir_mod.StringId) CheckError!void {
        const name_str = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' does not exist on type.",
            .{name_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .pos = self.memberAccessNamePos(node),
            .code = TsCodes.property_does_not_exist,
            .message = msg,
        });
    }

    fn reportPropertyDoesNotExistOnType(self: *Checker, node: NodeId, name: hir_mod.StringId, target_t: TypeId) CheckError!void {
        const name_str = self.string_interner.get(name);
        if (self.memberAccessRootNameIs(node, "Symbol")) {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Property '{s}' does not exist on type 'SymbolConstructor'.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = node,
                .pos = self.memberAccessNamePos(node),
                .code = TsCodes.property_does_not_exist,
                .message = msg,
            });
            return;
        }
        if (try self.allocPropertyMissingTargetTypeName(target_t)) |target_text| {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Property '{s}' does not exist on type '{s}'.",
                .{ name_str, target_text },
            );
            try self.diagnostics.append(self.gpa, .{
                .node = node,
                .pos = self.memberAccessNamePos(node),
                .code = TsCodes.property_does_not_exist,
                .message = msg,
            });
            return;
        }
        try self.reportPropertyDoesNotExist(node, name);
    }

    fn memberAccessRootNameIs(self: *Checker, node: NodeId, expected: []const u8) bool {
        const root = self.calleeRootIdentifier(node) orelse return false;
        const id = hir_mod.identifierOf(self.hir, root);
        return std.mem.eql(u8, self.string_interner.get(id.name), expected);
    }

    fn memberAccessNamePos(self: *Checker, node: NodeId) ?u32 {
        if (self.source == null or self.hir.kindOf(node) != .member_access) return null;
        const src = self.source.?;
        const span = self.hir.spanOf(node);
        if (span.end > src.len or span.start >= span.end) return null;
        const text = src[span.start..span.end];
        var i = text.len;
        while (i > 0) {
            i -= 1;
            if (text[i] == '.') return span.start + @as(u32, @intCast(i + 1));
        }
        return null;
    }

    fn allocPropertyMissingTargetTypeName(self: *Checker, target_t: TypeId) !?[]const u8 {
        if (try self.allocSimpleTypeName(target_t)) |name| return name;
        if (target_t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_object_type and
            self.interner.objectMembers(target_t).len == 0 and
            self.interner.objectStringIndex(target_t) == types.Primitive.none and
            self.interner.objectNumberIndex(target_t) == types.Primitive.none)
        {
            return "{}";
        }
        // Render small literal object types like `{ x: number; }` so
        // TS2339 prose matches upstream when the target was a local
        // object literal preserved by `satisfies` or by contextual
        // typing. Bail on indexers/methods/optionals so we don't
        // mis-render shapes the simple printer can't faithfully
        // reproduce.
        if (flags.is_object_type and
            self.interner.objectStringIndex(target_t) == types.Primitive.none and
            self.interner.objectNumberIndex(target_t) == types.Primitive.none)
        {
            const members = self.interner.objectMembers(target_t);
            if (members.len > 0 and members.len <= 8) {
                var obj_buf: std.ArrayListUnmanaged(u8) = .empty;
                const arena_o = self.diag_arena.allocator();
                try obj_buf.appendSlice(arena_o, "{ ");
                var renderable = true;
                for (members) |m| {
                    if (m.is_method or m.is_optional) {
                        renderable = false;
                        break;
                    }
                    const member_name_str = self.string_interner.get(m.name);
                    if (member_name_str.len == 0 or member_name_str[0] == '_') {
                        renderable = false;
                        break;
                    }
                    const value_text = (try self.allocSimpleTypeName(m.type)) orelse {
                        renderable = false;
                        break;
                    };
                    try obj_buf.appendSlice(arena_o, member_name_str);
                    try obj_buf.appendSlice(arena_o, ": ");
                    try obj_buf.appendSlice(arena_o, value_text);
                    try obj_buf.appendSlice(arena_o, "; ");
                }
                if (renderable) {
                    try obj_buf.append(arena_o, '}');
                    return obj_buf.items;
                }
            }
        }
        return null;
    }

    /// Best-effort name for the target of an `implements` clause used by
    /// TS2420 ("Class 'X' incorrectly implements interface ..."). Returns
    /// the interface's declared name when one is recoverable; otherwise
    /// null so the caller falls back to the bare diagnostic.
    fn allocImplementsTargetName(self: *Checker, impl_node: NodeId, target_t: TypeId) !?[]const u8 {
        if (try self.allocSimpleTypeName(target_t)) |name| return name;
        // Try to recover the syntactic type-reference name (handles cases
        // where the lowered type is opaque but the source spelled it out).
        return self.implementsClauseSyntacticName(impl_node);
    }

    fn implementsClauseSyntacticName(self: *Checker, impl_node: NodeId) ?[]const u8 {
        const src = self.source orelse return null;
        const span = self.hir.spanOf(impl_node);
        if (span.start >= span.end or span.end > src.len) return null;
        const text = src[span.start..span.end];
        // Trim to the leading identifier (stop at `<`, `.`, whitespace).
        var end: usize = 0;
        while (end < text.len) : (end += 1) {
            const ch = text[end];
            const is_ident = (ch == '_') or (ch == '$') or
                (ch >= 'a' and ch <= 'z') or
                (ch >= 'A' and ch <= 'Z') or
                (end > 0 and ch >= '0' and ch <= '9');
            if (!is_ident) break;
        }
        if (end == 0) return null;
        return text[0..end];
    }

    /// Span start of the class identifier (`class X`) used as the
    /// diagnostic position for TS2420 / TS2415, matching tsc which
    /// reports against the class name rather than the `class` keyword.
    fn classNameSpanStart(self: *Checker, class_node: NodeId) ?u32 {
        if (self.hir.kindOf(class_node) != .class_decl and self.hir.kindOf(class_node) != .class_expr) {
            return null;
        }
        const c = hir_mod.classOf(self.hir, class_node);
        if (c.name == hir_mod.none_node_id) return null;
        const sp = self.hir.spanOf(c.name);
        return sp.start;
    }

    /// True when `class_node` is nested inside a `declare module
    /// "x" { ... }` (or `declare namespace ...`). Used to suppress
    /// TS2564 ("Property has no initializer ...") for fields in
    /// ambient blocks where tsc treats the class shape as purely
    /// declarative — see fixture `importTypeAmbient`. A regular
    /// `namespace Foo { class C { ... } }` (no `declare`) still
    /// emits TS2564, matching `assignmentCompatWithCallSignatures4`.
    fn classNodeIsInsideAmbientDeclaredModule(self: *Checker, class_node: NodeId) bool {
        var cur = self.hir.parentOf(class_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .module_decl or k == .namespace_decl) {
                if (self.namespaceDeclWasPrefixedWithDeclare(cur)) return true;
            }
        }
        return false;
    }

    fn namespaceDeclWasPrefixedWithDeclare(self: *Checker, ns_node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(ns_node);
        if (span.start >= src.len) return false;
        // Span begins at `namespace` / `module`; the `declare`
        // modifier sits just before. Bounded look-behind avoids
        // drifting into a previous statement.
        const look_back: u32 = 16;
        const lb_start: u32 = if (span.start > look_back) span.start - look_back else 0;
        const slice = src[lb_start..span.start];
        return std.mem.indexOf(u8, slice, "declare") != null;
    }

    fn typeIsDefinitelyNonConstructable(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.none or self.typeIsAnyLike(t)) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.typeIsDefinitelyNonConstructable(member)) return false;
            }
            return true;
        }
        return f.is_string or f.is_number or f.is_bigint or f.is_boolean or f.is_symbol or f.is_null or f.is_undefined or f.is_void;
    }

    fn isRelationalOperandAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.isRelationalOperandAllowed(member)) return false;
            }
            return true;
        }
        if (f.is_type_parameter) return true;
        if (f.is_null or f.is_undefined) return true;
        if (f.is_object or f.is_object_type or f.is_signature or f.is_tuple or f.is_intersection) return true;
        return f.is_string or f.is_number or f.is_bigint or f.is_boolean or f.is_void;
    }

    fn typeIsExactNullish(self: *Checker, t: TypeId) bool {
        const f = self.interner.pool.flagsOf(t);
        return f.is_null or f.is_undefined;
    }

    fn relationalNullishName(self: *Checker, t: TypeId) []const u8 {
        const f = self.interner.pool.flagsOf(t);
        return if (f.is_null) "null" else "undefined";
    }

    fn reportNullishRelationalOperand(self: *Checker, node: NodeId, t: TypeId) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "The value '{s}' cannot be used here.",
            .{self.relationalNullishName(t)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.nullish_relational_operand,
            .message = msg,
        });
    }

    /// `null` / `undefined` literal name, anchored on the node kind
    /// (not the type) so we mirror tsgo's "checkNonNullType" branch
    /// that gates on whether the operand source token is literally
    /// `null` or the `undefined` identifier — independent of any
    /// flow-narrowed type. Returns null when the node isn't one of
    /// those literals.
    fn nullishLiteralOperandName(self: *Checker, node: NodeId) ?[]const u8 {
        return switch (self.hir.kindOf(node)) {
            .literal_null => "null",
            .literal_undefined => "undefined",
            else => null,
        };
    }

    fn reportNullishLiteralBinaryOperand(self: *Checker, node: NodeId, name: []const u8) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "The value '{s}' cannot be used here.",
            .{name},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.nullish_relational_operand,
            .message = msg,
        });
    }

    fn reportInOperandLeft(self: *Checker, node: NodeId, t: TypeId) CheckError!void {
        const arena = self.diag_arena.allocator();
        const type_text = (try self.simpleDiagnosticTypeName(t)) orelse "";
        const msg = if (type_text.len > 0)
            try std.fmt.allocPrint(arena, "Type '{s}' is not assignable to type 'string | number | symbol'.", .{type_text})
        else
            try arena.dupe(u8, "Type is not assignable to type 'string | number | symbol'.");
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.type_not_assignable,
            .message = msg,
        });
    }

    fn reportInOperandRight(self: *Checker, node: NodeId, t: TypeId) CheckError!void {
        const arena = self.diag_arena.allocator();
        const type_text = (try self.simpleDiagnosticTypeName(t)) orelse "";
        const msg = if (type_text.len > 0)
            try std.fmt.allocPrint(arena, "Type '{s}' is not assignable to type 'object'.", .{type_text})
        else
            try arena.dupe(u8, "Type is not assignable to type 'object'.");
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.type_not_assignable,
            .message = msg,
        });
    }

    fn relationalTypeHasNumberLike(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_object or f.is_object_type or f.is_signature or f.is_tuple) return false;
        // Numeric enum nominal types render as `number & { __enum:X }`.
        // Treat the intersection as number-like so relational compare
        // with `number` / another numeric enum doesn't fire TS2365.
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (member == types.Primitive.number_t) return true;
            }
            return false;
        }
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.relationalTypeHasNumberLike(member)) return true;
            }
        }
        return f.is_number;
    }

    fn relationalTypeHasObjectLike(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_object or f.is_object_type or f.is_signature or f.is_tuple) return true;
        if (f.is_intersection) {
            // A numeric enum nominal (`number & { __enum:X }`) is
            // primitive-like, not object-like, for relational compares.
            for (self.interner.intersectionMembers(t)) |member| {
                if (member == types.Primitive.number_t) return false;
            }
            return true;
        }
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.relationalTypeHasObjectLike(member)) return true;
            }
        }
        return false;
    }

    fn isUnconstrainedTypeParameter(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        return f.is_type_parameter and self.typeParameterConstraint(t) == null;
    }

    fn isConstrainedTypeParameter(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (!f.is_type_parameter) return false;
        const constraint = self.typeParameterConstraint(t) orelse return false;
        return constraint != t;
    }

    /// Detect the parser's `++x`/`x--` desugaring shape: the
    /// assignment value is a literal `1` whose span sits at the
    /// operator-token slot — outside the target's span. Used so
    /// arithmetic-operand diagnostics on update-expression operands
    /// render as TS2356 instead of TS2362/TS2363.
    fn assignmentIsSynthesizedUpdate(self: *Checker, node: NodeId, a: hir_mod.AssignmentPayload) bool {
        if (self.hir.kindOf(a.value) != .literal_number) return false;
        if (hir_mod.literalNumberOf(self.hir, a.value) != 1.0) return false;
        const value_span = self.hir.spanOf(a.value);
        // Synthesised `1` carries the `++`/`--` operator token's span
        // (2 chars wide). A user-written `1` literal is 1 char. This
        // distinguishes `++x` from `x += 1` / `x -= 1`, which would
        // otherwise both match the postfix-span shape below.
        if (value_span.end - value_span.start != 2) return false;
        const target_span = self.hir.spanOf(a.target);
        const node_span = self.hir.spanOf(node);
        // Prefix `++x`: value span starts at the assignment start,
        // before the target span.
        const is_prefix_shape = value_span.start == node_span.start and
            value_span.end <= target_span.start;
        // Postfix `x++`: value span ends at the assignment end,
        // after the target span.
        const is_postfix_shape = value_span.end == node_span.end and
            value_span.start >= target_span.end;
        return is_prefix_shape or is_postfix_shape;
    }

    fn loweredLogicalAssignmentAssignableToTarget(self: *Checker, target: NodeId, value: NodeId, target_t: TypeId) CheckError!bool {
        if (target == hir_mod.none_node_id or value == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(value) != .logical_op) return false;
        const l = hir_mod.logicalOf(self.hir, value);
        if (self.hir.kindOf(target) != .identifier or self.hir.kindOf(l.lhs) != .identifier) return false;
        if (hir_mod.identifierOf(self.hir, target).name != hir_mod.identifierOf(self.hir, l.lhs).name) return false;
        const lhs_t = self.hir.typeOf(l.lhs);
        const rhs_t = self.hir.typeOf(l.rhs);
        const lhs_ok = lhs_t == types.Primitive.none or (self.engine.isAssignableTo(lhs_t, target_t) catch true);
        const rhs_ok = (try self.literalExpressionAssignableToTarget(l.rhs, target_t)) or
            (try self.templateExpressionAssignableToType(l.rhs, target_t)) or
            (self.engine.isAssignableTo(rhs_t, target_t) catch true);
        return lhs_ok and rhs_ok;
    }

    fn genericSignatureAssignmentAssignable(self: *Checker, source: TypeId, target: TypeId) bool {
        if (source >= self.interner.pool.typeCount() or target >= self.interner.pool.typeCount()) return false;
        if (!self.interner.isSignature(source) or !self.interner.isSignature(target)) return false;
        if (!self.containsFreeTypeParameter(source) or !self.containsFreeTypeParameter(target)) return false;
        if (self.interner.signatureParams(source).len != self.interner.signatureParams(target).len) return false;
        return self.interner.signatureParams(source).len == 0;
    }

    fn relationalComparisonInvalid(self: *Checker, lhs: TypeId, rhs: TypeId) bool {
        const lhs_tp = self.isUnconstrainedTypeParameter(lhs);
        const rhs_tp = self.isUnconstrainedTypeParameter(rhs);
        if (lhs_tp and rhs_tp and lhs != rhs) return true;
        if ((lhs_tp and self.relationalTypeHasNumberLike(rhs)) or
            (rhs_tp and self.relationalTypeHasNumberLike(lhs)))
        {
            return true;
        }
        if ((self.relationalTypeHasObjectLike(lhs) and self.relationalTypeHasNumberLike(rhs)) or
            (self.relationalTypeHasObjectLike(rhs) and self.relationalTypeHasNumberLike(lhs)))
        {
            return true;
        }
        return false;
    }

    fn reportRelationalOperatorCannotBeApplied(self: *Checker, node: NodeId, op: []const u8) CheckError!void {
        try self.reportRelationalOperatorCannotBeAppliedWithTypes(node, op, types.Primitive.none, types.Primitive.none);
    }

    fn reportRelationalOperatorCannotBeAppliedWithTypes(
        self: *Checker,
        node: NodeId,
        op: []const u8,
        lhs_t: TypeId,
        rhs_t: TypeId,
    ) CheckError!void {
        // Prefer tsc's render shape when both operand types have
        // printable names: `Operator '>=' cannot be applied to types
        // 'A' and 'B'.` Fall back to the bare wording otherwise so we
        // never half-render.
        if (lhs_t != types.Primitive.none and rhs_t != types.Primitive.none) {
            if (try self.allocSimpleTypeName(lhs_t)) |left_name| {
                if (try self.allocSimpleTypeName(rhs_t)) |right_name| {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Operator '{s}' cannot be applied to types '{s}' and '{s}'.",
                        .{ op, left_name, right_name },
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.operator_cannot_be_applied,
                        .message = msg,
                    });
                    return;
                }
            }
        }
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Operator '{s}' cannot be applied to these operand types.",
            .{op},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.operator_cannot_be_applied,
            .message = msg,
        });
    }

    fn typeMaybeStringLike(self: *Checker, t: TypeId) bool {
        const f = self.interner.pool.flagsOf(t);
        if (f.is_string) return true;
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.typeMaybeStringLike(member)) return true;
            }
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.typeMaybeStringLike(member)) return true;
            }
        }
        return false;
    }

    fn typeHasStringPrimitivePart(self: *Checker, t: TypeId) bool {
        const f = self.interner.pool.flagsOf(t);
        if (f.is_string) return true;
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.typeHasStringPrimitivePart(member)) return true;
            }
            return false;
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.typeHasStringPrimitivePart(member)) return true;
            }
            return false;
        }
        return false;
    }

    fn typeMaybeNumericLike(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.typeMaybeNumericLike(member)) return true;
            }
            return false;
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.typeMaybeNumericLike(member)) return true;
            }
            return false;
        }
        if (f.is_boolean or f.is_string or f.is_symbol or f.is_object or f.is_object_type or f.is_signature or f.is_tuple) return false;
        return f.is_number or f.is_bigint;
    }

    fn typeHasNumericPrimitivePart(self: *Checker, t: TypeId) bool {
        const f = self.interner.pool.flagsOf(t);
        if (f.is_number or f.is_bigint) return true;
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.typeHasNumericPrimitivePart(member)) return true;
            }
            return false;
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.typeHasNumericPrimitivePart(member)) return true;
            }
            return false;
        }
        return false;
    }

    fn isInstanceofLeftAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.isInstanceofLeftAllowed(member)) return true;
            }
            return false;
        }
        return f.is_object or f.is_object_type or f.is_signature or f.is_tuple or f.is_type_parameter;
    }

    fn isInstanceofRightAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.isInstanceofRightAllowed(member)) return false;
            }
            return true;
        }
        if (f.is_signature) return true;
        if (f.is_object_type) return true;
        if (f.is_intersection) return true;
        return false;
    }

    fn isInLeftOperandAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.isInLeftOperandAllowed(member)) return false;
            }
            return true;
        }
        if (f.is_intersection) {
            // Numeric enums are encoded as `number & { __enum:E }`;
            // tsc treats them as `number`-like for `in` LHS. Accept
            // any intersection whose primitive backbone is number,
            // string, or symbol (the allowed leaf kinds).
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.isInLeftOperandAllowed(member)) return true;
            }
            return false;
        }
        if (f.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return self.isInLeftOperandAllowed(constraint);
        }
        if (f.is_keyof) return true;
        return f.is_string or f.is_number or f.is_symbol;
    }

    fn isInRightOperandAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.isInRightOperandAllowed(member)) return false;
            }
            return true;
        }
        if (f.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return self.isInRightOperandAllowed(constraint);
        }
        return f.is_object or f.is_object_type or f.is_signature or f.is_tuple;
    }

    fn expressionHasObservableSideEffect(self: *Checker, node: NodeId) bool {
        return switch (self.hir.kindOf(node)) {
            .call_expr, .new_expr, .assignment, .await_expr, .yield_expr => true,
            .unary_op => blk: {
                const u = hir_mod.unaryOf(self.hir, node);
                break :blk u.op == .delete or u.op == .void_;
            },
            .binary_op => blk: {
                const b = hir_mod.binopOf(self.hir, node);
                break :blk self.expressionHasObservableSideEffect(b.lhs) or self.expressionHasObservableSideEffect(b.rhs);
            },
            .logical_op => blk: {
                const l = hir_mod.logicalOf(self.hir, node);
                break :blk self.expressionHasObservableSideEffect(l.lhs) or self.expressionHasObservableSideEffect(l.rhs);
            },
            .conditional => blk: {
                const c = hir_mod.conditionalOf(self.hir, node);
                break :blk self.expressionHasObservableSideEffect(c.cond) or
                    self.expressionHasObservableSideEffect(c.then_branch) or
                    self.expressionHasObservableSideEffect(c.else_branch);
            },
            else => false,
        };
    }

    fn comparisonOperandType(self: *Checker, operand: NodeId, checked_t: TypeId) CheckError!TypeId {
        if (self.hir.kindOf(operand) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, operand);
            if (self.enclosingLoopBodyAssignsIdentifier(operand, id.name)) {
                const declared_t = self.typeOfIdentifierDeclared(operand);
                if (declared_t != types.Primitive.none and
                    declared_t != types.Primitive.any and
                    declared_t != types.Primitive.unknown)
                {
                    return declared_t;
                }
            }
        }
        return (try self.expressionNarrowLiteralType(operand)) orelse checked_t;
    }

    fn enclosingLoopBodyAssignsIdentifier(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            switch (self.hir.kindOf(cur)) {
                .while_stmt => return self.nodeAssignsIdentifier(hir_mod.whileOf(self.hir, cur).body, name),
                .do_while_stmt => return self.nodeAssignsIdentifier(hir_mod.doWhileOf(self.hir, cur).body, name),
                .for_stmt => return self.nodeAssignsIdentifier(hir_mod.forStmtOf(self.hir, cur).body, name),
                .for_in_stmt, .for_of_stmt => return self.nodeAssignsIdentifier(hir_mod.forInOf(self.hir, cur).body, name),
                .fn_decl, .fn_expr, .arrow_fn => return false,
                else => {},
            }
        }
        return false;
    }

    fn expressionNeverNullishForNullishDiag(self: *Checker, node: NodeId, t: TypeId) bool {
        if (self.typeIsAnyLike(t) or self.typeIsPossiblyNullish(t)) return false;
        return switch (self.hir.kindOf(node)) {
            .literal_string,
            .literal_number,
            .literal_bigint,
            .literal_bool,
            .object_literal,
            .array_literal,
            .fn_decl,
            .fn_expr,
            .arrow_fn,
            => true,
            else => false,
        };
    }

    fn checkBinop(self: *Checker, node: NodeId) CheckError!TypeId {
        const b = hir_mod.binopOf(self.hir, node);
        const lhs = try self.checkExpression(b.lhs);
        const rhs = try self.checkExpression(b.rhs);
        return switch (b.op) {
            // Arithmetic — number unless either side is string (matches JS).
            .add => blk: {
                // tsc only emits TS2469 for symbol-typed operands when
                // the OTHER operand is string-like or any-like (the
                // mixed-with-string/any case where string concat is
                // ambiguous). When both sides are symbol/numeric/etc.
                // the TS2365 "Operator '+' cannot be applied" diagnostic
                // below covers it instead. Mirrors fixture
                // `symbolType6.ts` rows for `s + ""` (string side
                // present → TS2469) versus `s + s` / `s + 0` (no
                // string side → TS2365 only).
                const lhs_has_sym = self.typeContainsSymbol(lhs);
                const rhs_has_sym = self.typeContainsSymbol(rhs);
                if (lhs_has_sym or rhs_has_sym) {
                    const other = if (lhs_has_sym) rhs else lhs;
                    const other_partner_ok = self.typeMaybeStringLike(other) or self.typeIsAnyLike(other);
                    if (other_partner_ok) {
                        const anchor = if (lhs_has_sym) b.lhs else b.rhs;
                        const pos = self.symbolOperandAnchorPos(anchor);
                        try self.reportSymbolOperatorAt(anchor, pos, "+");
                    }
                }
                // tsc routes binary `+` through `checkNonNullType` on
                // each operand UNLESS one side is already string-like
                // (in which case `+` becomes string concat). The
                // checkNonNullType branch fires TS18050 whenever the
                // operand node is the literal `null` keyword or the
                // `undefined` identifier. Mirror that gate here — `any`
                // is "assignable to string-like" in tsgo (its kind
                // check returns true for any), so an `any` partner
                // suppresses the diagnostic. Fixtures:
                //   - additionOperatorWithUndefinedValueAndValidOperator
                //   - additionOperatorWithOnlyNullValueOrUndefinedValue
                //   - additionOperatorWithNullValueAndInvalidOperator
                const add_string_like = self.typeMaybeStringLike(lhs) or self.typeMaybeStringLike(rhs);
                const add_any_like = self.typeIsAnyLike(lhs) or self.typeIsAnyLike(rhs);
                var lhs_eff = lhs;
                var rhs_eff = rhs;
                if (!add_string_like and !add_any_like) {
                    // After checkNonNullType, a literal null/undefined
                    // operand contributes the non-nullable variant of
                    // its type — and because tsc emits TS18050 and
                    // returns errorType (never-like) on such operands,
                    // the downstream `Operator '+' cannot be applied`
                    // diagnostic is suppressed. Mirror that: treat the
                    // literal-nullish side as any-like for the
                    // `Operator '+'` decision, but still emit the
                    // TS18050 anchor.
                    if (self.nullishLiteralOperandName(b.lhs)) |name| {
                        try self.reportNullishLiteralBinaryOperand(b.lhs, name);
                        lhs_eff = types.Primitive.any;
                    }
                    if (self.nullishLiteralOperandName(b.rhs)) |name| {
                        try self.reportNullishLiteralBinaryOperand(b.rhs, name);
                        rhs_eff = types.Primitive.any;
                    }
                }
                if (self.typeMaybeStringLike(lhs_eff) or self.typeMaybeStringLike(rhs_eff)) {
                    break :blk types.Primitive.string_t;
                }
                if (self.typeMaybeNumericLike(lhs_eff) and self.typeMaybeNumericLike(rhs_eff)) {
                    break :blk types.Primitive.number_t;
                }
                if (!self.typeIsAnyLike(lhs_eff) and !self.typeIsAnyLike(rhs_eff)) {
                    // Prefer tsc's type-rich form
                    // `Operator '+' cannot be applied to types 'A' and 'B'.`
                    // when both endpoints have a simple display
                    // name. Mirrors fixtures
                    // `logicalNotOperatorInvalidOperations.ts`
                    // and `additionOperatorWithInvalidOperands.ts`.
                    var emitted = false;
                    if (try self.simpleDiagnosticTypeName(lhs_eff)) |a_name| {
                        if (try self.simpleDiagnosticTypeName(rhs_eff)) |b_name| {
                            const msg = try std.fmt.allocPrint(
                                self.diag_arena.allocator(),
                                "Operator '+' cannot be applied to types '{s}' and '{s}'.",
                                .{ a_name, b_name },
                            );
                            try self.diagnostics.append(self.gpa, .{
                                .node = node,
                                .code = TsCodes.operator_cannot_be_applied,
                                .message = msg,
                            });
                            emitted = true;
                        }
                    }
                    if (!emitted) {
                        try self.report(node, TsCodes.operator_cannot_be_applied, "Operator '+' cannot be applied to these operand types.");
                    }
                }
                break :blk types.Primitive.number_t;
            },
            .sub, .mul, .div, .mod, .pow => blk: {
                // tsc calls `checkNonNullType` on each operand
                // unconditionally for these ops; when the operand
                // node is the literal `null` keyword or the
                // `undefined` identifier it returns the errorType
                // (treated as any-like by `checkArithmeticOperandType`)
                // — that suppresses the TS2362/TS2363 on the SAME
                // side while still letting the OTHER operand's check
                // run. Fixture:
                //   arithmeticOperatorWithNullValueAndInvalidOperands.
                const lhs_nullish = self.nullishLiteralOperandName(b.lhs);
                const rhs_nullish = self.nullishLiteralOperandName(b.rhs);
                if (lhs_nullish) |name| try self.reportNullishLiteralBinaryOperand(b.lhs, name);
                if (rhs_nullish) |name| try self.reportNullishLiteralBinaryOperand(b.rhs, name);
                if (lhs_nullish == null and !self.isArithmeticOperandAllowed(lhs)) {
                    try self.reportArithmeticOperand(b.lhs, TsCodes.arithmetic_left_operand_type, "The left-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                }
                if (rhs_nullish == null and !self.isArithmeticOperandAllowed(rhs)) {
                    try self.reportArithmeticOperand(b.rhs, TsCodes.arithmetic_right_operand_type, "The right-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                }
                break :blk types.Primitive.number_t;
            },
            .bit_and, .bit_or, .bit_xor, .shl, .shr, .shr_unsigned => blk: {
                const lhs_nullish = self.nullishLiteralOperandName(b.lhs);
                const rhs_nullish = self.nullishLiteralOperandName(b.rhs);
                if (lhs_nullish) |name| try self.reportNullishLiteralBinaryOperand(b.lhs, name);
                if (rhs_nullish) |name| try self.reportNullishLiteralBinaryOperand(b.rhs, name);
                if (lhs_nullish == null and !self.isArithmeticOperandAllowed(lhs)) {
                    try self.reportArithmeticOperand(b.lhs, TsCodes.arithmetic_left_operand_type, "The left-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                }
                if (rhs_nullish == null and !self.isArithmeticOperandAllowed(rhs)) {
                    try self.reportArithmeticOperand(b.rhs, TsCodes.arithmetic_right_operand_type, "The right-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                }
                break :blk types.Primitive.number_t;
            },
            .eq, .neq, .eq_strict, .neq_strict => blk: {
                // TS2367: warn when equality compares two known
                // types that have no overlap. Unions compare if any
                // constituent can overlap, primitive intersections
                // compare by constituent, and object intersections
                // use the structural relation as a whole.
                const cmp_lhs = try self.comparisonOperandType(b.lhs, lhs);
                const cmp_rhs = try self.comparisonOperandType(b.rhs, rhs);
                if (!try self.typesHaveComparableOverlap(cmp_lhs, cmp_rhs) or
                    self.templateTypesHaveNoOverlap(cmp_lhs, cmp_rhs))
                {
                    try self.reportNoOverlapComparison(node, cmp_lhs, cmp_rhs);
                }
                break :blk types.Primitive.boolean_t;
            },
            .lt, .le, .gt, .ge => blk: {
                const op_text = switch (b.op) {
                    .lt => "<",
                    .le => "<=",
                    .gt => ">",
                    .ge => ">=",
                    else => unreachable,
                };
                if (self.typeContainsSymbol(lhs) or self.typeContainsSymbol(rhs)) {
                    // tsc anchors TS2469 at the symbol-typed operand,
                    // not the whole binop. When BOTH sides contain
                    // symbol, the LHS wins. Mirrors fixtures
                    // `symbolType8.ts(11,6)` (RHS-only) and
                    // `symbolType8.ts(12,1)` (LHS). When the operand
                    // is parenthesized the span starts at `(`, so we
                    // include any wrapping parens on the anchor.
                    const anchor = if (self.typeContainsSymbol(lhs)) b.lhs else b.rhs;
                    const pos = self.symbolOperandAnchorPos(anchor);
                    try self.reportSymbolOperatorAt(anchor, pos, op_text);
                } else {
                    // tsc fires TS18050 on EACH nullish operand of a
                    // relational comparison, not just the first.
                    // Mirrors `comparisonOperatorWithIdenticalPrimitiveType.ts`
                    // where `null < null` emits at both operand
                    // columns (15,11) AND (15,18). Equality ops
                    // (==, !=, ===, !==) do NOT trigger TS18050 in
                    // tsc — only ordered comparisons (lt/le/gt/ge).
                    const lhs_nullish = self.strict_flags.strict_null_checks and self.typeIsExactNullish(lhs);
                    const rhs_nullish = self.strict_flags.strict_null_checks and self.typeIsExactNullish(rhs);
                    if (lhs_nullish) try self.reportNullishRelationalOperand(b.lhs, lhs);
                    if (rhs_nullish) try self.reportNullishRelationalOperand(b.rhs, rhs);
                    if (!lhs_nullish and !rhs_nullish and (!self.isRelationalOperandAllowed(lhs) or
                        !self.isRelationalOperandAllowed(rhs) or
                        self.relationalComparisonInvalid(lhs, rhs)))
                    {
                        try self.reportRelationalOperatorCannotBeAppliedWithTypes(node, op_text, lhs, rhs);
                    }
                }
                break :blk types.Primitive.boolean_t;
            },
            .instanceof => blk: {
                if (!self.isInstanceofLeftAllowed(lhs)) {
                    try self.report(b.lhs, TsCodes.instanceof_left_type, "The left-hand side of an 'instanceof' expression must be of type 'any', an object type or a type parameter.");
                }
                if (!self.isInstanceofRightAllowed(rhs)) {
                    try self.report(b.rhs, TsCodes.instanceof_right_type, "The right-hand side of an 'instanceof' expression must be either of type 'any', a class, function, or other type assignable to the 'Function' interface type, or an object type with a 'Symbol.hasInstance' method.");
                }
                break :blk types.Primitive.boolean_t;
            },
            .in => blk: {
                // `in`: tsc routes both operands through
                // `checkNonNullType` first, which fires TS18050
                // when the operand source is the literal `null`
                // keyword or the `undefined` identifier. The
                // operand-kind check fires AFTER and is gated on
                // a non-error result type, so a nullish-literal
                // operand suppresses the TS2322 on the SAME side
                // while the OTHER operand still validates.
                // Fixture: `inOperatorWithInvalidOperands.ts`.
                const lhs_nullish = self.nullishLiteralOperandName(b.lhs);
                const rhs_nullish = self.nullishLiteralOperandName(b.rhs);
                if (lhs_nullish) |name| try self.reportNullishLiteralBinaryOperand(b.lhs, name);
                if (rhs_nullish) |name| try self.reportNullishLiteralBinaryOperand(b.rhs, name);
                if (lhs_nullish == null and !self.isInLeftOperandAllowed(lhs)) {
                    try self.reportInOperandLeft(b.lhs, lhs);
                }
                if (rhs_nullish == null and !self.isInRightOperandAllowed(rhs)) {
                    try self.reportInOperandRight(b.rhs, rhs);
                }
                break :blk types.Primitive.boolean_t;
            },
            .comma => blk: {
                if (!self.sourceHasAllowUnreachableTrueDirective() and !self.expressionHasObservableSideEffect(b.lhs)) {
                    try self.report(b.lhs, TsCodes.comma_left_unused, "Left side of comma operator is unused and has no side effects.");
                }
                break :blk rhs;
            },
        };
    }

    fn checkUnary(self: *Checker, node: NodeId) CheckError!TypeId {
        const u = hir_mod.unaryOf(self.hir, node);
        const delete_operand_is_this = u.op == .delete and self.hir.kindOf(u.operand) == .identifier and
            std.mem.eql(u8, self.string_interner.get(hir_mod.identifierOf(self.hir, u.operand).name), "this");
        const operand_t = if (delete_operand_is_this)
            types.Primitive.any
        else
            try self.checkExpression(u.operand);
        return switch (u.op) {
            .neg, .plus, .bit_not => blk: {
                if (self.typeContainsSymbol(operand_t)) {
                    // tsc anchors TS2469 at the operand (including any
                    // wrapping parens), not at the leading operator.
                    // Mirrors fixtures `symbolType3.ts(7,3)` /
                    // `(12,2)` for `+ Symbol()` and `+(Symbol() || 0)`.
                    const pos = self.symbolOperandAnchorPos(u.operand);
                    try self.reportSymbolOperatorAt(u.operand, pos, switch (u.op) {
                        .neg => "-",
                        .plus => "+",
                        .bit_not => "~",
                        else => unreachable,
                    });
                }
                // tsc fires TS18050 ("The value 'null' / 'undefined'
                // cannot be used here.") when the operand of `-`, `+`
                // or `~` is a literal `null` or `undefined`. Mirrors
                // fixtures `negateOperatorWithAnyOtherType.ts(34,…)`,
                // `bitwiseNotOperatorWithAnyOtherType.ts(34,…)`, and
                // friends — the diagnostic is anchored at the operand
                // start, not the operator. Emits regardless of
                // `strictNullChecks` since tsc's grammar-level check
                // doesn't gate on it.
                if (self.typeIsExactNullish(operand_t)) {
                    try self.reportNullishRelationalOperand(u.operand, operand_t);
                }
                break :blk types.Primitive.number_t;
            },
            .not => blk: {
                // `!{ … }` / `![ … ]` / `!fn` / `!/re/` always evaluate to
                // `false` because the operand is a truthy literal.
                // tsc fires TS2872 ("This kind of expression is
                // always truthy.") at the operand. Restrict to the
                // operand kinds tsc actually flags (object literal,
                // array literal, function-shaped, regex literal) — `!"x"` / `!0`
                // are intentionally not flagged.
                switch (self.hir.kindOf(u.operand)) {
                    .object_literal, .array_literal, .fn_decl, .fn_expr, .arrow_fn, .literal_regex => {
                        try self.report(u.operand, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
                    },
                    .literal_string => {
                        // tsc fires TS2873 ("This kind of expression
                        // is always falsy.") for `!""` — the empty
                        // string is the only falsy string literal.
                        const s = hir_mod.literalStringOf(self.hir, u.operand);
                        if (self.string_interner.get(s.value).len == 0) {
                            try self.report(u.operand, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
                        }
                    },
                    // `!null` / `!undefined` — both operands are the
                    // canonical falsy literals. tsc emits TS2873 at
                    // the operand. Mirrors fixture
                    // `logicalNotOperatorWithAnyOtherType` rows
                    // `var ResultIsBoolean7 = !undefined` and
                    // `var ResultIsBoolean8 = !null` and the LHS-of-`&&`
                    // path already handled at the logical-op site.
                    .literal_null, .literal_undefined => {
                        try self.report(u.operand, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
                    },
                    else => {},
                }
                break :blk types.Primitive.boolean_t;
            },
            .typeof => types.Primitive.string_t,
            .void_ => types.Primitive.undefined_t,
            .delete => blk: {
                const operand_kind = self.hir.kindOf(u.operand);
                if (operand_kind == .identifier) {
                    // TS always parses in strict mode, so this is a
                    // grammar error regardless of an explicit "use
                    // strict" directive. TS2703 still fires below
                    // because an identifier is not a property reference.
                    // `this` is parsed as an identifier in our HIR but
                    // is a reserved keyword, not a variable binding;
                    // upstream restricts TS1102 to real identifiers and
                    // only emits TS2703 for `delete this`. Mirrors
                    // `parserStrictMode16.ts(2,8)` baseline.
                    const ident_name = hir_mod.identifierOf(self.hir, u.operand).name;
                    const is_this_keyword = std.mem.eql(u8, self.string_interner.get(ident_name), "this");
                    if (!is_this_keyword) {
                        try self.report(u.operand, TsCodes.delete_identifier_strict_mode, "'delete' cannot be called on an identifier in strict mode.");
                    }
                }
                if (operand_kind != .member_access and operand_kind != .element_access) {
                    try self.report(u.operand, TsCodes.delete_operand_property_reference, "The operand of a 'delete' operator must be a property reference.");
                } else if (self.strict_flags.strict_null_checks and !self.deleteOperandAllowed(u.operand)) {
                    try self.report(u.operand, TsCodes.delete_operand_must_be_optional, "The operand of a 'delete' operator must be optional.");
                }
                break :blk types.Primitive.boolean_t;
            },
        };
    }

    fn checkLogical(self: *Checker, node: NodeId) CheckError!TypeId {
        const l = hir_mod.logicalOf(self.hir, node);
        const lhs = try self.checkExpression(l.lhs);
        const rhs = switch (l.op) {
            .@"and" => blk: {
                try self.pushNarrowScope();
                try self.applyTypeGuard(l.lhs, true);
                try self.reportAliasAssignmentAndToStringImpossible(l.lhs, l.rhs);
                const t = try self.checkExpression(l.rhs);
                self.popNarrowScope();
                break :blk t;
            },
            .@"or" => blk: {
                try self.pushNarrowScope();
                try self.applyTypeGuard(l.lhs, false);
                const t = try self.checkExpression(l.rhs);
                self.popNarrowScope();
                break :blk t;
            },
            .nullish => try self.checkExpression(l.rhs),
        };
        // `a ?? b` — when `a` is non-null/undefined the result is
        // `a`'s type minus null/undefined; otherwise it's `b`'s
        // type. The runtime forks on nullish, so the result type
        // is `(a minus null|undefined) | b`. For `&&`/`||` we keep
        // the existing simple union — TS narrows further but our
        // current relation engine doesn't yet model truthiness.
        if (l.op == .nullish) {
            if (self.expressionNeverNullishForNullishDiag(l.lhs, lhs)) {
                try self.report(l.lhs, TsCodes.nullish_rhs_unreachable, "Right operand of ?? is unreachable because the left operand is never nullish.");
            }
            const lhs_non_null = self.subtractNullUndefined(lhs) catch lhs;
            return self.interner.internUnion(&.{ lhs_non_null, rhs }) catch error.OutOfMemory;
        }
        if (lhs == types.Primitive.void_t) {
            try self.report(l.lhs, TsCodes.void_truthiness, "An expression of type 'void' cannot be tested for truthiness.");
        }
        if (l.op == .@"or" and self.hir.kindOf(l.lhs) == .object_literal) {
            // tsc anchors at the opening `(` for parenthesized LHS
            // forms like `({}) || s`. Mirrors fixture
            // `symbolType11.ts(7,1)`.
            const lhs_pos = self.symbolOperandAnchorPos(l.lhs);
            try self.reportAt(l.lhs, lhs_pos, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
        }
        if (l.op == .@"and" and self.expressionAlwaysTruthyInLogicalAnd(l.lhs, lhs)) {
            try self.report(l.lhs, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
        }
        if (l.op == .@"or" and self.expressionAlwaysFalsyInLogicalOr(l.lhs, lhs)) {
            try self.report(l.lhs, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
        }
        // tsc also fires TS2873 on the LHS of `&&` when it is a
        // literal `null` / `undefined` (the always-falsy gate
        // short-circuits the right operand). Mirrors fixtures like
        // `logicalAndOperatorWithEveryType.ts` rows 23-24 and the
        // null/undefined repeats every 11 lines.
        if (l.op == .@"and") {
            switch (self.hir.kindOf(l.lhs)) {
                .literal_null, .literal_undefined => {
                    try self.report(l.lhs, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
                },
                else => {},
            }
        }
        if (l.op == .@"or" and self.hir.kindOf(l.lhs) == .literal_string) {
            const lit = hir_mod.literalStringOf(self.hir, l.lhs);
            if (self.string_interner.get(lit.value).len == 0) {
                try self.report(l.lhs, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
            }
        }
        const lhs_result = try self.expressionLiteralType(l.lhs, lhs);
        const rhs_result = try self.expressionLiteralType(l.rhs, rhs);
        return self.interner.internUnion(&.{ lhs_result, rhs_result }) catch error.OutOfMemory;
    }

    fn reportAliasAssignmentAndToStringImpossible(self: *Checker, lhs: NodeId, rhs: NodeId) CheckError!void {
        if (!self.nodeHasLogicalAncestor(lhs, .@"or")) return;
        if (self.hir.kindOf(lhs) != .assignment) return;
        const member_node = switch (self.hir.kindOf(rhs)) {
            .member_access => rhs,
            .call_expr => blk: {
                const c = hir_mod.callOf(self.hir, rhs);
                if (self.hir.kindOf(c.callee) != .member_access) return;
                break :blk c.callee;
            },
            else => return,
        };
        const a = hir_mod.assignmentOf(self.hir, lhs);
        if (a.op != null or self.hir.kindOf(a.target) != .identifier or self.hir.kindOf(a.value) != .identifier) return;
        const m = hir_mod.memberOf(self.hir, member_node);
        if (self.hir.kindOf(m.object) != .identifier) return;
        if (!std.mem.eql(u8, self.string_interner.get(m.name), "toString")) return;
        const value_id = hir_mod.identifierOf(self.hir, a.value);
        const object_id = hir_mod.identifierOf(self.hir, m.object);
        if (value_id.name != object_id.name) return;
        try self.reportPropertyDoesNotExist(member_node, m.name);
    }

    fn nodeHasLogicalAncestor(self: *Checker, node: NodeId, op: hir_mod.LogicalOp) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) != .logical_op) continue;
            if (hir_mod.logicalOf(self.hir, cur).op == op) return true;
        }
        return false;
    }

    fn expressionAlwaysTruthyInLogicalAnd(self: *Checker, node: NodeId, t: TypeId) bool {
        _ = t;
        return switch (self.hir.kindOf(node)) {
            .literal_number => hir_mod.literalNumberOf(self.hir, node) != 0,
            // Function expressions / arrow functions / function declarations /
            // regex literals are heap-allocated objects — always truthy.
            // Mirrors tsc's TS2872 emit at e.g. `contextuallyTypeLogicalAnd03.ts`.
            .object_literal, .array_literal, .fn_expr, .arrow_fn, .fn_decl, .literal_regex => true,
            else => false,
        };
    }

    fn expressionAlwaysFalsyInLogicalOr(self: *Checker, node: NodeId, t: TypeId) bool {
        _ = t;
        return switch (self.hir.kindOf(node)) {
            .literal_null, .literal_undefined => true,
            .unary_op => blk: {
                const u = hir_mod.unaryOf(self.hir, node);
                break :blk u.op == .void_;
            },
            else => false,
        };
    }

    fn checkConditional(self: *Checker, node: NodeId) CheckError!TypeId {
        const c = hir_mod.conditionalOf(self.hir, node);
        _ = try self.checkExpression(c.cond);
        try self.reportStaticTruthiness(c.cond);
        // TS narrows through `cond ? then : else`: the test expression's
        // truthy guard applies inside `then`, the falsy guard inside
        // `else`. Mirror the if-statement scoping so e.g.
        // `x ? x.length : -1` types `x` as the truthy half in the
        // then-branch.
        try self.pushNarrowScope();
        try self.applyTypeGuard(c.cond, true);
        const tt = try self.checkExpression(c.then_branch);
        self.popNarrowScope();
        try self.pushNarrowScope();
        try self.applyTypeGuard(c.cond, false);
        const ff = try self.checkExpression(c.else_branch);
        self.popNarrowScope();
        return self.interner.internUnion(&.{ tt, ff }) catch error.OutOfMemory;
    }

    fn reportStaticTruthiness(self: *Checker, node: NodeId) CheckError!void {
        switch (self.hir.kindOf(node)) {
            .object_literal, .array_literal, .fn_decl, .fn_expr, .arrow_fn, .literal_regex => {
                try self.report(node, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
            },
            .literal_string => {
                const lit = hir_mod.literalStringOf(self.hir, node);
                if (self.string_interner.get(lit.value).len == 0) {
                    try self.report(node, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
                } else {
                    try self.report(node, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
                }
            },
            .literal_number => {
                const value = hir_mod.literalNumberOf(self.hir, node);
                if (value == 0) {
                    try self.report(node, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
                } else {
                    try self.report(node, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
                }
            },
            // Literal `null` / `undefined` — always falsy. tsc fires
            // TS2873 in any truthiness slot (conditional cond,
            // if-stmt, while-stmt). Fixture coverage includes
            // `conditionalOperatorConditoinIsAnyType.ts` rows 26-31.
            .literal_null, .literal_undefined => {
                try self.report(node, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
            },
            else => {},
        }
    }

    /// Variant of `reportStaticTruthiness` used for if/while/do-while
    /// statement conditions. Matches tsgo's pattern: numeric & boolean
    /// literals are excluded (tsc skips them in statement contexts —
    /// see baselines/reference/ifDoWhileStatements.errors.txt where
    /// `if (true)` and `if (0.0)` are NOT flagged), but `null`,
    /// `undefined`, and the empty string ARE flagged as falsy.
    /// Constructor calls (`new Foo()`) are not flagged either.
    fn reportStaticTruthinessForStatementCond(self: *Checker, node: NodeId) CheckError!void {
        switch (self.hir.kindOf(node)) {
            .object_literal, .array_literal, .arrow_fn, .literal_regex => {
                try self.report(node, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
            },
            .literal_null, .literal_undefined => {
                try self.report(node, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
            },
            .literal_string => {
                const lit = hir_mod.literalStringOf(self.hir, node);
                if (self.string_interner.get(lit.value).len == 0) {
                    try self.report(node, TsCodes.expression_always_falsy, "This kind of expression is always falsy.");
                } else {
                    try self.report(node, TsCodes.expression_always_truthy, "This kind of expression is always truthy.");
                }
            },
            else => {},
        }
    }

    fn isElseIfStatement(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id or self.hir.kindOf(parent) != .if_stmt) return false;
        return hir_mod.ifOf(self.hir, parent).else_branch == node;
    }

    /// Generic call-site instantiation. For each parameter slot
    /// whose type is a type-parameter id, record a substitution
    /// `param_ts[i] -> arg_ts[i]`. Then walk `ret_type` and
    /// substitute any type-parameter occurrences. Returns the
    /// substituted return type. Falls through to `ret_type`
    /// unchanged if the signature isn't generic or substitution
    /// can't determine a single type.
    fn instantiateReturn(
        self: *Checker,
        param_ts: []const TypeId,
        arg_ts: []const TypeId,
        ret_type: TypeId,
    ) !TypeId {
        // Build a map: type-parameter-id -> inferred-type
        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);

        const n = @min(param_ts.len, arg_ts.len);
        for (0..n) |i| {
            try self.inferFromPair(param_ts[i], arg_ts[i], &subs);
        }
        // Default-type fallback: walk every TypeId reachable from the
        // signature (params + return) and, for any type-parameter id
        // not already substituted, fall back to its declaration-site
        // default (`<T = string>`). Lets `f()` resolve `T` to `string`
        // when no value pins it. The walker reaches into unions /
        // intersections so optional `x?: T` (lowered to `T |
        // undefined`) still surfaces the underlying T.
        var visited_defaults: std.AutoHashMapUnmanaged(TypeId, void) = .empty;
        defer visited_defaults.deinit(self.gpa);
        for (param_ts) |p| try self.collectFreeTypeParamDefaults(p, &subs, &visited_defaults);
        try self.collectFreeTypeParamDefaults(ret_type, &subs, &visited_defaults);
        if (ret_type < self.interner.pool.typeCount() and self.interner.pool.flagsOf(ret_type).is_type_parameter) {
            var visited_fallbacks: std.AutoHashMapUnmanaged(TypeId, void) = .empty;
            defer visited_fallbacks.deinit(self.gpa);
            try self.collectFreeTypeParamFallbacks(ret_type, &subs, &visited_fallbacks);
        }
        if (subs.count() == 0) return ret_type;
        return self.substituteType(ret_type, &subs);
    }

    /// Widen a literal type (`42`, `"hi"`, `true`) to its base
    /// primitive (`number`, `string`, `boolean`) when binding a fresh
    /// type-parameter from an argument. Matches tsc's call-site
    /// behavior: `id(42)` infers `T = number`, not `T = 42`. Anything
    /// non-literal is returned unchanged.
    fn widenForInference(self: *Checker, t: TypeId) TypeId {
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_literal) {
            if (flags.is_string) return types.Primitive.string_t;
            if (flags.is_number) return types.Primitive.number_t;
            if (flags.is_boolean) return types.Primitive.boolean_t;
            if (flags.is_bigint) return types.Primitive.bigint_t;
            return t;
        }
        // Union of literals: array literals like `[1, 2, 3]` produce
        // a numeric indexer typed as `1 | 2 | 3`. Widen each branch
        // and, if all collapse to the same primitive, return that
        // primitive directly. Otherwise leave the union shape alone
        // (the user wrote a heterogeneous array).
        if (flags.is_union) {
            const members = self.interner.unionMembers(t);
            if (members.len == 0) return t;
            const first = self.widenForInference(members[0]);
            for (members[1..]) |m| {
                if (self.widenForInference(m) != first) return t;
            }
            return first;
        }
        return t;
    }

    /// Recursively infer type-parameter substitutions by walking the
    /// parameter shape and the argument shape in parallel. Handles:
    ///
    ///   - Bare type parameter: `T` against `number` → `T = number`.
    ///     Literals are widened to their base primitive (matches tsc).
    ///   - Array element: `T[]` against `number[]` → `T = number`.
    ///     Arrays are object types with a number indexer, so we read
    ///     `objectNumberIndex` on both sides.
    ///   - Function param: `(x: T) => U` against `(x: number) => string`
    ///     → `T = number, U = string`.
    ///   - Object property: `{ value: T }` against `{ value: number }`
    ///     → `T = number`. Walks every member by name.
    ///   - Union / intersection on the parameter side: recurse into
    ///     each member against the same arg (any structural match
    ///     contributes a mapping). Keeps `T | undefined` working.
    ///
    /// First-seen wins on conflict; common-supertype is a follow-up.
    fn inferUnionRemainder(
        self: *Checker,
        param_t: TypeId,
        arg_t: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) CheckError!bool {
        const pool = &self.interner.pool;
        if (arg_t >= pool.typeCount()) return false;
        const a_flags = pool.flagsOf(arg_t);
        if (!a_flags.is_union) return false;

        const param_members = self.interner.unionMembers(param_t);
        var generic_member: TypeId = types.Primitive.none;
        var generic_count: usize = 0;
        var fixed_count: usize = 0;
        for (param_members) |member| {
            if (self.containsFreeTypeParameter(member)) {
                generic_member = member;
                generic_count += 1;
            } else {
                fixed_count += 1;
            }
        }
        if (generic_count != 1 or fixed_count == 0) return false;

        var remaining: std.ArrayListUnmanaged(TypeId) = .empty;
        defer remaining.deinit(self.gpa);
        var removed_fixed = false;
        for (self.interner.unionMembers(arg_t)) |arg_member| {
            var covered_by_fixed = false;
            for (param_members) |param_member| {
                if (self.containsFreeTypeParameter(param_member)) continue;
                if (arg_member == param_member or (self.engine.isAssignableTo(arg_member, param_member) catch false)) {
                    covered_by_fixed = true;
                    break;
                }
            }
            if (covered_by_fixed) {
                removed_fixed = true;
            } else {
                try remaining.append(self.gpa, arg_member);
            }
        }
        if (!removed_fixed or remaining.items.len == 0) return false;

        const inferred_arg = if (remaining.items.len == 1)
            remaining.items[0]
        else
            self.interner.internUnion(remaining.items) catch return error.OutOfMemory;
        try self.inferFromPair(generic_member, inferred_arg, subs);
        return true;
    }

    fn inferFromPair(
        self: *Checker,
        param_t: TypeId,
        arg_t: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) CheckError!void {
        const pool = &self.interner.pool;
        if (param_t >= pool.typeCount()) return;
        if (arg_t >= pool.typeCount()) return;
        const p_flags = pool.flagsOf(param_t);
        const p_payload = pool.payloadOf(param_t);
        // Union/intersection flags are aggregate ORs of their members,
        // so a union containing `T` also has `is_type_parameter`.
        // Dispatch compound containers before the bare type-parameter
        // case or `(T | undefined)[]` will bind the whole union as T.
        if (p_flags.is_union) {
            if (p_payload >= pool.union_payloads.items.len) return;
            if (try self.inferUnionRemainder(param_t, arg_t, subs)) return;
            for (self.interner.unionMembers(param_t)) |um| {
                const uf = pool.flagsOf(um);
                if (uf.is_type_parameter and !uf.is_union and !uf.is_intersection) continue;
                try self.inferFromPair(um, arg_t, subs);
            }
            for (self.interner.unionMembers(param_t)) |um| {
                const uf = pool.flagsOf(um);
                if (!(uf.is_type_parameter and !uf.is_union and !uf.is_intersection)) continue;
                try self.inferFromPair(um, arg_t, subs);
            }
            return;
        }
        if (p_flags.is_intersection) {
            if (p_payload >= pool.intersection_payloads.items.len) return;
            for (self.interner.intersectionMembers(param_t)) |im| {
                try self.inferFromPair(im, arg_t, subs);
            }
            return;
        }
        if (p_flags.is_type_parameter) {
            if (!subs.contains(param_t)) {
                const tp = pool.type_parameter_payloads.items[p_payload];
                var inferred = if (tp.is_const) arg_t else self.widenForInference(arg_t);
                inferred = self.substituteType(inferred, subs) catch inferred;
                if (self.scalarTypeParameterConstraint(param_t)) |raw_constraint_t| {
                    const constraint_t = self.substituteType(raw_constraint_t, subs) catch raw_constraint_t;
                    const candidate_t = if (tp.is_const) inferred else arg_t;
                    if (!(self.engine.isAssignableTo(candidate_t, constraint_t) catch false)) return;
                }
                try subs.put(self.gpa, param_t, inferred);
            }
            return;
        }
        const a_flags = pool.flagsOf(arg_t);
        // Both sides object-typed: match each named member, plus the
        // number indexer (`T[]` parameter / array argument).
        if (p_flags.is_object_type and a_flags.is_object_type) {
            if (p_payload >= pool.object_type_payloads.items.len) return;
            if (pool.payloadOf(arg_t) >= pool.object_type_payloads.items.len) return;
            const p_members = self.interner.objectMembers(param_t);
            for (p_members) |pm| {
                if (self.interner.objectMember(arg_t, pm.name)) |am_t| {
                    try self.inferFromPair(pm.type, am_t, subs);
                }
            }
            const p_num = self.interner.objectNumberIndex(param_t);
            const a_num = self.interner.objectNumberIndex(arg_t);
            if (p_num != types.Primitive.none and a_num != types.Primitive.none) {
                try self.inferFromPair(p_num, a_num, subs);
            }
            const p_str = self.interner.objectStringIndex(param_t);
            const a_str = self.interner.objectStringIndex(arg_t);
            if (p_str != types.Primitive.none and a_str != types.Primitive.none) {
                try self.inferFromPair(p_str, a_str, subs);
            }
            return;
        }
        // Both signatures: match params slot-by-slot and return types.
        if (p_flags.is_signature and a_flags.is_signature) {
            if (p_payload >= pool.signature_payloads.items.len) return;
            if (pool.payloadOf(arg_t) >= pool.signature_payloads.items.len) return;
            const pp = self.interner.signatureParams(param_t);
            const ap = self.interner.signatureParams(arg_t);
            try self.inferRestTupleFromSignatureParams(param_t, pp, ap, subs);
            const m = @min(pp.len, ap.len);
            var source_subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
            defer source_subs.deinit(self.gpa);
            for (0..m) |i| {
                const expected_param = self.substituteType(pp[i], subs) catch pp[i];
                const actual_param = ap[i];
                if ((actual_param == types.Primitive.any or actual_param == types.Primitive.unknown) and
                    self.containsFreeTypeParameter(expected_param))
                {
                    continue;
                }
                const af = pool.flagsOf(actual_param);
                if (af.is_type_parameter) {
                    if (!source_subs.contains(actual_param)) {
                        try source_subs.put(self.gpa, actual_param, expected_param);
                    }
                    continue;
                }
                try self.inferFromPair(expected_param, actual_param, subs);
            }
            if (self.interner.signatureReturn(param_t)) |pr| {
                if (self.interner.signatureReturn(arg_t)) |ar| {
                    const actual_ret = self.substituteType(ar, &source_subs) catch ar;
                    try self.inferFromPair(pr, actual_ret, subs);
                }
            }
            return;
        }
    }

    fn inferRestTupleFromSignatureParams(
        self: *Checker,
        param_sig: TypeId,
        param_params: []const TypeId,
        arg_params: []const TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) CheckError!void {
        if (!self.rest_signatures.contains(param_sig) or param_params.len == 0) return;
        const rest_param_t = param_params[param_params.len - 1];
        if (rest_param_t >= self.interner.pool.typeCount()) return;
        if (!self.interner.pool.flagsOf(rest_param_t).is_type_parameter) return;
        if (subs.contains(rest_param_t)) return;
        const fixed_count = param_params.len - 1;
        if (arg_params.len < fixed_count) return;
        const tuple_t = try self.internTupleFromTypes(arg_params[fixed_count..], false);
        try subs.put(self.gpa, rest_param_t, tuple_t);
    }

    fn signatureHasBareGenericRestParam(self: *Checker, sig: TypeId) bool {
        if (!self.rest_signatures.contains(sig)) return false;
        const params = self.interner.signatureParams(sig);
        if (params.len == 0) return false;
        const rest_param_t = params[params.len - 1];
        if (rest_param_t >= self.interner.pool.typeCount()) return false;
        return self.interner.pool.flagsOf(rest_param_t).is_type_parameter;
    }

    fn internTupleFromTypes(self: *Checker, elem_types: []const TypeId, readonly: bool) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        for (elem_types, 0..) |t, i| {
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{i}) catch continue;
            const name = self.string_interner.intern(name_str) catch return error.OutOfMemory;
            try members.append(self.gpa, .{
                .name = name,
                .type = t,
                .is_optional = false,
                .is_readonly = readonly,
                .is_method = false,
            });
        }
        const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
        const length_t = self.interner.internNumberLiteral(@floatFromInt(elem_types.len)) catch types.Primitive.number_t;
        try members.append(self.gpa, .{
            .name = length_id,
            .type = length_t,
            .is_optional = false,
            .is_readonly = true,
            .is_method = false,
        });
        const elem_union: TypeId = if (elem_types.len == 0)
            types.Primitive.never
        else if (elem_types.len == 1)
            elem_types[0]
        else
            self.interner.internUnion(elem_types) catch types.Primitive.any;
        return self.interner.internObjectTypeWithIndex(members.items, types.Primitive.none, elem_union) catch error.OutOfMemory;
    }

    fn inferFromArgument(
        self: *Checker,
        param_t: TypeId,
        arg_t: TypeId,
        arg_node: NodeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !void {
        if (param_t >= types.Primitive.first_dynamic and
            param_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(param_t).is_intersection)
        {
            if (self.interner.pool.payloadOf(param_t) >= self.interner.pool.intersection_payloads.items.len) return;
            for (self.interner.intersectionMembers(param_t)) |member| {
                try self.inferFromArgument(member, arg_t, arg_node, subs);
            }
            return;
        }
        if (param_t >= types.Primitive.first_dynamic and
            param_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(param_t).is_type_parameter and
            self.interner.typeParameterIsConst(param_t) and
            !subs.contains(param_t))
        {
            var inferred = self.literalizeForAsConst(arg_node, arg_t) catch arg_t;
            inferred = self.substituteType(inferred, subs) catch inferred;
            if (self.scalarTypeParameterConstraint(param_t)) |raw_constraint_t| {
                const constraint_t = self.substituteType(raw_constraint_t, subs) catch raw_constraint_t;
                if (!(self.engine.isAssignableTo(inferred, constraint_t) catch false)) return;
            }
            try subs.put(self.gpa, param_t, inferred);
            return;
        }
        if (param_t >= types.Primitive.first_dynamic and
            param_t < self.interner.pool.typeCount() and
            arg_t >= types.Primitive.first_dynamic and
            arg_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(param_t).is_union and
            self.interner.pool.flagsOf(arg_t).is_object_type)
        {
            for (self.interner.unionMembers(param_t)) |member| {
                if (member >= types.Primitive.first_dynamic and
                    member < self.interner.pool.typeCount() and
                    self.interner.pool.flagsOf(member).is_object_type and
                    (self.engine.isAssignableTo(arg_t, member) catch false))
                {
                    try self.inferFromPair(member, arg_t, subs);
                    return;
                }
            }
        }
        if (self.hir.kindOf(arg_node) == .object_literal and
            param_t >= types.Primitive.first_dynamic and
            param_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(param_t).is_union)
        {
            for (self.interner.unionMembers(param_t)) |member| {
                if (try self.objectLiteralMayMatchTarget(arg_node, member)) {
                    try self.inferFromPair(member, arg_t, subs);
                    return;
                }
            }
        }
        try self.inferFromPair(param_t, arg_t, subs);
    }

    fn inferCallSubstitutions(
        self: *Checker,
        sig: TypeId,
        args: []const NodeId,
        arg_types: []const TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !void {
        if (!self.interner.isSignature(sig)) return;
        const param_ts = self.interner.signatureParams(sig);
        if (self.rest_signatures.contains(sig) and param_ts.len > 0) {
            const fixed_count: usize = param_ts.len - 1;
            const n = @min(fixed_count, arg_types.len);
            for (0..n) |i| {
                // §4.A.X TS 4.0 — signature-typed params still need
                // inference so a bare rest type-param `T extends any[]`
                // in `(...args: T) => R` binds T to the argument
                // signature's positional params as a tuple (handled
                // via inferRestTupleFromSignatureParams inside
                // inferFromPair). Previously this branch skipped
                // signature-typed params entirely, losing the higher-
                // order rest-tuple inference.
                if (self.interner.pool.flagsOf(param_ts[i]).is_signature) {
                    if (self.interner.pool.flagsOf(arg_types[i]).is_signature) {
                        try self.inferFromPair(param_ts[i], arg_types[i], subs);
                    }
                    continue;
                }
                try self.inferFromArgument(param_ts[i], arg_types[i], args[i], subs);
            }
            const rest_arr_t = param_ts[param_ts.len - 1];
            if (rest_arr_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(rest_arr_t).is_type_parameter) {
                return;
            }
            const rest_elem_t = self.interner.objectNumberIndex(rest_arr_t);
            const rest_target_t = if (rest_elem_t != types.Primitive.none) rest_elem_t else rest_arr_t;
            if (rest_target_t < self.interner.pool.typeCount()) {
                var j: usize = fixed_count;
                while (j < arg_types.len) : (j += 1) {
                    var candidate_t = arg_types[j];
                    if (self.hir.kindOf(args[j]) == .spread) {
                        candidate_t = try self.iterableElementType(candidate_t);
                    }
                    try self.inferFromArgument(rest_target_t, candidate_t, args[j], subs);
                }
            }
        } else {
            const n = @min(param_ts.len, arg_types.len);
            for (0..n) |i| {
                // §4.A.X TS 4.0 — signature-vs-signature inference for
                // variadic rest type-params. See the rest-signature
                // branch above for the rationale.
                if (self.interner.pool.flagsOf(param_ts[i]).is_signature) {
                    if (self.interner.pool.flagsOf(arg_types[i]).is_signature) {
                        try self.inferFromPair(param_ts[i], arg_types[i], subs);
                    }
                    continue;
                }
                try self.inferFromArgument(param_ts[i], arg_types[i], args[i], subs);
            }
        }
    }

    /// Walk `t` and, for any encountered type-parameter id with a
    /// declaration-site default that isn't already in `subs`, record
    /// `tp_id -> default`. Used by `instantiateReturn` so optional
    /// params (`x?: T` → `T | undefined`) and nested generics still
    /// surface T.
    fn collectFreeTypeParamDefaults(
        self: *Checker,
        t: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
        visited: *std.AutoHashMapUnmanaged(TypeId, void),
    ) !void {
        if (t < types.Primitive.first_dynamic) return;
        if (t >= self.interner.pool.typeCount()) return;
        if (visited.contains(t)) return;
        try visited.put(self.gpa, t, {});
        const flags = self.interner.pool.flagsOf(t);
        const payload_idx = self.interner.pool.payloadOf(t);
        if (flags.is_type_parameter) {
            if (!subs.contains(t)) {
                if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return;
                const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
                if (tp.default != types.Primitive.none) {
                    try subs.put(self.gpa, t, tp.default);
                }
            }
            return;
        }
        if (flags.is_union) {
            if (payload_idx >= self.interner.pool.union_payloads.items.len) return;
            for (self.interner.unionMembers(t)) |m| try self.collectFreeTypeParamDefaults(m, subs, visited);
            return;
        }
        if (flags.is_intersection) {
            if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return;
            for (self.interner.intersectionMembers(t)) |m| try self.collectFreeTypeParamDefaults(m, subs, visited);
            return;
        }
    }

    fn collectFreeTypeParamFallbacks(
        self: *Checker,
        t: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
        visited: *std.AutoHashMapUnmanaged(TypeId, void),
    ) !void {
        if (t < types.Primitive.first_dynamic) return;
        if (t >= self.interner.pool.typeCount()) return;
        if (visited.contains(t)) return;
        try visited.put(self.gpa, t, {});
        const flags = self.interner.pool.flagsOf(t);
        const payload_idx = self.interner.pool.payloadOf(t);
        if (flags.is_type_parameter) {
            if (self.isThisTypeParameter(t)) return;
            if (!subs.contains(t)) try subs.put(self.gpa, t, types.Primitive.unknown);
            return;
        }
        if (flags.is_union) {
            if (payload_idx >= self.interner.pool.union_payloads.items.len) return;
            for (self.interner.unionMembers(t)) |m| try self.collectFreeTypeParamFallbacks(m, subs, visited);
            return;
        }
        if (flags.is_intersection) {
            if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return;
            for (self.interner.intersectionMembers(t)) |m| try self.collectFreeTypeParamFallbacks(m, subs, visited);
            return;
        }
        if (flags.is_object_type) {
            for (self.interner.objectMembers(t)) |m| try self.collectFreeTypeParamFallbacks(m.type, subs, visited);
            const str_idx = self.interner.objectStringIndex(t);
            if (str_idx != types.Primitive.none) try self.collectFreeTypeParamFallbacks(str_idx, subs, visited);
            const num_idx = self.interner.objectNumberIndex(t);
            if (num_idx != types.Primitive.none) try self.collectFreeTypeParamFallbacks(num_idx, subs, visited);
            return;
        }
        if (flags.is_signature) {
            for (self.interner.signatureParams(t)) |p| try self.collectFreeTypeParamFallbacks(p, subs, visited);
            if (self.interner.signatureReturn(t)) |r| try self.collectFreeTypeParamFallbacks(r, subs, visited);
        }
    }

    /// Substitute occurrences of type-parameter ids in `t` per the
    /// `subs` map. Recurses into compound types — unions,
    /// intersections, signatures, object types — so a parameterized
    /// alias body fully resolves under instantiation.
    fn substituteType(
        self: *Checker,
        t: TypeId,
        subs: *const std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !TypeId {
        if (subs.get(t)) |s| return s;
        if (t >= self.interner.pool.typeCount()) return t;
        const flags = self.interner.pool.flagsOf(t);
        const payload_idx = self.interner.pool.payloadOf(t);
        if (flags.is_union) {
            if (payload_idx >= self.interner.pool.union_payloads.items.len) return t;
            const members = self.interner.unionMembers(t);
            const members_snapshot = try self.gpa.dupe(TypeId, members);
            defer self.gpa.free(members_snapshot);
            var new: std.ArrayListUnmanaged(TypeId) = .empty;
            defer new.deinit(self.gpa);
            for (members_snapshot) |m| {
                const subbed = try self.substituteType(m, subs);
                try new.append(self.gpa, if (subbed < self.interner.pool.typeCount()) subbed else types.Primitive.unknown);
            }
            return self.interner.internUnion(new.items) catch return t;
        }
        if (flags.is_intersection) {
            if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return t;
            const members = self.interner.intersectionMembers(t);
            const members_snapshot = try self.gpa.dupe(TypeId, members);
            defer self.gpa.free(members_snapshot);
            var new: std.ArrayListUnmanaged(TypeId) = .empty;
            defer new.deinit(self.gpa);
            for (members_snapshot) |m| {
                const subbed = try self.substituteType(m, subs);
                try new.append(self.gpa, if (subbed < self.interner.pool.typeCount()) subbed else types.Primitive.unknown);
            }
            return self.interner.internIntersection(new.items) catch return t;
        }
        if (flags.is_signature) {
            if (payload_idx >= self.interner.pool.signature_payloads.items.len) return t;
            const params = self.interner.signatureParams(t);
            const params_snapshot = try self.gpa.dupe(TypeId, params);
            defer self.gpa.free(params_snapshot);
            var new: std.ArrayListUnmanaged(TypeId) = .empty;
            defer new.deinit(self.gpa);
            for (params_snapshot) |p| try new.append(self.gpa, try self.substituteType(p, subs));
            const ret = if (self.interner.signatureReturn(t)) |r|
                try self.substituteType(r, subs)
            else
                types.Primitive.void_t;
            const is_construct = self.interner.pool.signature_payloads.items[payload_idx].is_construct;
            const new_sig = self.interner.internSignature(new.items, ret, is_construct) catch return t;
            if (self.rest_signatures.contains(t)) {
                try self.rest_signatures.put(self.gpa, new_sig, {});
            }
            {
                const old_min_required = self.signature_min_args.get(t) orelse params.len;
                var omittable: std.ArrayListUnmanaged(bool) = .empty;
                defer omittable.deinit(self.gpa);
                for (new.items, 0..) |param_t, param_i| {
                    try omittable.append(self.gpa, param_i >= old_min_required or param_t == types.Primitive.void_t);
                }
                try self.recordSignatureMinArgs(new_sig, omittable.items);
            }
            if (self.signature_predicates.get(t)) |pred| {
                var next_pred = pred;
                next_pred.target_type = self.substituteType(pred.target_type, subs) catch pred.target_type;
                try self.signature_predicates.put(self.gpa, new_sig, next_pred);
            }
            var param_ix: usize = 0;
            while (param_ix < params_snapshot.len) : (param_ix += 1) {
                const key: SignatureParamKey = .{ .signature = t, .param_index = @intCast(param_ix) };
                if (self.signature_param_predicates.get(key)) |pred| {
                    var next_pred = pred;
                    next_pred.target_type = self.substituteType(pred.target_type, subs) catch pred.target_type;
                    try self.signature_param_predicates.put(self.gpa, .{
                        .signature = new_sig,
                        .param_index = @intCast(param_ix),
                    }, next_pred);
                }
            }
            return new_sig;
        }
        if (flags.is_object_type) {
            if (payload_idx >= self.interner.pool.object_type_payloads.items.len) return t;
            const orig = self.interner.objectMembers(t);
            const orig_snapshot = try self.gpa.dupe(types.ObjectMember, orig);
            defer self.gpa.free(orig_snapshot);
            var new_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
            defer new_members.deinit(self.gpa);
            for (orig_snapshot) |om| {
                try new_members.append(self.gpa, .{
                    .name = om.name,
                    .type = try self.substituteType(om.type, subs),
                    .is_optional = om.is_optional,
                    .is_readonly = om.is_readonly,
                    .is_method = om.is_method,
                });
            }
            // Preserve and substitute index signatures so `T[]`
            // (which lowers to an object with `length: number` plus a
            // numeric indexer pointing to T) keeps its indexer after
            // instantiation. Without this, the substituted return
            // would still have `length: number` but no element type,
            // which breaks downstream `objectNumberIndex` reads.
            const orig_str = self.interner.objectStringIndex(t);
            const orig_num = self.interner.objectNumberIndex(t);
            const orig_sym = self.interner.objectSymbolIndex(t);
            const new_str = if (orig_str != types.Primitive.none)
                try self.substituteType(orig_str, subs)
            else
                types.Primitive.none;
            const new_num = if (orig_num != types.Primitive.none)
                try self.substituteType(orig_num, subs)
            else
                types.Primitive.none;
            const new_sym = if (orig_sym != types.Primitive.none)
                try self.substituteType(orig_sym, subs)
            else
                types.Primitive.none;
            const new_obj = if (new_str == types.Primitive.none and new_num == types.Primitive.none and new_sym == types.Primitive.none)
                self.interner.internObjectType(new_members.items) catch return t
            else
                self.interner.internObjectTypeWithIndexAndSymbol(new_members.items, new_str, new_num, new_sym) catch return t;
            if (self.this_type_markers.get(t)) |this_raw| {
                try self.this_type_markers.put(self.gpa, new_obj, try self.substituteType(this_raw, subs));
            }
            if (self.readonly_index_types.contains(t)) {
                try self.readonly_index_types.put(self.gpa, new_obj, {});
            }
            if (self.generator_type_info.get(t)) |gen| {
                try self.generator_type_info.put(self.gpa, new_obj, .{
                    .yield_type = try self.substituteType(gen.yield_type, subs),
                    .return_type = try self.substituteType(gen.return_type, subs),
                    .next_type = try self.substituteType(gen.next_type, subs),
                });
            }
            for (orig_snapshot) |om| {
                var pred_opt = self.member_predicates.get(.{ .receiver_type = t, .member_name = om.name });
                if (pred_opt == null) {
                    const substituted_member_t = self.substituteType(om.type, subs) catch om.type;
                    pred_opt = self.signature_predicates.get(substituted_member_t);
                }
                if (pred_opt) |pred| {
                    var next_pred = pred;
                    next_pred.target_type = self.substituteType(pred.target_type, subs) catch pred.target_type;
                    try self.recordMemberPredicate(new_obj, om.name, next_pred);
                }
            }
            return new_obj;
        }
        if (flags.is_conditional) {
            // Substitute into each leaf, then re-attempt eager
            // evaluation. If the check is now concrete, this
            // collapses to the picked branch.
            const c = self.interner.conditionalPayload(t);
            const new_check = try self.substituteType(c.check_type, subs);
            const new_ext = try self.substituteType(c.extends_type, subs);
            const new_tt = try self.substituteType(c.true_branch, subs);
            const new_ff = try self.substituteType(c.false_branch, subs);
            return self.evalConditional(new_check, new_ext, new_tt, new_ff, false);
        }
        if (flags.is_keyof) {
            // `keyof T` after substitution may resolve eagerly.
            const k = self.interner.pool.keyof_payloads.items[self.interner.pool.payloadOf(t)];
            const new_operand = try self.substituteType(k.operand, subs);
            var key_names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
            defer key_names.deinit(self.gpa);
            if (try self.collectKeyofObjectKeys(new_operand, &key_names)) {
                if (key_names.items.len == 0) return types.Primitive.never;
                var lits: std.ArrayListUnmanaged(TypeId) = .empty;
                defer lits.deinit(self.gpa);
                for (key_names.items) |name| {
                    const lit = self.interner.internStringLiteral(name) catch continue;
                    try lits.append(self.gpa, lit);
                }
                if (lits.items.len == 1) return lits.items[0];
                return self.interner.internUnion(lits.items) catch return t;
            }
            return self.interner.internKeyof(new_operand) catch return t;
        }
        if (flags.is_indexed_access) {
            // T[K] after substitution. If K resolves to a union of
            // string literals (typically `keyof T`), distribute the
            // indexed access over each member. If K is a single
            // string literal, look up the matching member's type.
            // Otherwise re-intern.
            const ia = self.interner.pool.indexed_access_payloads.items[self.interner.pool.payloadOf(t)];
            const new_obj = try self.substituteType(ia.object, subs);
            const new_idx = try self.substituteType(ia.index, subs);
            if (try self.resolveObjectIndexedAccessType(new_obj, new_idx)) |resolved| return resolved;
            return self.interner.internIndexedAccess(new_obj, new_idx) catch return t;
        }
        if (flags.is_template_literal) {
            const texts = self.interner.templateLiteralTexts(t);
            const part_types = self.interner.templateLiteralTypes(t);
            var new_parts: std.ArrayListUnmanaged(TypeId) = .empty;
            defer new_parts.deinit(self.gpa);
            var changed = false;
            var all_literal = true;
            var buf: std.ArrayListUnmanaged(u8) = .empty;
            defer buf.deinit(self.gpa);
            for (texts, 0..) |text_sid, i| {
                try buf.appendSlice(self.gpa, self.string_interner.get(text_sid));
                if (i < part_types.len) {
                    const new_part = try self.substituteType(part_types[i], subs);
                    try new_parts.append(self.gpa, new_part);
                    if (new_part != part_types[i]) changed = true;
                    if (self.stringLiteralValueFromType(new_part)) |lit_sid| {
                        try buf.appendSlice(self.gpa, self.string_interner.get(lit_sid));
                    } else {
                        all_literal = false;
                    }
                }
            }
            if (!changed) return t;
            if (all_literal) {
                const sid = self.string_interner.intern(buf.items) catch return error.OutOfMemory;
                return self.interner.internStringLiteral(sid) catch return t;
            }
            return self.interner.internTemplateLiteral(texts, new_parts.items) catch return t;
        }
        if (flags.is_string_mapping) {
            const sm = self.interner.stringMappingPayload(t);
            const new_inner = try self.substituteType(sm.inner, subs);
            if (new_inner == sm.inner) return t;
            return self.applyStringMappingBuiltin(switch (sm.kind) {
                .lowercase => "Lowercase",
                .uppercase => "Uppercase",
                .capitalize => "Capitalize",
                .uncapitalize => "Uncapitalize",
            }, new_inner) catch return t;
        }
        if (flags.is_type_parameter) {
            if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return t;
            const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
            const new_constraint = if (tp.constraint != types.Primitive.none)
                try self.substituteType(tp.constraint, subs)
            else
                tp.constraint;
            const new_default = if (tp.default != types.Primitive.none)
                try self.substituteType(tp.default, subs)
            else
                tp.default;
            if (new_constraint == tp.constraint and new_default == tp.default) return t;
            return self.interner.internTypeParameterWithFlags(
                tp.name,
                new_constraint,
                new_default,
                tp.variance,
                tp.is_const,
            ) catch return t;
        }
        return t;
    }

    fn substituteThisTypeParametersInReturn(self: *Checker, ret: TypeId, receiver_t: TypeId) CheckError!TypeId {
        if (ret >= self.interner.pool.typeCount()) return ret;
        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);
        var visited: std.AutoHashMapUnmanaged(TypeId, void) = .empty;
        defer visited.deinit(self.gpa);
        try self.collectThisTypeParameterSubs(ret, receiver_t, &subs, &visited);
        if (subs.count() == 0) return ret;
        return self.substituteType(ret, &subs) catch ret;
    }

    fn collectThisTypeParameterSubs(
        self: *Checker,
        t: TypeId,
        receiver_t: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
        visited: *std.AutoHashMapUnmanaged(TypeId, void),
    ) CheckError!void {
        if (t >= self.interner.pool.typeCount()) return;
        if (visited.contains(t)) return;
        try visited.put(self.gpa, t, {});
        if (self.isThisTypeParameter(t)) {
            try subs.put(self.gpa, t, receiver_t);
            return;
        }
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| try self.collectThisTypeParameterSubs(m, receiver_t, subs, visited);
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| try self.collectThisTypeParameterSubs(m, receiver_t, subs, visited);
            return;
        }
        if (flags.is_object_type) {
            for (self.interner.objectMembers(t)) |m| try self.collectThisTypeParameterSubs(m.type, receiver_t, subs, visited);
            const str_idx = self.interner.objectStringIndex(t);
            if (str_idx != types.Primitive.none) try self.collectThisTypeParameterSubs(str_idx, receiver_t, subs, visited);
            const num_idx = self.interner.objectNumberIndex(t);
            if (num_idx != types.Primitive.none) try self.collectThisTypeParameterSubs(num_idx, receiver_t, subs, visited);
            const sym_idx = self.interner.objectSymbolIndex(t);
            if (sym_idx != types.Primitive.none) try self.collectThisTypeParameterSubs(sym_idx, receiver_t, subs, visited);
            return;
        }
        if (flags.is_signature) {
            for (self.interner.signatureParams(t)) |p| try self.collectThisTypeParameterSubs(p, receiver_t, subs, visited);
            if (self.interner.signatureReturn(t)) |r| try self.collectThisTypeParameterSubs(r, receiver_t, subs, visited);
            return;
        }
        if (flags.is_conditional) {
            const c = self.interner.conditionalPayload(t);
            try self.collectThisTypeParameterSubs(c.check_type, receiver_t, subs, visited);
            try self.collectThisTypeParameterSubs(c.extends_type, receiver_t, subs, visited);
            try self.collectThisTypeParameterSubs(c.true_branch, receiver_t, subs, visited);
            try self.collectThisTypeParameterSubs(c.false_branch, receiver_t, subs, visited);
            return;
        }
        if (flags.is_keyof) {
            const k = self.interner.pool.keyof_payloads.items[self.interner.pool.payloadOf(t)];
            try self.collectThisTypeParameterSubs(k.operand, receiver_t, subs, visited);
            return;
        }
        if (flags.is_indexed_access) {
            const ia = self.interner.pool.indexed_access_payloads.items[self.interner.pool.payloadOf(t)];
            try self.collectThisTypeParameterSubs(ia.object, receiver_t, subs, visited);
            try self.collectThisTypeParameterSubs(ia.index, receiver_t, subs, visited);
            return;
        }
        if (flags.is_template_literal) {
            for (self.interner.templateLiteralTypes(t)) |part| try self.collectThisTypeParameterSubs(part, receiver_t, subs, visited);
            return;
        }
        if (flags.is_string_mapping) {
            const sm = self.interner.stringMappingPayload(t);
            try self.collectThisTypeParameterSubs(sm.inner, receiver_t, subs, visited);
            return;
        }
        if (flags.is_type_parameter) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return;
            const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
            if (tp.constraint != types.Primitive.none) try self.collectThisTypeParameterSubs(tp.constraint, receiver_t, subs, visited);
            if (tp.default != types.Primitive.none) try self.collectThisTypeParameterSubs(tp.default, receiver_t, subs, visited);
        }
    }

    fn memberCallReceiverType(self: *Checker, callee: NodeId) CheckError!?TypeId {
        if (self.hir.kindOf(callee) != .member_access) return null;
        const m = hir_mod.memberOf(self.hir, callee);
        if (self.nodeIsSuperReference(m.object)) {
            if (self.currentThisType()) |this_t| return this_t;
        }
        var receiver_t = self.hir.typeOf(m.object);
        if (receiver_t == types.Primitive.none) receiver_t = try self.checkExpression(m.object);
        if (m.optional or self.expressionIsOptionalChain(m.object)) {
            receiver_t = self.subtractNullUndefined(receiver_t) catch receiver_t;
        }
        return receiver_t;
    }

    fn instantiateMemberThisReturn(self: *Checker, callee: NodeId, ret: TypeId) CheckError!TypeId {
        const receiver_t = (try self.memberCallReceiverType(callee)) orelse return ret;
        return try self.substituteThisTypeParametersInReturn(ret, receiver_t);
    }

    /// Arity-only fit test: does `args.len` land inside the
    /// `[min_required, max_count]` range that `sig` accepts (where
    /// `min_required` strips trailing optionals/defaults and
    /// `max_count` is `params.len` unless the sig is variadic, in
    /// which case any count is allowed at or above the rest's fixed
    /// prefix)? Used by the new-expression path to decide whether
    /// the call would type-check against any constructor overload
    /// before falling back to the implementation signature's stricter
    /// arity. Spread args bump the min count by their tuple-prefix
    /// length so `[a, ...rest]` matches the overload that requires
    /// the prefix arity.
    fn callArityFitsSignature(self: *Checker, sig: TypeId, args: []const NodeId) bool {
        const param_ts = self.interner.signatureParams(sig);
        const is_variadic = self.rest_signatures.contains(sig) and param_ts.len > 0;
        const fixed_count: usize = if (is_variadic) param_ts.len - 1 else param_ts.len;
        const rest_min_required: usize = if (is_variadic) self.tupleFixedPrefixCount(param_ts[param_ts.len - 1]) else 0;
        const fixed_min_required = @min(self.signatureMinRequiredArgs(sig, param_ts), fixed_count);
        const min_required: usize = fixed_min_required + rest_min_required;
        var effective_min_count: usize = 0;
        for (args) |arg| {
            if (self.hir.kindOf(arg) == .spread) {
                effective_min_count += 1;
            } else {
                effective_min_count += 1;
            }
        }
        const rest_max_count: ?usize = if (is_variadic) blk: {
            if (self.fixedTupleLength(param_ts[param_ts.len - 1])) |len| {
                break :blk fixed_count + @as(usize, @intCast(len));
            }
            break :blk null;
        } else null;
        const too_few = effective_min_count < min_required;
        const too_many = if (is_variadic)
            (if (rest_max_count) |max_count| effective_min_count > max_count else false)
        else
            args.len > param_ts.len;
        return !(too_few or too_many);
    }

    /// Shared arg / signature checker used by both `call_expr` and
    /// `new_expr`. Emits TS2554 (count mismatch) and TS2345 (per-arg
    /// type mismatch) against `sig`'s parameter list. Type-parameter
    /// slots are skipped — full instantiation lives in
    /// `instantiateReturn`.
    fn checkArgsAgainstSignature(
        self: *Checker,
        call_node: NodeId,
        args: []const NodeId,
        arg_types: []const TypeId,
        sig: TypeId,
    ) CheckError!void {
        const param_ts = self.interner.signatureParams(sig);
        const is_variadic = self.rest_signatures.contains(sig) and param_ts.len > 0;
        // For rest signatures, the trailing slot accepts any number of
        // args (including zero), each typed against the array-element
        // type. Required-arg count drops the rest slot and trims
        // trailing optional/defaulted params (typed as `T | undefined`
        // by the signature pass, matching tsc's call-site behavior).
        const fixed_count: usize = if (is_variadic) param_ts.len - 1 else param_ts.len;
        const rest_min_required: usize = if (is_variadic) self.tupleFixedPrefixCount(param_ts[param_ts.len - 1]) else 0;
        const fixed_min_required = @min(self.signatureMinRequiredArgs(sig, param_ts), fixed_count);
        const min_required: usize = fixed_min_required + rest_min_required;
        var effective_min_count: usize = 0;
        for (args, 0..) |arg, arg_i| {
            if (self.hir.kindOf(arg) == .spread) {
                const fixed_prefix = self.tupleFixedPrefixCount(arg_types[arg_i]);
                effective_min_count += @max(fixed_prefix, 1);
            } else {
                effective_min_count += 1;
            }
        }
        const rest_max_count: ?usize = if (is_variadic) blk: {
            if (self.fixedTupleLength(param_ts[param_ts.len - 1])) |len| {
                break :blk fixed_count + @as(usize, @intCast(len));
            }
            break :blk null;
        } else null;
        const too_few = effective_min_count < min_required;
        const too_many = if (is_variadic)
            (if (rest_max_count) |max_count| effective_min_count > max_count else false)
        else
            args.len > param_ts.len;
        if (too_few or too_many) {
            const fixed_variadic_count = is_variadic and rest_max_count != null;
            // tsc renders the "Expected at least N arguments" form
            // (TS2555) for variadic-too-few and the "Expected N or
            // more arguments" form (TS2554) for non-variadic-too-few
            // with optionals; the two diverged in TS 2.0 to give
            // overload diagnostics a distinct discriminator.
            const use_at_least_form = is_variadic and too_few and !fixed_variadic_count;
            const expected_label: []const u8 = if (fixed_variadic_count)
                ""
            else if (is_variadic)
                " or more"
            else if (min_required == param_ts.len)
                ""
            else
                " or fewer";
            const expected_n: usize = if (fixed_variadic_count) rest_max_count.? else if (is_variadic) min_required else param_ts.len;
            const msg = if (use_at_least_form)
                try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Expected at least {d} arguments, but got {d}.",
                    .{ expected_n, args.len },
                )
            else
                try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Expected {d}{s} arguments, but got {d}.",
                    .{ expected_n, expected_label, args.len },
                );
            // tsc anchors a too-many TS2554 on the first excess
            // argument when one exists (matches `genericRestArity`,
            // `genericRestArityStrict` and similar). Too-few is
            // anchored on the call expression itself.
            var anchor_pos: ?u32 = null;
            if (too_many) {
                const first_excess_idx: usize = if (fixed_variadic_count)
                    rest_max_count.?
                else if (is_variadic)
                    min_required
                else
                    param_ts.len;
                if (first_excess_idx < args.len) {
                    anchor_pos = self.hir.spanOf(args[first_excess_idx]).start;
                }
            }
            try self.diagnostics.append(self.gpa, .{
                .node = call_node,
                .pos = anchor_pos,
                .code = if (use_at_least_form) TsCodes.expected_at_least_n_arguments else TsCodes.expected_n_arguments,
                .message = msg,
            });
        }
        // Fixed-position pairs.
        const npairs_fixed = @min(args.len, fixed_count);
        var i: usize = 0;
        while (i < npairs_fixed) : (i += 1) {
            var param_t = param_ts[i];
            if (param_t >= self.interner.pool.typeCount()) continue;
            if (self.interner.pool.flagsOf(param_t).is_type_parameter) {
                param_t = self.scalarTypeParameterConstraint(param_t) orelse continue;
            }
            var arg_t = arg_types[i];
            // Track whether this arg already triggered the spread-shape
            // diagnostic so the trailing TS2345 fall-through (which
            // checks the IteratorElementType<T> against the param) can
            // skip — upstream tsc reports only TS2556 in that case.
            var emitted_2556 = false;
            if (self.hir.kindOf(args[i]) == .spread) {
                if (!is_variadic or i < fixed_count) {
                    const is_union_arg = arg_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(arg_t).is_union;
                    if (is_union_arg or !self.isTupleShapedTarget(arg_t)) {
                        try self.report(args[i], TsCodes.spread_argument_requires_tuple_or_rest, "A spread argument must either have a tuple type or be passed to a rest parameter.");
                        emitted_2556 = true;
                    }
                }
                var tuple_i: usize = 0;
                while (i + tuple_i < fixed_count) : (tuple_i += 1) {
                    const elem_t = self.tupleElementType(arg_t, tuple_i);
                    if (elem_t == types.Primitive.none) break;
                    var tuple_param_t = param_ts[i + tuple_i];
                    if (tuple_param_t >= self.interner.pool.typeCount()) continue;
                    if (self.interner.pool.flagsOf(tuple_param_t).is_type_parameter) {
                        tuple_param_t = self.scalarTypeParameterConstraint(tuple_param_t) orelse continue;
                    }
                    const tuple_ok = self.isArgumentAssignableToParam(args[i], elem_t, tuple_param_t) catch true;
                    if (!tuple_ok) {
                        // Prefer the typed `Argument of type 'A' is not
                        // assignable to parameter of type 'P'` shape
                        // when both endpoints render via
                        // `simpleDiagnosticTypeName`; falls back to
                        // the positional summary otherwise to keep
                        // exact-baseline parity for cases tsc renders
                        // with concrete type names.
                        const msg = try self.formatArgumentNotAssignable(elem_t, tuple_param_t, i + tuple_i);
                        try self.diagnostics.append(self.gpa, .{
                            .node = args[i],
                            .code = TsCodes.argument_type_mismatch,
                            .message = msg,
                        });
                    }
                }
                const spread_elem_t = self.tupleElementType(arg_t, 0);
                if (spread_elem_t != types.Primitive.none) {
                    arg_t = spread_elem_t;
                } else {
                    arg_t = try self.iterableElementType(arg_t);
                }
            }
            const ok = self.isArgumentAssignableToParam(args[i], arg_t, param_t) catch true;
            const contextual_ok = if (!ok)
                self.unresolvedRestTupleCallbackFromPriorArrayArg(args, param_ts, i, param_t) catch false
            else
                false;
            if (!ok and !contextual_ok and !emitted_2556) {
                const msg = try self.formatArgumentNotAssignable(arg_t, param_t, i);
                try self.diagnostics.append(self.gpa, .{
                    .node = args[i],
                    .code = TsCodes.argument_type_mismatch,
                    .message = msg,
                });
            }
            try self.checkExcessProperties(args[i], param_t);
        }
        if (is_variadic) {
            // Trailing args bind to the rest slot. The rest's declared
            // type is an array (`number[]`); each individual call-site
            // arg is checked against the array's element type, which
            // we read from the number-key index signature.
            const rest_arr_t = param_ts[param_ts.len - 1];
            if (rest_arr_t >= self.interner.pool.typeCount()) return;
            const elem_t = self.interner.objectNumberIndex(rest_arr_t);
            const target_t = if (elem_t == types.Primitive.none) rest_arr_t else elem_t;
            if (target_t >= self.interner.pool.typeCount()) return;
            if (!self.interner.pool.flagsOf(target_t).is_type_parameter) {
                var j: usize = fixed_count;
                while (j < args.len) : (j += 1) {
                    var arg_t = arg_types[j];
                    if (self.hir.kindOf(args[j]) == .spread) {
                        const spread_elem_t = self.interner.objectNumberIndex(arg_t);
                        if (spread_elem_t != types.Primitive.none) {
                            arg_t = spread_elem_t;
                        } else {
                            arg_t = try self.iterableElementType(arg_t);
                        }
                    }
                    const ok = self.restArgumentAssignable(arg_t, target_t) catch true;
                    if (!ok) {
                        // Use the shared formatter so rest-arg TS2345
                        // sites also get the richer `Argument of type 'A'
                        // is not assignable to parameter of type 'P'.`
                        // prose when both endpoints have simple type
                        // names. Matches upstream baselines for
                        // `iterableArrayPattern{13,17,18,29}` etc.
                        const msg = try self.formatArgumentNotAssignable(arg_t, target_t, j);
                        try self.diagnostics.append(self.gpa, .{
                            .node = args[j],
                            .code = TsCodes.argument_type_mismatch,
                            .message = msg,
                        });
                    }
                }
            }
        }
    }

    /// TS2345: render upstream's `Argument of type 'A' is not
    /// assignable to parameter of type 'P'.` shape when both type
    /// names resolve through `simpleDiagnosticTypeName`. Otherwise
    /// fall back to the older positional summary so we never emit a
    /// half-formatted diagnostic. The simple-name helper deliberately
    /// covers only primitives + literals + named class/interface
    /// references — complex object/tuple/instantiation types stay on
    /// the fallback path so we don't emit noise like `[any, any]` or
    /// recurse through arbitrary instances such as `new Map()`.
    fn formatArgumentNotAssignable(self: *Checker, arg_t: TypeId, param_t: TypeId, position: usize) ![]const u8 {
        // Mirror tsc's diagnostic widening: when the source side is a
        // literal type (e.g. `1`) but the target is its base primitive
        // (`number`), upstream renders the source as the base type so
        // the message reads `'number' is not assignable to 'Date'` —
        // not `'1' is not assignable to 'Date'`. The `param_t` literal
        // case still keeps its literal form so `string-literal -> "abc"`
        // mismatches preserve the precise label.
        const display_arg_t = if (self.shouldWidenForArgDiagnostic(arg_t, param_t))
            self.widenLiteralType(arg_t)
        else
            arg_t;
        if (try self.simpleDiagnosticTypeName(display_arg_t)) |arg_text| {
            if (try self.simpleDiagnosticTypeName(param_t)) |param_text| {
                return try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Argument of type '{s}' is not assignable to parameter of type '{s}'.",
                    .{ arg_text, param_text },
                );
            }
        }
        // When both endpoints are callable (non-construct) signatures
        // render them as `(p: T) => U` so fixtures like
        // `subtypingWithCallSignaturesA` get upstream-shaped TS2345
        // prose instead of the positional placeholder.
        if (self.argumentCallSignatureNames(arg_t, param_t)) |pair| {
            return try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Argument of type '{s}' is not assignable to parameter of type '{s}'.",
                .{ pair.arg, pair.param },
            );
        }
        // Last-resort upgrade: when both operands have a registered
        // generic-alias display name (`Foo3<string>` etc.) populated
        // by `lowererLowerWithTypeParams`, prefer the named form over
        // the positional placeholder. Restricted to the alias-display
        // table specifically so we don't accidentally render arbitrary
        // structural shapes that upstream tsc elides.
        if (self.alias_display_names.get(arg_t)) |arg_text| {
            if (self.alias_display_names.get(param_t)) |param_text| {
                return try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Argument of type '{s}' is not assignable to parameter of type '{s}'.",
                    .{ arg_text, param_text },
                );
            }
        }
        return try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Argument is not assignable to parameter at position {d}.",
            .{position},
        );
    }

    /// Render both signature TypeIds as `(p: T) => U` strings, when
    /// every parameter type and the return type are nameable via
    /// `allocSimpleTypeName`. Uses recorded source-level parameter
    /// names when available, falling back to `x0`/`x1`. Returns null
    /// (so the caller emits the positional placeholder) on any
    /// non-signature input or non-nameable inner type.
    fn argumentCallSignatureNames(
        self: *Checker,
        arg_t: TypeId,
        param_t: TypeId,
    ) ?struct { arg: []const u8, param: []const u8 } {
        if (!self.interner.isSignature(arg_t) or !self.interner.isSignature(param_t)) return null;
        const arg_name = (self.allocCallSignatureFnTypeName(arg_t) catch return null) orelse return null;
        const param_name = (self.allocCallSignatureFnTypeName(param_t) catch return null) orelse return null;
        return .{ .arg = arg_name, .param = param_name };
    }

    /// Render a callable signature TypeId as `(p: T, q: U) => R`.
    /// Returns null when any constituent type isn't nameable so
    /// callers fall through to the positional placeholder.
    fn allocCallSignatureFnTypeName(self: *Checker, t: TypeId) CheckError!?[]const u8 {
        if (!self.interner.isSignature(t)) return null;
        if (t >= self.interner.pool.typeCount()) return null;
        const sig_payload_idx = self.interner.pool.payloadOf(t);
        if (sig_payload_idx >= self.interner.pool.signature_payloads.items.len) return null;
        const sig = self.interner.pool.signature_payloads.items[sig_payload_idx];
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        const arena = self.diag_arena.allocator();
        if (sig.is_construct) try buf.appendSlice(arena, "new ");
        try buf.append(arena, '(');
        const params = self.interner.signatureParams(t);
        const recorded_names: ?[]const hir_mod.StringId = self.signature_param_names.get(t);
        for (params, 0..) |p, i| {
            if (i > 0) try buf.appendSlice(arena, ", ");
            const name_text: []const u8 = blk: {
                if (recorded_names) |names| if (i < names.len) {
                    break :blk self.string_interner.get(names[i]);
                };
                break :blk try std.fmt.allocPrint(arena, "x{d}", .{i});
            };
            try buf.appendSlice(arena, name_text);
            try buf.appendSlice(arena, ": ");
            const pn = (try self.allocSimpleTypeName(p)) orelse return null;
            try buf.appendSlice(arena, pn);
        }
        try buf.appendSlice(arena, ") => ");
        const ret = self.interner.signatureReturn(t) orelse types.Primitive.any;
        const rn = (try self.allocSimpleTypeName(ret)) orelse return null;
        try buf.appendSlice(arena, rn);
        return buf.items;
    }

    /// Restricted variant of `allocSimpleTypeName` for diagnostic
    /// envelopes — primitives, literals, named class/interface refs,
    /// and enum nominal types only. Returns `null` for object types,
    /// tuples, signatures, unions, intersections, instantiations, etc.
    /// Callers fall back to a generic phrasing when this returns null
    /// so we never half-render a complex type.
    fn simpleDiagnosticTypeName(self: *Checker, t: TypeId) !?[]const u8 {
        return switch (t) {
            types.Primitive.any => "any",
            types.Primitive.unknown => "unknown",
            types.Primitive.never => "never",
            types.Primitive.void_t => "void",
            types.Primitive.null_t => "null",
            types.Primitive.undefined_t => "undefined",
            types.Primitive.string_t => "string",
            types.Primitive.number_t => "number",
            types.Primitive.boolean_t => "boolean",
            types.Primitive.bigint_t => "bigint",
            types.Primitive.symbol_t => "symbol",
            types.Primitive.object_t => "object",
            types.Primitive.true_lit => "true",
            types.Primitive.false_lit => "false",
            else => blk: {
                if (self.enumNameFromNominal(t)) |enum_name| {
                    break :blk self.string_interner.get(enum_name);
                }
                if (self.namedTypeForId(t)) |type_name| {
                    break :blk self.string_interner.get(type_name);
                }
                if (self.builtin_object_names.get(t)) |bname| {
                    break :blk bname;
                }
                if (self.interner.typeParameterName(t)) |tp_name| {
                    break :blk self.string_interner.get(tp_name);
                }
                if (t >= self.interner.pool.typeCount()) break :blk null;
                const flags = self.interner.pool.flagsOf(t);
                // Template literal types and intrinsic string-mapping
                // types — render structurally so TS2345 prose for
                // fixtures like `templateLiteralTypesPatterns.ts` and
                // `stringMappingOverPatternLiterals.ts` matches the
                // upstream baselines. Delegates to `allocSimpleTypeName`
                // which already handles these structural shapes.
                if (flags.is_template_literal or flags.is_string_mapping) {
                    break :blk try self.allocSimpleTypeName(t);
                }
                // Unions whose members are all simple (primitive,
                // literal, named, template-literal, or string-mapping)
                // — render `A | B | C` so TS2345 prose for fixtures like
                // `templateLiteralTypesPatterns.ts(14,10)` matches the
                // upstream `'\`http://${string}\` | \`https://${string}\` | \`ftp://${string}\`'`
                // shape. Restricted to unions whose members each pass
                // through this same simple-name helper, so we keep the
                // safety property described in the function's docstring
                // (no `[any, any]` noise from object/tuple shapes).
                if (flags.is_union) {
                    var union_buf: std.ArrayListUnmanaged(u8) = .empty;
                    const arena_u = self.diag_arena.allocator();
                    var first = true;
                    var ok = true;
                    // Mirrors tsc's display order: non-nullish members
                    // first, then `null`, then `undefined`. Without
                    // this, parameter targets like `number | undefined`
                    // render as `undefined | number` because the
                    // interner sorts members by ascending TypeId and
                    // `undefined`'s primitive id is lower than
                    // `number`'s. Fixture: `callWithSpread5.ts(6,4)`.
                    var has_null = false;
                    var has_undef = false;
                    // Textual dedup — distinct TypeIds can render to the
                    // same label (`string_t` vs a separately-interned
                    // string-flagged type); we should only mention each
                    // surface form once. See `restElementWithAssignmentPattern2`.
                    var seen_names: std.ArrayListUnmanaged([]const u8) = .empty;
                    defer seen_names.deinit(self.gpa);
                    for (self.interner.unionMembers(t)) |member| {
                        if (member == types.Primitive.null_t) {
                            has_null = true;
                            continue;
                        }
                        if (member == types.Primitive.undefined_t) {
                            has_undef = true;
                            continue;
                        }
                        const member_name = (try self.simpleDiagnosticTypeName(member)) orelse {
                            ok = false;
                            break;
                        };
                        var duplicate = false;
                        for (seen_names.items) |prior_name| {
                            if (std.mem.eql(u8, prior_name, member_name)) {
                                duplicate = true;
                                break;
                            }
                        }
                        if (duplicate) continue;
                        try seen_names.append(self.gpa, member_name);
                        if (!first) try union_buf.appendSlice(arena_u, " | ");
                        first = false;
                        try union_buf.appendSlice(arena_u, member_name);
                    }
                    if (!ok) break :blk null;
                    if (has_null) {
                        if (!first) try union_buf.appendSlice(arena_u, " | ");
                        first = false;
                        try union_buf.appendSlice(arena_u, "null");
                    }
                    if (has_undef) {
                        if (!first) try union_buf.appendSlice(arena_u, " | ");
                        first = false;
                        try union_buf.appendSlice(arena_u, "undefined");
                    }
                    if (union_buf.items.len == 0) break :blk null;
                    break :blk union_buf.items;
                }
                // Fixed-width tuples (`[any, any]`, `[number, string]`,
                // `[any, ...any[]]`) — render structurally so TS2345
                // prose for fixtures like `iterableArrayPattern10.ts`
                // matches the upstream `Argument of type 'X' is not
                // assignable to parameter of type '[any, any]'.` shape
                // instead of falling back to the positional placeholder.
                //
                // Many tuple types lack the `is_tuple` flag (they
                // surface only as object types with a numeric
                // `length` literal); detect via `fixedTupleLength`
                // which gates on the `length` member.
                if (flags.is_object_type) {
                    if (self.fixedTupleLength(t)) |fixed_len_u64| {
                        const fixed_len: usize = @intCast(fixed_len_u64);
                        var tuple_buf: std.ArrayListUnmanaged(u8) = .empty;
                        const arena_t = self.diag_arena.allocator();
                        try tuple_buf.append(arena_t, '[');
                        var i: usize = 0;
                        var tuple_ok = true;
                        while (i < fixed_len) : (i += 1) {
                            if (i > 0) try tuple_buf.appendSlice(arena_t, ", ");
                            const elem_t = self.tupleElementType(t, i);
                            const elem_name = (try self.simpleDiagnosticTypeName(elem_t)) orelse {
                                tuple_ok = false;
                                break;
                            };
                            try tuple_buf.appendSlice(arena_t, elem_name);
                        }
                        if (!tuple_ok) break :blk null;
                        // `[A, ...B[]]` rest tail — the indexer carries
                        // the element type of the rest portion. Render
                        // when present and we can name the element.
                        const rest_elem_t = self.interner.objectNumberIndex(t);
                        if (rest_elem_t != types.Primitive.none) {
                            if (try self.simpleDiagnosticTypeName(rest_elem_t)) |rest_name| {
                                if (fixed_len > 0) try tuple_buf.appendSlice(arena_t, ", ");
                                try tuple_buf.appendSlice(arena_t, "...");
                                try tuple_buf.appendSlice(arena_t, rest_name);
                                try tuple_buf.append(arena_t, '[');
                                try tuple_buf.append(arena_t, ']');
                            } else {
                                // Mixed rest with un-nameable element —
                                // skip rendering to avoid noise.
                                break :blk null;
                            }
                        }
                        try tuple_buf.append(arena_t, ']');
                        break :blk tuple_buf.items;
                    }
                }
                // Empty object types — anonymous, no declared members,
                // no index signatures — render as `{}` so TS2322 prose
                // on fixtures like `inOperatorWithInvalidOperands.ts(17,…)`
                // matches upstream. Excludes nominal classes/interfaces
                // (named) and fixed tuples (handled above).
                if (flags.is_object_type and self.namedTypeForId(t) == null) {
                    const members = self.interner.objectMembers(t);
                    const string_idx = self.interner.objectStringIndex(t);
                    const number_idx = self.interner.objectNumberIndex(t);
                    if (members.len == 0 and
                        string_idx == types.Primitive.none and
                        number_idx == types.Primitive.none)
                    {
                        break :blk "{}";
                    }
                }
                if (!flags.is_literal) break :blk null;
                const payload_idx = self.interner.pool.payloadOf(t);
                if (payload_idx >= self.interner.pool.literal_payloads.items.len) break :blk null;
                const literal = self.interner.pool.literal_payloads.items[payload_idx];
                break :blk switch (literal) {
                    .string_lit => |sid| try std.fmt.allocPrint(self.diag_arena.allocator(), "\"{s}\"", .{self.string_interner.get(sid)}),
                    .number_lit => |bits| try std.fmt.allocPrint(self.diag_arena.allocator(), "{d}", .{@as(f64, @bitCast(bits))}),
                    .bigint_lit => |sid| try std.fmt.allocPrint(self.diag_arena.allocator(), "{s}", .{self.string_interner.get(sid)}),
                    .boolean_lit => |b| if (b) "true" else "false",
                };
            },
        };
    }

    fn scalarTypeParameterConstraint(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_type_parameter) return null;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return null;
        const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
        if (tp.constraint == types.Primitive.none or tp.constraint == types.Primitive.unknown) return null;
        if (self.containsFreeTypeParameter(tp.constraint)) return null;
        // `T extends object` (the lowercase non-primitive sentinel)
        // surfaces TS2345 on primitive arguments regardless of
        // strict_null_checks: tsc treats `object` as a hard constraint
        // because it is the only generic constraint that excludes all
        // primitive types. Reuses the param-display substitution so
        // `Argument of type 'number' is not assignable to parameter of
        // type 'object'` renders verbatim (nonPrimitiveInGeneric.ts:18-19).
        if (tp.constraint == types.Primitive.object_t) return tp.constraint;
        if (!self.strict_flags.strict_null_checks) return null;
        if (tp.constraint < types.Primitive.first_dynamic) {
            return switch (tp.constraint) {
                types.Primitive.string_t,
                types.Primitive.number_t,
                types.Primitive.boolean_t,
                types.Primitive.bigint_t,
                types.Primitive.symbol_t,
                => tp.constraint,
                else => null,
            };
        }
        const constraint_flags = self.interner.pool.flagsOf(tp.constraint);
        if (!constraint_flags.is_literal) return null;
        return tp.constraint;
    }

    fn restArgumentAssignable(self: *Checker, arg_t: TypeId, target_t: TypeId) !bool {
        if (self.engine.isAssignableTo(arg_t, target_t) catch false) return true;
        if (arg_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(arg_t).is_union) {
            for (self.interner.unionMembers(arg_t)) |member| {
                if (self.engine.isAssignableTo(member, target_t) catch false) return true;
            }
        }
        return false;
    }

    fn checkTypeParameterDeclList(self: *Checker, type_params: []const NodeId) CheckError!void {
        if (type_params.len == 0) return;
        var seen: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer seen.deinit(self.gpa);

        var names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer names.deinit(self.gpa);
        var constraints: std.ArrayListUnmanaged(?hir_mod.StringId) = .empty;
        defer constraints.deinit(self.gpa);

        for (type_params) |tp_node| {
            if (self.hir.kindOf(tp_node) != .type_parameter) continue;
            const tp = hir_mod.typeParameterOf(self.hir, tp_node);
            if (seen.contains(tp.name)) {
                try self.reportDuplicateIdentifier(tp_node, tp.name);
            } else {
                try seen.put(self.gpa, tp.name, {});
            }
            try names.append(self.gpa, tp.name);
            try constraints.append(self.gpa, self.constraintTypeParameterName(tp.constraint));
        }

        for (names.items, 0..) |name, i| {
            if (!self.typeParameterConstraintHasCycle(name, names.items, constraints.items, i)) continue;
            // Include the parameter name so the message matches
            // upstream's `Type parameter 'T' has a circular constraint.`
            // shape. Mirrors `intrinsicKeyword.ts` baseline.
            const name_str = self.string_interner.get(name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Type parameter '{s}' has a circular constraint.",
                .{name_str},
            );
            // Anchor the diagnostic at the constraint node when one
            // exists (e.g. column of `T` in `<U extends T, ...>`),
            // mirroring upstream's reporting position from
            // `typeParameterIndirectlyConstrainedToItself.ts`.
            const tp = hir_mod.typeParameterOf(self.hir, type_params[i]);
            const target_node = if (tp.constraint != hir_mod.none_node_id) tp.constraint else type_params[i];
            try self.diagnostics.append(self.gpa, .{
                .node = target_node,
                .code = TsCodes.circular_constraint,
                .message = msg,
            });
        }
    }

    fn constraintTypeParameterName(self: *Checker, constraint: NodeId) ?hir_mod.StringId {
        if (constraint == hir_mod.none_node_id) return null;
        if (self.hir.kindOf(constraint) != .type_ref) return null;
        const r = hir_mod.typeRefOf(self.hir, constraint);
        if (r.qualifier_len != 0) return null;
        return r.name;
    }

    fn typeParameterConstraintHasCycle(
        self: *Checker,
        start: hir_mod.StringId,
        names: []const hir_mod.StringId,
        constraints: []const ?hir_mod.StringId,
        start_i: usize,
    ) bool {
        _ = self;
        var cur_i = start_i;
        var steps: usize = 0;
        while (steps < names.len) : (steps += 1) {
            const next_name = constraints[cur_i] orelse return false;
            if (next_name == start) return true;
            var found: ?usize = null;
            for (names, 0..) |name, i| {
                if (name == next_name) {
                    found = i;
                    break;
                }
            }
            cur_i = found orelse return false;
        }
        return false;
    }

    fn checkStaticMemberTypeParameterUse(
        self: *Checker,
        member: NodeId,
        class_type_params: []const NodeId,
    ) CheckError!void {
        if (class_type_params.len == 0) return;
        switch (self.hir.kindOf(member)) {
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, member);
                if (!op.is_static or op.type_annotation == hir_mod.none_node_id) return;
                if (self.typeNodeReferencesTypeParams(op.type_annotation, class_type_params)) {
                    // Upstream TS pins the diagnostic to the offending
                    // type-parameter reference inside the annotation,
                    // not the property key. Match that so positions
                    // line up with `.errors.txt` baselines.
                    const ref_node = self.firstTypeParamRefIn(op.type_annotation, class_type_params) orelse op.type_annotation;
                    try self.report(ref_node, TsCodes.static_member_type_parameter, "Static members cannot reference class type parameters.");
                }
            },
            .fn_decl, .fn_expr, .arrow_fn => {
                const f = hir_mod.fnDeclOf(self.hir, member);
                if (!f.flags.is_static) return;
                const own_type_params = hir_mod.fnTypeParams(self.hir, member);
                var visible_class_params: std.ArrayListUnmanaged(NodeId) = .empty;
                defer visible_class_params.deinit(self.gpa);
                for (class_type_params) |class_tp| {
                    if (self.hir.kindOf(class_tp) != .type_parameter) continue;
                    const class_name = hir_mod.typeParameterOf(self.hir, class_tp).name;
                    var shadowed = false;
                    for (own_type_params) |own_tp| {
                        if (self.hir.kindOf(own_tp) != .type_parameter) continue;
                        if (hir_mod.typeParameterOf(self.hir, own_tp).name == class_name) {
                            shadowed = true;
                            break;
                        }
                    }
                    if (!shadowed) try visible_class_params.append(self.gpa, class_tp);
                }
                const visible_params = visible_class_params.items;
                if (visible_params.len == 0) return;
                for (hir_mod.fnParams(self.hir, member)) |param| {
                    if (self.hir.kindOf(param) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, param);
                    if (p.type_annotation != hir_mod.none_node_id and
                        self.typeNodeReferencesTypeParams(p.type_annotation, visible_params))
                    {
                        try self.report(param, TsCodes.static_member_type_parameter, "Static members cannot reference class type parameters.");
                    }
                }
                if (f.return_type != hir_mod.none_node_id and self.typeNodeReferencesTypeParams(f.return_type, visible_params)) {
                    try self.report(member, TsCodes.static_member_type_parameter, "Static members cannot reference class type parameters.");
                }
            },
            else => {},
        }
    }

    fn firstTypeParamRefIn(self: *Checker, node: NodeId, type_params: []const NodeId) ?NodeId {
        if (node == hir_mod.none_node_id) return null;
        switch (self.hir.kindOf(node)) {
            .identifier => {
                if (self.typeParamNameMatches(hir_mod.identifierOf(self.hir, node).name, type_params)) return node;
                return null;
            },
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len == 0 and self.typeParamNameMatches(r.name, type_params)) return node;
                for (hir_mod.typeRefArgs(self.hir, node)) |arg| {
                    if (self.firstTypeParamRefIn(arg, type_params)) |hit| return hit;
                }
                return null;
            },
            .union_type => {
                for (hir_mod.unionTypeMembers(self.hir, node)) |m| {
                    if (self.firstTypeParamRefIn(m, type_params)) |hit| return hit;
                }
                return null;
            },
            .intersection_type => {
                for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| {
                    if (self.firstTypeParamRefIn(m, type_params)) |hit| return hit;
                }
                return null;
            },
            .array_type => return self.firstTypeParamRefIn(hir_mod.arrayTypeOf(self.hir, node).element, type_params),
            .rest_type => return self.firstTypeParamRefIn(hir_mod.restTypeOf(self.hir, node).operand, type_params),
            .tuple_type => {
                for (hir_mod.tupleTypeElements(self.hir, node)) |elem| {
                    if (self.firstTypeParamRefIn(elem, type_params)) |hit| return hit;
                }
                return null;
            },
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                return self.firstTypeParamRefIn(ia.object, type_params) orelse self.firstTypeParamRefIn(ia.index, type_params);
            },
            .keyof_type => return self.firstTypeParamRefIn(hir_mod.keyofTypeOf(self.hir, node).operand, type_params),
            else => return null,
        }
    }

    fn typeNodeReferencesTypeParams(self: *Checker, node: NodeId, type_params: []const NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .identifier => {
                return self.typeParamNameMatches(hir_mod.identifierOf(self.hir, node).name, type_params);
            },
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len == 0 and self.typeParamNameMatches(r.name, type_params)) return true;
                for (hir_mod.typeRefArgs(self.hir, node)) |arg| {
                    if (self.typeNodeReferencesTypeParams(arg, type_params)) return true;
                }
                return false;
            },
            .union_type => {
                for (hir_mod.unionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeReferencesTypeParams(member, type_params)) return true;
                }
                return false;
            },
            .intersection_type => {
                for (hir_mod.intersectionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeReferencesTypeParams(member, type_params)) return true;
                }
                return false;
            },
            .array_type => return self.typeNodeReferencesTypeParams(hir_mod.arrayTypeOf(self.hir, node).element, type_params),
            .rest_type => return self.typeNodeReferencesTypeParams(hir_mod.restTypeOf(self.hir, node).operand, type_params),
            .tuple_type => {
                for (hir_mod.tupleTypeElements(self.hir, node)) |elem| {
                    if (self.typeNodeReferencesTypeParams(elem, type_params)) return true;
                }
                return false;
            },
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                return self.typeNodeReferencesTypeParams(ia.object, type_params) or
                    self.typeNodeReferencesTypeParams(ia.index, type_params);
            },
            .keyof_type => return self.typeNodeReferencesTypeParams(hir_mod.keyofTypeOf(self.hir, node).operand, type_params),
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                return self.typeNodeReferencesTypeParams(c.check, type_params) or
                    self.typeNodeReferencesTypeParams(c.extends, type_params) or
                    self.typeNodeReferencesTypeParams(c.true_branch, type_params) or
                    self.typeNodeReferencesTypeParams(c.false_branch, type_params);
            },
            .mapped_type => {
                const m = hir_mod.mappedTypeOf(self.hir, node);
                return self.typeNodeReferencesTypeParams(m.type_param, type_params) or
                    self.typeNodeReferencesTypeParams(m.constraint, type_params) or
                    self.typeNodeReferencesTypeParams(m.value, type_params) or
                    self.typeNodeReferencesTypeParams(m.remap, type_params);
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            if (self.typeNodeReferencesTypeParams(im.type_node, type_params)) return true;
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            if (self.typeNodeReferencesTypeParams(ix.key_type, type_params) or
                                self.typeNodeReferencesTypeParams(ix.value_type, type_params)) return true;
                        },
                        else => {},
                    }
                }
                return false;
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                for (self.hir.childSlice(ft.type_params_start, ft.type_params_len)) |tp_node| {
                    if (self.hir.kindOf(tp_node) != .type_parameter) continue;
                    const tp = hir_mod.typeParameterOf(self.hir, tp_node);
                    if (self.typeNodeReferencesTypeParams(tp.constraint, type_params) or
                        self.typeNodeReferencesTypeParams(tp.default, type_params)) return true;
                }
                for (self.hir.childSlice(ft.params_start, ft.params_len)) |param_node| {
                    if (self.hir.kindOf(param_node) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, param_node);
                    if (self.typeNodeReferencesTypeParams(p.type_annotation, type_params)) return true;
                }
                return self.typeNodeReferencesTypeParams(ft.return_type, type_params);
            },
            .type_parameter => {
                const tp = hir_mod.typeParameterOf(self.hir, node);
                return self.typeParamNameMatches(tp.name, type_params) or
                    self.typeNodeReferencesTypeParams(tp.constraint, type_params) or
                    self.typeNodeReferencesTypeParams(tp.default, type_params);
            },
            .type_predicate_type => return self.typeNodeReferencesTypeParams(hir_mod.typePredicateOf(self.hir, node).target_type, type_params),
            .template_literal_type => {
                for (hir_mod.templateLiteralTypeTypes(self.hir, node)) |part| {
                    if (self.typeNodeReferencesTypeParams(part, type_params)) return true;
                }
                return false;
            },
            .as_expr, .satisfies_expr, .type_assertion => {
                const a = hir_mod.asExpressionOf(self.hir, node);
                return self.typeNodeReferencesTypeParams(a.type_node, type_params);
            },
            else => return false,
        }
    }

    fn typeParamNameMatches(self: *Checker, name: hir_mod.StringId, type_params: []const NodeId) bool {
        for (type_params) |tp_node| {
            if (self.hir.kindOf(tp_node) != .type_parameter) continue;
            if (hir_mod.typeParameterOf(self.hir, tp_node).name == name) return true;
        }
        return false;
    }

    fn bareTypeNodeIsTypeParam(self: *Checker, node: NodeId, type_params: []const NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(node)) {
            .identifier => self.typeParamNameMatches(hir_mod.identifierOf(self.hir, node).name, type_params),
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, node);
                break :blk r.qualifier_len == 0 and
                    hir_mod.typeRefArgs(self.hir, node).len == 0 and
                    self.typeParamNameMatches(r.name, type_params);
            },
            else => false,
        };
    }

    fn checkGenericIndexedAssignment(self: *Checker, node: NodeId, target: NodeId, value: NodeId) !void {
        if (!self.strict_flags.strict_null_checks) return;
        if (target == hir_mod.none_node_id or value == hir_mod.none_node_id) return;
        if (self.hir.kindOf(target) != .element_access or self.hir.kindOf(value) != .element_access) return;
        const target_el = hir_mod.elementOf(self.hir, target);
        const value_el = hir_mod.elementOf(self.hir, value);
        if (self.hir.kindOf(target_el.object) != .identifier or self.hir.kindOf(value_el.object) != .identifier) return;
        const target_obj = hir_mod.identifierOf(self.hir, target_el.object).name;
        const value_obj = hir_mod.identifierOf(self.hir, value_el.object).name;
        if (target_obj == value_obj) return;
        if (self.hir.kindOf(target_el.index) != .identifier or self.hir.kindOf(value_el.index) != .identifier) return;
        if (hir_mod.identifierOf(self.hir, target_el.index).name != hir_mod.identifierOf(self.hir, value_el.index).name) return;

        const target_obj_t = self.hir.typeOf(target_el.object);
        const value_obj_t = self.hir.typeOf(value_el.object);
        if (!self.containsFreeTypeParameter(target_obj_t) and !self.containsFreeTypeParameter(value_obj_t)) return;
        try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to target indexed access type.");
    }

    fn checkRemappedMappedIndexedDecl(self: *Checker, node: NodeId, declared_type: TypeId, init_node: NodeId) !void {
        if (!self.strict_flags.strict_null_checks) return;
        if (init_node == hir_mod.none_node_id or self.hir.kindOf(init_node) != .element_access) return;
        if (!self.containsFreeTypeParameter(declared_type)) return;
        const e = hir_mod.elementOf(self.hir, init_node);
        const idx_t = self.hir.typeOf(e.index);
        if (idx_t == types.Primitive.none) return;
        if (self.containsFreeTypeParameter(idx_t)) {
            if (idx_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(idx_t).is_template_literal) return;
        }
        try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
    }

    fn checkGenericValueMappedTargetDecl(
        self: *Checker,
        node: NodeId,
        type_annotation: NodeId,
        init_type: TypeId,
        init_node: NodeId,
    ) !void {
        if (type_annotation == hir_mod.none_node_id or init_node == hir_mod.none_node_id) return;
        if (self.hir.kindOf(init_node) != .identifier) return;
        if (init_type >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(init_type).is_type_parameter) return;
        if (self.hir.kindOf(type_annotation) != .type_ref) return;
        const r = hir_mod.typeRefOf(self.hir, type_annotation);
        if (r.qualifier_len != 0) return;
        const info = self.generic_aliases.get(r.name) orelse return;
        if (info.body_node == hir_mod.none_node_id or self.hir.kindOf(info.body_node) != .mapped_type) return;

        var source_arg_matches = false;
        for (hir_mod.typeRefArgs(self.hir, type_annotation)) |arg| {
            const arg_t = self.lowererLowerWithTypeParams(arg) catch continue;
            if (arg_t == init_type) {
                source_arg_matches = true;
                break;
            }
        }
        if (!source_arg_matches) return;

        const m = hir_mod.mappedTypeOf(self.hir, info.body_node);
        if (!self.mappedTargetRequiresGenericSourceCheck(m)) return;
        try self.reportOnce(node, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
    }

    fn mappedTargetRequiresGenericSourceCheck(self: *Checker, m: hir_mod.MappedTypePayload) bool {
        // Removing optionality can require properties that the
        // unconstrained source `T` may not have, so `T` is not
        // assignable to `{ [K in keyof T]-?: ... }`.
        if (m.optional == 2) return true;
        if (m.remap == hir_mod.none_node_id) return false;
        return !self.mappedRemapPreservesSourceKeys(m);
    }

    fn mappedRemapPreservesSourceKeys(self: *Checker, m: hir_mod.MappedTypePayload) bool {
        if (m.type_param == hir_mod.none_node_id or m.remap == hir_mod.none_node_id) return true;
        const tp = hir_mod.typeParameterOf(self.hir, m.type_param);
        if (self.typeNodeIsName(m.remap, tp.name)) return true;
        if (self.hir.kindOf(m.remap) != .conditional_type) return false;
        const c = hir_mod.conditionalTypeOf(self.hir, m.remap);
        const true_is_key = self.typeNodeIsName(c.true_branch, tp.name);
        const false_is_key = self.typeNodeIsName(c.false_branch, tp.name);
        const true_is_never = self.typeNodeIsNever(c.true_branch);
        const false_is_never = self.typeNodeIsNever(c.false_branch);
        if (true_is_key and false_is_key) return true;
        return (true_is_key and false_is_never) or (true_is_never and false_is_key);
    }

    fn typeNodeIsName(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        return (self.bareTypeNodeName(node) orelse return false) == name;
    }

    fn typeNodeIsNever(self: *Checker, node: NodeId) bool {
        const name = self.bareTypeNodeName(node) orelse return false;
        return std.mem.eql(u8, self.string_interner.get(name), "never");
    }

    fn checkInvalidIndexedAccessType(self: *Checker, index_node: NodeId, object_t: TypeId, index_t: TypeId) !void {
        if (!self.indexTypeHasKeysMissingFromObject(object_t, index_t)) return;
        try self.reportOnce(index_node, TsCodes.type_cannot_be_used_to_index_type, "Type cannot be used to index type.");
    }

    fn checkInvalidMappedObjectIndexedAccessType(self: *Checker, object_node: NodeId, index_node: NodeId) !void {
        if (object_node == hir_mod.none_node_id or index_node == hir_mod.none_node_id) return;
        if (self.hir.kindOf(object_node) != .mapped_type) return;
        const m = hir_mod.mappedTypeOf(self.hir, object_node);
        if (m.constraint == hir_mod.none_node_id) return;
        if (!self.typeNodeIndexedAccessHasMissingKeys(m.constraint)) return;
        try self.reportOnce(index_node, TsCodes.type_cannot_be_used_to_index_type, "Type cannot be used to index type.");
    }

    fn typeNodeIndexedAccessHasMissingKeys(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                const obj_t = self.lowererLowerWithTypeParams(ia.object) catch return false;
                const idx_t = self.lowererLowerWithTypeParams(ia.index) catch return false;
                return self.indexTypeHasKeysMissingFromObject(obj_t, idx_t);
            },
            .union_type => {
                for (hir_mod.unionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeIndexedAccessHasMissingKeys(member)) return true;
                }
                return false;
            },
            .intersection_type => {
                for (hir_mod.intersectionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeIndexedAccessHasMissingKeys(member)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn resolveObjectIndexedAccessType(self: *Checker, object_t: TypeId, index_t: TypeId) CheckError!?TypeId {
        const obj = self.typeParameterConstraint(object_t) orelse object_t;
        if (obj >= self.interner.pool.typeCount()) return null;
        const obj_flags = self.interner.pool.flagsOf(obj);
        if (!obj_flags.is_object_type and !obj_flags.is_intersection) return null;

        var keys: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer keys.deinit(self.gpa);
        if (!self.collectKnownStringKeysFromIndexType(index_t, &keys) or keys.items.len == 0) return null;
        var vals: std.ArrayListUnmanaged(TypeId) = .empty;
        defer vals.deinit(self.gpa);
        for (keys.items) |key| {
            const member_t = (try self.lookupObjectMember(obj, key)) orelse return null;
            try vals.append(self.gpa, member_t);
        }
        if (vals.items.len == 1) return vals.items[0];
        return self.interner.internUnion(vals.items) catch return error.OutOfMemory;
    }

    fn indexTypeHasKeysMissingFromObject(self: *Checker, object_t: TypeId, index_t: TypeId) bool {
        const obj = self.typeParameterConstraint(object_t) orelse object_t;
        if (obj >= self.interner.pool.typeCount()) return false;
        const obj_flags = self.interner.pool.flagsOf(obj);
        if (!obj_flags.is_object_type) return false;
        if (self.interner.objectStringIndex(obj) != types.Primitive.none) return false;

        var keys: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer keys.deinit(self.gpa);
        if (!self.collectKnownStringKeysFromIndexType(index_t, &keys)) return false;
        for (keys.items) |key| {
            if (self.interner.objectMember(obj, key) == null) return true;
        }
        return false;
    }

    fn collectKnownStringKeysFromIndexType(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
    ) bool {
        if (t == types.Primitive.never) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(t) orelse return false;
            if (constraint == t) return false;
            return self.collectKnownStringKeysFromIndexType(constraint, out);
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.collectKnownStringKeysFromIndexType(member, out)) return false;
            }
            return true;
        }
        if (flags.is_keyof) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.keyof_payloads.items.len) return false;
            const k = self.interner.pool.keyof_payloads.items[payload_idx];
            const operand = self.typeParameterConstraint(k.operand) orelse k.operand;
            if (operand >= self.interner.pool.typeCount()) return false;
            if (!self.interner.pool.flagsOf(operand).is_object_type) return false;
            for (self.interner.objectMembers(operand)) |member| {
                out.append(self.gpa, member.name) catch return false;
            }
            return true;
        }
        if (flags.is_literal and flags.is_string) {
            switch (self.interner.literalOf(t)) {
                .string_lit => |sid| {
                    out.append(self.gpa, sid) catch return false;
                    return true;
                },
                else => return false,
            }
        }
        return false;
    }

    fn reportOnce(self: *Checker, node: NodeId, code: u32, message: []const u8) !void {
        for (self.diagnostics.items) |d| {
            if (d.node == node and d.code == code) return;
        }
        try self.report(node, code, message);
    }

    fn sortDiagnosticsByPosition(self: *Checker) void {
        self.dedupeRedundantCannotFindName();
        var i: usize = 1;
        while (i < self.diagnostics.items.len) : (i += 1) {
            const current = self.diagnostics.items[i];
            const current_pos = self.diagnosticStart(current);
            var j = i;
            while (j > 0 and self.diagnosticStart(self.diagnostics.items[j - 1]) > current_pos) : (j -= 1) {
                self.diagnostics.items[j] = self.diagnostics.items[j - 1];
            }
            self.diagnostics.items[j] = current;
        }
    }

    /// Drop TS2304 / TS2552 ("cannot find name [did you mean]") at
    /// the same node as a TS2448 / TS2449 ("used before declaration"
    /// / "class used before its declaration") — tsc treats those as
    /// the narrower diagnostic and never doubles up. Mirrors
    /// `awaitUsingDeclarationsInForAwaitOf.2` and similar fixtures
    /// where a binding is declared mid-expression and the right-of-
    /// declaration use resolves to that same binding.
    fn dedupeRedundantCannotFindName(self: *Checker) void {
        if (self.diagnostics.items.len < 2) return;
        var keep_count: usize = 0;
        outer: for (self.diagnostics.items, 0..) |d, idx| {
            if (d.code == TsCodes.cannot_find_name or d.code == TsCodes.cannot_find_name_did_you_mean) {
                for (self.diagnostics.items, 0..) |other, j| {
                    if (j == idx) continue;
                    if (other.node != d.node) continue;
                    if (other.code == TsCodes.block_scoped_used_before_decl or
                        other.code == TsCodes.class_used_before_declaration)
                    {
                        continue :outer;
                    }
                }
            }
            self.diagnostics.items[keep_count] = d;
            keep_count += 1;
        }
        self.diagnostics.shrinkRetainingCapacity(keep_count);
    }

    fn diagnosticStart(self: *Checker, diagnostic: Diagnostic) u32 {
        return diagnostic.pos orelse self.hir.spanOf(diagnostic.node).start;
    }

    fn callExpressionHasAnyArgument(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .call_expr) return false;
        for (hir_mod.callArgs(self.hir, node)) |arg| {
            if (self.hir.typeOf(arg) == types.Primitive.any) return true;
        }
        return false;
    }

    fn isArgumentAssignableToParam(self: *Checker, arg_node: NodeId, arg_t: TypeId, param_t: TypeId) !bool {
        if (try self.overloadedIdentifierAssignableToParam(arg_node, param_t)) |ok| return ok;
        if (try self.literalExpressionAssignableToTarget(arg_node, param_t)) return true;
        if (try self.templateExpressionAssignableToType(arg_node, param_t)) return true;
        if (try self.restTupleCallbackAssignableToParam(arg_node, param_t)) return true;
        if (try self.identityObjectSpreadFunctionAssignableToParam(arg_node, param_t)) return true;
        if (try self.functionExpressionAssignableToCallableObject(arg_node, param_t)) return true;
        if (try self.functionExpressionAssignableToSignatureTarget(arg_node, arg_t, param_t)) return true;
        if (self.hir.kindOf(arg_node) == .object_literal) {
            if (try self.objectLiteralAssignableToTarget(arg_node, arg_t, param_t)) return true;
            if (self.thisTypeMarkerConstraint(param_t) != null) {
                try self.checkObjectLiteralMethodBodiesWithThis(arg_node, param_t);
                return true;
            }
        }
        if (self.hir.kindOf(arg_node) == .array_literal) {
            if (self.containsFreeTypeParameter(param_t)) return true;
            if (try self.arrayLiteralAssignableToTarget(arg_node, param_t)) return true;
        }
        if (try self.contextualCallReturnAssignableToParam(arg_node, param_t)) return true;
        if (try self.contextualGeneratorFunctionAssignableToParam(arg_node, arg_t, param_t)) return true;
        if (try self.typeParameterConstraintAssignableToParam(arg_t, param_t)) return true;
        if (try self.promisePayloadArgumentAssignable(arg_t, param_t)) return true;
        if (try self.restAnySignatureAssignableToCallback(arg_t, param_t)) return true;
        if (try self.symbolNamedObjectArgumentAssignable(arg_t, param_t)) return true;
        if (self.strict_flags.strict_null_checks) {
            if (self.typeIncludesNull(arg_t) and !self.typeIncludesNull(param_t)) return false;
            if (self.typeIncludesUndefined(arg_t) and !self.typeIncludesUndefined(param_t)) return false;
        }
        return self.engine.isAssignableTo(arg_t, param_t);
    }

    fn identityObjectSpreadFunctionAssignableToParam(self: *Checker, arg_node: NodeId, param_t: TypeId) CheckError!bool {
        const arg_kind = self.hir.kindOf(arg_node);
        if (arg_kind != .arrow_fn and arg_kind != .fn_expr) return false;
        if (param_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(param_t).is_signature) return false;
        const params = self.interner.signatureParams(param_t);
        if (params.len != 1) return false;
        const ret_t = self.interner.signatureReturn(param_t) orelse return false;
        if (!(self.engine.isAssignableTo(params[0], ret_t) catch false) and !(self.engine.isAssignableTo(ret_t, params[0]) catch false)) return false;
        if (self.functionSourceLooksObjectSpreadIdentity(arg_node)) return true;
        const f = hir_mod.fnDeclOf(self.hir, arg_node);
        if (f.body == hir_mod.none_node_id or self.hir.kindOf(f.body) != .object_literal) return false;
        const fn_params = hir_mod.fnParams(self.hir, arg_node);
        if (fn_params.len != 1 or self.hir.kindOf(fn_params[0]) != .parameter) return false;
        const p = hir_mod.parameterOf(self.hir, fn_params[0]);
        if (p.name == hir_mod.none_node_id or self.hir.kindOf(p.name) != .identifier) return false;
        const pname = hir_mod.identifierOf(self.hir, p.name).name;
        const props = hir_mod.objectLiteralProps(self.hir, f.body);
        if (props.len != 1 or self.hir.kindOf(props[0]) != .spread) return false;
        const sp = hir_mod.spreadOf(self.hir, props[0]);
        if (sp.expression == hir_mod.none_node_id or self.hir.kindOf(sp.expression) != .identifier) return false;
        return hir_mod.identifierOf(self.hir, sp.expression).name == pname;
    }

    fn functionSourceLooksObjectSpreadIdentity(self: *Checker, fn_node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(fn_node);
        if (span.start >= span.end or span.end > src.len) return false;
        const text = src[span.start..span.end];
        return std.mem.indexOf(u8, text, "=>") != null and
            std.mem.indexOf(u8, text, "...") != null and
            std.mem.indexOf(u8, text, "}") != null;
    }

    fn sourceHasVarDeclarationText(self: *Checker, name: hir_mod.StringId) bool {
        const src = self.source orelse return false;
        const raw_name = self.string_interner.get(name);
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "var")) |var_pos| {
            search_start = var_pos + "var".len;
            if (var_pos > 0 and isJsDocIdentChar(src[var_pos - 1])) continue;
            if (search_start < src.len and isJsDocIdentChar(src[search_start])) continue;
            var p = search_start;
            while (p < src.len and (src[p] == ' ' or src[p] == '\t' or src[p] == '\r' or src[p] == '\n')) : (p += 1) {}
            if (!std.mem.startsWith(u8, src[p..], raw_name)) continue;
            if (p + raw_name.len < src.len and isJsDocIdentChar(src[p + raw_name.len])) continue;
            return true;
        }
        return false;
    }

    fn symbolNamedObjectArgumentAssignable(self: *Checker, arg_t: TypeId, param_t: TypeId) CheckError!bool {
        if (arg_t >= self.interner.pool.typeCount() or param_t >= self.interner.pool.typeCount()) return false;
        const af = self.interner.pool.flagsOf(arg_t);
        const pf = self.interner.pool.flagsOf(param_t);
        if (!af.is_object_type or !pf.is_object_type) return false;
        var saw_symbol_requirement = false;
        for (self.interner.objectMembers(param_t)) |tm| {
            if (!self.isSymbolNamedMember(tm.name)) continue;
            saw_symbol_requirement = true;
            const sm_t = self.interner.objectMember(arg_t, tm.name) orelse {
                if (tm.is_optional) continue;
                return false;
            };
            if (self.engine.isAssignableTo(sm_t, tm.type) catch false) continue;
            if (try self.symbolMemberSignatureAssignable(sm_t, tm.type)) continue;
            return false;
        }
        return saw_symbol_requirement;
    }

    fn symbolMemberSignatureAssignable(self: *Checker, source_t: TypeId, target_t: TypeId) CheckError!bool {
        if (source_t >= self.interner.pool.typeCount() or target_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(source_t).is_signature or !self.interner.pool.flagsOf(target_t).is_signature) return false;
        const sp = self.interner.signatureParams(source_t);
        const tp = self.interner.signatureParams(target_t);
        if (sp.len > tp.len) return false;
        const source_ret = self.interner.signatureReturn(source_t) orelse types.Primitive.void_t;
        const target_ret = self.interner.signatureReturn(target_t) orelse types.Primitive.void_t;
        if (target_ret == types.Primitive.void_t or target_ret == types.Primitive.any or target_ret == types.Primitive.unknown) return true;
        if (self.engine.isAssignableTo(source_ret, target_ret) catch false) return true;
        return try self.presentObjectMembersAssignable(source_ret, target_ret);
    }

    fn restAnySignatureAssignableToCallback(self: *Checker, arg_t: TypeId, param_t: TypeId) CheckError!bool {
        if (arg_t >= self.interner.pool.typeCount() or param_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(arg_t).is_signature or !self.interner.pool.flagsOf(param_t).is_signature) return false;
        if (!self.rest_signatures.contains(arg_t)) return false;
        const params = self.interner.signatureParams(arg_t);
        if (params.len == 0) return false;
        const rest_arr = params[params.len - 1];
        if (rest_arr >= self.interner.pool.typeCount()) return false;
        const elem_t = self.interner.objectNumberIndex(rest_arr);
        return elem_t == types.Primitive.any or elem_t == types.Primitive.unknown;
    }

    fn functionExpressionAssignableToSignatureTarget(self: *Checker, arg_node: NodeId, arg_t: TypeId, target_t: TypeId) CheckError!bool {
        const arg_kind = self.hir.kindOf(arg_node);
        if (arg_kind != .arrow_fn and arg_kind != .fn_expr) return false;
        if (target_t >= self.interner.pool.typeCount()) return false;
        const target_flags = self.interner.pool.flagsOf(target_t);
        if (target_flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (try self.functionExpressionAssignableToSignatureTarget(arg_node, arg_t, member)) return true;
            }
            return false;
        }
        if (!target_flags.is_signature) return false;
        const source_t = if (arg_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(arg_t).is_signature)
            arg_t
        else
            self.hir.typeOf(arg_node);
        if (source_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(source_t).is_signature) return false;
        if (self.engine.isAssignableTo(source_t, target_t) catch false) return true;
        return self.contextualFunctionSignatureAssignable(source_t, target_t) catch false;
    }

    fn contextualFunctionSignatureAssignable(self: *Checker, source_t: TypeId, target_t: TypeId) CheckError!bool {
        if (source_t >= self.interner.pool.typeCount() or target_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(source_t).is_signature or !self.interner.pool.flagsOf(target_t).is_signature) return false;
        const source_params = self.interner.signatureParams(source_t);
        const target_params = self.interner.signatureParams(target_t);
        if (self.rest_signatures.contains(target_t) and target_params.len > 0) {
            if (!try self.contextualRestSignatureParamsAssignable(source_params, target_params)) return false;
            const source_ret_rest = self.interner.signatureReturn(source_t) orelse types.Primitive.void_t;
            const target_ret_rest = self.interner.signatureReturn(target_t) orelse types.Primitive.void_t;
            if (target_ret_rest == types.Primitive.void_t or target_ret_rest == types.Primitive.any or target_ret_rest == types.Primitive.unknown) return true;
            return self.engine.isAssignableTo(source_ret_rest, target_ret_rest) catch false;
        }
        if (source_params.len > target_params.len) return false;
        for (source_params, 0..) |source_param, i| {
            if (!try self.contextualTargetParamAssignableToSource(target_params[i], source_param)) return false;
        }
        const source_ret = self.interner.signatureReturn(source_t) orelse types.Primitive.void_t;
        const target_ret = self.interner.signatureReturn(target_t) orelse types.Primitive.void_t;
        if (target_ret == types.Primitive.void_t or target_ret == types.Primitive.any or target_ret == types.Primitive.unknown) return true;
        return self.engine.isAssignableTo(source_ret, target_ret) catch false;
    }

    fn contextualRestSignatureParamsAssignable(
        self: *Checker,
        source_params: []const TypeId,
        target_params: []const TypeId,
    ) CheckError!bool {
        const fixed_count = target_params.len - 1;
        const rest_t = target_params[target_params.len - 1];
        if (self.fixedTupleLength(rest_t)) |rest_len| {
            if (source_params.len > fixed_count + @as(usize, @intCast(rest_len))) return false;
        }
        for (source_params, 0..) |source_param, i| {
            const target_param = if (i < fixed_count)
                target_params[i]
            else
                self.tupleElementType(rest_t, i - fixed_count);
            if (target_param == types.Primitive.none) return false;
            if (!try self.contextualTargetParamAssignableToSource(target_param, source_param)) return false;
        }
        return true;
    }

    fn contextualTargetParamAssignableToSource(self: *Checker, target_param: TypeId, source_param: TypeId) CheckError!bool {
        if (self.engine.isAssignableTo(target_param, source_param) catch false) return true;
        if (target_param >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_param);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target_param)) |member| {
                if (self.engine.isAssignableTo(member, source_param) catch false) return true;
            }
        }
        return false;
    }

    fn restTupleCallbackAssignableToParam(self: *Checker, arg_node: NodeId, param_t: TypeId) CheckError!bool {
        const arg_kind = self.hir.kindOf(arg_node);
        if (arg_kind != .arrow_fn and arg_kind != .fn_expr) return false;
        if (param_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(param_t).is_signature) return false;
        const params = self.interner.signatureParams(param_t);
        if (!self.rest_signatures.contains(param_t)) {
            const source_t = self.hir.typeOf(arg_node);
            if (source_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(source_t).is_signature) return false;
            const source_params = self.interner.signatureParams(source_t);
            if (params.len == 1 and source_params.len > 1 and self.containsFreeTypeParameter(params[0])) return true;
            return false;
        }
        if (params.len != 1) return false;
        if (!self.containsFreeTypeParameter(params[0])) return false;
        return true;
    }

    fn functionExpressionAssignableToCallableObject(self: *Checker, arg_node: NodeId, target_t: TypeId) CheckError!bool {
        const k = self.hir.kindOf(arg_node);
        if (k != .arrow_fn and k != .fn_expr) return false;
        if (target_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(target_t).is_object_type) return false;
        const source_t = self.hir.typeOf(arg_node);
        if (source_t >= self.interner.pool.typeCount() or !self.interner.isSignature(source_t)) return false;
        const source_params = self.interner.signatureParams(source_t);
        var saw_signature = false;
        for (self.interner.objectMembers(target_t)) |member| {
            if (member.type >= self.interner.pool.typeCount() or !self.interner.isSignature(member.type)) continue;
            saw_signature = true;
            if (source_params.len > self.interner.signatureParams(member.type).len) return false;
        }
        return saw_signature and self.containsFreeTypeParameter(source_t);
    }

    fn unresolvedRestTupleCallbackFromPriorArrayArg(
        self: *Checker,
        args: []const NodeId,
        param_ts: []const TypeId,
        index: usize,
        param_t: TypeId,
    ) CheckError!bool {
        if (index == 0 or index >= args.len) return false;
        const arg_kind = self.hir.kindOf(args[index]);
        if (arg_kind != .arrow_fn and arg_kind != .fn_expr) return false;
        if (param_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(param_t).is_signature) return false;
        if (!self.rest_signatures.contains(param_t)) return false;
        const callback_params = self.interner.signatureParams(param_t);
        if (callback_params.len != 1 or callback_params[0] != types.Primitive.unknown) return false;
        const prior_count = @min(index, param_ts.len);
        for (0..prior_count) |prior_i| {
            if (self.hir.kindOf(args[prior_i]) != .array_literal) continue;
            return true;
        }
        return false;
    }

    fn promisePayloadArgumentAssignable(self: *Checker, arg_t: TypeId, param_t: TypeId) CheckError!bool {
        const arg_payload = self.promisePayloadType(arg_t) orelse return false;
        const param_payload = self.promisePayloadType(param_t) orelse return false;
        if (param_payload == types.Primitive.any) return true;
        return self.engine.isAssignableTo(arg_payload, param_payload) catch false;
    }

    fn promisePayloadType(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        if (!self.interner.pool.flagsOf(t).is_object_type) return null;
        const value_id = self.string_interner.intern("__home_promise_value") catch return null;
        return self.interner.objectMember(t, value_id);
    }

    fn typeParameterConstraintAssignableToParam(self: *Checker, arg_t: TypeId, param_t: TypeId) !bool {
        if (arg_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(arg_t).is_type_parameter) return false;
        const constraint = self.typeParameterConstraint(arg_t) orelse return false;
        if (constraint == arg_t or constraint == types.Primitive.none or constraint == types.Primitive.unknown) return false;
        return self.engine.isAssignableTo(constraint, param_t) catch false;
    }

    fn contextualGeneratorFunctionAssignableToParam(
        self: *Checker,
        arg_node: NodeId,
        arg_t: TypeId,
        param_t: TypeId,
    ) !bool {
        const kind = self.hir.kindOf(arg_node);
        if (kind != .fn_decl and kind != .fn_expr and kind != .arrow_fn) return false;
        const f = hir_mod.fnDeclOf(self.hir, arg_node);
        if (!f.flags.is_generator) return false;
        if (arg_t >= self.interner.pool.typeCount() or param_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(arg_t).is_signature or
            !self.interner.pool.flagsOf(param_t).is_signature)
        {
            return false;
        }
        const arg_ret = self.interner.signatureReturn(arg_t) orelse return false;
        const param_ret = self.interner.signatureReturn(param_t) orelse return false;
        return try self.generatorReturnAssignableToTargetReturn(arg_ret, param_ret);
    }

    fn generatorReturnAssignableToTargetReturn(
        self: *Checker,
        source_ret: TypeId,
        target_ret: TypeId,
    ) !bool {
        if (target_ret < self.interner.pool.typeCount() and self.interner.pool.flagsOf(target_ret).is_union) {
            for (self.interner.unionMembers(target_ret)) |member| {
                if (try self.generatorReturnAssignableToTargetReturn(source_ret, member)) return true;
            }
            return false;
        }
        const source = self.generator_type_info.get(source_ret) orelse return false;
        const target = self.generator_type_info.get(target_ret) orelse return false;
        if (!try self.generatorSlotAssignable(source.yield_type, target.yield_type)) return false;
        if (!try self.generatorSlotAssignable(source.return_type, target.return_type)) return false;
        return try self.generatorSlotAssignable(target.next_type, source.next_type);
    }

    fn generatorSlotAssignable(self: *Checker, source: TypeId, target: TypeId) !bool {
        if (self.engine.isAssignableTo(source, target) catch false) return true;
        if (source >= self.interner.pool.typeCount() or target >= self.interner.pool.typeCount()) return false;
        const sf = self.interner.pool.flagsOf(source);
        const tf = self.interner.pool.flagsOf(target);
        if (!tf.is_literal) return false;
        return (sf.is_number and tf.is_number) or
            (sf.is_string and tf.is_string) or
            (sf.is_boolean and tf.is_boolean) or
            (sf.is_bigint and tf.is_bigint);
    }

    fn overloadedIdentifierAssignableToParam(
        self: *Checker,
        arg_node: NodeId,
        param_t: TypeId,
    ) CheckError!?bool {
        if (self.hir.kindOf(arg_node) != .identifier) return null;
        if (param_t >= self.interner.pool.typeCount()) return null;
        if (!self.interner.pool.flagsOf(param_t).is_signature) return null;

        var overload_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer overload_sigs.deinit(self.gpa);
        try self.collectSiblingFunctionSignatures(arg_node, &overload_sigs);
        if (overload_sigs.items.len <= 1) return null;

        var target_t = param_t;
        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);
        try self.inferFromPair(param_t, overload_sigs.items[overload_sigs.items.len - 1], &subs);
        if (subs.count() > 0) {
            target_t = self.substituteType(param_t, &subs) catch param_t;
        }
        for (overload_sigs.items) |sig| {
            if (!(self.engine.isAssignableTo(sig, target_t) catch false)) return false;
        }
        return true;
    }

    fn collectSiblingFunctionSignatures(
        self: *Checker,
        arg_node: NodeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        const id = hir_mod.identifierOf(self.hir, arg_node);
        var cur = self.hir.parentOf(arg_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .namespace_decl) {
                try self.collectFunctionSignaturesFromStatements(hir_mod.namespaceBody(self.hir, cur), id.name, out);
                return;
            }
            if (k == .block_stmt) {
                try self.collectFunctionSignaturesFromStatements(hir_mod.blockStmts(self.hir, cur), id.name, out);
                if (out.items.len > 0) return;
            }
        }
    }

    fn collectFunctionSignaturesFromStatements(
        self: *Checker,
        stmts: []const NodeId,
        name: hir_mod.StringId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        for (stmts) |stmt| {
            var fn_node = stmt;
            if (self.hir.kindOf(stmt) == .export_decl) {
                const ex = hir_mod.exportOf(self.hir, stmt);
                if (ex.decl == hir_mod.none_node_id) continue;
                fn_node = ex.decl;
            }
            if (self.hir.kindOf(fn_node) != .fn_decl) continue;
            const f = hir_mod.fnDeclOf(self.hir, fn_node);
            if (f.name == hir_mod.none_node_id or self.hir.kindOf(f.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, f.name).name != name) continue;
            const sig = self.hir.typeOf(fn_node);
            if (sig < self.interner.pool.typeCount() and self.interner.pool.flagsOf(sig).is_signature) {
                try out.append(self.gpa, sig);
            }
        }
    }

    fn findSiblingFunctionDecl(self: *Checker, callee_node: NodeId) ?NodeId {
        if (self.hir.kindOf(callee_node) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, callee_node);
        var cur = self.hir.parentOf(callee_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .namespace_decl) {
                return self.findFunctionDeclInStatements(hir_mod.namespaceBody(self.hir, cur), id.name);
            }
            if (k == .block_stmt) {
                if (self.findFunctionDeclInStatements(hir_mod.blockStmts(self.hir, cur), id.name)) |fn_node| return fn_node;
            }
        }
        return null;
    }

    fn findFunctionDeclInStatements(self: *Checker, stmts: []const NodeId, name: hir_mod.StringId) ?NodeId {
        for (stmts) |stmt| {
            var fn_node = stmt;
            if (self.hir.kindOf(stmt) == .export_decl) {
                const ex = hir_mod.exportOf(self.hir, stmt);
                if (ex.decl == hir_mod.none_node_id) continue;
                fn_node = ex.decl;
            }
            if (self.hir.kindOf(fn_node) != .fn_decl) continue;
            const f = hir_mod.fnDeclOf(self.hir, fn_node);
            if (f.name == hir_mod.none_node_id or self.hir.kindOf(f.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, f.name).name == name) return fn_node;
        }
        return null;
    }

    fn relowerFunctionSignatureWithSubstitutions(
        self: *Checker,
        fn_node: NodeId,
        subs: *const std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) CheckError!?TypeId {
        if (self.hir.kindOf(fn_node) != .fn_decl) return null;
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        try self.pushNarrowScope();
        defer self.popNarrowScope();

        var it = subs.iterator();
        while (it.next()) |entry| {
            const param_t = entry.key_ptr.*;
            if (param_t >= self.interner.pool.typeCount()) continue;
            const flags = self.interner.pool.flagsOf(param_t);
            if (!flags.is_type_parameter) continue;
            const payload_idx = self.interner.pool.payloadOf(param_t);
            if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) continue;
            const payload = self.interner.pool.type_parameter_payloads.items[payload_idx];
            try self.recordNarrow(payload.name, entry.value_ptr.*);
        }

        var param_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer param_types.deinit(self.gpa);
        var omittable: std.ArrayListUnmanaged(bool) = .empty;
        defer omittable.deinit(self.gpa);
        var has_rest = false;
        for (hir_mod.fnParams(self.hir, fn_node)) |param_node| {
            const p = hir_mod.parameterOf(self.hir, param_node);
            if (self.isThisParameter(param_node)) continue;
            if (p.flags.is_rest) has_rest = true;
            const has_anno = p.type_annotation != hir_mod.none_node_id;
            var param_t: TypeId = if (has_anno)
                try self.lowererLowerWithTypeParams(p.type_annotation)
            else
                types.Primitive.any;
            if (p.flags.is_optional or p.default_value != hir_mod.none_node_id) {
                param_t = self.unionWithUndefined(param_t) catch param_t;
            }
            try param_types.append(self.gpa, param_t);
            try omittable.append(self.gpa, !has_anno or p.flags.is_optional or p.default_value != hir_mod.none_node_id or param_t == types.Primitive.void_t);
        }
        const ret_t = if (f.return_type != hir_mod.none_node_id)
            try self.lowererLowerWithTypeParams(f.return_type)
        else
            types.Primitive.void_t;
        const sig = self.interner.internSignature(param_types.items, ret_t, false) catch return error.OutOfMemory;
        try self.recordSignatureMinArgs(sig, omittable.items);
        if (has_rest) try self.rest_signatures.put(self.gpa, sig, {});
        return sig;
    }

    fn contextualCallReturnAssignableToParam(self: *Checker, arg_node: NodeId, param_t: TypeId) !bool {
        if (self.hir.kindOf(arg_node) != .call_expr) return false;
        if (param_t >= types.Primitive.first_dynamic and param_t < self.interner.pool.typeCount()) {
            const param_flags = self.interner.pool.flagsOf(param_t);
            if (param_flags.is_union) {
                for (self.interner.unionMembers(param_t)) |member| {
                    if (try self.contextualCallReturnAssignableToParam(arg_node, member)) return true;
                }
                return false;
            }
        }
        const c = hir_mod.callOf(self.hir, arg_node);
        var callee_t = self.hir.typeOf(c.callee);
        if (callee_t == types.Primitive.none) {
            callee_t = try self.checkExpression(c.callee);
        }
        if (callee_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(callee_t).is_signature) return false;
        const ret_t = self.interner.signatureReturn(callee_t) orelse return false;
        if ((ret_t == types.Primitive.any or ret_t == types.Primitive.unknown) and
            self.callHasFreeGenericArrayArgument(arg_node, callee_t))
        {
            return true;
        }

        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
        defer subs.deinit(self.gpa);
        try self.inferFromPair(ret_t, param_t, &subs);
        if (subs.count() == 0) return false;

        const instantiated_sig = self.substituteType(callee_t, &subs) catch return false;
        if (instantiated_sig >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(instantiated_sig).is_signature) return false;
        const instantiated_ret = self.interner.signatureReturn(instantiated_sig) orelse ret_t;
        if (!(self.engine.isAssignableTo(instantiated_ret, param_t) catch false)) return false;

        const checking_sig = if (self.findSiblingFunctionDecl(c.callee)) |fn_node|
            (try self.relowerFunctionSignatureWithSubstitutions(fn_node, &subs)) orelse instantiated_sig
        else
            instantiated_sig;

        const inner_args = hir_mod.callArgs(self.hir, arg_node);
        var inner_arg_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer inner_arg_types.deinit(self.gpa);
        for (inner_args) |inner_arg| {
            var inner_t = self.hir.typeOf(inner_arg);
            if (inner_t == types.Primitive.none) {
                inner_t = try self.checkExpression(inner_arg);
            }
            try inner_arg_types.append(self.gpa, inner_t);
        }
        const retry_diag_start = self.diagnostics.items.len;
        try self.checkArgsAgainstSignature(arg_node, inner_args, inner_arg_types.items, checking_sig);
        if (self.diagnostics.items.len != retry_diag_start) return false;
        self.clearContextualCallShapeDiagnostics(arg_node, inner_args);
        return true;
    }

    fn clearContextualCallShapeDiagnostics(self: *Checker, call_node: NodeId, args: []const NodeId) void {
        var write_i: usize = 0;
        for (self.diagnostics.items) |d| {
            if (!self.isContextualCallShapeDiagnostic(d, call_node, args)) {
                self.diagnostics.items[write_i] = d;
                write_i += 1;
            }
        }
        self.diagnostics.shrinkRetainingCapacity(write_i);
    }

    fn isContextualCallShapeDiagnostic(self: *Checker, d: Diagnostic, call_node: NodeId, args: []const NodeId) bool {
        switch (d.code) {
            TsCodes.argument_type_mismatch,
            TsCodes.expected_n_arguments,
            TsCodes.no_overload_matches,
            => {},
            else => return false,
        }
        if (d.node == call_node) return true;
        for (args) |arg| {
            if (d.node == arg) return true;
        }
        _ = self;
        return false;
    }

    fn callHasFreeGenericArrayArgument(self: *Checker, call_node: NodeId, sig: TypeId) bool {
        const args = hir_mod.callArgs(self.hir, call_node);
        const params = self.interner.signatureParams(sig);
        const n = @min(args.len, params.len);
        for (0..n) |i| {
            if (self.hir.kindOf(args[i]) == .array_literal and self.containsFreeTypeParameter(params[i])) {
                return true;
            }
        }
        return false;
    }

    fn arrayLiteralAssignableToTarget(self: *Checker, arg_node: NodeId, target_t: TypeId) !bool {
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(target_t).is_object_type) return false;
        const elem_target = self.interner.objectNumberIndex(target_t);
        if (elem_target == types.Primitive.none) return false;
        for (hir_mod.arrayLiteralElements(self.hir, arg_node)) |el| {
            if (el == hir_mod.none_node_id) continue;
            if (try self.literalExpressionAssignableToTarget(el, elem_target)) continue;
            var elem_t = self.hir.typeOf(el);
            if (elem_t == types.Primitive.none) elem_t = try self.checkExpression(el);
            if (!(self.engine.isAssignableTo(elem_t, elem_target) catch false)) return false;
        }
        return true;
    }

    fn objectTargetHasLiteralMember(self: *Checker, target_t: TypeId) bool {
        if (target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_literal) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (self.objectTargetHasLiteralMember(member)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target_t)) |member| {
                if (self.objectTargetHasLiteralMember(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(target_t)) |member| {
            if (self.objectTargetHasLiteralMember(member.type)) return true;
        }
        return false;
    }

    fn functionExpressionAssignableToTarget(self: *Checker, fn_node: NodeId, target_t: TypeId) CheckError!bool {
        if (target_t >= self.interner.pool.typeCount()) return false;
        const target_flags = self.interner.pool.flagsOf(target_t);
        if (target_flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (try self.functionExpressionAssignableToTarget(fn_node, member)) return true;
            }
            return false;
        }
        if (!target_flags.is_signature) return false;
        const source_t = self.hir.typeOf(fn_node);
        if (source_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(source_t).is_signature) return false;
        const source_params = self.interner.signatureParams(source_t);
        const target_params = self.interner.signatureParams(target_t);
        if (source_params.len != target_params.len) return false;
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.body == hir_mod.none_node_id) return false;
        const target_ret = self.interner.signatureReturn(target_t) orelse return false;
        const body_expr = if (self.hir.kindOf(f.body) == .block_stmt) blk: {
            const stmts = hir_mod.blockStmts(self.hir, f.body);
            if (stmts.len != 1 or self.hir.kindOf(stmts[0]) != .return_stmt) return false;
            const ret = hir_mod.returnOf(self.hir, stmts[0]);
            if (ret.value == hir_mod.none_node_id) return target_ret == types.Primitive.void_t;
            break :blk ret.value;
        } else f.body;
        if (self.hir.kindOf(body_expr) == .identifier) {
            const body_id = hir_mod.identifierOf(self.hir, body_expr);
            for (hir_mod.fnParams(self.hir, fn_node), 0..) |param, i| {
                if (self.hir.kindOf(param) != .parameter) continue;
                const p = hir_mod.parameterOf(self.hir, param);
                if (p.name == hir_mod.none_node_id or self.hir.kindOf(p.name) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, p.name).name != body_id.name) continue;
                if (i < target_params.len and (self.engine.isAssignableTo(target_params[i], target_ret) catch false)) return true;
            }
        }
        if (self.hir.kindOf(body_expr) == .call_expr) {
            const call = hir_mod.callOf(self.hir, body_expr);
            if (call.callee != hir_mod.none_node_id and self.hir.kindOf(call.callee) == .identifier) {
                const callee_id = hir_mod.identifierOf(self.hir, call.callee);
                for (hir_mod.fnParams(self.hir, fn_node), 0..) |param, i| {
                    if (i >= target_params.len) break;
                    if (self.hir.kindOf(param) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, param);
                    if (p.name == hir_mod.none_node_id or self.hir.kindOf(p.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, p.name).name != callee_id.name) continue;
                    const callee_target = target_params[i];
                    if (callee_target >= self.interner.pool.typeCount() or
                        !self.interner.pool.flagsOf(callee_target).is_signature) break;
                    const callee_ret = self.interner.signatureReturn(callee_target) orelse types.Primitive.any;
                    if (!(self.engine.isAssignableTo(callee_ret, target_ret) catch false)) break;
                    const callee_params = self.interner.signatureParams(callee_target);
                    const args = hir_mod.callArgs(self.hir, body_expr);
                    if (args.len > callee_params.len) break;
                    var ok = true;
                    for (args, 0..) |arg, arg_i| {
                        var arg_t: TypeId = types.Primitive.any;
                        if (self.hir.kindOf(arg) == .identifier) {
                            const arg_id = hir_mod.identifierOf(self.hir, arg);
                            for (hir_mod.fnParams(self.hir, fn_node), 0..) |src_param, src_i| {
                                if (src_i >= target_params.len) break;
                                if (self.hir.kindOf(src_param) != .parameter) continue;
                                const sp = hir_mod.parameterOf(self.hir, src_param);
                                if (sp.name == hir_mod.none_node_id or self.hir.kindOf(sp.name) != .identifier) continue;
                                if (hir_mod.identifierOf(self.hir, sp.name).name == arg_id.name) {
                                    arg_t = target_params[src_i];
                                    break;
                                }
                            }
                        } else {
                            arg_t = self.hir.typeOf(arg);
                            if (arg_t == types.Primitive.none) arg_t = try self.checkExpression(arg);
                        }
                        if (!(self.engine.isAssignableTo(arg_t, callee_params[arg_i]) catch false)) {
                            ok = false;
                            break;
                        }
                    }
                    if (ok) return true;
                }
            }
        }
        const body_t = self.hir.typeOf(body_expr);
        const checked_body_t = if (body_t != types.Primitive.none) body_t else try self.checkExpression(body_expr);
        if (self.engine.isAssignableTo(checked_body_t, target_ret) catch false) return true;
        return try self.literalExpressionAssignableToTarget(body_expr, target_ret);
    }

    fn objectLiteralAssignableToTarget(self: *Checker, arg_node: NodeId, arg_t: TypeId, target_t: TypeId) anyerror!bool {
        return try self.objectLiteralAssignableToTargetInner(arg_node, arg_t, target_t, true);
    }

    fn objectLiteralAssignableToTargetInner(self: *Checker, arg_node: NodeId, arg_t: TypeId, target_t: TypeId, check_methods: bool) anyerror!bool {
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (try self.objectLiteralAssignableToTargetInner(arg_node, arg_t, member, check_methods)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target_t)) |member| {
                if (self.thisTypeMarkerConstraint(member) != null) continue;
                if (!try self.objectLiteralAssignableToTargetInner(arg_node, arg_t, member, false)) return false;
            }
            if (check_methods) try self.checkObjectLiteralMethodBodiesWithThis(arg_node, target_t);
            return true;
        }
        if (!flags.is_object_type) return false;
        if (!self.interner.pool.flagsOf(arg_t).is_object_type) return false;
        const string_idx = self.interner.objectStringIndex(target_t);
        if (string_idx != types.Primitive.none) {
            for (self.interner.objectMembers(arg_t)) |am| {
                if (!(self.engine.isAssignableTo(am.type, string_idx) catch false)) return false;
            }
        }
        const number_idx = self.interner.objectNumberIndex(target_t);
        if (number_idx != types.Primitive.none) {
            for (self.interner.objectMembers(arg_t)) |am| {
                if (!self.isNumericPropertyName(am.name)) continue;
                if (!(self.engine.isAssignableTo(am.type, number_idx) catch false)) return false;
            }
        }
        for (self.interner.objectMembers(target_t)) |tm| {
            const am_t = self.interner.objectMember(arg_t, tm.name) orelse {
                if (tm.is_optional) continue;
                return false;
            };
            if (self.findObjectLiteralPropValue(arg_node, tm.name)) |value_node| {
                if (self.hir.kindOf(value_node) == .object_literal and
                    try self.objectLiteralAssignableToTargetInner(value_node, am_t, tm.type, true))
                {
                    continue;
                }
                if (self.hir.kindOf(value_node) == .array_literal and
                    try self.arrayLiteralAssignableToTarget(value_node, tm.type))
                {
                    continue;
                }
                if (try self.literalExpressionAssignableToTarget(value_node, tm.type)) continue;
                if (try self.isArgumentAssignableToParam(value_node, am_t, tm.type)) continue;
            }
            if (!try self.engine.isAssignableTo(am_t, tm.type)) return false;
        }
        if (check_methods) try self.checkObjectLiteralMethodBodiesWithThis(arg_node, target_t);
        return true;
    }

    fn objectLiteralNeedsIndexerValidation(self: *Checker, target_t: TypeId) bool {
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (self.objectLiteralNeedsIndexerValidation(member)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target_t)) |member| {
                if (self.objectLiteralNeedsIndexerValidation(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        const string_idx = self.interner.objectStringIndex(target_t);
        if (string_idx != types.Primitive.none and self.indexerTypeNeedsLiteralValidation(string_idx)) return true;
        const number_idx = self.interner.objectNumberIndex(target_t);
        return number_idx != types.Primitive.none and self.indexerTypeNeedsLiteralValidation(number_idx);
    }

    fn indexerTypeNeedsLiteralValidation(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_signature) return false;
        if (flags.is_object_type and self.interner.objectMembers(t).len == 0) return false;
        return true;
    }

    fn objectLiteralMayMatchTarget(self: *Checker, arg_node: NodeId, target_t: TypeId) !bool {
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (try self.objectLiteralMayMatchTarget(arg_node, member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return true;
        var saw_discriminant = false;
        for (self.interner.objectMembers(target_t)) |tm| {
            if (!self.isLiteralType(tm.type)) continue;
            saw_discriminant = true;
            const value_node = self.findObjectLiteralPropValue(arg_node, tm.name) orelse continue;
            if (!try self.literalExpressionAssignableToTarget(value_node, tm.type)) return false;
        }
        return saw_discriminant;
    }

    fn findObjectLiteralPropValue(self: *Checker, object_node: NodeId, name: hir_mod.StringId) ?NodeId {
        if (self.hir.kindOf(object_node) != .object_literal) return null;
        for (hir_mod.objectLiteralProps(self.hir, object_node)) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            if (op.value == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(op.key) != .identifier) continue;
            const key = hir_mod.identifierOf(self.hir, op.key);
            if (key.name == name) return op.value;
        }
        return null;
    }

    /// When an object-literal init doesn't fit a structurally-known
    /// target and the gap is a single property whose value is not
    /// assignable, fire TS2322 at the property KEY position with
    /// full `Type 'X' is not assignable to type 'Y'.` prose. Returns
    /// true when a property-level diagnostic was emitted, so the
    /// caller can skip the line-level fallback. Mirrors upstream tsc
    /// behaviour for `nonPrimitiveAsProperty.ts(7,28)` — the source
    /// position of the property name, not the value or declaration.
    fn tryReportObjectLiteralPropertyMismatch(
        self: *Checker,
        init_node: NodeId,
        target_t: TypeId,
    ) !bool {
        if (self.hir.kindOf(init_node) != .object_literal) return false;
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (!flags.is_object_type) return false;
        var emitted = false;
        for (self.interner.objectMembers(target_t)) |tm| {
            const prop_node = self.findObjectLiteralPropNode(init_node, tm.name) orelse continue;
            const op = hir_mod.objectPropertyOf(self.hir, prop_node);
            if (op.value == hir_mod.none_node_id) continue;
            const value_t = self.hir.typeOf(op.value);
            if (value_t == types.Primitive.none) continue;
            if (try self.literalExpressionAssignableToTarget(op.value, tm.type)) continue;
            if (self.engine.isAssignableTo(value_t, tm.type) catch true) continue;
            // Anchor at the property key so the column matches
            // upstream — `nonPrimitiveAsProperty.ts(7,28)`.
            const anchor = if (op.key != hir_mod.none_node_id) op.key else op.value;
            try self.reportTypeNotAssignable(
                anchor,
                value_t,
                tm.type,
                "Type is not assignable to property type.",
            );
            emitted = true;
            break;
        }
        return emitted;
    }

    /// Like `findObjectLiteralPropValue` but returns the
    /// `object_property` node itself so callers can also access the
    /// key node.
    fn findObjectLiteralPropNode(self: *Checker, object_node: NodeId, name: hir_mod.StringId) ?NodeId {
        if (self.hir.kindOf(object_node) != .object_literal) return null;
        for (hir_mod.objectLiteralProps(self.hir, object_node)) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            if (op.value == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(op.key) != .identifier) continue;
            const key = hir_mod.identifierOf(self.hir, op.key);
            if (key.name == name) return p;
        }
        return null;
    }

    fn isLiteralType(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.true_lit or t == types.Primitive.false_lit) return true;
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return false;
        return self.interner.pool.flagsOf(t).is_literal;
    }

    /// Widen a literal type (`123`, `"foo"`, `true`) to its primitive
    /// base (`number`, `string`, `boolean`). Used for diagnostic
    /// rendering when the target type is non-literal — upstream
    /// reports `'number'` not `'123'` in `a = 123` where `a: object`.
    /// True when the TS2345 source operand should render in its
    /// widened form. Matches the narrow case where `arg_t` is a
    /// literal (e.g. `1`, `"abc"`, `true`) and `param_t` is anything
    /// that isn't itself a literal-bearing target — i.e. a primitive,
    /// a named class/interface, a type parameter, or other complex
    /// shape. Literal vs literal mismatches (`"a" -> "b"`) keep their
    /// precise labels so the message stays informative.
    fn shouldWidenForArgDiagnostic(self: *Checker, arg_t: TypeId, param_t: TypeId) bool {
        if (arg_t == types.Primitive.true_lit or arg_t == types.Primitive.false_lit) {
            return param_t != types.Primitive.true_lit and param_t != types.Primitive.false_lit;
        }
        if (arg_t < types.Primitive.first_dynamic or arg_t >= self.interner.pool.typeCount()) return false;
        const arg_flags = self.interner.pool.flagsOf(arg_t);
        if (!arg_flags.is_literal) return false;
        // Literal target — keep both literal labels so `'1' -> '2'`
        // mismatches read precisely.
        if (param_t < types.Primitive.first_dynamic) return true;
        if (param_t >= self.interner.pool.typeCount()) return true;
        const param_flags = self.interner.pool.flagsOf(param_t);
        return !param_flags.is_literal;
    }

    fn widenLiteralType(self: *Checker, t: TypeId) TypeId {
        if (t == types.Primitive.true_lit or t == types.Primitive.false_lit) return types.Primitive.boolean_t;
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return t;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_literal) return t;
        if (flags.is_string) return types.Primitive.string_t;
        if (flags.is_number) return types.Primitive.number_t;
        if (flags.is_boolean) return types.Primitive.boolean_t;
        if (flags.is_bigint) return types.Primitive.bigint_t;
        return t;
    }

    fn stringLiteralAssignableToType(self: *Checker, sid: hir_mod.StringId, target_t: TypeId) CheckError!bool {
        if (target_t == types.Primitive.string_t or target_t == types.Primitive.any or target_t == types.Primitive.unknown) return true;
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_union) {
            for (self.interner.unionMembers(target_t)) |member| {
                if (try self.stringLiteralAssignableToType(sid, member)) return true;
            }
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(target_t)) |member| {
                if (!try self.stringLiteralAssignableToType(sid, member)) return false;
            }
            return true;
        }
        if (flags.is_literal and flags.is_string) {
            const lit = self.interner.literalOf(target_t);
            return switch (lit) {
                .string_lit => |target_sid| target_sid == sid or try self.cookedStringIdEquals(sid, target_sid),
                else => false,
            };
        }
        if (flags.is_template_literal) return try self.templateLiteralTypeMatchesString(target_t, sid);
        if (flags.is_string_mapping) return try self.stringMappingTypeMatchesString(target_t, sid);
        return false;
    }

    fn templateLiteralTypeMatchesString(self: *Checker, target_t: TypeId, sid: hir_mod.StringId) CheckError!bool {
        const texts = self.interner.templateLiteralTexts(target_t);
        const parts = self.interner.templateLiteralTypes(target_t);
        if (texts.len != parts.len + 1) return false;
        const raw = self.string_interner.get(sid);
        return try self.templateLiteralMatchFrom(texts, parts, raw, 0, 0);
    }

    fn templateLiteralMatchFrom(
        self: *Checker,
        texts: []const hir_mod.StringId,
        parts: []const TypeId,
        raw: []const u8,
        text_index: usize,
        pos: usize,
    ) CheckError!bool {
        const text = self.string_interner.get(texts[text_index]);
        if (pos > raw.len or raw.len - pos < text.len) return false;
        if (!std.mem.eql(u8, raw[pos .. pos + text.len], text)) return false;
        const after_text = pos + text.len;
        if (text_index == parts.len) return after_text == raw.len;

        const next_text = self.string_interner.get(texts[text_index + 1]);
        if (next_text.len == 0) {
            var end = after_text;
            while (end <= raw.len) : (end += 1) {
                const part_ok = try self.templatePlaceholderAcceptsSlice(parts[text_index], raw[after_text..end]);
                const rest_ok = if (part_ok)
                    try self.templateLiteralMatchFrom(texts, parts, raw, text_index + 1, end)
                else
                    false;
                if (part_ok and rest_ok) {
                    return true;
                }
            }
            return false;
        }

        var search = after_text;
        while (search <= raw.len) {
            const rel = std.mem.indexOfPos(u8, raw, search, next_text) orelse return false;
            const part_ok = try self.templatePlaceholderAcceptsSlice(parts[text_index], raw[after_text..rel]);
            const rest_ok = if (part_ok)
                try self.templateLiteralMatchFrom(texts, parts, raw, text_index + 1, rel)
            else
                false;
            if (part_ok and rest_ok) {
                return true;
            }
            search = rel + 1;
        }
        return false;
    }

    fn templatePlaceholderAcceptsSlice(self: *Checker, part_t: TypeId, slice: []const u8) CheckError!bool {
        if (part_t == types.Primitive.any or part_t == types.Primitive.unknown or part_t == types.Primitive.string_t) return true;
        if (part_t == types.Primitive.number_t) return sliceLooksNumeric(slice);
        if (part_t == types.Primitive.boolean_t) return std.mem.eql(u8, slice, "true") or std.mem.eql(u8, slice, "false");
        if (part_t == types.Primitive.bigint_t) return sliceLooksBigInt(slice);
        if (part_t < types.Primitive.first_dynamic or part_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(part_t);
        if (flags.is_union) {
            for (self.interner.unionMembers(part_t)) |member| {
                if (try self.templatePlaceholderAcceptsSlice(member, slice)) return true;
            }
            return false;
        }
        if (flags.is_literal and flags.is_string) {
            const lit = self.interner.literalOf(part_t);
            return switch (lit) {
                .string_lit => |target_sid| std.mem.eql(u8, self.string_interner.get(target_sid), slice) or
                    try self.cookedStringEqualsSlice(target_sid, slice),
                else => false,
            };
        }
        if (flags.is_literal and flags.is_number) return sliceLooksNumeric(slice);
        if (flags.is_template_literal or flags.is_string_mapping) {
            const sid = self.string_interner.intern(slice) catch return error.OutOfMemory;
            return try self.stringLiteralAssignableToType(sid, part_t);
        }
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(part_t) orelse return true;
            if (constraint == part_t) return true;
            return try self.templatePlaceholderAcceptsSlice(constraint, slice);
        }
        return false;
    }

    fn sliceLooksNumeric(slice: []const u8) bool {
        if (slice.len == 0) return false;
        _ = std.fmt.parseFloat(f64, slice) catch return false;
        return true;
    }

    fn sliceLooksBigInt(slice: []const u8) bool {
        if (slice.len == 0) return false;
        var i: usize = 0;
        if (slice[0] == '-' or slice[0] == '+') i = 1;
        if (i == slice.len) return false;
        while (i < slice.len) : (i += 1) {
            if (!std.ascii.isDigit(slice[i])) return false;
        }
        return true;
    }

    fn literalStringCookedId(self: *Checker, node: NodeId) CheckError!hir_mod.StringId {
        const lit = hir_mod.literalStringOf(self.hir, node);
        const raw = self.string_interner.get(lit.value);
        if (std.mem.indexOfScalar(u8, raw, '\\') == null and std.mem.indexOfScalar(u8, raw, '\r') == null) return lit.value;
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        defer buf.deinit(self.gpa);
        try self.appendCookedStringText(raw, &buf);
        return self.string_interner.intern(buf.items) catch return error.OutOfMemory;
    }

    fn cookedStringIdEquals(self: *Checker, a: hir_mod.StringId, b: hir_mod.StringId) CheckError!bool {
        if (a == b) return true;
        const raw_a = self.string_interner.get(a);
        const raw_b = self.string_interner.get(b);
        if (std.mem.eql(u8, raw_a, raw_b)) return true;
        var cooked_a: std.ArrayListUnmanaged(u8) = .empty;
        defer cooked_a.deinit(self.gpa);
        var cooked_b: std.ArrayListUnmanaged(u8) = .empty;
        defer cooked_b.deinit(self.gpa);
        try self.appendCookedStringText(raw_a, &cooked_a);
        try self.appendCookedStringText(raw_b, &cooked_b);
        return std.mem.eql(u8, cooked_a.items, cooked_b.items);
    }

    fn cookedStringEqualsSlice(self: *Checker, sid: hir_mod.StringId, slice: []const u8) CheckError!bool {
        const raw = self.string_interner.get(sid);
        if (std.mem.eql(u8, raw, slice)) return true;
        var cooked: std.ArrayListUnmanaged(u8) = .empty;
        defer cooked.deinit(self.gpa);
        try self.appendCookedStringText(raw, &cooked);
        return std.mem.eql(u8, cooked.items, slice);
    }

    fn appendCookedStringText(
        self: *Checker,
        raw: []const u8,
        out: *std.ArrayListUnmanaged(u8),
    ) CheckError!void {
        var i: usize = 0;
        while (i < raw.len) {
            const c = raw[i];
            if (c == '\r') {
                try out.append(self.gpa, '\n');
                i += if (i + 1 < raw.len and raw[i + 1] == '\n') 2 else 1;
                continue;
            }
            if (c != '\\') {
                try out.append(self.gpa, c);
                i += 1;
                continue;
            }
            if (i + 1 >= raw.len) {
                try out.append(self.gpa, c);
                i += 1;
                continue;
            }
            const esc = raw[i + 1];
            i += 2;
            switch (esc) {
                '0' => try out.append(self.gpa, 0),
                'b' => try out.append(self.gpa, 0x08),
                'f' => try out.append(self.gpa, 0x0c),
                'n' => try out.append(self.gpa, '\n'),
                'r' => try out.append(self.gpa, '\r'),
                't' => try out.append(self.gpa, '\t'),
                'v' => try out.append(self.gpa, 0x0b),
                '\n' => {},
                '\r' => {
                    if (i < raw.len and raw[i] == '\n') i += 1;
                },
                'x' => {
                    if (i + 1 < raw.len) {
                        if (hexValue(raw[i])) |hi| {
                            if (hexValue(raw[i + 1])) |lo| {
                                try out.append(self.gpa, (hi << 4) | lo);
                                i += 2;
                                continue;
                            }
                        }
                    }
                    try out.appendSlice(self.gpa, "\\x");
                },
                'u' => {
                    if (try self.appendUnicodeEscape(raw, &i, out)) continue;
                    try out.appendSlice(self.gpa, "\\u");
                },
                else => try out.append(self.gpa, esc),
            }
        }
    }

    fn appendUnicodeEscape(
        self: *Checker,
        raw: []const u8,
        index: *usize,
        out: *std.ArrayListUnmanaged(u8),
    ) CheckError!bool {
        if (index.* < raw.len and raw[index.*] == '{') {
            var j = index.* + 1;
            var cp: u21 = 0;
            var saw_digit = false;
            while (j < raw.len and raw[j] != '}') : (j += 1) {
                const v = hexValue(raw[j]) orelse return false;
                saw_digit = true;
                const next = (@as(u32, cp) << 4) | v;
                if (next > 0x10ffff) return false;
                cp = @intCast(next);
            }
            if (!saw_digit or j >= raw.len or raw[j] != '}') return false;
            var enc: [4]u8 = undefined;
            const len = std.unicode.utf8Encode(cp, &enc) catch return false;
            try out.appendSlice(self.gpa, enc[0..len]);
            index.* = j + 1;
            return true;
        }
        if (index.* + 3 >= raw.len) return false;
        var cp: u21 = 0;
        var j = index.*;
        while (j < index.* + 4) : (j += 1) {
            const v = hexValue(raw[j]) orelse return false;
            cp = @intCast((@as(u32, cp) << 4) | v);
        }
        var enc: [4]u8 = undefined;
        const len = std.unicode.utf8Encode(cp, &enc) catch return false;
        try out.appendSlice(self.gpa, enc[0..len]);
        index.* += 4;
        return true;
    }

    fn hexValue(c: u8) ?u8 {
        if (c >= '0' and c <= '9') return c - '0';
        if (c >= 'a' and c <= 'f') return c - 'a' + 10;
        if (c >= 'A' and c <= 'F') return c - 'A' + 10;
        return null;
    }

    fn stringMappingTypeMatchesString(self: *Checker, target_t: TypeId, sid: hir_mod.StringId) CheckError!bool {
        const payload = self.interner.stringMappingPayload(target_t);
        const raw = self.string_interner.get(sid);
        var candidate = try self.gpa.alloc(u8, raw.len);
        defer self.gpa.free(candidate);
        @memcpy(candidate, raw);
        switch (payload.kind) {
            .lowercase => {
                for (candidate) |*c| c.* = std.ascii.toUpper(c.*);
            },
            .uppercase => {
                for (candidate) |*c| c.* = std.ascii.toLower(c.*);
            },
            .capitalize => {
                if (candidate.len > 0) candidate[0] = std.ascii.toLower(candidate[0]);
            },
            .uncapitalize => {
                if (candidate.len > 0) candidate[0] = std.ascii.toUpper(candidate[0]);
            },
        }
        const remapped = try self.gpa.alloc(u8, candidate.len);
        defer self.gpa.free(remapped);
        @memcpy(remapped, candidate);
        applyStringMappingToBuffer(payload.kind, remapped);
        if (!std.mem.eql(u8, remapped, raw)) return false;
        const candidate_sid = self.string_interner.intern(candidate) catch return error.OutOfMemory;
        return try self.stringLiteralAssignableToType(candidate_sid, payload.inner);
    }

    fn literalExpressionAssignableToTarget(self: *Checker, value_node: NodeId, target_t: TypeId) !bool {
        if (target_t == types.Primitive.true_lit) return self.hir.kindOf(value_node) == .literal_bool and hir_mod.literalBoolOf(self.hir, value_node);
        if (target_t == types.Primitive.false_lit) return self.hir.kindOf(value_node) == .literal_bool and !hir_mod.literalBoolOf(self.hir, value_node);
        if (self.hir.kindOf(value_node) == .literal_string) {
            const sid = try self.literalStringCookedId(value_node);
            if (try self.stringLiteralAssignableToType(sid, target_t)) return true;
            if (target_t >= types.Primitive.first_dynamic and target_t < self.interner.pool.typeCount()) {
                const flags = self.interner.pool.flagsOf(target_t);
                if (flags.is_template_literal or flags.is_string_mapping) return false;
            }
        }
        if (self.hir.kindOf(value_node) == .template_literal) {
            if (try self.templateLiteralConcreteString(value_node)) |sid| {
                if (try self.stringLiteralAssignableToType(sid, target_t)) return true;
            }
        }
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_union) {
            if (self.interner.pool.payloadOf(target_t) >= self.interner.pool.union_payloads.items.len) return false;
            for (self.interner.unionMembers(target_t)) |member| {
                if (try self.literalExpressionAssignableToTarget(value_node, member)) return true;
            }
            return false;
        }
        if (flags.is_keyof) {
            return self.hir.kindOf(value_node) == .literal_string or
                self.hir.kindOf(value_node) == .literal_number or
                self.hir.kindOf(value_node) == .literal_bigint;
        }
        if (!flags.is_literal) return false;
        const lit = self.interner.literalOf(target_t);
        return switch (lit) {
            .string_lit => |sid| self.hir.kindOf(value_node) == .literal_string and
                try self.cookedStringIdEquals(try self.literalStringCookedId(value_node), sid),
            .number_lit => |bits| blk: {
                const expected = @as(f64, @bitCast(bits));
                if (self.hir.kindOf(value_node) == .literal_number) {
                    break :blk self.literalNumberWithSourceSign(value_node) == expected;
                }
                if (self.hir.kindOf(value_node) == .unary_op) {
                    const u = hir_mod.unaryOf(self.hir, value_node);
                    if (u.op == .neg and self.hir.kindOf(u.operand) == .literal_number) {
                        break :blk -hir_mod.literalNumberOf(self.hir, u.operand) == expected;
                    }
                    if (u.op == .plus and self.hir.kindOf(u.operand) == .literal_number) {
                        break :blk hir_mod.literalNumberOf(self.hir, u.operand) == expected;
                    }
                }
                break :blk false;
            },
            .bigint_lit => false,
            .boolean_lit => |b| self.hir.kindOf(value_node) == .literal_bool and hir_mod.literalBoolOf(self.hir, value_node) == b,
        };
    }

    fn expressionIsNumericLiteral(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) == .literal_number) return true;
        if (self.hir.kindOf(node) != .unary_op) return false;
        const u = hir_mod.unaryOf(self.hir, node);
        return (u.op == .neg or u.op == .plus) and self.hir.kindOf(u.operand) == .literal_number;
    }

    fn expressionLiteralType(self: *Checker, value_node: NodeId, fallback: TypeId) !TypeId {
        return switch (self.hir.kindOf(value_node)) {
            .literal_string => blk: {
                const sid = try self.literalStringCookedId(value_node);
                break :blk self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
            },
            .literal_number => blk: {
                const value = self.literalNumberWithSourceSign(value_node);
                break :blk self.interner.internNumberLiteral(value) catch return error.OutOfMemory;
            },
            .literal_bool => if (hir_mod.literalBoolOf(self.hir, value_node)) types.Primitive.true_lit else types.Primitive.false_lit,
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, value_node);
                if (self.hir.kindOf(m.object) == .identifier) {
                    const obj = hir_mod.identifierOf(self.hir, m.object);
                    if (self.constEnumLiteralAccess(obj.name, m.name, value_node)) |lit_t| break :blk lit_t;
                }
                break :blk fallback;
            },
            .template_literal => blk: {
                const sid = (try self.templateLiteralConcreteString(value_node)) orelse break :blk fallback;
                break :blk self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
            },
            else => fallback,
        };
    }

    fn reportTypeNotAssignable(
        self: *Checker,
        node: NodeId,
        source: TypeId,
        target: TypeId,
        fallback: []const u8,
    ) !void {
        const source_name = (try self.allocSimpleTypeName(source)) orelse
            (try self.allocObjectTypeShape(source)) orelse
            return try self.report(node, TsCodes.type_not_assignable, fallback);
        const target_name = (try self.allocSimpleTypeName(target)) orelse
            (try self.allocObjectTypeShape(target)) orelse
            return try self.report(node, TsCodes.type_not_assignable, fallback);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Type '{s}' is not assignable to type '{s}'.",
            .{ source_name, target_name },
        );
        try self.report(node, TsCodes.type_not_assignable, msg);
    }

    /// TS2741 — single-required-property gap. Returns true and emits
    /// the diagnostic when the source object type is missing exactly
    /// one of `target`'s required non-method members. Mirrors tsc's
    /// preference for the more-specific TS2741 wording over TS2322
    /// — matches `renamed.ts`, `exportSpecifiers_js.ts`,
    /// `objectSpreadNegative.ts`, `assignmentCompatWithEnumIndexer.ts`
    /// and the union-of-objects family. Otherwise returns false so
    /// callers fall through to the generic TS2322 path.
    fn tryReportSinglePropertyMissing(
        self: *Checker,
        diag_node: NodeId,
        value_node: NodeId,
        source: TypeId,
        target: TypeId,
    ) !bool {
        if (target == types.Primitive.none or target == types.Primitive.any or
            target == types.Primitive.unknown)
        {
            return false;
        }
        if (target >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(target).is_object_type) return false;
        if (source == types.Primitive.any or source == types.Primitive.unknown or
            source == types.Primitive.none)
        {
            return false;
        }

        // Source-side gate: either the value is a literal object
        // (empty or otherwise) OR the resolved source is an object
        // type whose members we can enumerate, OR the resolved
        // source is the broad `object` primitive (which upstream
        // tsc widens to `{}` for the missing-property error).
        // tsc fires TS2741 in the empty-source (`{}` flowing into
        // `{ x: T }`), partial-source (`{ s: string }` into
        // `{ b: boolean; s: string }`), and broad-object cases.
        const source_is_object_shaped = blk: {
            if (value_node != hir_mod.none_node_id and
                self.hir.kindOf(value_node) == .object_literal)
            {
                break :blk true;
            }
            if (source == types.Primitive.object_t) break :blk true;
            if (source < self.interner.pool.typeCount() and
                self.interner.pool.flagsOf(source).is_object_type)
            {
                break :blk true;
            }
            break :blk false;
        };
        if (!source_is_object_shaped) return false;

        // When target is a tuple and source is a number-indexed array
        // shape (e.g. `number[]`), upstream tsc emits the generic
        // TS2322 ("Type 'number[]' is not assignable to type
        // '[number]'.") rather than the missing-property TS2741.
        // Mirrors `strictTupleLength.ts(18,1)` and
        // `assignmentCompatBetweenTupleAndArray.ts(18,1)`.
        const target_tuple_len_opt = self.fixedTupleLength(target);
        if (target_tuple_len_opt != null and
            source < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(source).is_object_type)
        {
            const sm = self.interner.objectMembers(source);
            const num_idx = self.interner.objectNumberIndex(source);
            if (num_idx != types.Primitive.none) {
                // Treat the source as an array-shape (and skip TS2741)
                // unless it has any *non-`length*, non-numeric, non-method
                // members — those would indicate a richer object literal
                // where TS2741 is still the correct preference.
                const length_id = self.string_interner.intern("length") catch 0;
                var has_extra_member = false;
                for (sm) |m| {
                    if (m.name == length_id) continue;
                    // Numeric-indexed members (e.g. tuple element `0`) are
                    // structurally part of the array shape, not extra
                    // properties.
                    const nm = self.string_interner.get(m.name);
                    if (nm.len > 0 and isAllDigits(nm)) continue;
                    has_extra_member = true;
                    break;
                }
                if (!has_extra_member) return false;
            }
        }

        // Find required (non-optional, non-method) target members the
        // source lacks. Only fire when there's exactly one such
        // missing member — for two or more, tsc switches to the
        // multi-property TS2739 wording.
        const target_members = self.interner.objectMembers(target);
        const source_members = if (source < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(source).is_object_type)
            self.interner.objectMembers(source)
        else
            &[_]types.ObjectMember{};

        var missing_count: usize = 0;
        var first_missing_name: hir_mod.StringId = 0;
        for (target_members) |tm| {
            if (tm.is_optional or tm.is_method) continue;
            var found = false;
            for (source_members) |sm| {
                if (sm.name == tm.name) {
                    found = true;
                    break;
                }
            }
            if (found) continue;
            missing_count += 1;
            if (missing_count == 1) first_missing_name = tm.name;
            if (missing_count > 1) break;
        }
        if (missing_count != 1) return false;

        const target_name = (try self.allocSimpleTypeName(target)) orelse
            (try self.allocObjectTypeShape(target)) orelse return false;
        // Upstream tsc renders the broad `object` primitive as `{}`
        // in this missing-property error — see
        // `nonPrimitiveAssignError.ts(5,1)`.
        const source_name = if (source == types.Primitive.object_t)
            "{}"
        else
            (try self.allocSimpleTypeName(source)) orelse
                (try self.allocObjectTypeShape(source)) orelse "{}";
        // Tuple types render their numeric element index as `'2'`
        // (no inner quotes) — see `arityAndOrderCompatibility01.ts`.
        // For other object types the missing string-named property is
        // double-quoted when the name isn't a JS identifier — see
        // `assignmentCompatWithObjectMembersStringNumericNames.ts`.
        // (Tuples are stored as object types with a numeric `length`
        // member; `is_tuple` flag is not consistently set, so detect
        // via `fixedTupleLength`.)
        const target_is_tuple = target_tuple_len_opt != null;
        const prop_text = if (target_is_tuple)
            self.string_interner.get(first_missing_name)
        else
            self.formatPropertyNameForDiagnostic(self.string_interner.get(first_missing_name));
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' is missing in type '{s}' but required in type '{s}'.",
            .{ prop_text, source_name, target_name },
        );
        try self.report(diag_node, TsCodes.property_missing_required, msg);
        return true;
    }

    /// Formats a property name for use in a diagnostic message that
    /// already wraps it in single quotes (e.g. `Property '{s}' is
    /// missing...`). Upstream tsc applies an outer single-quote layer
    /// and, when the name isn't a JS identifier (numeric like `1`,
    /// dotted like `1.0`, or otherwise non-identifier), additionally
    /// wraps the name itself in single quotes, producing `''1''` /
    /// `''1.0''` in the rendered message.
    fn formatPropertyNameForDiagnostic(self: *Checker, name: []const u8) []const u8 {
        if (isJsIdentifier(name)) return name;
        return std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}'", .{name}) catch name;
    }

    /// Render a structural object type as `{ k: T; … }`. Used by
    /// the TS2741 missing-property message when the target type
    /// has named members and `allocSimpleTypeName` returns null.
    /// Returns null when any constituent member type can't be named.
    fn allocObjectTypeShape(self: *Checker, t: TypeId) !?[]const u8 {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_object_type) return null;
        const members = self.interner.objectMembers(t);
        const string_idx = self.interner.objectStringIndex(t);
        const number_idx = self.interner.objectNumberIndex(t);
        const has_string_idx = string_idx != types.Primitive.none;
        const has_number_idx = number_idx != types.Primitive.none;
        if (members.len == 0 and !has_string_idx and !has_number_idx) return "{}";
        // Cap render at a small member count to avoid runaway allocation
        // on large object types — tsc itself elides past ~7 members but
        // for the missing-property case we usually hit 1-3.
        if (members.len > 8) return null;
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        const arena = self.diag_arena.allocator();
        try buf.appendSlice(arena, "{ ");
        // Render index signatures BEFORE named members so the
        // output matches `{ [x: string]: T; foo: U; }` ordering
        // upstream tsc emits for fixtures like
        // `assignmentCompatWithStringIndexer2.ts(15,1)`.
        if (has_string_idx) {
            const value_name = (try self.allocSimpleTypeName(string_idx)) orelse return null;
            const ix_text = try std.fmt.allocPrint(arena, "[x: string]: {s}; ", .{value_name});
            try buf.appendSlice(arena, ix_text);
        }
        if (has_number_idx) {
            const value_name = (try self.allocSimpleTypeName(number_idx)) orelse return null;
            const ix_text = try std.fmt.allocPrint(arena, "[x: number]: {s}; ", .{value_name});
            try buf.appendSlice(arena, ix_text);
        }
        const call_id = self.string_interner.intern("__call") catch 0;
        const construct_id = self.string_interner.intern("__construct") catch 0;
        for (members) |m| {
            const name = self.string_interner.get(m.name);
            // `__call` / `__construct` members are internal markers
            // for call / construct signatures and overload bundles.
            // Render them upstream-style as `(params): R` / `new
            // (params): R` (no leading name/colon) so TS2322 prose
            // for fixtures like
            // `stringLiteralTypesOverloadAssignability05.ts(15,1)`,
            // `functionLiterals.ts(28,1)`, and the construct-signature
            // family matches the tsc baselines.
            if ((m.name == call_id or m.name == construct_id) and self.interner.isSignature(m.type)) {
                const sig_text = (try self.allocCallSignatureFnTypeName(m.type)) orelse return null;
                // `allocCallSignatureFnTypeName` already prefixes
                // `new ` for construct sigs and produces `(p: T) => R`;
                // call-signature object-member form drops the `=>`
                // for the upstream method-style rendering.
                const arrow = std.mem.indexOf(u8, sig_text, ") => ") orelse {
                    try buf.appendSlice(arena, sig_text);
                    try buf.appendSlice(arena, "; ");
                    continue;
                };
                try buf.appendSlice(arena, sig_text[0 .. arrow + 1]);
                try buf.appendSlice(arena, ": ");
                try buf.appendSlice(arena, sig_text[arrow + 5 ..]);
                try buf.appendSlice(arena, "; ");
                continue;
            }
            try buf.appendSlice(arena, name);
            if (m.is_optional) try buf.append(arena, '?');
            try buf.appendSlice(arena, ": ");
            const type_name = (try self.allocSimpleTypeName(m.type)) orelse return null;
            try buf.appendSlice(arena, type_name);
            try buf.appendSlice(arena, "; ");
        }
        try buf.append(arena, '}');
        return buf.items;
    }


    /// "Weak type" detection: target type has only optional named
    /// members (and no index signatures / call / construct
    /// signatures), and the source's named members share no name
    /// with the target's. Upstream tsc treats this as a likely
    /// typo and surfaces TS2559 instead of TS2322. Returns true
    /// when the diagnostic was emitted.
    fn tryReportWeakTypeNoOverlap(
        self: *Checker,
        node: NodeId,
        source: TypeId,
        target: TypeId,
    ) CheckError!bool {
        if (source < types.Primitive.first_dynamic or
            source >= self.interner.pool.typeCount()) return false;
        if (target < types.Primitive.first_dynamic or
            target >= self.interner.pool.typeCount()) return false;
        const tflags = self.interner.pool.flagsOf(target);
        const sflags = self.interner.pool.flagsOf(source);
        if (!tflags.is_object_type) return false;
        if (!sflags.is_object_type) return false;
        const target_members = self.interner.objectMembers(target);
        if (target_members.len == 0) return false;
        // Target must be "weak": every named member is optional, and
        // there is no index / call / construct signature that could
        // accept arbitrary keys.
        if (self.interner.objectStringIndex(target) != types.Primitive.none) return false;
        if (self.interner.objectNumberIndex(target) != types.Primitive.none) return false;
        if (self.interner.objectSymbolIndex(target) != types.Primitive.none) return false;
        const call_id = self.string_interner.intern("__call") catch return false;
        const construct_id = self.string_interner.intern("__construct") catch return false;
        for (target_members) |m| {
            if (m.name == call_id or m.name == construct_id) return false;
            if (!m.is_optional) return false;
        }
        const source_members = self.interner.objectMembers(source);
        if (source_members.len == 0) return false;
        // Bail on source-side index signatures / call/construct
        // members — those make "overlap" ill-defined for weak-type
        // diagnostics; upstream tsc skips TS2559 in those cases too.
        if (self.interner.objectStringIndex(source) != types.Primitive.none) return false;
        if (self.interner.objectNumberIndex(source) != types.Primitive.none) return false;
        if (self.interner.objectSymbolIndex(source) != types.Primitive.none) return false;
        for (source_members) |sm| {
            if (sm.name == call_id or sm.name == construct_id) return false;
        }
        // Detect overlap by property name only — the property's type
        // is checked separately by the relation engine and isn't part
        // of the TS2559 trigger.
        for (target_members) |tm| {
            for (source_members) |sm| {
                if (tm.name == sm.name) return false;
            }
        }
        const source_name = (try self.allocSimpleTypeName(source)) orelse
            (try self.allocObjectTypeShape(source)) orelse return false;
        const target_name = (try self.allocSimpleTypeName(target)) orelse
            (try self.allocObjectTypeShape(target)) orelse return false;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Type '{s}' has no properties in common with type '{s}'.",
            .{ source_name, target_name },
        );
        try self.report(node, TsCodes.no_properties_in_common, msg);
        return true;
    }

    fn reportAssignmentTypeNotAssignable(
        self: *Checker,
        node: NodeId,
        value_node: NodeId,
        source: TypeId,
        target: TypeId,
        fallback: []const u8,
    ) !void {
        // Prefer the more-specific TS2741 ("Property X is missing
        // in type A but required in type B") wording over the
        // generic TS2322 when the source is missing exactly one
        // required property — mirrors fixture
        // `nonPrimitiveAssignError.ts(5,1)`.
        if (try self.tryReportSinglePropertyMissing(node, value_node, source, target)) return;
        // Weak-type check: when the target's named members are all
        // optional and the source shares no property name with the
        // target, upstream tsc surfaces TS2559 in place of TS2322.
        // See `assignmentCompatWithObjectMembersOptionality2.ts(33,5)`.
        if (try self.tryReportWeakTypeNoOverlap(node, source, target)) return;
        const source_name = self.objectAnnotationNameForIdentifier(value_node) orelse
            (try self.allocSimpleTypeName(source)) orelse
            (try self.allocObjectTypeShape(source)) orelse
            return try self.report(node, TsCodes.type_not_assignable, fallback);
        const target_name = (try self.allocSimpleTypeName(target)) orelse
            (try self.allocObjectTypeShape(target)) orelse
            return try self.report(node, TsCodes.type_not_assignable, fallback);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Type '{s}' is not assignable to type '{s}'.",
            .{ source_name, target_name },
        );
        try self.report(node, TsCodes.type_not_assignable, msg);
    }

    fn objectAnnotationNameForIdentifier(self: *Checker, node: NodeId) ?[]const u8 {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, node);
        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const stmts: ?[]const NodeId = switch (self.hir.kindOf(cur)) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => null,
            };
            if (stmts) |items| {
                for (items) |stmt| {
                    if (self.hir.spanOf(stmt).start > use_start) break;
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    const dk = self.hir.kindOf(decl);
                    if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, v.name).name != id.name) continue;
                    return self.objectAnnotationName(v.type_annotation);
                }
            }
        }
        if (self.module) |module| {
            if (module.root.lookup(id.name)) |sym| {
                if (sym.decls.items.len == 0) return null;
                const decl = sym.decls.items[0];
                const dk = self.hir.kindOf(decl);
                if (dk != .var_decl and dk != .let_decl and dk != .const_decl) return null;
                return self.objectAnnotationName(hir_mod.varDeclOf(self.hir, decl).type_annotation);
            }
        }
        return null;
    }

    fn objectAnnotationName(self: *Checker, type_node: NodeId) ?[]const u8 {
        if (type_node == hir_mod.none_node_id) return null;
        const object_name = "Object";
        return switch (self.hir.kindOf(type_node)) {
            .identifier => blk: {
                const name = hir_mod.identifierOf(self.hir, type_node).name;
                break :blk if (std.mem.eql(u8, self.string_interner.get(name), object_name)) object_name else null;
            },
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, type_node);
                if (r.qualifier_len != 0 or r.args_len != 0) break :blk null;
                break :blk if (std.mem.eql(u8, self.string_interner.get(r.name), object_name)) object_name else null;
            },
            else => null,
        };
    }

    fn reportSwitchCaseNotComparable(self: *Checker, node: NodeId, case_t: TypeId, disc_t: TypeId) !void {
        if (try self.allocSimpleTypeName(case_t)) |case_name| {
            if (try self.allocSimpleTypeName(disc_t)) |disc_name| {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Type '{s}' is not comparable to type '{s}'.",
                    .{ case_name, disc_name },
                );
                try self.report(node, TsCodes.switch_case_not_comparable, msg);
                return;
            }
        }
        try self.report(node, TsCodes.switch_case_not_comparable, "Type is not comparable to switch expression type.");
    }

    fn reportNoOverlapComparison(self: *Checker, node: NodeId, lhs: TypeId, rhs: TypeId) !void {
        const pos = self.adjustedComparisonDiagnosticPos(node);
        // When one operand is a literal type but the other is the
        // base primitive of a DIFFERENT family (e.g. `"foo" == 42`,
        // where the literal's base is `string` and the other side
        // is `number`), tsc widens the literal to its base before
        // rendering — so the message reads `'string' and 'number'`,
        // not `'"foo"' and 'number'`. Mirrors upstream prose for
        // `stringLiteralsAssertionsInEqualityComparisons02.ts(5,9)`.
        // Same-family pairs (`"foo" === "bar"`) keep both literals,
        // matching upstream's no-widen behavior for line 3 of the
        // same fixture.
        var display_lhs = lhs;
        var display_rhs = rhs;
        if (self.shouldWidenLiteralAgainstPrimitive(lhs, rhs)) {
            display_lhs = self.widenLiteralType(lhs);
        }
        if (self.shouldWidenLiteralAgainstPrimitive(rhs, lhs)) {
            display_rhs = self.widenLiteralType(rhs);
        }
        if (try self.allocComparisonOperandName(display_lhs)) |lhs_name| {
            if (try self.allocComparisonOperandName(display_rhs)) |rhs_name| {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "This comparison appears to be unintentional because the types '{s}' and '{s}' have no overlap.",
                    .{ lhs_name, rhs_name },
                );
                try self.reportAt(node, pos, TsCodes.no_overlap_comparison, msg);
                return;
            }
        }
        try self.reportAt(node, pos, TsCodes.no_overlap_comparison, "This comparison appears to be unintentional because the types have no overlap.");
    }

    /// Returns true when `lit` is a literal type and `other` is the
    /// base primitive of a DIFFERENT family (so widening `lit` keeps
    /// the no-overlap message readable). `lit` itself may already be
    /// a base primitive; in that case we don't widen.
    fn shouldWidenLiteralAgainstPrimitive(self: *Checker, lit: TypeId, other: TypeId) bool {
        if (lit >= self.interner.pool.typeCount()) return false;
        const lflags = self.interner.pool.flagsOf(lit);
        if (!lflags.is_literal) return false;
        if (other >= self.interner.pool.typeCount()) return false;
        const oflags = self.interner.pool.flagsOf(other);
        if (oflags.is_literal) return false;
        // `other` must be a primitive of a DIFFERENT family — only
        // then does the no-overlap diagnostic widen the literal.
        const other_is_primitive_family = oflags.is_string or oflags.is_number or
            oflags.is_boolean or oflags.is_bigint or oflags.is_symbol;
        if (!other_is_primitive_family) return false;
        const literal_family_matches = (lflags.is_string and oflags.is_string) or
            (lflags.is_number and oflags.is_number) or
            (lflags.is_boolean and oflags.is_boolean) or
            (lflags.is_bigint and oflags.is_bigint);
        return !literal_family_matches;
    }

    /// Like `allocSimpleTypeName` but renders intersections as
    /// `A & B & ...` so TS2367 can report `'T & number' and 'string'`.
    /// Returns null when any constituent isn't nameable so callers
    /// fall through to the bare diagnostic.
    /// For TS2367 specifically, prefers rendering literal values
    /// (`'1'` instead of `'A'` for `type A = 1`) and prints unions
    /// of literals in upstream sort order (smallest number first,
    /// then alphabetic) — matches `numericLiteralTypes3.ts` and
    /// the literal-equality diff family.
    fn allocComparisonOperandName(self: *Checker, t: TypeId) !?[]const u8 {
        if (try self.literalDiagnosticName(t)) |lit_text| return lit_text;
        if (try self.literalUnionDiagnosticName(t)) |union_text| return union_text;
        if (try self.allocSimpleTypeName(t)) |n| return n;
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_intersection) return null;
        const members = self.interner.intersectionMembers(t);
        if (members.len == 0) return null;
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        const arena = self.diag_arena.allocator();
        for (members, 0..) |m, i| {
            if (i > 0) try buf.appendSlice(arena, " & ");
            const name = (try self.allocSimpleTypeName(m)) orelse return null;
            try buf.appendSlice(arena, name);
        }
        return buf.items;
    }

    /// Render a literal type's value text directly (`1`, `"foo"`,
    /// `true`) regardless of whether the type-id has a named-alias
    /// binding — the TS2367/TS2678 diff family prefers literal text.
    fn literalDiagnosticName(self: *Checker, t: TypeId) !?[]const u8 {
        if (t == types.Primitive.true_lit) return "true";
        if (t == types.Primitive.false_lit) return "false";
        if (t < types.Primitive.first_dynamic) return null;
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_literal) return null;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.literal_payloads.items.len) return null;
        const literal = self.interner.pool.literal_payloads.items[payload_idx];
        return switch (literal) {
            .string_lit => |sid| try std.fmt.allocPrint(self.diag_arena.allocator(), "\"{s}\"", .{self.string_interner.get(sid)}),
            .number_lit => |bits| try std.fmt.allocPrint(self.diag_arena.allocator(), "{d}", .{@as(f64, @bitCast(bits))}),
            .bigint_lit => |sid| try std.fmt.allocPrint(self.diag_arena.allocator(), "{s}", .{self.string_interner.get(sid)}),
            .boolean_lit => |b| if (b) "true" else "false",
        };
    }

    /// Render unions of literal types as `0 | 1 | 2` in upstream
    /// sort order (numeric ascending; strings alphabetic). Returns
    /// null for unions that contain non-literal members so callers
    /// fall back to the standard union renderer (which keeps the
    /// outer alias name when present).
    fn literalUnionDiagnosticName(self: *Checker, t: TypeId) !?[]const u8 {
        if (t < types.Primitive.first_dynamic) return null;
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_union) return null;
        const members = self.interner.unionMembers(t);
        if (members.len < 2) return null;
        // Verify all members are literal-like (number, string,
        // boolean lit) so we render predictably. Skip otherwise.
        for (members) |m| {
            if (m == types.Primitive.true_lit or m == types.Primitive.false_lit) continue;
            if (m < self.interner.pool.typeCount() and self.interner.pool.flagsOf(m).is_literal) continue;
            return null;
        }
        // Collect rendered names then sort lexicographically
        // (number-as-string sort works in upstream's diagnostic
        // formatter for small integer literals; we do not attempt
        // numeric-aware sorting since that would diverge from
        // tsc's own writer for negative or float values).
        var names: std.ArrayListUnmanaged([]const u8) = .empty;
        defer names.deinit(self.gpa);
        for (members) |m| {
            const name = (try self.literalDiagnosticName(m)) orelse return null;
            try names.append(self.gpa, name);
        }
        const Less = struct {
            fn lt(_: void, a: []const u8, b: []const u8) bool {
                return std.mem.lessThan(u8, a, b);
            }
        };
        std.mem.sort([]const u8, names.items, {}, Less.lt);
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        const arena = self.diag_arena.allocator();
        for (names.items, 0..) |n, i| {
            if (i > 0) try buf.appendSlice(arena, " | ");
            try buf.appendSlice(arena, n);
        }
        return buf.items;
    }

    fn adjustedComparisonDiagnosticPos(self: *Checker, node: NodeId) ?u32 {
        const src = self.source orelse return null;
        const span = self.hir.spanOf(node);
        if (span.start > 0 and span.start <= src.len and src[span.start - 1] == '(') {
            // Don't shift to `(` when it's the open-paren of a
            // control-flow head (`if`, `while`, `for`, `switch`).
            // tsc keeps the diagnostic on the operand identifier
            // there — see fixture `discriminatedUnionTypes1` which
            // expects col `m` rather than col `(` for
            // `if (m.kind === "X")`.
            if (self.parenIsControlFlowHead(span.start - 1)) return span.start;
            return span.start - 1;
        }
        return span.start;
    }

    fn parenIsControlFlowHead(self: *Checker, paren_pos: u32) bool {
        const src = self.source orelse return false;
        if (paren_pos == 0) return false;
        // Skip whitespace before the `(`.
        var i: u32 = paren_pos;
        while (i > 0) {
            const ch = src[i - 1];
            if (ch == ' ' or ch == '\t' or ch == '\n' or ch == '\r') {
                i -= 1;
                continue;
            }
            break;
        }
        if (i == 0) return false;
        const head_keywords = [_][]const u8{ "if", "while", "for", "switch" };
        for (head_keywords) |kw| {
            if (i >= kw.len and std.mem.eql(u8, src[i - kw.len .. i], kw)) {
                // Ensure the keyword stands alone (not a suffix
                // of a longer identifier).
                if (i == kw.len) return true;
                const prev = src[i - kw.len - 1];
                const ident_char = (prev == '_') or (prev == '$') or
                    (prev >= 'a' and prev <= 'z') or
                    (prev >= 'A' and prev <= 'Z') or
                    (prev >= '0' and prev <= '9');
                if (!ident_char) return true;
            }
        }
        return false;
    }

    /// Render a call or construct signature as `(p: T, q: U) => R`
    /// (or `new (p: T) => R`), preferring source-level parameter
    /// names recorded in `signature_param_names` and falling back
    /// to synthesized `x0`/`x1`/etc. positional placeholders.
    ///
    /// Generic signatures emit a `<T, U>` (or `<T extends C>`)
    /// prefix from the `generic_signature_params` side table —
    /// e.g. `<T>(x: T) => T[]`. Optional parameter slots beyond
    /// `signature_min_args` render as `(x?: T)`, and the trailing
    /// rest parameter (when `rest_signatures` flags the signature)
    /// renders as `...x: T`. Mirrors upstream tsc's TS2322 prose
    /// for the `callSignatureAssignabilityInInheritance*` and
    /// `assignmentCompatWith{Call,Construct}Signatures*` family.
    ///
    /// Returns null when the TypeId is not a signature payload or
    /// when the payload index is out of bounds. The caller
    /// (`allocSimpleTypeName`) gates on `interner.isSignature(t)`,
    /// so the OOB guards are only defensive.
    fn allocCallableSignatureName(self: *Checker, t: TypeId) CheckError!?[]const u8 {
        if (t >= self.interner.pool.typeCount()) return null;
        const sig_payload_idx = self.interner.pool.payloadOf(t);
        if (sig_payload_idx >= self.interner.pool.signature_payloads.items.len) return null;
        const sig = self.interner.pool.signature_payloads.items[sig_payload_idx];
        const params = self.interner.signatureParams(t);
        var sig_buf: std.ArrayListUnmanaged(u8) = .empty;
        const arena = self.diag_arena.allocator();
        if (sig.is_construct) try sig_buf.appendSlice(arena, "new ");
        // `<T, U extends Foo>` generic prefix. The
        // `generic_signature_params` side table records the
        // type-parameter TypeIds in declaration order; we render
        // each via `typeParameterName` plus an optional
        // `extends C` constraint via `typeParameterConstraint`.
        if (self.generic_signature_params.get(t)) |tp_ids| {
            if (tp_ids.len > 0) {
                try sig_buf.append(arena, '<');
                for (tp_ids, 0..) |tp_id, ti| {
                    if (ti > 0) try sig_buf.appendSlice(arena, ", ");
                    if (self.interner.typeParameterName(tp_id)) |tp_name| {
                        try sig_buf.appendSlice(arena, self.string_interner.get(tp_name));
                    } else {
                        try sig_buf.appendSlice(arena, "T");
                    }
                    if (self.interner.typeParameterConstraint(tp_id)) |c_id| {
                        if (try self.allocSimpleTypeName(c_id)) |cn| {
                            try sig_buf.appendSlice(arena, " extends ");
                            try sig_buf.appendSlice(arena, cn);
                        }
                    }
                }
                try sig_buf.append(arena, '>');
            }
        }
        try sig_buf.append(arena, '(');
        const recorded_names: ?[]const hir_mod.StringId = self.signature_param_names.get(t);
        const min_required = self.signature_min_args.get(t) orelse params.len;
        const has_rest = self.rest_signatures.contains(t);
        for (params, 0..) |p, i| {
            if (i > 0) try sig_buf.appendSlice(arena, ", ");
            const is_last = i == params.len - 1;
            const is_rest = has_rest and is_last;
            const is_optional = !is_rest and i >= min_required;
            if (is_rest) try sig_buf.appendSlice(arena, "...");
            const name_text: []const u8 = blk: {
                if (recorded_names) |names| if (i < names.len) {
                    break :blk self.string_interner.get(names[i]);
                };
                break :blk try std.fmt.allocPrint(arena, "x{d}", .{i});
            };
            try sig_buf.appendSlice(arena, name_text);
            if (is_optional) try sig_buf.append(arena, '?');
            try sig_buf.appendSlice(arena, ": ");
            if (try self.allocSimpleTypeName(p)) |pn| {
                try sig_buf.appendSlice(arena, pn);
            } else {
                try sig_buf.appendSlice(arena, "any");
            }
        }
        try sig_buf.appendSlice(arena, ") => ");
        const ret = self.interner.signatureReturn(t) orelse types.Primitive.any;
        if (try self.allocSimpleTypeName(ret)) |rn| {
            try sig_buf.appendSlice(arena, rn);
        } else {
            try sig_buf.appendSlice(arena, "any");
        }
        return sig_buf.items;
    }

    fn allocSimpleTypeName(self: *Checker, t: TypeId) !?[]const u8 {
        return switch (t) {
            types.Primitive.any => "any",
            types.Primitive.unknown => "unknown",
            types.Primitive.never => "never",
            types.Primitive.void_t => "void",
            types.Primitive.null_t => "null",
            types.Primitive.undefined_t => "undefined",
            types.Primitive.string_t => "string",
            types.Primitive.number_t => "number",
            types.Primitive.boolean_t => "boolean",
            types.Primitive.bigint_t => "bigint",
            types.Primitive.symbol_t => "symbol",
            types.Primitive.object_t => "object",
            types.Primitive.true_lit => "true",
            types.Primitive.false_lit => "false",
            else => blk: {
                if (self.enumNameFromNominal(t)) |enum_name| {
                    break :blk self.string_interner.get(enum_name);
                }
                if (self.namedTypeForId(t)) |type_name| {
                    break :blk self.string_interner.get(type_name);
                }
                // Built-in object names (`Date`, `Function`, `Number`,
                // `String`, `RegExp`, etc.) — populated lazily by
                // `lowerBuiltinObjectType` the first time the user's
                // source references the type. Mirrors the existing
                // `simpleDiagnosticTypeName` fallback so TS2322 prose
                // for `var e: Date = undefined` renders as
                // `Type 'undefined' is not assignable to type 'Date'.`
                // rather than collapsing to the structural shape.
                if (self.builtin_object_names.get(t)) |bname| {
                    break :blk bname;
                }
                // Generic-alias instantiation display name
                // (`Covariant<A>`, `Partial<T>`, `FunctionProperties<T>`).
                // Populated by `lowererLowerWithTypeParams` whenever a
                // generic alias is instantiated with type-arguments;
                // mirrors upstream tsc which preserves the alias name
                // in TS2322 prose rather than collapsing to the
                // substituted body. See `conditionalTypes2.ts(15,5)`.
                if (self.alias_display_names.get(t)) |display| {
                    break :blk display;
                }
                // Defensive guard: `typeParameterName` indexes the
                // type-parameter payloads directly without bounds
                // checking the payload index. Non-tp types occasionally
                // share the `is_type_parameter` flag bit (interner is
                // sharded; recycled slots can leak transient flags),
                // which crashed the full-corpus run before this guard
                // landed.
                if (t < self.interner.pool.typeCount()) {
                    const tp_flags = self.interner.pool.flagsOf(t);
                    if (tp_flags.is_type_parameter) {
                        const tp_payload_idx = self.interner.pool.payloadOf(t);
                        if (tp_payload_idx < self.interner.pool.type_parameter_payloads.items.len) {
                            if (self.interner.typeParameterName(t)) |tp_name| {
                                break :blk self.string_interner.get(tp_name);
                            }
                        }
                    }
                }
                if (t >= self.interner.pool.typeCount()) break :blk null;
                // `typeof Foo` rendering for class constructor types.
                // The static side of `class Foo { … }` lives in
                // `class_static_types[Foo]`; when that matches `t`,
                // tsc renders the type as `typeof Foo`. Mirrors the
                // upstream prose for fixtures like
                // `superSymbolIndexedAccess3.ts(11,22)`.
                {
                    var sit = self.class_static_types.iterator();
                    while (sit.next()) |entry| {
                        if (entry.value_ptr.* != t) continue;
                        const class_name_str = self.string_interner.get(entry.key_ptr.*);
                        const buf = std.fmt.allocPrint(self.diag_arena.allocator(), "typeof {s}", .{class_name_str}) catch break :blk null;
                        break :blk buf;
                    }
                }
                const flags = self.interner.pool.flagsOf(t);
                // Render fixed-width tuples (`[any]`, `[undefined, null]`)
                // so TS2322 prose includes the literal element shape.
                if (flags.is_object_type) {
                    const members = self.interner.objectMembers(t);
                    if (members.len == 1) {
                        const call_id = self.string_interner.intern("__call") catch break :blk null;
                        if (members[0].name == call_id and self.interner.isSignature(members[0].type)) {
                            if (try self.allocCallableSignatureName(members[0].type)) |name| break :blk name;
                        }
                    }
                    if (self.fixedTupleLength(t)) |length| {
                        var tuple_buf: std.ArrayListUnmanaged(u8) = .empty;
                        const arena_t = self.diag_arena.allocator();
                        try tuple_buf.append(arena_t, '[');
                        var ti: u64 = 0;
                        while (ti < length) : (ti += 1) {
                            if (ti > 0) try tuple_buf.appendSlice(arena_t, ", ");
                            const elem_t = self.tupleElementType(t, @intCast(ti));
                            if (try self.allocSimpleTypeName(elem_t)) |nm| {
                                try tuple_buf.appendSlice(arena_t, nm);
                            } else {
                                try tuple_buf.appendSlice(arena_t, "any");
                            }
                        }
                        try tuple_buf.append(arena_t, ']');
                        break :blk tuple_buf.items;
                    }
                    // Render array shapes (`T[]`) when the object type
                    // has a number index signature, no string/symbol
                    // index, and no own non-method, non-numeric, non-
                    // `length` members. Mirrors upstream TS prose for
                    // fixtures like
                    // `assignmentCompatBetweenTupleAndArray.ts(18,1)`
                    // and `strictTupleLength.ts(18,1)`.
                    //
                    // Additionally require that a `length: number`
                    // member is actually present — a literal index-
                    // signature type like `{ [x: number]: T; }` (no
                    // `length`) must render as the literal shape
                    // rather than `T[]`. tsc preserves the literal
                    // form because the type doesn't structurally
                    // satisfy the `Array<T>` shape. See
                    // `assignmentCompatWithNumericIndexer.ts(14,1)`.
                    const num_idx = self.interner.objectNumberIndex(t);
                    const length_id_arr = self.string_interner.intern("length") catch 0;
                    var has_only_length_or_numeric = true;
                    var has_length_member = false;
                    for (members) |m| {
                        if (m.name == length_id_arr) {
                            has_length_member = true;
                            continue;
                        }
                        const nm = self.string_interner.get(m.name);
                        if (nm.len > 0 and isAllDigits(nm)) continue;
                        has_only_length_or_numeric = false;
                        break;
                    }
                    if (has_only_length_or_numeric and
                        has_length_member and
                        num_idx != types.Primitive.none and
                        self.interner.objectStringIndex(t) == types.Primitive.none and
                        self.interner.objectSymbolIndex(t) == types.Primitive.none)
                    {
                        if (try self.allocSimpleTypeName(num_idx)) |elem_name| {
                            // Wrap union element type in parens so
                            // `T[]` doesn't become ambiguous in prose.
                            const wrap = std.mem.indexOfScalar(u8, elem_name, '|') != null or
                                std.mem.indexOf(u8, elem_name, "=>") != null;
                            const arena_arr = self.diag_arena.allocator();
                            const out_text = if (wrap)
                                try std.fmt.allocPrint(arena_arr, "({s})[]", .{elem_name})
                            else
                                try std.fmt.allocPrint(arena_arr, "{s}[]", .{elem_name});
                            break :blk out_text;
                        }
                    }
                    // Empty object type (`{}`) — used by
                    // `assignmentCompatBetweenTupleAndArray.ts(18,1)`.
                    if (members.len == 0 and
                        num_idx == types.Primitive.none and
                        self.interner.objectStringIndex(t) == types.Primitive.none and
                        self.interner.objectSymbolIndex(t) == types.Primitive.none)
                    {
                        break :blk "{}";
                    }
                    // Pure index-signature object types
                    // (`{ [x: number]: T; }`, `{ [x: string]: T; }`).
                    // No named members, no `length`, exactly one
                    // string-or-number indexer — render the literal
                    // index-signature shape. Mirrors upstream TS for
                    // `assignmentCompatWithNumericIndexer.ts(14,1)`
                    // and the `assignmentCompatWithStringIndexer`
                    // family, where the source type was declared via
                    // `var x: { [x: number]: T; }` rather than `T[]`.
                    if (members.len == 0) {
                        const str_idx = self.interner.objectStringIndex(t);
                        const sym_idx = self.interner.objectSymbolIndex(t);
                        const has_num = num_idx != types.Primitive.none;
                        const has_str = str_idx != types.Primitive.none;
                        const has_sym = sym_idx != types.Primitive.none;
                        const single_count: u32 = @as(u32, @intFromBool(has_num)) +
                            @as(u32, @intFromBool(has_str)) +
                            @as(u32, @intFromBool(has_sym));
                        if (single_count == 1) {
                            const key_label: []const u8 = if (has_str) "string" else if (has_num) "number" else "symbol";
                            const value_t: TypeId = if (has_str) str_idx else if (has_num) num_idx else sym_idx;
                            if (try self.allocSimpleTypeName(value_t)) |value_name| {
                                const arena_ix = self.diag_arena.allocator();
                                const out_text = try std.fmt.allocPrint(
                                    arena_ix,
                                    "{{ [x: {s}]: {s}; }}",
                                    .{ key_label, value_name },
                                );
                                break :blk out_text;
                            }
                        }
                    }
                }
                // Render unions (`object | null | undefined`) so the
                // exact-baseline ratchet can match upstream TS prose
                // for assignability mismatches involving nullable
                // union sources. Upstream TS prints non-nullish
                // members first and pushes `null` / `undefined` to
                // the tail; mirror that ordering.
                if (flags.is_union) {
                    var union_buf: std.ArrayListUnmanaged(u8) = .empty;
                    const arena_u = self.diag_arena.allocator();
                    var has_null = false;
                    var has_undef = false;
                    var first = true;
                    // Textual dedup of rendered member names. Distinct
                    // TypeIds can render to the same TS prose (e.g. a
                    // primitive `string_t` and a separately-interned
                    // string-flagged type both render as "string"); the
                    // union prose should only mention each label once.
                    // Mirrors upstream tsc which deduplicates by display
                    // form before joining with `|`. See fixture
                    // `restElementWithAssignmentPattern2.ts` which would
                    // otherwise render as `string | string | number`.
                    var seen_names: std.ArrayListUnmanaged([]const u8) = .empty;
                    defer seen_names.deinit(self.gpa);
                    for (self.interner.unionMembers(t)) |member| {
                        if (member == types.Primitive.null_t) {
                            has_null = true;
                            continue;
                        }
                        if (member == types.Primitive.undefined_t) {
                            has_undef = true;
                            continue;
                        }
                        const member_name = (try self.allocSimpleTypeName(member)) orelse break :blk null;
                        // Skip if we've already emitted this exact label.
                        var duplicate = false;
                        for (seen_names.items) |prior_name| {
                            if (std.mem.eql(u8, prior_name, member_name)) {
                                duplicate = true;
                                break;
                            }
                        }
                        if (duplicate) continue;
                        try seen_names.append(self.gpa, member_name);
                        if (!first) try union_buf.appendSlice(arena_u, " | ");
                        first = false;
                        // Wrap function/construct signature members and
                        // intersection members in parens within a union
                        // so `(() => string) | (() => number)` and
                        // `(A & B) | (C & D)` read unambiguously —
                        // matches upstream tsc for `unionTypeLiterals.ts`
                        // and `intersectionAndUnionTypes.ts(23,1)`.
                        const member_flags = self.interner.pool.flagsOf(member);
                        const needs_parens = std.mem.indexOf(u8, member_name, "=>") != null or
                            member_flags.is_intersection;
                        if (needs_parens) try union_buf.append(arena_u, '(');
                        try union_buf.appendSlice(arena_u, member_name);
                        if (needs_parens) try union_buf.append(arena_u, ')');
                    }
                    if (has_null) {
                        if (!first) try union_buf.appendSlice(arena_u, " | ");
                        first = false;
                        try union_buf.appendSlice(arena_u, "null");
                    }
                    if (has_undef) {
                        if (!first) try union_buf.appendSlice(arena_u, " | ");
                        first = false;
                        try union_buf.appendSlice(arena_u, "undefined");
                    }
                    if (union_buf.items.len == 0) break :blk null;
                    break :blk union_buf.items;
                }
                // Intersections (`Real & Fake`) — render only when
                // every member is nameable so the prose stays
                // unambiguous. Union members get parens so prose like
                // `(A | B) & (C | D)` is unambiguous; matches upstream
                // tsc — see `intersectionAndUnionTypes.ts(31,1)`.
                if (flags.is_intersection) {
                    var int_buf: std.ArrayListUnmanaged(u8) = .empty;
                    const arena_i = self.diag_arena.allocator();
                    var first_i = true;
                    for (self.interner.intersectionMembers(t)) |member| {
                        const member_name = (try self.allocSimpleTypeName(member)) orelse break :blk null;
                        if (!first_i) try int_buf.appendSlice(arena_i, " & ");
                        first_i = false;
                        const member_flags = self.interner.pool.flagsOf(member);
                        const needs_parens = member_flags.is_union or
                            std.mem.indexOf(u8, member_name, "=>") != null;
                        if (needs_parens) try int_buf.append(arena_i, '(');
                        try int_buf.appendSlice(arena_i, member_name);
                        if (needs_parens) try int_buf.append(arena_i, ')');
                    }
                    if (int_buf.items.len == 0) break :blk null;
                    break :blk int_buf.items;
                }
                // Render call and construct signatures via the
                // shared `allocCallableSignatureName` helper. The
                // helper consults `signature_param_names` so we
                // emit source-level parameter names (`(x: number)
                // => void`) when available, matching upstream TS
                // prose for fixtures like
                // `stringLiteralTypesOverloadAssignability01`.
                // Synthesized signatures (no recorded names) fall
                // back to positional `xN` placeholders.
                if (self.interner.isSignature(t)) {
                    if (try self.allocCallableSignatureName(t)) |name| break :blk name;
                    break :blk null;
                }
                if (flags.is_intersection) {
                    var intersection_buf: std.ArrayListUnmanaged(u8) = .empty;
                    const arena = self.diag_arena.allocator();
                    for (self.interner.intersectionMembers(t), 0..) |member, i| {
                        const member_name = (try self.allocSimpleTypeName(member)) orelse break :blk null;
                        if (i > 0) try intersection_buf.appendSlice(arena, " & ");
                        try intersection_buf.appendSlice(arena, member_name);
                    }
                    break :blk intersection_buf.items;
                }
                // Indexed-access types (`T[P]`, `Arr[number]`) — render
                // as `<object>[<index>]` so TS2322 prose for fixtures
                // like `nonPrimitiveConstraintOfIndexAccessType.ts`
                // includes the indexed-access shape rather than
                // falling through to the generic fallback.
                if (flags.is_indexed_access) {
                    const ia_payload_idx = self.interner.pool.payloadOf(t);
                    if (ia_payload_idx < self.interner.pool.indexed_access_payloads.items.len) {
                        const ia = self.interner.pool.indexed_access_payloads.items[ia_payload_idx];
                        const obj_name = (try self.allocSimpleTypeName(ia.object)) orelse break :blk null;
                        const idx_name = (try self.allocSimpleTypeName(ia.index)) orelse break :blk null;
                        break :blk try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "{s}[{s}]",
                            .{ obj_name, idx_name },
                        );
                    }
                }
                // Template literal types (`` `prefix${T}suffix` ``) —
                // render as a backtick-delimited template with `${...}`
                // placeholders so TS2322 prose for fixtures like
                // `templateLiteralTypes2.ts`,
                // `templateLiteralTypesPatterns.ts`,
                // `templateLiteralTypesPatternsPrefixSuffixAssignability.ts`,
                // and `stringMappingOverPatternLiterals.ts` matches the
                // upstream baselines.
                if (flags.is_template_literal) {
                    const texts = self.interner.templateLiteralTexts(t);
                    const part_types = self.interner.templateLiteralTypes(t);
                    var tl_buf: std.ArrayListUnmanaged(u8) = .empty;
                    const arena_tl = self.diag_arena.allocator();
                    try tl_buf.append(arena_tl, '`');
                    var tl_ok = true;
                    for (texts, 0..) |text_sid, i| {
                        try tl_buf.appendSlice(arena_tl, self.string_interner.get(text_sid));
                        if (i < part_types.len) {
                            // For string-literal placeholder types,
                            // upstream renders the bare value (without
                            // surrounding double quotes) inside `${...}`.
                            const part_t = part_types[i];
                            try tl_buf.appendSlice(arena_tl, "${");
                            if (self.stringLiteralValueFromType(part_t)) |sid| {
                                try tl_buf.appendSlice(arena_tl, self.string_interner.get(sid));
                            } else if (try self.allocSimpleTypeName(part_t)) |part_name| {
                                try tl_buf.appendSlice(arena_tl, part_name);
                            } else {
                                tl_ok = false;
                                break;
                            }
                            try tl_buf.append(arena_tl, '}');
                        }
                    }
                    if (!tl_ok) break :blk null;
                    try tl_buf.append(arena_tl, '`');
                    break :blk tl_buf.items;
                }
                // Intrinsic string-mapping types (`Uppercase<T>`,
                // `Lowercase<T>`, `Capitalize<T>`, `Uncapitalize<T>`)
                // — render as `<Kind><<inner>>` so TS2322 prose for
                // fixtures like `stringLiteralsAssignedToStringMappings.ts`
                // and `stringMappingOverPatternLiterals.ts` matches.
                if (flags.is_string_mapping) {
                    const sm = self.interner.stringMappingPayload(t);
                    const inner_name = (try self.allocSimpleTypeName(sm.inner)) orelse break :blk null;
                    const kind_name: []const u8 = switch (sm.kind) {
                        .lowercase => "Lowercase",
                        .uppercase => "Uppercase",
                        .capitalize => "Capitalize",
                        .uncapitalize => "Uncapitalize",
                    };
                    break :blk try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "{s}<{s}>",
                        .{ kind_name, inner_name },
                    );
                }
                if (!flags.is_literal) break :blk null;
                // Some non-literal types share a flag bit; guard against payload OOB.
                const payload_idx = self.interner.pool.payloadOf(t);
                if (payload_idx >= self.interner.pool.literal_payloads.items.len) break :blk null;
                const literal = self.interner.pool.literal_payloads.items[payload_idx];
                break :blk switch (literal) {
                    .string_lit => |sid| try std.fmt.allocPrint(self.diag_arena.allocator(), "\"{s}\"", .{self.string_interner.get(sid)}),
                    .number_lit => |bits| try std.fmt.allocPrint(self.diag_arena.allocator(), "{d}", .{@as(f64, @bitCast(bits))}),
                    .bigint_lit => |sid| try std.fmt.allocPrint(self.diag_arena.allocator(), "{s}", .{self.string_interner.get(sid)}),
                    .boolean_lit => |b| if (b) "true" else "false",
                };
            },
        };
    }

    fn namedTypeForId(self: *Checker, t: TypeId) ?hir_mod.StringId {
        var it = self.type_names.iterator();
        while (it.next()) |entry| {
            if (entry.value_ptr.* == t) return entry.key_ptr.*;
        }
        return null;
    }

    /// Record `<alias_name><<arg1, arg2, ...>>` as the display name
    /// for the substituted alias result `t`. Skipped when the result
    /// is a primitive, when no type-arguments materialize, when the
    /// result already has a more direct named identity, or when any
    /// argument fails to render. First-write wins so the earliest
    /// instantiation observed for a given collapsed body keeps its
    /// name; later collisions stay silent rather than thrashing the
    /// table.
    fn registerAliasDisplayName(
        self: *Checker,
        t: TypeId,
        alias_name: hir_mod.StringId,
        args: []const TypeId,
    ) !void {
        if (t < types.Primitive.first_dynamic) return;
        if (t >= self.interner.pool.typeCount()) return;
        if (args.len == 0) return;
        if (self.alias_display_names.contains(t)) return;
        // Skip if the result already has a more direct display name
        // via `type_names` (so we don't shadow class/interface
        // identity) or via the enum-nominal table.
        if (self.namedTypeForId(t) != null) return;
        if (self.enumNameFromNominal(t) != null) return;
        const arena = self.diag_arena.allocator();
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        const alias_str = self.string_interner.get(alias_name);
        try buf.appendSlice(arena, alias_str);
        try buf.append(arena, '<');
        for (args, 0..) |a, i| {
            if (i > 0) try buf.appendSlice(arena, ", ");
            const arg_name = (try self.allocSimpleTypeName(a)) orelse return;
            try buf.appendSlice(arena, arg_name);
        }
        try buf.append(arena, '>');
        try self.alias_display_names.put(self.gpa, t, buf.items);
    }

    fn report(self: *Checker, node: NodeId, code: u32, message: []const u8) !void {
        try self.reportAt(node, null, code, message);
    }

    /// Report TS2838 (`infer X` constraint mismatch) anchored at the
    /// `X` identifier's position rather than the `infer` keyword
    /// span start. Mirrors upstream tsc which underlines the
    /// type-parameter name.
    fn reportInferTypeName(
        self: *Checker,
        node: NodeId,
        name: hir_mod.StringId,
        message: []const u8,
    ) !void {
        const span = self.hir.spanOf(node);
        var pos: ?u32 = null;
        if (self.source) |src| {
            const tp_name = self.string_interner.get(name);
            if (tp_name.len > 0 and span.start < src.len) {
                const end = @min(src.len, @as(usize, span.end));
                if (std.mem.indexOfPos(u8, src[0..end], span.start, tp_name)) |idx| {
                    pos = @intCast(idx);
                }
            }
        }
        try self.reportAt(node, pos, TsCodes.infer_constraints_not_identical, message);
    }

    fn reportAt(self: *Checker, node: NodeId, pos: ?u32, code: u32, message: []const u8) !void {
        const msg = try self.diag_arena.allocator().dupe(u8, message);
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .pos = pos,
            .code = code,
            .message = msg,
        });
    }

    /// Anchor a diagnostic at the opening `[` of a class/object
    /// computed-property-name slot. Scans backward from the key
    /// node's source span for the `[`, ignoring `?`, whitespace,
    /// and other punctuation. Falls back to the key span start
    /// when the `[` can't be located (e.g. no source loaded).
    /// Mirrors tsc which underlines the entire `[expr]` group.
    fn reportComputedKeyBracket(
        self: *Checker,
        key_node: NodeId,
        code: u32,
        message: []const u8,
    ) !void {
        var pos: ?u32 = null;
        if (self.source) |src| {
            const span = self.hir.spanOf(key_node);
            if (span.start > 0 and span.start <= src.len) {
                var i: usize = span.start;
                while (i > 0) {
                    i -= 1;
                    if (src[i] == '[') {
                        pos = @intCast(i);
                        break;
                    }
                    // Bail out if we cross a non-whitespace,
                    // non-? character — keeps us from false-matching
                    // a `[` belonging to an enclosing structure.
                    if (src[i] != ' ' and src[i] != '\t' and src[i] != '\n' and src[i] != '\r') break;
                }
            }
        }
        try self.reportAt(key_node, pos, code, message);
    }

    fn reportUnknownReference(self: *Checker, node: NodeId) CheckError!void {
        const name = if (self.hir.kindOf(node) == .identifier)
            self.string_interner.get(hir_mod.identifierOf(self.hir, node).name)
        else
            "value";
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' is of type 'unknown'.",
            .{name},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.unknown_catch_variable,
            .message = msg,
        });
    }

    fn shouldReportUnknownReference(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) != .try_stmt) continue;
            const ts = hir_mod.tryOf(self.hir, cur);
            if (ts.catch_param == hir_mod.none_node_id or self.hir.kindOf(ts.catch_param) != .identifier) continue;
            const catch_id = hir_mod.identifierOf(self.hir, ts.catch_param);
            if (catch_id.name == id.name) return self.strict_flags.use_unknown_in_catch_variables;
        }
        return false;
    }

    fn isAssignmentTarget(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id or self.hir.kindOf(parent) != .assignment) return false;
        return hir_mod.assignmentOf(self.hir, parent).target == node;
    }

    fn isInAssignmentTargetChain(self: *Checker, node: NodeId) bool {
        var current = node;
        while (true) {
            if (self.isAssignmentTarget(current)) return true;
            const parent = self.hir.parentOf(current);
            if (parent == hir_mod.none_node_id) return false;
            switch (self.hir.kindOf(parent)) {
                .member_access => {
                    if (hir_mod.memberOf(self.hir, parent).object != current) return false;
                    current = parent;
                },
                .element_access => {
                    if (hir_mod.elementOf(self.hir, parent).object != current) return false;
                    current = parent;
                },
                else => return false,
            }
        }
    }

    /// True when `type_node` is the synthetic `type_ref` to `const`
    /// the parser uses to encode `expr as const`.
    fn isAsConstMarker(self: *Checker, type_node: NodeId) bool {
        if (self.hir.kindOf(type_node) != .type_ref) return false;
        const r = hir_mod.typeRefOf(self.hir, type_node);
        if (r.qualifier_len != 0 or r.args_len != 0) return false;
        const name = self.string_interner.get(r.name);
        return std.mem.eql(u8, name, "const");
    }

    fn flowTypeForAssignmentValue(self: *Checker, value_node: NodeId, fallback: TypeId) CheckError!TypeId {
        return switch (self.hir.kindOf(value_node)) {
            .literal_string => blk: {
                const lit = hir_mod.literalStringOf(self.hir, value_node);
                break :blk self.interner.internStringLiteral(lit.value) catch return error.OutOfMemory;
            },
            .literal_number => blk: {
                const v = hir_mod.literalNumberOf(self.hir, value_node);
                break :blk self.interner.internNumberLiteral(v) catch return error.OutOfMemory;
            },
            .literal_bool => blk: {
                const v = hir_mod.literalBoolOf(self.hir, value_node);
                break :blk if (v) types.Primitive.true_lit else types.Primitive.false_lit;
            },
            .literal_null => types.Primitive.null_t,
            .literal_undefined => types.Primitive.undefined_t,
            .as_expr, .type_assertion => blk: {
                const a = hir_mod.asExpressionOf(self.hir, value_node);
                if (a.type_node != hir_mod.none_node_id and self.isAsConstMarker(a.type_node)) {
                    break :blk self.literalizeForAsConst(a.expr, fallback) catch fallback;
                }
                break :blk fallback;
            },
            .assignment => blk: {
                const a = hir_mod.assignmentOf(self.hir, value_node);
                if (a.op != null) break :blk fallback;
                const value_t = if (self.hir.typeOf(a.value) != types.Primitive.none)
                    self.hir.typeOf(a.value)
                else
                    try self.checkExpression(a.value);
                const flow_t = try self.flowTypeForAssignmentValue(a.value, value_t);
                if (!self.nodeIsInsideFunctionLike(value_node) and
                    !self.nodeIsInsideLoop(value_node) and
                    self.hir.kindOf(a.target) == .identifier and
                    flow_t != types.Primitive.none and
                    flow_t != types.Primitive.any and
                    flow_t != types.Primitive.unknown)
                {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    try self.recordNarrow(id.name, flow_t);
                }
                break :blk flow_t;
            },
            .identifier => blk: {
                const t = self.typeOfIdentifier(value_node);
                if (t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(t).is_literal) break :blk t;
                break :blk fallback;
            },
            else => fallback,
        };
    }

    /// Implement `expr as const`: re-type the inner expression as
    /// its narrowest literal form. For literals this is the literal
    /// type itself; for `{ k: v }` we walk the properties and
    /// recursively literalize. Other shapes fall through unchanged.
    fn literalizeForAsConst(self: *Checker, expr: NodeId, fallback: TypeId) !TypeId {
        switch (self.hir.kindOf(expr)) {
            .literal_string => {
                const sid = try self.literalStringCookedId(expr);
                return self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
            },
            .literal_number => {
                const v = hir_mod.literalNumberOf(self.hir, expr);
                return self.interner.internNumberLiteral(v) catch return error.OutOfMemory;
            },
            .literal_bool => {
                const v = hir_mod.literalBoolOf(self.hir, expr);
                return if (v) types.Primitive.true_lit else types.Primitive.false_lit;
            },
            .object_literal => {
                const props = hir_mod.objectLiteralProps(self.hir, expr);
                var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                defer members.deinit(self.gpa);
                for (props) |p| {
                    if (self.hir.kindOf(p) != .object_property) continue;
                    const op = hir_mod.objectPropertyOf(self.hir, p);
                    if (self.hir.kindOf(op.key) != .identifier) continue;
                    if (op.value == hir_mod.none_node_id) continue;
                    const k = hir_mod.identifierOf(self.hir, op.key);
                    const inner = try self.checkExpression(op.value);
                    const lit_t = try self.literalizeForAsConst(op.value, inner);
                    try members.append(self.gpa, .{
                        .name = k.name,
                        .type = lit_t,
                        .is_optional = false,
                        .is_readonly = true,
                        .is_method = false,
                    });
                }
                return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
            },
            .array_literal => {
                // `[a, b, c] as const` -> readonly tuple
                // `readonly [TYPE_OF(a), TYPE_OF(b), TYPE_OF(c)]`,
                // where each element is recursively literalized.
                // The lowered tuple shape mirrors `lower.zig`'s
                // `lowerTuple`: positional members "0", "1", ...
                // plus a literal-length member, all marked readonly.
                const elements = hir_mod.arrayLiteralElements(self.hir, expr);
                var elem_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer elem_types.deinit(self.gpa);
                for (elements) |el| {
                    if (el == hir_mod.none_node_id) continue;
                    // Spreads inside `as const` aren't expanded
                    // structurally yet; bail to the array fallback
                    // type if we encounter one.
                    if (self.hir.kindOf(el) == .spread) return fallback;
                    const inner = try self.checkExpression(el);
                    const lit_t = try self.literalizeForAsConst(el, inner);
                    try elem_types.append(self.gpa, lit_t);
                }
                var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                defer members.deinit(self.gpa);
                for (elem_types.items, 0..) |t, i| {
                    var nbuf: [12]u8 = undefined;
                    const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{i}) catch continue;
                    const name = self.string_interner.intern(name_str) catch continue;
                    try members.append(self.gpa, .{
                        .name = name,
                        .type = t,
                        .is_optional = false,
                        .is_readonly = true,
                        .is_method = false,
                    });
                }
                const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
                const length_t = self.interner.internNumberLiteral(@floatFromInt(elem_types.items.len)) catch types.Primitive.number_t;
                try members.append(self.gpa, .{
                    .name = length_id,
                    .type = length_t,
                    .is_optional = false,
                    .is_readonly = true,
                    .is_method = false,
                });
                const elem_union: TypeId = if (elem_types.items.len == 0)
                    types.Primitive.never
                else if (elem_types.items.len == 1)
                    elem_types.items[0]
                else
                    self.interner.internUnion(elem_types.items) catch types.Primitive.any;
                return self.interner.internObjectTypeWithIndex(members.items, types.Primitive.none, elem_union) catch return error.OutOfMemory;
            },
            else => return fallback,
        }
    }

    /// Filter a union type by whether each variant declares
    /// `prop_name` as a member. Used by `in`-operator narrowing:
    /// `"foo" in obj` keeps the union arms that have `foo`;
    /// the else branch keeps the arms that don't. For non-union
    /// inputs, the unfiltered type passes through (matches tsc:
    /// `in` narrowing only fires on unions of object types).
    fn narrowByPropertyPresence(
        self: *Checker,
        t: TypeId,
        prop_name: hir_mod.StringId,
        keep_with_prop: bool,
    ) !TypeId {
        if (!self.interner.pool.flagsOf(t).is_union) {
            if (self.interner.pool.flagsOf(t).is_object_type) {
                const has = self.interner.objectMember(t, prop_name) != null;
                if (has and !keep_with_prop) return types.Primitive.never;
            }
            return t;
        }
        const members = self.interner.unionMembers(t);
        var kept: std.ArrayListUnmanaged(TypeId) = .empty;
        defer kept.deinit(self.gpa);
        for (members) |m| {
            const has = self.interner.objectMember(m, prop_name) != null;
            if (has == keep_with_prop) try kept.append(self.gpa, m);
        }
        if (kept.items.len == 0) return types.Primitive.never;
        if (kept.items.len == 1) return kept.items[0];
        return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
    }

    /// Bind the loop variable in `for (TARGET in/of SOURCE) ...`
    /// to `elem_t`. Target may be a `let`/`const`/`var` decl
    /// (binding shape) or a bare identifier (assignment shape).
    /// Both get the loop's element type recorded on the binding's
    /// HIR node so identifier lookups inside the body see it.
    fn bindForLoopTarget(self: *Checker, target: NodeId, elem_t: TypeId) CheckError!void {
        if (target == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(target)) {
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, target);
                self.hir.setType(target, elem_t);
                if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, elem_t);
            },
            .identifier => {
                self.hir.setType(target, elem_t);
            },
            .object_pattern, .array_pattern => {
                self.hir.setType(target, elem_t);
            },
            else => {},
        }
    }

    fn checkForInTarget(self: *Checker, target: NodeId) CheckError!void {
        if (target == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(target)) {
            .var_decl,
            .let_decl,
            .const_decl,
            .object_pattern,
            .array_pattern,
            .object_literal,
            .array_literal,
            => return,
            .identifier,
            .member_access,
            .element_access,
            => {
                if (self.expressionIsOptionalChain(target)) {
                    try self.report(target, TsCodes.optional_chain_for_in_target, "The left-hand side of a 'for...in' statement may not be an optional property access.");
                }
                if (self.hir.kindOf(target) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, target);
                    if (std.mem.eql(u8, self.string_interner.get(id.name), "this")) {
                        try self.report(target, TsCodes.for_in_left_type, "The left-hand side of a 'for...in' statement must be of type 'string' or 'any'.");
                        return;
                    }
                }
                const t = try self.checkExpression(target);
                if (self.hir.kindOf(target) == .identifier and
                    t == types.Primitive.undefined_t and
                    self.identifierIsUntypedUninitializedVar(target))
                {
                    return;
                }
                if (!self.forInTargetTypeAllowed(t)) {
                    try self.report(target, TsCodes.for_in_left_type, "The left-hand side of a 'for...in' statement must be of type 'string' or 'any'.");
                }
            },
            .assignment => {
                const t = try self.checkExpression(target);
                if (!self.forInTargetTypeAllowed(t)) {
                    try self.report(target, TsCodes.for_in_left_type, "The left-hand side of a 'for...in' statement must be of type 'string' or 'any'.");
                }
            },
            .this_expr => {
                try self.report(target, TsCodes.for_in_left_type, "The left-hand side of a 'for...in' statement must be of type 'string' or 'any'.");
            },
            .new_expr => {
                try self.report(target, TsCodes.for_in_left_invalid, "The left-hand side of a 'for...in' statement must be a variable or a property access.");
                _ = try self.checkExpression(target);
            },
            .call_expr => {
                _ = try self.checkExpression(target);
                try self.report(target, TsCodes.for_in_left_invalid, "The left-hand side of a 'for...in' statement must be a variable or a property access.");
            },
            else => {
                _ = try self.checkExpression(target);
                try self.report(target, TsCodes.for_in_left_invalid, "The left-hand side of a 'for...in' statement must be a variable or a property access.");
            },
        }
    }

    fn checkForInDestructuringTarget(self: *Checker, target: NodeId) CheckError!void {
        const pattern = self.forLoopTargetPattern(target) orelse return;
        const pk = self.hir.kindOf(pattern);
        // When the for-in head is an assignment-pattern (`for ([a, b]
        // in x)` / `for ({a, b} in x)`), the parser already reported
        // TS2491 ("LHS of a for-in cannot be a destructuring
        // pattern."). tsc stops at that diagnostic and does not
        // additionally try to destructure the iteration element, so
        // suppress the follow-up TS2322 / TS2339 chain we'd otherwise
        // raise per pattern slot. Binding patterns
        // (`for (let [a] in x)`) still receive the string-iteration
        // / property checks because those forms are syntactically
        // legal at parse time even though they fail TS2491 at the
        // checker.
        if (pk == .array_literal or pk == .object_literal) return;
        switch (pk) {
            .array_pattern => {
                if (self.sourceDirectiveValueMentions("target", "es5")) {
                    try self.report(pattern, TsCodes.string_iteration_requires_downlevel, "Type 'string' can only be iterated through when using the '--downlevelIteration' flag or with a '--target' of 'es2015' or higher.");
                } else {
                    try self.checkArrayDestructuringAssignment(pattern, types.Primitive.string_t, hir_mod.none_node_id, 0);
                }
            },
            .object_pattern => try self.reportForInStringObjectPatternProperties(pattern),
            else => {},
        }
    }

    fn forLoopTargetPattern(self: *Checker, target: NodeId) ?NodeId {
        if (target == hir_mod.none_node_id) return null;
        switch (self.hir.kindOf(target)) {
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, target);
                if (v.name == hir_mod.none_node_id) return null;
                const nk = self.hir.kindOf(v.name);
                return if (nk == .array_pattern or nk == .object_pattern or nk == .array_literal or nk == .object_literal) v.name else null;
            },
            .array_pattern, .object_pattern, .array_literal, .object_literal => return target,
            else => return null,
        }
    }

    fn reportForInStringObjectPatternProperties(self: *Checker, pattern: NodeId) CheckError!void {
        const elements: []const NodeId = switch (self.hir.kindOf(pattern)) {
            .object_pattern => hir_mod.patternElements(self.hir, pattern),
            .object_literal => hir_mod.objectLiteralProps(self.hir, pattern),
            else => return,
        };
        for (elements) |elem| {
            if (self.hir.kindOf(elem) == .parameter) {
                const p = hir_mod.parameterOf(self.hir, elem);
                if (p.name == hir_mod.none_node_id or p.flags.is_rest) continue;
                const key_name = (try self.objectBindingElementKeyName(elem, p.name)) orelse continue;
                try self.reportStringObjectPropertyMissing(p.name, key_name);
            } else if (self.hir.kindOf(elem) == .object_property) {
                const op = hir_mod.objectPropertyOf(self.hir, elem);
                const key_name = self.propertyNameFromKeyNode(op.key) orelse continue;
                try self.reportStringObjectPropertyMissing(op.key, key_name);
            }
        }
    }

    fn reportStringObjectPropertyMissing(self: *Checker, node: NodeId, name: hir_mod.StringId) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' does not exist on type 'String'.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.property_does_not_exist,
            .message = msg,
        });
    }

    fn forInTargetTypeAllowed(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_string) return true;
        if (f.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.forInTargetTypeAllowed(member)) return false;
            }
            return true;
        }
        if (f.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.forInTargetTypeAllowed(member)) return true;
            }
        }
        // tsc accepts `for (k in obj)` when `k`'s declared type is a
        // type parameter whose constraint is string-compatible (e.g.
        // `K extends string`, `K extends keyof T`). Without this,
        // generic key-iteration loops like
        // `function f<K extends string>(obj: { [P in K]: V }, k: K) { for (k in obj) ... }`
        // wrongly trip TS2405. Mirrors `keyofAndForIn.ts` upstream.
        if (f.is_type_parameter) {
            if (self.typeParameterConstraint(t)) |constraint| {
                if (self.forInTargetTypeAllowed(constraint)) return true;
            }
        }
        // `keyof T` is structurally a subtype of `string | number |
        // symbol` — tsc accepts it as a `for...in` LHS because the
        // iteration produces string keys at runtime and the
        // assignment is sound when narrowed. Without this, `let k:
        // keyof T; for (k in obj)` wrongly trips TS2405.
        if (f.is_keyof) return true;
        return false;
    }

    fn checkForOfTarget(self: *Checker, target: NodeId) CheckError!void {
        if (target == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(target)) {
            .var_decl,
            .let_decl,
            .const_decl,
            .identifier,
            .member_access,
            .element_access,
            .array_literal,
            .object_literal,
            => {
                if (self.expressionIsOptionalChain(target)) {
                    try self.report(target, TsCodes.optional_chain_for_of_target, "The left-hand side of a 'for...of' statement may not be an optional property access.");
                }
            },
            else => try self.report(target, TsCodes.for_of_lhs_invalid, "The left-hand side of a 'for...of' statement must be a variable or a property access."),
        }
    }

    fn checkForOfVarSelfReferenceDiagnostics(self: *Checker, for_node: NodeId, target: NodeId, source: NodeId) CheckError!void {
        if (target == hir_mod.none_node_id) return;
        const name_node: NodeId = switch (self.hir.kindOf(target)) {
            .identifier => target,
            .var_decl => blk: {
                const v = hir_mod.varDeclOf(self.hir, target);
                if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) return;
                if (v.type_annotation != hir_mod.none_node_id or v.init != hir_mod.none_node_id) return;
                break :blk v.name;
            },
            else => return,
        };
        const id = hir_mod.identifierOf(self.hir, name_node);
        if (std.mem.eql(u8, self.string_interner.get(id.name), "_")) return;
        if (self.sourceHasDeclareAnyVarName(id.name)) return;
        if (self.firstTopLevelReferenceBefore(for_node, id.name)) |ref| {
            try self.reportUsedBeforeAssignmentSimple(ref, id.name);
        }
        var has_self_reference = false;
        const class_name = self.newExpressionClassName(source);
        if (class_name) |name| {
            if (try self.reportIteratorMethodSelfReference(for_node, name, id.name, "next")) {
                has_self_reference = true;
            }
            if (try self.reportIteratorMethodSelfReference(for_node, name, id.name, "Symbol.iterator")) {
                has_self_reference = true;
            }
        }
        if (self.nodeContainsIdentifier(source, id.name)) {
            has_self_reference = true;
        }
        if (has_self_reference) {
            try self.reportForOfVarSelfReference(name_node, id.name);
        }
    }

    fn reportUsedBeforeAssignmentSimple(self: *Checker, ref_node: NodeId, name: hir_mod.StringId) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Variable '{s}' is used before being assigned.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = ref_node,
            .code = TsCodes.used_before_assignment,
            .message = msg,
        });
    }

    fn reportForOfVarSelfReference(self: *Checker, node: NodeId, name: hir_mod.StringId) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' implicitly has type 'any' because it does not have a type annotation and is referenced directly or indirectly in its own initializer.",
            .{self.string_interner.get(name)},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.variable_self_reference_implicitly_any,
            .message = msg,
        });
    }

    fn reportIteratorMethodSelfReference(self: *Checker, from_node: NodeId, class_name: hir_mod.StringId, loop_name: hir_mod.StringId, method_name: []const u8) CheckError!bool {
        const class_node = self.findTopLevelClassDecl(from_node, class_name) orelse return false;
        const method_node = try self.findIteratorSelfReferenceMethod(class_node, loop_name, method_name) orelse return false;
        const fn_node = self.classMemberFunctionNode(method_node) orelse return false;
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.return_type != hir_mod.none_node_id) return false;
        const display = if (std.mem.eql(u8, method_name, "Symbol.iterator")) "[Symbol.iterator]" else method_name;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' implicitly has return type 'any' because it does not have a return type annotation and is referenced directly or indirectly in one of its return expressions.",
            .{display},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = self.classMemberDiagnosticNode(method_node),
            .code = TsCodes.function_return_self_reference_implicitly_any,
            .message = msg,
        });
        return true;
    }

    fn newExpressionClassName(self: *Checker, source: NodeId) ?hir_mod.StringId {
        if (source == hir_mod.none_node_id or self.hir.kindOf(source) != .new_expr) return null;
        const c = hir_mod.callOf(self.hir, source);
        if (c.callee != hir_mod.none_node_id and self.hir.kindOf(c.callee) == .identifier) {
            return hir_mod.identifierOf(self.hir, c.callee).name;
        }
        const src = self.source orelse return null;
        const span = self.hir.spanOf(source);
        if (span.start >= span.end or span.end > src.len) return null;
        const text = src[span.start..span.end];
        const new_pos = std.mem.indexOf(u8, text, "new") orelse return null;
        var p = new_pos + "new".len;
        while (p < text.len and (text[p] == ' ' or text[p] == '\t' or text[p] == '\r' or text[p] == '\n')) : (p += 1) {}
        const start = p;
        if (start >= text.len or !isJsDocIdentStart(text[start])) return null;
        while (p < text.len and isJsDocIdentChar(text[p])) : (p += 1) {}
        return self.string_interner.intern(text[start..p]) catch null;
    }

    fn firstTopLevelReferenceBefore(self: *Checker, before_node: NodeId, name: hir_mod.StringId) ?NodeId {
        const root = self.rootBlockFor(before_node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const before_start = self.hir.spanOf(before_node).start;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.spanOf(stmt).start >= before_start) break;
            if (self.firstIdentifierReferenceNoNested(stmt, name)) |ref| return ref;
        }
        return null;
    }

    fn firstIdentifierReferenceNoNested(self: *Checker, node: NodeId, name: hir_mod.StringId) ?NodeId {
        if (node == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(node)) {
            .identifier => if (!self.isDeclNameSlot(node) and hir_mod.identifierOf(self.hir, node).name == name) node else null,
            .block_stmt => blk: {
                for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                    if (self.firstIdentifierReferenceNoNested(stmt, name)) |ref| break :blk ref;
                }
                break :blk null;
            },
            .return_stmt => self.firstIdentifierReferenceNoNested(hir_mod.returnOf(self.hir, node).value, name),
            .throw_stmt => self.firstIdentifierReferenceNoNested(hir_mod.throwOf(self.hir, node).value, name),
            .binary_op => blk: {
                const b = hir_mod.binopOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(b.lhs, name) orelse self.firstIdentifierReferenceNoNested(b.rhs, name);
            },
            .unary_op => self.firstIdentifierReferenceNoNested(hir_mod.unaryOf(self.hir, node).operand, name),
            .logical_op => blk: {
                const l = hir_mod.logicalOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(l.lhs, name) orelse self.firstIdentifierReferenceNoNested(l.rhs, name);
            },
            .conditional => blk: {
                const c = hir_mod.conditionalOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(c.cond, name) orelse
                    self.firstIdentifierReferenceNoNested(c.then_branch, name) orelse
                    self.firstIdentifierReferenceNoNested(c.else_branch, name);
            },
            .call_expr, .new_expr => blk: {
                const c = hir_mod.callOf(self.hir, node);
                if (self.firstIdentifierReferenceNoNested(c.callee, name)) |ref| break :blk ref;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.firstIdentifierReferenceNoNested(arg, name)) |ref| break :blk ref;
                }
                break :blk null;
            },
            .member_access => self.firstIdentifierReferenceNoNested(hir_mod.memberOf(self.hir, node).object, name),
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(e.object, name) orelse self.firstIdentifierReferenceNoNested(e.index, name);
            },
            .array_literal => blk: {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                    if (self.firstIdentifierReferenceNoNested(el, name)) |ref| break :blk ref;
                }
                break :blk null;
            },
            .object_literal => blk: {
                for (hir_mod.objectLiteralProps(self.hir, node)) |prop| {
                    if (self.firstIdentifierReferenceNoNested(prop, name)) |ref| break :blk ref;
                }
                break :blk null;
            },
            .object_property => blk: {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                break :blk (if (op.is_computed) self.firstIdentifierReferenceNoNested(op.key, name) else null) orelse
                    self.firstIdentifierReferenceNoNested(op.value, name);
            },
            .spread => self.firstIdentifierReferenceNoNested(hir_mod.spreadOf(self.hir, node).expression, name),
            .assignment => blk: {
                const a = hir_mod.assignmentOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(a.target, name) orelse self.firstIdentifierReferenceNoNested(a.value, name);
            },
            .as_expr, .satisfies_expr, .type_assertion => self.firstIdentifierReferenceNoNested(hir_mod.asExpressionOf(self.hir, node).expr, name),
            .var_decl, .let_decl, .const_decl => blk: {
                const v = hir_mod.varDeclOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(v.init, name);
            },
            .if_stmt => blk: {
                const i = hir_mod.ifOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(i.cond, name) orelse
                    self.firstIdentifierReferenceNoNested(i.then_branch, name) orelse
                    self.firstIdentifierReferenceNoNested(i.else_branch, name);
            },
            .while_stmt => self.firstIdentifierReferenceNoNested(hir_mod.whileOf(self.hir, node).cond, name),
            .do_while_stmt => blk: {
                const d = hir_mod.doWhileOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(d.body, name) orelse self.firstIdentifierReferenceNoNested(d.cond, name);
            },
            .for_stmt => blk: {
                const f = hir_mod.forStmtOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(f.init, name) orelse
                    self.firstIdentifierReferenceNoNested(f.cond, name) orelse
                    self.firstIdentifierReferenceNoNested(f.update, name);
            },
            .for_in_stmt, .for_of_stmt => blk: {
                const f = hir_mod.forInOf(self.hir, node);
                break :blk self.firstIdentifierReferenceNoNested(f.source, name);
            },
            .try_stmt, .switch_stmt, .switch_case => null,
            .fn_decl, .fn_expr, .arrow_fn, .class_decl, .class_expr, .interface_decl, .type_alias_decl, .enum_decl, .namespace_decl => null,
            else => null,
        };
    }

    fn findTopLevelClassDecl(self: *Checker, from_node: NodeId, class_name: hir_mod.StringId) ?NodeId {
        const root = self.rootBlockFor(from_node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const k = self.hir.kindOf(stmt);
            if (k != .class_decl and k != .class_expr) continue;
            const c = hir_mod.classOf(self.hir, stmt);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, c.name).name == class_name) return stmt;
        }
        return null;
    }

    fn findClassMethodByName(self: *Checker, class_node: NodeId, method_name: []const u8) CheckError!?NodeId {
        for (hir_mod.classMembers(self.hir, class_node)) |member| {
            if (self.classMemberFunctionNode(member) == null) continue;
            if (std.mem.eql(u8, method_name, "next")) {
                const name = self.classMethodDeclName(member) orelse continue;
                if (std.mem.eql(u8, self.string_interner.get(name), "next")) return member;
            }
            if (std.mem.eql(u8, method_name, "Symbol.iterator") and self.hir.kindOf(member) == .object_property) {
                const op = hir_mod.objectPropertyOf(self.hir, member);
                if (op.key == hir_mod.none_node_id) continue;
                if (try self.classMemberNameFromPropertyKey(op.key, true)) |name| {
                    if (std.mem.eql(u8, self.string_interner.get(name), "Symbol.iterator")) return member;
                }
            }
        }
        return null;
    }

    fn findIteratorSelfReferenceMethod(self: *Checker, class_node: NodeId, loop_name: hir_mod.StringId, method_name: []const u8) CheckError!?NodeId {
        const src = self.source orelse return null;
        const raw_loop = self.string_interner.get(loop_name);
        for (hir_mod.classMembers(self.hir, class_node)) |member| {
            const fn_node = self.classMemberFunctionNode(member) orelse continue;
            const f = hir_mod.fnDeclOf(self.hir, fn_node);
            if (f.return_type != hir_mod.none_node_id) continue;
            const member_span = self.hir.spanOf(member);
            if (member_span.start >= member_span.end or member_span.end > src.len) continue;
            const member_text = src[member_span.start..member_span.end];
            if (!self.iteratorMemberSourceMatches(member_text, method_name)) continue;
            const body_span = self.hir.spanOf(f.body);
            if (body_span.start >= body_span.end or body_span.end > src.len) continue;
            const body_text = src[body_span.start..body_span.end];
            if (std.mem.eql(u8, method_name, "Symbol.iterator")) {
                if (containsReturnIdentifier(body_text, raw_loop)) return member;
            } else if (containsReturnIdentifier(body_text, raw_loop) or containsPropertyValueIdentifier(body_text, "value", raw_loop)) {
                return member;
            }
        }
        if (try self.findClassMethodByName(class_node, method_name)) |method_node| {
            const fn_node = self.classMemberFunctionNode(method_node) orelse return null;
            const f = hir_mod.fnDeclOf(self.hir, fn_node);
            if (f.return_type != hir_mod.none_node_id) return null;
            if (!self.nodeContainsIdentifier(f.body, loop_name)) return null;
            return method_node;
        }
        return null;
    }

    fn classMemberFunctionNode(self: *Checker, member: NodeId) ?NodeId {
        return switch (self.hir.kindOf(member)) {
            .fn_decl, .fn_expr => member,
            .object_property => blk: {
                const op = hir_mod.objectPropertyOf(self.hir, member);
                if (op.value == hir_mod.none_node_id) break :blk null;
                const vk = self.hir.kindOf(op.value);
                if (vk == .fn_decl or vk == .fn_expr) break :blk op.value;
                break :blk null;
            },
            else => null,
        };
    }

    fn classMemberDiagnosticNode(self: *Checker, member: NodeId) NodeId {
        return switch (self.hir.kindOf(member)) {
            .fn_decl, .fn_expr => blk: {
                const f = hir_mod.fnDeclOf(self.hir, member);
                break :blk if (f.name != hir_mod.none_node_id) f.name else member;
            },
            .object_property => blk: {
                const op = hir_mod.objectPropertyOf(self.hir, member);
                break :blk if (op.key != hir_mod.none_node_id) op.key else member;
            },
            else => member,
        };
    }

    fn iteratorMemberSourceMatches(self: *Checker, member_text: []const u8, method_name: []const u8) bool {
        _ = self;
        if (std.mem.eql(u8, method_name, "next")) {
            var i: usize = 0;
            while (std.mem.indexOfPos(u8, member_text, i, "next")) |pos| {
                const after = pos + "next".len;
                if ((pos == 0 or !isJsDocIdentChar(member_text[pos - 1])) and
                    (after >= member_text.len or !isJsDocIdentChar(member_text[after])))
                {
                    return true;
                }
                i = after;
            }
            return false;
        }
        return std.mem.indexOf(u8, member_text, "Symbol.iterator") != null;
    }

    fn containsReturnIdentifier(text: []const u8, name: []const u8) bool {
        var i: usize = 0;
        while (std.mem.indexOfPos(u8, text, i, "return")) |pos| {
            const after = pos + "return".len;
            if (pos > 0 and isJsDocIdentChar(text[pos - 1])) {
                i = after;
                continue;
            }
            if (after < text.len and isJsDocIdentChar(text[after])) {
                i = after;
                continue;
            }
            const p = skipAsciiWhitespace(text, after);
            if (identifierAt(text, p, name)) return true;
            i = after;
        }
        return false;
    }

    fn containsPropertyValueIdentifier(text: []const u8, property: []const u8, name: []const u8) bool {
        var i: usize = 0;
        while (std.mem.indexOfPos(u8, text, i, property)) |pos| {
            const after = pos + property.len;
            if (pos > 0 and isJsDocIdentChar(text[pos - 1])) {
                i = after;
                continue;
            }
            if (after < text.len and isJsDocIdentChar(text[after])) {
                i = after;
                continue;
            }
            var p = skipAsciiWhitespace(text, after);
            if (p >= text.len or text[p] != ':') {
                i = after;
                continue;
            }
            p = skipAsciiWhitespace(text, p + 1);
            if (identifierAt(text, p, name)) return true;
            i = after;
        }
        return false;
    }

    fn skipAsciiWhitespace(text: []const u8, start: usize) usize {
        var p = start;
        while (p < text.len and (text[p] == ' ' or text[p] == '\t' or text[p] == '\r' or text[p] == '\n')) : (p += 1) {}
        return p;
    }

    fn identifierAt(text: []const u8, pos: usize, name: []const u8) bool {
        if (pos > text.len or pos + name.len > text.len) return false;
        if (!std.mem.eql(u8, text[pos .. pos + name.len], name)) return false;
        if (pos > 0 and isJsDocIdentChar(text[pos - 1])) return false;
        const after = pos + name.len;
        return after >= text.len or !isJsDocIdentChar(text[after]);
    }

    fn recordLoopTargetBindings(self: *Checker, target: NodeId, elem_t: TypeId) CheckError!void {
        if (target == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(target)) {
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, target);
                try self.recordLoopTargetBindings(v.name, elem_t);
            },
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, target);
                try self.recordNarrow(id.name, elem_t);
            },
            .object_pattern, .array_pattern => {
                const elements = hir_mod.patternElements(self.hir, target);
                for (elements) |element| {
                    if (self.hir.kindOf(element) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, element);
                    if (p.name == hir_mod.none_node_id) continue;
                    if (self.hir.kindOf(p.name) == .identifier) {
                        const id = hir_mod.identifierOf(self.hir, p.name);
                        const binding_t = self.typeOfPatternBinding(target, elem_t, id.name) orelse types.Primitive.any;
                        try self.recordNarrow(id.name, binding_t);
                    } else if (self.hir.kindOf(p.name) == .object_pattern or self.hir.kindOf(p.name) == .array_pattern) {
                        try self.recordLoopTargetBindings(p.name, types.Primitive.any);
                    }
                }
            },
            else => {},
        }
    }

    fn nodeContainsIdentifier(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .identifier => return hir_mod.identifierOf(self.hir, node).name == name,
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                return self.nodeContainsIdentifier(m.object, name);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                return self.nodeContainsIdentifier(e.object, name) or self.nodeContainsIdentifier(e.index, name);
            },
            .call_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.nodeContainsIdentifier(c.callee, name)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| if (self.nodeContainsIdentifier(arg, name)) return true;
                return false;
            },
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| if (self.nodeContainsIdentifier(el, name)) return true;
                return false;
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |prop| if (self.nodeContainsIdentifier(prop, name)) return true;
                return false;
            },
            .object_property => {
                const p = hir_mod.objectPropertyOf(self.hir, node);
                return self.nodeContainsIdentifier(p.key, name) or self.nodeContainsIdentifier(p.value, name);
            },
            .class_decl, .class_expr => {
                const c = hir_mod.classOf(self.hir, node);
                if (self.nodeContainsIdentifier(c.name, name)) return true;
                if (self.nodeContainsIdentifier(c.extends, name)) return true;
                for (hir_mod.classMembers(self.hir, node)) |member| if (self.nodeContainsIdentifier(member, name)) return true;
                return false;
            },
            .decorator => return self.nodeContainsIdentifier(hir_mod.decoratorOf(self.hir, node).expression, name),
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.nodeContainsIdentifier(b.lhs, name) or self.nodeContainsIdentifier(b.rhs, name);
            },
            .unary_op => return self.nodeContainsIdentifier(hir_mod.unaryOf(self.hir, node).operand, name),
            .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => return self.nodeContainsIdentifier(hir_mod.asExpressionOf(self.hir, node).expr, name),
            .template_literal => {
                for (hir_mod.templateLiteralExprs(self.hir, node)) |expr| if (self.nodeContainsIdentifier(expr, name)) return true;
                return false;
            },
            else => return false,
        }
    }

    fn removeCondAliasesReferencing(self: *Checker, name: hir_mod.StringId) CheckError!void {
        if (self.cond_aliases.count() == 0) return;
        var to_remove: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer to_remove.deinit(self.gpa);
        var it = self.cond_aliases.iterator();
        while (it.next()) |entry| {
            if (self.nodeContainsIdentifier(entry.value_ptr.*, name)) {
                try to_remove.append(self.gpa, entry.key_ptr.*);
            }
        }
        for (to_remove.items) |alias| {
            _ = self.cond_aliases.remove(alias);
        }
    }

    /// Walks the same tree as `bodyHasVarDeclarationNamed` but returns
    /// the matching `var_decl`'s identifier node (so the caller can
    /// anchor a diagnostic at the named declarator instead of the
    /// outer block). Returns `null` when no match is found.
    fn findVarDeclarationNodeNamed(self: *Checker, node: NodeId, name: hir_mod.StringId) ?NodeId {
        if (node == hir_mod.none_node_id) return null;
        switch (self.hir.kindOf(node)) {
            .var_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                if (v.name == hir_mod.none_node_id) return null;
                if (self.hir.kindOf(v.name) != .identifier) return null;
                if (hir_mod.identifierOf(self.hir, v.name).name != name) return null;
                return v.name;
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |stmt|
                    if (self.findVarDeclarationNodeNamed(stmt, name)) |n| return n;
                return null;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                return self.findVarDeclarationNodeNamed(i.then_branch, name) orelse
                    self.findVarDeclarationNodeNamed(i.else_branch, name);
            },
            .for_in_stmt, .for_of_stmt => {
                const f = hir_mod.forInOf(self.hir, node);
                return self.findVarDeclarationNodeNamed(f.target, name) orelse
                    self.findVarDeclarationNodeNamed(f.body, name);
            },
            .for_stmt => {
                const f = hir_mod.forStmtOf(self.hir, node);
                return self.findVarDeclarationNodeNamed(f.init, name) orelse
                    self.findVarDeclarationNodeNamed(f.body, name);
            },
            .try_stmt => {
                const t = hir_mod.tryOf(self.hir, node);
                return self.findVarDeclarationNodeNamed(t.block, name) orelse
                    self.findVarDeclarationNodeNamed(t.catch_block, name) orelse
                    self.findVarDeclarationNodeNamed(t.finally_block, name);
            },
            .while_stmt => return self.findVarDeclarationNodeNamed(hir_mod.whileOf(self.hir, node).body, name),
            .do_while_stmt => return self.findVarDeclarationNodeNamed(hir_mod.doWhileOf(self.hir, node).body, name),
            .switch_stmt => {
                for (hir_mod.switchCases(self.hir, node)) |case|
                    if (self.findVarDeclarationNodeNamed(case, name)) |n| return n;
                return null;
            },
            .switch_case => {
                for (hir_mod.switchCaseStmts(self.hir, node)) |stmt|
                    if (self.findVarDeclarationNodeNamed(stmt, name)) |n| return n;
                return null;
            },
            else => return null,
        }
    }

    fn bodyHasVarDeclarationNamed(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .var_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                return v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier and hir_mod.identifierOf(self.hir, v.name).name == name;
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |stmt| if (self.bodyHasVarDeclarationNamed(stmt, name)) return true;
                return false;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                return self.bodyHasVarDeclarationNamed(i.then_branch, name) or self.bodyHasVarDeclarationNamed(i.else_branch, name);
            },
            .for_in_stmt, .for_of_stmt => {
                const f = hir_mod.forInOf(self.hir, node);
                return self.bodyHasVarDeclarationNamed(f.target, name) or self.bodyHasVarDeclarationNamed(f.body, name);
            },
            .for_stmt => {
                const f = hir_mod.forStmtOf(self.hir, node);
                return self.bodyHasVarDeclarationNamed(f.init, name) or self.bodyHasVarDeclarationNamed(f.body, name);
            },
            .try_stmt => {
                const t = hir_mod.tryOf(self.hir, node);
                return self.bodyHasVarDeclarationNamed(t.block, name) or
                    self.bodyHasVarDeclarationNamed(t.catch_block, name) or
                    self.bodyHasVarDeclarationNamed(t.finally_block, name);
            },
            .while_stmt => return self.bodyHasVarDeclarationNamed(hir_mod.whileOf(self.hir, node).body, name),
            .do_while_stmt => return self.bodyHasVarDeclarationNamed(hir_mod.doWhileOf(self.hir, node).body, name),
            .switch_stmt => {
                for (hir_mod.switchCases(self.hir, node)) |case| if (self.bodyHasVarDeclarationNamed(case, name)) return true;
                return false;
            },
            .switch_case => {
                for (hir_mod.switchCaseStmts(self.hir, node)) |stmt| if (self.bodyHasVarDeclarationNamed(stmt, name)) return true;
                return false;
            },
            else => return false,
        }
    }

    /// True when `t` admits `undefined` — either directly or as a
    /// member of a union. `any` and `unknown` count as well, since
    /// they accept any value.
    fn typeIncludesUndefined(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.void_t) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_undefined or f.is_any or f.is_unknown) return true;
        if (!f.is_union) return false;
        if (self.interner.pool.payloadOf(t) >= self.interner.pool.union_payloads.items.len) return false;
        for (self.interner.unionMembers(t)) |m| {
            if (m >= self.interner.pool.typeCount()) continue;
            if (self.interner.pool.flagsOf(m).is_undefined) return true;
        }
        return false;
    }

    fn recordSignatureMinArgs(self: *Checker, sig: TypeId, omittable: []const bool) CheckError!void {
        var min_required = omittable.len;
        while (min_required > 0 and omittable[min_required - 1]) {
            min_required -= 1;
        }
        try self.signature_min_args.put(self.gpa, sig, min_required);
    }

    /// Capture source-level parameter names for a signature so the
    /// diagnostic renderer can print `(x: T)` instead of `(x0: T)`.
    /// `param_nodes` is the HIR child slice of `parameter` nodes
    /// from a `fn_decl` / `fn_expr` / `arrow_fn` / `fn_type` /
    /// `constructor_type`. Skips non-parameter and `this`-parameter
    /// children (matching how `internSignature` is called: with the
    /// `this`-less type list). Aborts the recording if any
    /// parameter slot is a binding pattern (object/array
    /// destructuring) — partial recording could leak misaligned
    /// names into the renderer, and the positional `xN` fallback is
    /// stable. Idempotent: re-recording frees the previous slice.
    fn recordSignatureParamNames(self: *Checker, sig: TypeId, param_nodes: []const NodeId) CheckError!void {
        if (param_nodes.len == 0) return;
        var names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer names.deinit(self.gpa);
        try names.ensureTotalCapacity(self.gpa, param_nodes.len);
        for (param_nodes) |p| {
            if (self.hir.kindOf(p) != .parameter) continue;
            if (self.isThisParameter(p)) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.name == hir_mod.none_node_id) return;
            if (self.hir.kindOf(pp.name) != .identifier) return;
            const name_id = hir_mod.identifierOf(self.hir, pp.name).name;
            try names.append(self.gpa, name_id);
        }
        if (names.items.len == 0) return;
        const owned = names.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
        if (self.signature_param_names.fetchRemove(sig)) |old| self.gpa.free(old.value);
        try self.signature_param_names.put(self.gpa, sig, owned);
    }

    /// Carry recorded parameter names from a donor signature to a
    /// re-interned target signature. Used when only the return type
    /// or constructor flag changes — the parameter list is
    /// unchanged so the source names still apply.
    fn copySignatureParamNames(self: *Checker, target_sig: TypeId, donor_sig: TypeId) CheckError!void {
        if (target_sig == donor_sig) return;
        const donor_names = self.signature_param_names.get(donor_sig) orelse return;
        const dup = self.gpa.dupe(hir_mod.StringId, donor_names) catch return error.OutOfMemory;
        if (self.signature_param_names.fetchRemove(target_sig)) |old| self.gpa.free(old.value);
        try self.signature_param_names.put(self.gpa, target_sig, dup);
    }

    fn signatureMinRequiredArgs(self: *Checker, sig: TypeId, params: []const TypeId) usize {
        if (self.signature_min_args.get(sig)) |min_required| return @min(min_required, params.len);
        var min_required = params.len;
        while (min_required > 0 and self.parameterTypeCanBeOmitted(params[min_required - 1])) {
            min_required -= 1;
        }
        return min_required;
    }

    fn parameterTypeCanBeOmitted(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.void_t) return true;
        if (self.typeIncludesUndefined(t)) return true;
        return false;
    }

    fn typeIncludesNull(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_null or f.is_any or f.is_unknown) return true;
        if (!f.is_union) return false;
        if (self.interner.pool.payloadOf(t) >= self.interner.pool.union_payloads.items.len) return false;
        for (self.interner.unionMembers(t)) |m| {
            if (m >= self.interner.pool.typeCount()) continue;
            if (self.interner.pool.flagsOf(m).is_null) return true;
        }
        return false;
    }

    fn typeIsPossiblyNullish(self: *Checker, t: TypeId) bool {
        return self.typeIncludesNull(t) or self.typeIncludesUndefined(t);
    }

    /// Strict variant of `typeIsPossiblyNullish` for the
    /// TS18047/8/9 member-access diagnostic. Differs from the loose
    /// check by excluding `any` and `unknown`: tsc fires no nullish
    /// diagnostic on those, even though the underlying type
    /// technically subsumes `null` and `undefined`. The loose check
    /// is still appropriate for callers that want a "may be null in
    /// any way" signal (the non-null-assertion overlap test, etc).
    fn typeIsPossiblyNullishStrict(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_any or f.is_unknown) return false;
        if (f.is_null or f.is_undefined) return true;
        if (t == types.Primitive.void_t) return true;
        if (!f.is_union) return false;
        if (self.interner.pool.payloadOf(t) >= self.interner.pool.union_payloads.items.len) return false;
        for (self.interner.unionMembers(t)) |m| {
            if (m >= self.interner.pool.typeCount()) continue;
            const mf = self.interner.pool.flagsOf(m);
            if (mf.is_null or mf.is_undefined) return true;
        }
        return false;
    }

    /// Classification of which nullish constituents a possibly-nullish
    /// type contains. Used to pick TS18047 vs TS18048 vs TS18049 for
    /// member-access diagnostics. Caller must have already filtered
    /// out `any`/`unknown` via `typeIsPossiblyNullishStrict`.
    const NullishKind = enum { only_null, only_undefined, both };

    fn nullishKindOf(self: *Checker, t: TypeId) NullishKind {
        // Use the existing typeIncludesNull/typeIncludesUndefined
        // helpers, but with the any/unknown gate the strict caller
        // already performed, so they're safe to combine here. They
        // already walk one level of union nesting and treat `void`
        // as undefined, which matches tsc's classification.
        const has_null = self.typeIncludesNull(t);
        const has_undef = self.typeIncludesUndefined(t);
        if (has_null and has_undef) return .both;
        if (has_null) return .only_null;
        if (has_undef) return .only_undefined;
        // Fallback: caller already ensured the type is possibly
        // nullish, so at least one branch must hold. If both
        // helpers return false (eg degenerate type metadata) fall
        // back to the umbrella message.
        return .both;
    }

    /// Emit the appropriate TS18047/TS18048/TS18049 diagnostic for a
    /// possibly-nullish member-access object. When the object is a
    /// bare identifier, format the message with the variable name
    /// (`'x' is possibly 'null'.`); otherwise fall back to the
    /// `Object is possibly …` form. Mirrors tsc's exact messages so
    /// `.errors.txt` baselines line up.
    fn reportPossiblyNullishMember(self: *Checker, obj_node: NodeId, obj_t: TypeId) !void {
        const kind = self.nullishKindOf(obj_t);
        const code: u32 = switch (kind) {
            .only_null => TsCodes.object_possibly_null,
            .only_undefined => TsCodes.object_possibly_undefined_18048,
            .both => TsCodes.object_possibly_nullish,
        };
        const suffix: []const u8 = switch (kind) {
            .only_null => "'null'",
            .only_undefined => "'undefined'",
            .both => "'null' or 'undefined'",
        };
        if (self.hir.kindOf(obj_node) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, obj_node);
            const name = self.string_interner.get(id.name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "'{s}' is possibly {s}.",
                .{ name, suffix },
            );
            try self.diagnostics.append(self.gpa, .{
                .node = obj_node,
                .code = code,
                .message = msg,
            });
            return;
        }
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Object is possibly {s}.",
            .{suffix},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = obj_node,
            .code = code,
            .message = msg,
        });
    }

    fn checkTypeAssertionOverlap(self: *Checker, node: NodeId, source_t: TypeId, target_t: TypeId) CheckError!void {
        if (self.assertionIsInsideTypedObjectLiteralVarInit(node)) return;
        if (self.typeIsAnyLike(source_t) or self.typeIsAnyLike(target_t)) return;
        if (self.assertionTargetIsFunctionObject(target_t)) return;
        if (self.nullAssertionTargetIsPermissive(target_t)) return;
        if (source_t == types.Primitive.null_t and self.strict_flags.strict_null_checks and !self.typeIncludesNull(target_t)) {
            try self.emitConversionMayBeMistake(node, source_t, target_t);
            return;
        }
        if (source_t == types.Primitive.undefined_t and !self.typeIncludesUndefined(target_t)) {
            try self.emitConversionMayBeMistake(node, source_t, target_t);
            return;
        }
        if (try self.assertionUnionConstituentHasNoOverlap(source_t, target_t)) {
            try self.emitConversionMayBeMistake(node, source_t, target_t);
            return;
        }
        if (try self.typesHaveComparableOverlap(source_t, target_t)) return;
        try self.emitConversionMayBeMistake(node, source_t, target_t);
    }

    /// Format and emit TS2352 ("Conversion ... may be a mistake ...").
    /// When both endpoints are nameable, mirror upstream's verbose
    /// form including the "convert to 'unknown' first" hint; otherwise
    /// fall back to the bare message that pre-dated the helper.
    fn emitConversionMayBeMistake(self: *Checker, node: NodeId, source_t: TypeId, target_t: TypeId) CheckError!void {
        if (try self.allocSimpleTypeName(source_t)) |source_name| {
            if (try self.allocSimpleTypeName(target_t)) |target_name| {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Conversion of type '{s}' to type '{s}' may be a mistake because neither type sufficiently overlaps with the other. If this was intentional, convert the expression to 'unknown' first.",
                    .{ source_name, target_name },
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = node,
                    .code = TsCodes.conversion_may_be_mistake,
                    .message = msg,
                });
                return;
            }
        }
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.conversion_may_be_mistake,
            .message = "Conversion may be a mistake because neither type sufficiently overlaps with the other.",
        });
    }

    fn assertionUnionConstituentHasNoOverlap(self: *Checker, source_t: TypeId, target_t: TypeId) CheckError!bool {
        if (source_t >= self.interner.pool.typeCount()) return false;
        const source_flags = self.interner.pool.flagsOf(source_t);
        if (!source_flags.is_union) return false;
        // Upstream tsc only flags an assertion as TS2352 when *no*
        // constituent of the source union overlaps with the target
        // type. The union acts as "is this any of these things?";
        // asserting it to a specific subtype is fine when at least
        // one constituent is comparable to the target. Examples:
        //   * `(A | B) as A`           — `stringLiteralsWithTypeAssertions01.ts(5,9)`
        //   * `(S[] | S) as string`    — `stringLiteralTypeAssertion01.ts(29,7)`
        //     (`S` overlaps with `string` even though `S[]` doesn't)
        // Bail out as soon as any constituent overlaps so the caller
        // proceeds to the structural `typesHaveComparableOverlap`
        // check rather than emitting TS2352.
        for (self.interner.unionMembers(source_t)) |member| {
            if (try self.typesHaveComparableOverlap(member, target_t)) return false;
            if (self.engine.isAssignableTo(member, target_t) catch false) return false;
            if (self.engine.isAssignableTo(target_t, member) catch false) return false;
        }
        for (self.interner.unionMembers(source_t)) |member| {
            if (self.assertionObjectConstituentHasNoPrimitiveOverlap(member, target_t)) return true;
            if (!self.shouldCheckNoOverlap(member, target_t)) continue;
            const comparable = self.engine.isComparableTo(member, target_t) catch true;
            if (!comparable) return true;
        }
        return false;
    }

    fn assertionObjectConstituentHasNoPrimitiveOverlap(self: *Checker, source_t: TypeId, target_t: TypeId) bool {
        if (!self.isConcretePrimitiveLike(target_t)) return false;
        if (source_t >= self.interner.pool.typeCount()) return false;
        const source_flags = self.interner.pool.flagsOf(source_t);
        if (!source_flags.is_object_type and !source_flags.is_signature and !source_flags.is_tuple) return false;
        if (self.objectTypeIsWeak(source_t)) return false;
        if (target_t == types.Primitive.string_t) {
            const string_idx = self.interner.objectStringIndex(source_t);
            if (string_idx != types.Primitive.none) return false;
        }
        if (target_t == types.Primitive.number_t) {
            const number_idx = self.interner.objectNumberIndex(source_t);
            if (number_idx != types.Primitive.none) return false;
        }
        return true;
    }

    fn assertionTargetIsFunctionObject(self: *Checker, target_t: TypeId) bool {
        const function_t = self.lowerBuiltinObjectType("Function") orelse return false;
        return target_t == function_t or (self.engine.isAssignableTo(target_t, function_t) catch false);
    }

    fn nullAssertionTargetIsPermissive(self: *Checker, target_t: TypeId) bool {
        if (self.containsFreeTypeParameter(target_t)) return true;

        const target_flags = self.interner.pool.flagsOf(target_t);
        if (target_flags.is_object_type) {
            const string_idx = self.interner.objectStringIndex(target_t);
            if (self.typeIsAnyLike(string_idx)) return true;
            const number_idx = self.interner.objectNumberIndex(target_t);
            if (self.typeIsAnyLike(number_idx)) return true;
        }

        return false;
    }

    fn typeIsAnyLike(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.none or t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        return flags.is_any or flags.is_unknown;
    }

    fn assertionIsInsideTypedObjectLiteralVarInit(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            switch (self.hir.kindOf(cur)) {
                .object_literal => {
                    const parent = self.hir.parentOf(cur);
                    if (parent == hir_mod.none_node_id) return false;
                    switch (self.hir.kindOf(parent)) {
                        .var_decl, .let_decl, .const_decl => {
                            const v = hir_mod.varDeclOf(self.hir, parent);
                            return v.init == cur and v.type_annotation != hir_mod.none_node_id;
                        },
                        else => return false,
                    }
                },
                .fn_decl, .fn_expr, .arrow_fn => return false,
                else => {},
            }
        }
        return false;
    }

    fn typeExplicitlyIncludesUndefined(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const f = self.interner.pool.flagsOf(t);
        if (f.is_undefined) return true;
        if (!f.is_union) return false;
        if (self.interner.pool.payloadOf(t) >= self.interner.pool.union_payloads.items.len) return false;
        for (self.interner.unionMembers(t)) |m| {
            if (m >= self.interner.pool.typeCount()) continue;
            if (self.interner.pool.flagsOf(m).is_undefined) return true;
        }
        return false;
    }

    /// `any` and `unknown` field types are not subject to the
    /// strict-property-initialization (TS2564) check because they
    /// admit `undefined` as a value. Matches the upstream behavior
    /// in fixtures like `derivedClassWithAny` where `x: any;` does
    /// NOT report the diagnostic.
    fn classFieldTypeIsAnyOrUnknown(self: *Checker, t: TypeId) bool {
        _ = self;
        return t == types.Primitive.any or t == types.Primitive.unknown;
    }

    /// Return true when the syntactic type annotation on a class
    /// member is literally `any` or `unknown` (not a generic / class
    /// reference that happens to resolve to `any` because the lowerer
    /// hit a recursion guard on a self-referential generic). Used by
    /// `strictPropertyInitialization` to keep TS2564 firing on
    /// recursive fields like `class D<T> { recurse: D<T>; }` — upstream
    /// tsc emits the diagnostic there even though the resolved type is
    /// nominally the class itself, which we may bail to `any` during
    /// shallow recursion.
    fn classFieldAnnotationIsLiteralAnyOrUnknown(self: *Checker, annotation: NodeId) bool {
        if (annotation == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(annotation) != .type_ref) return false;
        const ref = hir_mod.typeRefOf(self.hir, annotation);
        if (ref.qualifier_len != 0) return false;
        const name = self.string_interner.get(ref.name);
        return std.mem.eql(u8, name, "any") or std.mem.eql(u8, name, "unknown");
    }

    /// Build `t | undefined` (or return `t` if it already includes
    /// `undefined`). Used to widen optional parameters and defaulted
    /// parameters so call sites can omit them.
    fn unionWithUndefined(self: *Checker, t: TypeId) !TypeId {
        // Already nullable — bail out so we don't create
        // `(T | undefined) | undefined`.
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_undefined or flags.is_any or flags.is_unknown) return t;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| {
                if (self.interner.pool.flagsOf(m).is_undefined) return t;
            }
        }
        return self.interner.internUnion(&.{ t, types.Primitive.undefined_t }) catch return error.OutOfMemory;
    }

    /// Remove `null` and `undefined` from `t` if it's a union; for
    /// non-union types pass through unchanged. Used by the
    /// `non_null_expr` typing path to support TS's `expr!` postfix
    /// operator. An empty result collapses to `never`.
    fn subtractNullUndefined(self: *Checker, t: TypeId) !TypeId {
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_union) {
            if (flags.is_null or flags.is_undefined) return types.Primitive.never;
            return t;
        }
        const members = self.interner.unionMembers(t);
        var kept: std.ArrayListUnmanaged(TypeId) = .empty;
        defer kept.deinit(self.gpa);
        for (members) |m| {
            const f = self.interner.pool.flagsOf(m);
            if (f.is_null or f.is_undefined) continue;
            try kept.append(self.gpa, m);
        }
        if (kept.items.len == 0) return types.Primitive.never;
        if (kept.items.len == 1) return kept.items[0];
        return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
    }

    /// Widen `t` with `undefined` when `noUncheckedIndexedAccess`
    /// is enabled. Returns `t` unchanged when the option is off,
    /// when `t` is already `undefined`, or when `t` already contains
    /// `undefined` as a union member. Used by `element_access`
    /// typing for index-signature paths so `arr[i]` types as
    /// `T | undefined`.
    fn maybeWidenWithUndefined(self: *Checker, t: TypeId) TypeId {
        if (!self.strict_flags.no_unchecked_indexed_access) return t;
        if (t == types.Primitive.undefined_t) return t;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| {
                if (m == types.Primitive.undefined_t) return t;
            }
        }
        return self.interner.internUnion(&.{ t, types.Primitive.undefined_t }) catch t;
    }

    /// Subtract a single type from a union (or return `t` unchanged
    /// if `t` isn't a union or doesn't contain `to_remove`). Used by
    /// negative-branch narrowing on `=== null`, `=== undefined`,
    /// `=== "literal"`, etc.
    fn subtractType(self: *Checker, t: TypeId, to_remove: TypeId) !TypeId {
        if (t == to_remove) return types.Primitive.never;
        if (!self.interner.pool.flagsOf(t).is_union) return t;
        const members = self.interner.unionMembers(t);
        var kept: std.ArrayListUnmanaged(TypeId) = .empty;
        defer kept.deinit(self.gpa);
        for (members) |m| {
            if (m == to_remove) continue;
            try kept.append(self.gpa, m);
        }
        if (kept.items.len == 0) return types.Primitive.never;
        if (kept.items.len == 1) return kept.items[0];
        return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
    }

    /// TS2353: when an object-literal init flows into a typed
    /// destination, every property in the literal must be declared
    /// on the target. Only fires for fresh literals (the actual
    /// `{ … }` syntax) — the same shape passed through a variable
    /// is treated as a regular structural assignment by tsc.
    fn checkExcessProperties(self: *Checker, init_node: NodeId, declared_t: TypeId) CheckError!void {
        if (init_node == hir_mod.none_node_id) return;
        // tsc propagates the declared contextual type into each
        // operand of `||` / `??` and into ternary branches so a
        // literal in any of those positions still gets the
        // excess-property check. Upstream only re-runs the check on
        // the LHS of `||` / `??` (the result of the binary is the
        // LHS type when truthy; the RHS sits behind the short-circuit
        // and is reported by other paths). Mirrors
        // `logicalOrExpressionIsContextuallyTyped` baseline (TS2353
        // on LHS only).
        switch (self.hir.kindOf(init_node)) {
            .logical_op => {
                const lop = hir_mod.logicalOf(self.hir, init_node);
                try self.checkExcessProperties(lop.lhs, declared_t);
                return;
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, init_node);
                try self.checkExcessProperties(c.then_branch, declared_t);
                try self.checkExcessProperties(c.else_branch, declared_t);
                return;
            },
            .object_literal => {},
            else => return,
        }
        if (!self.interner.pool.flagsOf(declared_t).is_object_type) return;
        if (try self.objectTargetHasStringIndex(declared_t)) return;
        const has_number_index = try self.objectTargetHasNumberIndex(declared_t);
        // When the target has a number index signature but NO named
        // members, tsc treats it as an "open" container and
        // suppresses the excess-property check for non-numeric keys
        // — TS2411 (member-type vs index-type mismatch) covers the
        // strict cases (`2.0: number` against `[x: number]: string`)
        // and the structural relation check fires TS2322 for the
        // rest. Mirrors `numericIndexerConstrainsPropertyDeclarations`
        // baseline which expects no TS2353 for string-keyed members.
        if (has_number_index and
            self.interner.objectStringIndex(declared_t) == types.Primitive.none and
            self.interner.objectMembers(declared_t).len == 0)
        {
            return;
        }
        const props = hir_mod.objectLiteralProps(self.hir, init_node);
        for (props) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            const prop_name = if (self.hir.kindOf(op.key) == .identifier)
                hir_mod.identifierOf(self.hir, op.key).name
            else
                (try self.classMemberNameFromPropertyKey(op.key, op.is_computed)) orelse continue;
            if (has_number_index and self.isNumericPropertyName(prop_name)) {
                continue;
            }
            const declared_member_t = try self.excessPropertyTargetMemberType(declared_t, prop_name);
            if (declared_member_t == null) {
                const name_str = self.string_interner.get(prop_name);
                // Prefer tsc's render shape:
                // `... and 'foo' does not exist in type 'X'.` when the
                // target has a printable name; fall back to the bare
                // `target type` wording otherwise.
                const msg = if (try self.allocPropertyMissingTargetTypeName(declared_t)) |target_text|
                    try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Object literal may only specify known properties, and '{s}' does not exist in type '{s}'.",
                        .{ name_str, target_text },
                    )
                else
                    try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Object literal may only specify known properties, and '{s}' does not exist on the target type.",
                        .{name_str},
                    );
                try self.diagnostics.append(self.gpa, .{
                    .node = p,
                    .code = TsCodes.object_literal_excess_property,
                    .message = msg,
                });
                continue;
            }
            // Recurse into nested object-literal values: if the
            // declared property is itself an object type, the
            // nested literal also gets the freshness check.
            if (self.hir.kindOf(op.value) == .object_literal) {
                try self.checkExcessProperties(op.value, declared_member_t.?);
            }
        }
    }

    fn checkArrayLiteralContextualElements(self: *Checker, init_node: NodeId, declared_t: TypeId) CheckError!void {
        if (init_node == hir_mod.none_node_id) return;
        if (self.hir.kindOf(init_node) != .array_literal) return;
        const elem_t = try self.contextualArrayElementType(declared_t);
        if (elem_t == types.Primitive.none) return;
        for (hir_mod.arrayLiteralElements(self.hir, init_node)) |el| {
            if (el == hir_mod.none_node_id) continue;
            try self.checkExcessProperties(el, elem_t);
            try self.checkArrayLiteralContextualElements(el, elem_t);
        }
    }

    fn contextualArrayElementType(self: *Checker, t: TypeId) CheckError!TypeId {
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            for (self.interner.unionMembers(t)) |member| {
                const elem = try self.contextualArrayElementType(member);
                if (elem != types.Primitive.none) try elems.append(self.gpa, elem);
            }
            if (elems.items.len == 0) return types.Primitive.none;
            if (elems.items.len == 1) return elems.items[0];
            return self.interner.internUnion(elems.items) catch return error.OutOfMemory;
        }
        if (!flags.is_object_type) return types.Primitive.none;
        return self.interner.objectNumberIndex(t);
    }

    fn objectTargetHasStringIndex(self: *Checker, t: TypeId) CheckError!bool {
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (try self.objectTargetHasStringIndex(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        return self.interner.objectStringIndex(t) != types.Primitive.none;
    }

    fn objectTargetHasNumberIndex(self: *Checker, t: TypeId) CheckError!bool {
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (try self.objectTargetHasNumberIndex(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        return self.interner.objectNumberIndex(t) != types.Primitive.none;
    }

    fn excessPropertyTargetMemberType(
        self: *Checker,
        t: TypeId,
        name: hir_mod.StringId,
    ) CheckError!?TypeId {
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            var found: std.ArrayListUnmanaged(TypeId) = .empty;
            defer found.deinit(self.gpa);
            for (self.interner.unionMembers(t)) |member| {
                if (try self.excessPropertyTargetMemberType(member, name)) |member_t| {
                    try found.append(self.gpa, member_t);
                }
            }
            if (found.items.len == 0) return null;
            if (found.items.len == 1) return found.items[0];
            return self.interner.internUnion(found.items) catch return error.OutOfMemory;
        }
        if (!flags.is_object_type) return null;
        if (self.interner.objectMemberInfo(t, name)) |member| return member.type;
        return null;
    }

    fn isNumericPropertyName(self: *Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.getOptional(name) orelse return false;
        return isNumericPropertyNameText(s);
    }

    fn isNumericPropertyNameText(s: []const u8) bool {
        if (s.len == 0) return false;
        var saw_digit = false;
        for (s, 0..) |c, i| {
            if (c >= '0' and c <= '9') {
                saw_digit = true;
                continue;
            }
            if (c == '.' and i + 1 == s.len and saw_digit) continue;
            return false;
        }
        return saw_digit;
    }

    /// TS2375: when `exactOptionalPropertyTypes` is on, an object
    /// literal that explicitly sets an optional property to
    /// `undefined` is rejected unless the property's declared type
    /// already includes `undefined`. Only fires for fresh literals
    /// flowing into a known object-shaped destination.
    fn checkExactOptionalProperties(self: *Checker, init_node: NodeId, declared_t: TypeId) CheckError!void {
        if (!self.strict_flags.exact_optional_property_types) return;
        if (init_node == hir_mod.none_node_id) return;
        if (self.hir.kindOf(init_node) != .object_literal) return;
        if (!self.interner.pool.flagsOf(declared_t).is_object_type) return;
        const props = hir_mod.objectLiteralProps(self.hir, init_node);
        for (props) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            if (self.hir.kindOf(op.key) != .identifier) continue;
            if (op.value == hir_mod.none_node_id) continue;
            const id = hir_mod.identifierOf(self.hir, op.key);
            const declared_member = self.interner.objectMemberInfo(declared_t, id.name) orelse continue;
            if (!declared_member.is_optional) continue;
            // Only flag literal `undefined` values — the strict v0
            // doesn't try to track `undefined` through narrowing.
            if (self.hir.kindOf(op.value) != .literal_undefined) continue;
            // Skip if the declared type already includes `undefined`
            // — `a?: number | undefined` permits explicit undefined
            // even when the strict flag is on.
            if (self.typeIncludesUndefined(declared_member.type)) continue;
            const name_str = self.string_interner.get(id.name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Type 'undefined' is not assignable to type of property '{s}'. With 'exactOptionalPropertyTypes: true', 'undefined' is not assignable to an optional property whose type does not include it.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = p,
                .code = TsCodes.exact_optional_property,
                .message = msg,
            });
        }
    }

    /// TS2369 — fires when a parameter carries `public`/`private`/
    /// `protected`/`readonly` (i.e. the parameter-property syntax)
    /// outside of a constructor implementation. Mirrors the upstream
    /// check at `checkParameter` in `tsc/checker.ts`. The walker
    /// inspects every `parameter` node in the HIR; if its enclosing
    /// function-like is anything other than a constructor with a body,
    /// the diagnostic fires on the parameter node itself.
    fn detectInvalidParamProperty(self: *Checker) CheckError!void {
        const total = self.hir.nodeCount();
        var i: hir_mod.NodeId = 1;
        while (i < total) : (i += 1) {
            if (self.hir.kindOf(i) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, i);
            if (!pp.flags.is_parameter_property) continue;
            // Find the enclosing function-like.
            var cur = self.hir.parentOf(i);
            var enclosing: hir_mod.NodeId = hir_mod.none_node_id;
            while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
                const k = self.hir.kindOf(cur);
                if (k == .fn_decl or k == .fn_expr or k == .arrow_fn or
                    k == .fn_type or k == .constructor_type)
                {
                    enclosing = cur;
                    break;
                }
            }
            if (enclosing == hir_mod.none_node_id) {
                try self.report(i, TsCodes.param_property_outside_ctor, "A parameter property is only allowed in a constructor implementation.");
                continue;
            }
            const enc_kind = self.hir.kindOf(enclosing);
            if (enc_kind == .arrow_fn or enc_kind == .fn_type or enc_kind == .constructor_type) {
                try self.report(i, TsCodes.param_property_outside_ctor, "A parameter property is only allowed in a constructor implementation.");
                continue;
            }
            const f = hir_mod.fnDeclOf(self.hir, enclosing);
            // Must be a constructor with a body (i.e. an
            // implementation, not an overload signature).
            if (!f.flags.is_constructor or f.body == hir_mod.none_node_id) {
                try self.report(i, TsCodes.param_property_outside_ctor, "A parameter property is only allowed in a constructor implementation.");
            }
        }
    }

    /// TS2526 — fires when `this` is used as a type outside a
    /// non-static class or interface member. Walks every `type_ref`
    /// node whose name is exactly "this" and applies the upstream
    /// `getThisType` rule: the closest enclosing this-container's
    /// parent must be a class-like or interface declaration, and the
    /// container itself must not be static.
    fn detectThisInStaticContext(self: *Checker) CheckError!void {
        const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
        const total = self.hir.nodeCount();
        var i: hir_mod.NodeId = 1;
        while (i < total) : (i += 1) {
            if (self.hir.kindOf(i) != .type_ref) continue;
            const tr = hir_mod.typeRefOf(self.hir, i);
            if (tr.qualifier_len != 0) continue;
            if (tr.name != this_id) continue;
            if (self.thisTypeIsValidHere(i)) continue;
            try self.report(i, TsCodes.this_type_outside_class, "A 'this' type is available only in a non-static member of a class or interface.");
        }
    }

    /// True when `node` is a (transitive) descendant of `ancestor`.
    /// Used by the TS2526 walker so constructor-parameter `this`
    /// types fire while constructor-body uses of `this` stay valid.
    fn nodeIsDescendantOf(self: *Checker, node: hir_mod.NodeId, ancestor: hir_mod.NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (cur == ancestor) return true;
        }
        return false;
    }

    /// Returns true when a `this` type ref located at `node` lands in
    /// a context that resolves to a class/interface this-type. The
    /// walker mirrors upstream's `getThisContainer` semantics:
    ///   * arrow functions are transparent — they capture the
    ///     enclosing `this`.
    ///   * the first non-arrow function-like, class-field, interface
    ///     member, or index signature encountered is the container.
    ///   * the container is "valid" only when it sits directly inside
    ///     a class or interface declaration AND is not declared with
    ///     the `static` modifier.
    fn thisTypeIsValidHere(self: *Checker, node: hir_mod.NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            switch (k) {
                .arrow_fn => continue,
                .fn_decl, .fn_expr => {
                    const f = hir_mod.fnDeclOf(self.hir, cur);
                    if (f.flags.is_static) return false;
                    const parent_kind = self.hir.kindOf(self.hir.parentOf(cur));
                    if (parent_kind != .class_decl and parent_kind != .class_expr) return false;
                    // For constructors, the `this` type is only
                    // available inside the body — parameter types and
                    // the return-type slot reject it (TS2526).
                    if (f.flags.is_constructor) {
                        if (f.body == hir_mod.none_node_id) return false;
                        return self.nodeIsDescendantOf(node, f.body);
                    }
                    return true;
                },
                .fn_type, .constructor_type => {
                    // Mirrors upstream: `FunctionType` is NOT a
                    // this-container — `getThisContainer` walks past
                    // it. The real container is whatever encloses the
                    // function-type node (an interface_member, class
                    // field, type alias body, etc.). Continue the walk.
                    continue;
                },
                .object_property => {
                    const op = hir_mod.objectPropertyOf(self.hir, cur);
                    if (op.is_static) return false;
                    const parent_kind = self.hir.kindOf(self.hir.parentOf(cur));
                    return parent_kind == .class_decl or parent_kind == .class_expr;
                },
                .interface_member => {
                    const parent_kind = self.hir.kindOf(self.hir.parentOf(cur));
                    return parent_kind == .interface_decl;
                },
                .index_signature => {
                    const parent_kind = self.hir.kindOf(self.hir.parentOf(cur));
                    return parent_kind == .class_decl or parent_kind == .class_expr or parent_kind == .interface_decl;
                },
                .class_decl, .class_expr, .interface_decl => {
                    // Reached the class/interface body without a
                    // member-level container — treat as valid since
                    // the type ref must be in a nested member position
                    // we did not recognise.
                    return true;
                },
                .source_file, .namespace_decl, .module_decl, .enum_decl => return false,
                else => continue,
            }
        }
        return false;
    }
};

/// Flip a polarity tag for the `inferVariance` walk. Covariant ⇄
/// contravariant on each input boundary; invariant and bivariant
/// are absorbing — they don't flip.
fn flipVariance(v: types.Variance) types.Variance {
    return switch (v) {
        .covariant => .contravariant,
        .contravariant => .covariant,
        .invariant => .invariant,
        .bivariant => .bivariant,
    };
}

/// Recognise expressions that produce control-flow narrowing when
/// used as conditions. Used by `cond_aliases` to decide whether to
/// record `let cond = <expr>` for later aliased-narrow expansion.
fn isNarrowingGuard(hir: *const Hir, node: NodeId) bool {
    const k = hir.kindOf(node);
    if (k == .call_expr) return true; // could be a predicate call
    if (k != .binary_op) return false;
    const b = hir_mod.binopOf(hir, node);
    return switch (b.op) {
        .eq_strict, .neq_strict, .instanceof, .in => true,
        else => false,
    };
}

/// Test whether a whitespace-trimmed line is a `// <name>` comment.
/// Accepts arbitrary trailing text after `<name>` (e.g. a colon and
/// reason: `// @ts-ignore: legacy api`).
fn matchDirective(trimmed: []const u8, name: []const u8) bool {
    if (trimmed.len < 2 + name.len) return false;
    if (trimmed[0] != '/' or trimmed[1] != '/') return false;
    var j: usize = 2;
    while (j < trimmed.len and (trimmed[j] == ' ' or trimmed[j] == '\t')) : (j += 1) {}
    return matchDirectiveText(trimmed[j..], name);
}

fn matchDirectiveText(text: []const u8, name: []const u8) bool {
    var trimmed = std.mem.trim(u8, text, " \t\r");
    if (std.mem.startsWith(u8, trimmed, "//")) {
        trimmed = std.mem.trim(u8, trimmed[2..], " \t\r");
    }
    while (std.mem.startsWith(u8, trimmed, "*")) {
        trimmed = std.mem.trim(u8, trimmed[1..], " \t\r");
    }
    if (trimmed.len < name.len) return false;
    if (!std.mem.eql(u8, trimmed[0..name.len], name)) return false;
    if (name.len == trimmed.len) return true;
    const c = trimmed[name.len];
    return !(std.ascii.isAlphanumeric(c) or c == '_' or c == '-');
}

fn directiveCommentText(trimmed: []const u8, in_block_comment: *bool) ?[]const u8 {
    if (in_block_comment.*) {
        if (std.mem.indexOf(u8, trimmed, "*/")) |end| {
            in_block_comment.* = false;
            return trimmed[0..end];
        }
        return trimmed;
    }
    if (std.mem.startsWith(u8, trimmed, "//")) {
        return std.mem.trim(u8, trimmed[2..], " \t\r");
    }
    if (std.mem.startsWith(u8, trimmed, "/*")) {
        const body = trimmed[2..];
        if (std.mem.indexOf(u8, body, "*/")) |end| {
            return body[0..end];
        }
        in_block_comment.* = true;
        return body;
    }
    if (std.mem.startsWith(u8, trimmed, "{/*")) {
        const body = trimmed[3..];
        if (std.mem.indexOf(u8, body, "*/")) |end| {
            return body[0..end];
        }
        in_block_comment.* = true;
        return body;
    }
    return null;
}

/// Convert a 0-based byte offset into a 0-based source-line number.
fn byteOffsetToLine(source: []const u8, byte_pos: u32) u32 {
    var line: u32 = 0;
    const limit = @min(@as(usize, byte_pos), source.len);
    var i: usize = 0;
    while (i < limit) : (i += 1) {
        if (source[i] == '\n') line += 1;
    }
    return line;
}

/// Return the 0-based byte offset at the start of `target_line`.
fn byteOffsetOfLine(source: []const u8, target_line: u32) u32 {
    if (target_line == 0) return 0;
    var line: u32 = 0;
    var i: usize = 0;
    while (i < source.len) : (i += 1) {
        if (source[i] != '\n') continue;
        line += 1;
        if (line == target_line) return @intCast(@min(i + 1, source.len));
    }
    return @intCast(source.len);
}

fn typeOfTypeofString(s: []const u8) ?TypeId {
    if (std.mem.eql(u8, s, "string")) return types.Primitive.string_t;
    if (std.mem.eql(u8, s, "number")) return types.Primitive.number_t;
    if (std.mem.eql(u8, s, "boolean")) return types.Primitive.boolean_t;
    if (std.mem.eql(u8, s, "bigint")) return types.Primitive.bigint_t;
    if (std.mem.eql(u8, s, "symbol")) return types.Primitive.symbol_t;
    if (std.mem.eql(u8, s, "undefined")) return types.Primitive.undefined_t;
    if (std.mem.eql(u8, s, "object")) return types.Primitive.object_t;
    // `typeof x === "function"` — narrow to a callable approximation.
    // We don't yet model a top-callable primitive, so use `object_t`,
    // which is the closest precomputed type (functions are objects).
    if (std.mem.eql(u8, s, "function")) return types.Primitive.object_t;
    return null;
}

// =============================================================================
// Tests
// =============================================================================

const T = std.testing;
const ts_lexer = @import("ts_lexer");
const ts_parser = @import("ts_parser");

const TestSetup = struct {
    sint: string_interner.Interner,
    hir: Hir,
    scanner: ts_lexer.Scanner,
    tokens: std.ArrayList(ts_lexer.Token),
    parser: ts_parser.Parser,
    ti: interner.Interner,
    engine: relation.Engine,
    checker: Checker,
    root: NodeId,
};

fn newSetup(source: []const u8) !*TestSetup {
    const s = try T.allocator.create(TestSetup);
    errdefer T.allocator.destroy(s);
    s.sint = try string_interner.Interner.init(T.allocator);
    errdefer s.sint.deinit();
    s.hir = try Hir.init(T.allocator);
    errdefer s.hir.deinit();
    s.scanner = ts_lexer.Scanner.init(T.allocator, source);
    errdefer s.scanner.deinit(T.allocator);
    s.tokens = try s.scanner.tokenize(T.allocator);
    errdefer s.tokens.deinit(T.allocator);
    s.parser = ts_parser.Parser.init(T.allocator, &s.hir, &s.sint, source, s.tokens.items);
    errdefer s.parser.deinit();
    s.root = try s.parser.parseSourceFile();
    s.ti = try interner.Interner.init(T.allocator);
    errdefer s.ti.deinit();
    s.engine = try relation.Engine.init(T.allocator, &s.ti);
    errdefer s.engine.deinit();
    s.engine.setStringInterner(&s.sint);
    s.checker = Checker.init(T.allocator, &s.hir, &s.ti, &s.sint, &s.engine);
    s.checker.setSource(source);
    return s;
}

fn newTsxSetup(source: []const u8) !*TestSetup {
    const s = try T.allocator.create(TestSetup);
    errdefer T.allocator.destroy(s);
    s.sint = try string_interner.Interner.init(T.allocator);
    errdefer s.sint.deinit();
    s.hir = try Hir.init(T.allocator);
    errdefer s.hir.deinit();
    s.scanner = ts_lexer.Scanner.init(T.allocator, source);
    errdefer s.scanner.deinit(T.allocator);
    s.tokens = try s.scanner.tokenize(T.allocator);
    errdefer s.tokens.deinit(T.allocator);
    s.parser = ts_parser.Parser.init(T.allocator, &s.hir, &s.sint, source, s.tokens.items);
    s.parser.setTsx(true);
    errdefer s.parser.deinit();
    s.root = try s.parser.parseSourceFile();
    s.ti = try interner.Interner.init(T.allocator);
    errdefer s.ti.deinit();
    s.engine = try relation.Engine.init(T.allocator, &s.ti);
    errdefer s.engine.deinit();
    s.engine.setStringInterner(&s.sint);
    s.checker = Checker.init(T.allocator, &s.hir, &s.ti, &s.sint, &s.engine);
    s.checker.setSource(source);
    return s;
}

fn destroySetup(s: *TestSetup) void {
    s.checker.deinit();
    s.engine.deinit();
    s.ti.deinit();
    s.parser.deinit();
    s.tokens.deinit(T.allocator);
    s.scanner.deinit(T.allocator);
    s.hir.deinit();
    s.sint.deinit();
    T.allocator.destroy(s);
}

fn firstStatement(s: *TestSetup) NodeId {
    return hir_mod.blockStmts(&s.hir, s.root)[0];
}

/// Setup variant that also runs the binder and attaches the resulting
/// module to the checker. Required for diagnostics whose detection
/// path consults the symbol table — TS2304 in particular needs the
/// module to know "I have full visibility, this name truly doesn't
/// exist." Caller owns the binder via `destroyBoundSetup`.
const BoundTestSetup = struct {
    base: *TestSetup,
    binder: binder_mod.Binder,
};

fn newBoundSetup(source: []const u8) !*BoundTestSetup {
    const b = try T.allocator.create(BoundTestSetup);
    errdefer T.allocator.destroy(b);
    b.base = try newSetup(source);
    errdefer destroySetup(b.base);
    b.binder = try binder_mod.Binder.init(T.allocator, &b.base.hir, &b.base.sint, 0);
    errdefer {
        b.binder.module.deinit();
        T.allocator.destroy(b.binder.module);
        b.binder.deinit();
    }
    try b.binder.bindSourceFile(b.base.root);
    b.base.checker.setModule(b.binder.module);
    return b;
}

fn destroyBoundSetup(b: *BoundTestSetup) void {
    b.binder.module.deinit();
    T.allocator.destroy(b.binder.module);
    b.binder.deinit();
    destroySetup(b.base);
    T.allocator.destroy(b);
}

test "checker: unresolved identifier emits TS2304" {
    const b = try newBoundSetup("unknownVar;");
    defer destroyBoundSetup(b);
    try b.base.checker.checkSourceFile(b.base.root);
    var found = false;
    for (b.base.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.cannot_find_name) found = true;
    }
    try T.expect(found);
}

test "checker: var globalThis emits TS2397 builtin-global conflict" {
    const s = try newSetup("var globalThis;");
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.declaration_name_conflicts_builtin_global and
            std.mem.indexOf(u8, d.message, "globalThis") != null)
        {
            found = true;
        }
    }
    try T.expect(found);
}

