    // Mirrors `parserStrictMode16.ts(2,8)` baseline.
    const s = try newSetup("\"use strict\"; delete this;");
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found_1102 = false;
    var found_2703 = false;
