test "checker: tagged primitive intersections stay primitive-like for operators and index keys" {
    const s = try newSetup(
        \\type Guid = string & { $Guid };
        \\type SerialNo = number & { $SerialNo };
        \\function createGuid() { return "x" as Guid; }
        \\function createSerialNo() { return 1 as SerialNo; }
        \\let map1: { [x: string]: number } = {};
        \\let guid = createGuid();
        \\map1[guid] = 123;
        \\let map2: { [x: number]: string } = {};
        \\let serialNo = createSerialNo();
        \\map2[serialNo] = "hello";
        \\const s1 = "{" + guid + "}";
        \\const s2 = guid.toLowerCase();
        \\const s3 = guid + guid;
        \\const s4 = guid + serialNo;
        \\const s5 = serialNo.toPrecision(0);
        \\const n1 = serialNo * 3;
        \\const n2 = serialNo + serialNo;
        \\const b1 = guid === "";
        \\const b2 = guid === guid;
        \\const b3 = serialNo === 0;
        \\const b4 = serialNo === serialNo;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.type_cannot_be_used_as_index);
        try T.expect(d.code != TsCodes.property_does_not_exist);
        try T.expect(d.code != TsCodes.operator_cannot_be_applied);
        try T.expect(d.code != TsCodes.arithmetic_left_operand_type);
        try T.expect(d.code != TsCodes.arithmetic_right_operand_type);
        try T.expect(d.code != TsCodes.no_overlap_comparison);
    }
}

test "checker: primitive receivers include Object prototype and interface augmentations" {
    const s = try newSetup(
        \\interface Number {
        \\  doStuff(): string;
        \\  doOtherStuff<T>(x: T): T;
        \\}
        \\interface String {
        \\  doStuff(): string;
        \\  doOtherStuff<T>(x: T): T;
        \\}
        \\var n = 1;
        \\var s = "";
        \\var a = n.hasOwnProperty("toFixed");
        \\var b = s.hasOwnProperty("charAt");
        \\var c = n["hasOwnProperty"]("toFixed");
        \\var d = s["hasOwnProperty"]("charAt");
        \\var e: string = n.doStuff();
        \\var f: string = n.doOtherStuff("hm");
        \\var g: string = n["doStuff"]();
        \\var h: string = n["doOtherStuff"]("hm");
        \\var i: string = s.doStuff();
        \\var j: string = s.doOtherStuff("hm");
        \\var k: string = s["doStuff"]();
        \\var l: string = s["doOtherStuff"]("hm");
        \\var nObj: Object = n;
        \\var sObj: Object = s;
        \\var nWrap: Number = n;
        \\var sWrap: String = s;
        \\enum E { A }
        \\var em = E.A;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    // NOTE: `var en: E = n;` and `em = n;` (number→enum direction)
    // used to live here, but tsc actually DOES emit TS2322 on both
    // ("Type 'number' is not assignable to type 'E'."). Their
    // absence was an oversight; the integration commit `767f11fd`
    // widened the lib string proto (charCodeAt) and the changed
    // TypeId hash distribution exposed the missed diagnostics.
    // Dropping the stray lines keeps this checker test focused on
    // its actual scope (primitive receivers + Object prototype +
    // interface augmentations).
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.property_does_not_exist);
        try T.expect(d.code != TsCodes.type_not_assignable);
    }
}

test "checker: string primitive is assignable to String wrapper (charCodeAt apparent)" {
    // Regression: adding `charCodeAt` to stringProto broke
    // primitive-apparent assignability because the hardcoded
    // member-whitelist in relation.zig didn't include it. The wrapper
    // type `String` is the same object as stringProto, so any member
    // we expose there must also be present in
    // `primitiveApparentHasMember` or the structural check refuses
    // `var sWrap: String = s` with TS2322.
    const s = try newSetup(
        \\var s = "";
        \\var sWrap: String = s;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.type_not_assignable);
    }
}

test "checker: generic arrow type parameters resolve in inner parameter annotations" {
    // Regression: `tryParseArrowAfterParen` used to drop the parsed
    // type parameters at the HIR boundary, so a generic arrow like
    // `<U, R, S>(x: Iterator<S, U, R>) => …` couldn't resolve `S`/`U`/`R`
    // inside the parameter annotations and over-reported TS2304 on
    // each. Threading the type-params through `addFnDeclGeneric`
    // restores resolution. Mirrors fixture
    // `unionAndIntersectionInference3` line 12.
    const s = try newSetup(
        \\const g: <U, R, S>(com: () => Iterator<S, U, R>) => Promise<U> =
        \\    async <U, R, S>(com: () => Iterator<S, U, R>): Promise<U> => {
        \\        throw com;
        \\    };
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.cannot_find_name);
        try T.expect(d.code != TsCodes.cannot_find_name_did_you_mean);
    }
}

