test "checker: `await await p` on `Promise<Promise<string>>` unwraps twice via two awaits" {
    // Each `await` peels one layer of `Promise<...>`, so two
    // awaits applied to a doubly-nested Promise should yield the
    // innermost type. We stage the doubly-nested Promise through
    // intermediate aliases to dodge the `>>` lex/parse limitation.
    const s = try newSetup(
        \\type Inner = Promise<string>;
        \\type Outer = Promise<Inner>;
        \\async function f() {
        \\  let p: Outer;
        \\  let x: string = await await p;
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    const stmts = hir_mod.blockStmts(&s.hir, s.root);
    const fn_node = stmts[2];
    const fp = hir_mod.fnDeclOf(&s.hir, fn_node);
    const body_stmts = hir_mod.blockStmts(&s.hir, fp.body);
    const x_decl = body_stmts[1];
    const v = hir_mod.varDeclOf(&s.hir, x_decl);
    // Outer await — type should be `string` after both layers peel.
    try T.expectEqual(hir_mod.NodeKind.await_expr, s.hir.kindOf(v.init));
    try T.expectEqual(types.Primitive.string_t, s.hir.typeOf(v.init));
    // No TS2322 should fire on the assignment to `x: string`.
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.type_not_assignable);
    }
}

test "checker: `yield expr` value defaults to sent any while operand drives generator yield type" {
    const s = try newSetup("function* gen() { yield 1; }");
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    const stmts = hir_mod.blockStmts(&s.hir, s.root);
    const fn_node = stmts[0];
    const fn_payload = hir_mod.fnDeclOf(&s.hir, fn_node);
    const body_stmts = hir_mod.blockStmts(&s.hir, fn_payload.body);
    // The parser drops expression-statement wrappers, so body_stmts[0]
    // is the yield_expr directly.
    const expr_id = body_stmts[0];
    try T.expectEqual(hir_mod.NodeKind.yield_expr, s.hir.kindOf(expr_id));
    try T.expectEqual(types.Primitive.any, s.hir.typeOf(expr_id));
    const sig = s.hir.typeOf(fn_node);
    const ret_t = s.ti.signatureReturn(sig) orelse return error.TestExpectedEqual;
    try T.expectEqual(types.Primitive.number_t, s.ti.objectNumberIndex(ret_t));
}

test "checker: generator fn return type infers a Generator<T> shape" {
    // §3.A — calling a generator function should yield a value with
    // the synthesized Generator shape (an object type), not `void`.
    // Test that `g()` is callable and its result type is an object
    // type with a number-key indexer of T = number.
    const s = try newSetup(
        \\function* g() { yield 1; }
        \\let it = g();
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    try T.expect(s.checker.diagnostics.items.len == 0);
    const stmts = hir_mod.blockStmts(&s.hir, s.root);
    const v = hir_mod.varDeclOf(&s.hir, stmts[1]);
    const it_t = s.hir.typeOf(v.init);
    try T.expect(s.ti.pool.flagsOf(it_t).is_object_type);
    try T.expectEqual(types.Primitive.number_t, s.ti.objectNumberIndex(it_t));
}

test "checker: for-of over a generator call binds element to yield type" {
    // The synthesized Generator shape exposes `[i: number]: T`, so
    // `for (const x of g())` resolves `x` to T via the existing
    // for-of element-type path. Round-trip: arithmetic against
    // `total: number` must remain consistent.
    const s = try newSetup(
        \\function* g() { yield 1; yield 2; }
        \\let total: number = 0;
        \\for (let x of g()) { total = total + x; }
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    try T.expect(s.checker.diagnostics.items.len == 0);
}

