    // default because the discriminant has been narrowed to `never`.
    const s = try newSetup(
        \\function unreachable(x: never): never { throw 0; }
        \\function f(x: "a" | "b") {
        \\  if (x === "a") {}
        \\  else if (x === "b") {}
        \\  else { unreachable(x); }
