test "checker: binding pattern defaults reject self and later references" {
    const s = try newSetup(
        \\const [c, d = c, e = e] = [1];
        \\const [f, g = f, h = i, i = f] = [1];
        \\function a([c, d = c, e = e]) {}
        \\function b([f, g = f, h = i, i = f]) {}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_var = false;
    var saw_param_self = false;
    var saw_param_later = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.block_scoped_used_before_decl) saw_var = true;
        if (d.code == TsCodes.parameter_cannot_reference_self) saw_param_self = true;
        if (d.code == TsCodes.parameter_cannot_reference_later) saw_param_later = true;
    }
    try T.expect(saw_var);
    try T.expect(saw_param_self);
    try T.expect(saw_param_later);
}

test "checker: plain identifier parameter default cannot reference itself (TS2372)" {
    // Mirrors `asyncFunctionDeclaration3_es2017.ts` and `asyncArrowFunction3_es2017.ts`:
    //   function f(await = await) {}
    // The destructuring-pattern self-ref check (`checkBindingPatternDefaultReferences`)
    // doesn't cover plain identifier parameters, so this exercises the
    // dedicated `nk == .identifier` branch in `checkFnParameterDefaultReferences`.
    const s = try newSetup(
        \\function f(x = x) {}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_param_self = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.parameter_cannot_reference_self) saw_param_self = true;
    }
    try T.expect(saw_param_self);
}

test "checker: TS2372 wording matches upstream tsc (no 'in its initializer' tail)" {
    // Mirrors upstream diagnosticMessages.json key
    // `Parameter '{0}' cannot reference itself.` — the trailing
    // "in its initializer." we used to emit caused an exact-baseline
    // mismatch across the async/await es5/es6/es2017 cluster.
    const s = try newSetup(
        \\function f(await = await) {}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found_exact = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.parameter_cannot_reference_self) continue;
        // Exact upstream wording, no trailing " in its initializer.".
        if (std.mem.eql(u8, d.message, "Parameter 'await' cannot reference itself.")) {
            found_exact = true;
        }
        // Hard-fail if the legacy wording crept back.
        try T.expect(std.mem.indexOf(u8, d.message, "in its initializer") == null);
    }
    try T.expect(found_exact);
}

