    }
    const stmts = hir_mod.blockStmts(&s.hir, s.root);
    const decl = hir_mod.varDeclOf(&s.hir, stmts[2]);
    try T.expectEqual(types.Primitive.number_t, s.hir.typeOf(decl.init));
}

