test "checker: post-return narrow persists for member access" {
    // `if (!obj.x) return; obj.x` — checkStatement's if_stmt path
    // applies the negated guard in the current scope (without
    // pushing) when the then-branch definitely exits. The unary `!`
    // re-flips polarity, so this routes through my new truthy
    // member-narrow path and records the narrow on the function-body
    // scope, persisting to subsequent statements.
    const s = try newSetup(
        \\function f(obj: { x?: string }): string {
        \\  if (!obj.x) return "default";
        \\  return obj.x;
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.type_not_assignable);
    }
}

test "checker: unrelated type parameters are not mutually assignable (TS2322)" {
    // Upstream `assignmentCompatibility/typeParameterAssignability.ts`
    // expects both `t = u` and `u = t` over `function foo<T, U>` to
    // produce TS2322. The relation engine stays permissive on
    // type-parameter targets to keep generic inference working; the
    // assignment-expression checker emits the diagnostic directly via
    // `unrelatedTypeParameterAssignment`.
    const s = try newSetup(
        \\function foo<T, U>(t: T, u: U) {
        \\  t = u;
        \\  u = t;
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    var ts2322_count: u32 = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.type_not_assignable) ts2322_count += 1;
    }
    try T.expectEqual(@as(u32, 2), ts2322_count);
}

test "checker: same type parameter is self-assignable" {
    // Sanity companion to the TS2322 case: `t = t` over the same
    // declared type parameter `T` must not trip the new
    // `unrelatedTypeParameterAssignment` gate. The source and target
    // share a TypeId, so the helper short-circuits before walking
    // the constraint chain.
    const s = try newSetup(
        \\function foo<T>(t: T, t2: T) {
        \\  t = t2;
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.type_not_assignable);
    }
}

test "checker: unrelated type parameters — three-param case fires per mismatch" {
    // Extends the canonical two-param case to `<T, U, V>` to prove
    // the helper fires per assignment, not per function. Six
    // permuted assignments between distinct TPs should produce six
    // TS2322 diagnostics — the same TP slot (`t = t`) is excluded
    // since the helper short-circuits on source == target.
    const s = try newSetup(
        \\function foo<T, U, V>(t: T, u: U, v: V) {
        \\  t = u;
        \\  t = v;
        \\  u = t;
        \\  u = v;
        \\  v = t;
        \\  v = u;
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    var ts2322_count: u32 = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.type_not_assignable) ts2322_count += 1;
    }
    try T.expectEqual(@as(u32, 6), ts2322_count);
}

test "checker: bare truthy narrow chains into nested member access" {
    // `if (p.x) p.x.y` — outer narrow on `p.x` strips the
    // `undefined` from the optional member, so the chained access
