test "checker: TS2496 suppressed when `arguments` resolves to a parameter binding" {
    // Mirrors `emitArrowFunctionWhenUsingArguments08.errors.txt`
    // (alwaysstrict=true,target=es5) — the inner `arguments`
    // identifier shadows the synthetic slot via the parameter
    // declaration `(arguments) =>`, so tsc emits only the TS1100
    // diagnostics, never TS2496 against the reference.
    const s = try newSetup(
        \\// @target: es5
        \\function f(arguments: any) {
        \\    var a = () => (arguments: any) => arguments;
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.arguments_in_arrow_es5);
    }
}

test "checker: TS2496 still fires when `arguments` escapes the param-arrow lexically" {
    // Mirrors `emitArrowFunctionWhenUsingArguments07.errors.txt`
    // (alwaysstrict=false,target=es5) — the inner `arguments` lives
    // inside `() => arguments` whose own parameter list is empty, so
    // the reference escapes one arrow up via the lexical chain. tsc
    // still fires TS2496 at the inner reference because no enclosing
    // function-form scope can provide a real arguments slot.
    const s = try newSetup(
        \\// @target: es5
        \\function f(arguments: any) {
        \\    var a = (arguments: any) => () => arguments;
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_ts2496 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.arguments_in_arrow_es5) saw_ts2496 = true;
    }
    try T.expect(saw_ts2496);
}

test "checker: TS2448 binding-default forward ref names the referenced variable" {
    // Mirrors `destructuringObjectBindingPatternAndAssignment4.ts(6,9)`
    // — `e = f` reports `'f' used before its declaration.` (the
    // *referenced* name), not `'e'` (the binding being declared).
    const s = try newSetup(
        \\const {
        \\    e = f,
        \\    f = f
        \\} = {} as any;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_f_msg = false;
    var saw_wrong_e_msg = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.block_scoped_used_before_decl) continue;
        if (std.mem.indexOf(u8, d.message, "'f'") != null) saw_f_msg = true;
        if (std.mem.indexOf(u8, d.message, "'e'") != null) saw_wrong_e_msg = true;
    }
    try T.expect(saw_f_msg);
    try T.expect(!saw_wrong_e_msg);
}

test "checker: TS2448 for-of inner reference anchors at identifier, not array literal" {
    // Mirrors `ES5For-of17` / `ES5For-of20` upstream baselines:
    // `for (let v of [v])` reports TS2448 at the inner `v` (the
    // referenced identifier), not at the `[` of the array literal.
    const src =
        "for (let v of []) {\n" ++
        "    v;\n" ++
        "    for (let v of [v]) {\n" ++
        "        var x = v;\n" ++
        "    }\n" ++
        "}\n";
    const s = try newSetup(src);
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);

    const inner_v_offset: u32 = @intCast(std.mem.indexOf(u8, src, "[v]").? + 1);
    var saw_at_inner = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.block_scoped_used_before_decl) continue;
        const anchor_pos: u32 = if (d.pos) |p| p else s.hir.spanOf(d.node).start;
        if (anchor_pos == inner_v_offset) saw_at_inner = true;
    }
    try T.expect(saw_at_inner);
}

// `for (k in obj)` where `k` has a type-parameter type whose
// constraint is `string`-compatible must NOT emit TS2405. Mirrors
// `keyofAndForIn.ts` upstream — `function f<K extends string>(...,
// k: K) { for (k in obj) {...} }` is sound because at runtime `k`
// receives string keys.
test "checker: for-in accepts type parameter extending string" {
    const s = try newSetup(
        \\function f1<K extends string, T>(obj: { [P in K]: T }, k: K) {
        \\  for (k in obj) {
        \\    let x = obj[k];
        \\  }
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.for_in_left_type);
    }
}

// `keyof T` is structurally a subtype of `string | number | symbol`;
// `for (k in obj)` with `k: keyof T` must NOT emit TS2405. Pins the
// `keyofAndForIn.ts` f2/f3 path.
test "checker: for-in accepts keyof T as LHS type" {
    const s = try newSetup(
        \\function f2<T>(obj: { [P in keyof T]: T[P] }, k: keyof T) {
        \\  for (k in obj) {
        \\    let x = obj[k];
        \\  }
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.for_in_left_type);
    }
}

// `<T extends Number>` instances expose `toFixed()` with an optional
// fraction-digits arg. Calling `toFixed()` (0 args) on such a value
// must NOT trip TS2554. Mirrors `innerTypeParameterShadowingOuterOne.ts`
// f.g body upstream.
test "checker: <T extends Number> x.toFixed() with 0 args is valid" {
    const s = try newSetup(
        \\function g<T extends Number>() {
        \\  var x: T;
        \\  x.toFixed();
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.expected_n_arguments);
    }
}

// `string` exposes `toLocaleLowerCase` / `toLocaleUpperCase` per
// `lib.es5.d.ts` — calling them must not trip TS2339. Pins
// `spreadObjectOrFalsy.ts:44` (narrowed `T extends string` calling
// `toLocaleLowerCase`) and any other `toLocale*` use on a string
// value.
test "checker: string proto exposes toLocaleLowerCase / toLocaleUpperCase" {
    const s = try newSetup(
        \\let s: string = "hi";
        \\let a: string = s.toLocaleLowerCase();
        \\let b: string = s.toLocaleUpperCase();
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.property_does_not_exist);
    }
}

test "checker: Array.from / Array.of suppress TS2339" {
    // Mirrors neverInference.ts which uses `Array.from([0])`.
    // Without `from` / `of` on the Array global, our checker fires
    // a spurious TS2339 "Property 'from' does not exist on type."
    const s = try newSetup(
        \\let a = Array.from([0]);
        \\let b = Array.of(1, 2, 3);
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.property_does_not_exist);
    }
}

test "checker: readonly class field with literal init narrows to literal" {
    // Mirrors literalTypesWidenInParameterPosition.ts: `readonly noWiden = 1`
    // narrows the field type to the literal `1`, so `this.noWiden = 5;`
    // in the constructor is a TS2322 mismatch.
    const s = try newSetup(
        \\class D {
        \\    readonly noWiden = 1;
        \\    constructor() {
        \\        this.noWiden = 5;
        \\    }
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_2322 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.type_not_assignable) saw_2322 = true;
    }
    try T.expect(saw_2322);
}

test "checker: arrow on LHS of `&&` fires TS2872 always-truthy" {
    // Mirrors contextuallyTypeLogicalAnd03.ts. The arrow function on
    // the LHS of `&&` is always truthy (heap-allocated function object),
    // so tsc fires TS2872 "This kind of expression is always truthy."
    const s = try newSetup(
        \\let x: (a: string) => string;
        \\x = (a => a) && (b => b);
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_2872 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.expression_always_truthy) saw_2872 = true;
    }
    try T.expect(saw_2872);
}

test "checker: class field annotation referencing undefined type emits TS2304" {
    // Mirrors typeParameterUsedAsTypeParameterConstraint4.ts: the class
    // declares <T, U, V> but `z: W` references the undeclared `W`. tsc
    // fires TS2304 "Cannot find name 'W'." on the annotation.
    const s = try newSetup(
        \\class C<T, U extends T, V extends U> {
        \\    z: W;
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_2304 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.cannot_find_name) saw_2304 = true;
    }
    try T.expect(saw_2304);
}

test "checker: relational op fires TS18050 on each nullish operand" {
    // Mirrors `comparisonOperatorWithIdenticalPrimitiveType.ts`:
    // `null < null` emits TS18050 at BOTH operand columns, not just
    // the LHS. Equality operators (==, !=, ===, !==) deliberately
    // do not trigger this — only ordered comparisons.
    const s = try newSetup("var r = null < null;");
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    var nullish_count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.nullish_relational_operand) nullish_count += 1;
    }
    try T.expectEqual(@as(usize, 2), nullish_count);
}

test "checker: relational op skips TS18050 on equality operators" {
    const s = try newSetup("var r = null == null;");
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.nullish_relational_operand);
    }
}

test "checker: for-of iterator with no value member doesn't double-report TS2322" {
    // Mirrors `for-of15.ts` upstream baseline: when `next()` returns a
    // type with no `value` property, the structural TS2490 fires on the
    // iterable source but the for-of target must NOT additionally
    // surface TS2322 — `iterableElementType` degrades to `any` so
    // assignability passes.
    const src =
        "class MyStringIterator {\n" ++
        "    next() { return \"\"; }\n" ++
        "    [Symbol.iterator]() { return this; }\n" ++
        "}\n" ++
        "var v: string;\n" ++
        "for (v of new MyStringIterator) { }\n";
    const s = try newSetup(src);
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_2490 = false;
    var saw_2322 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.iterator_value_missing) saw_2490 = true;
        if (d.code == TsCodes.type_not_assignable) saw_2322 = true;
    }
    try T.expect(saw_2490);
    try T.expect(!saw_2322);
}

test "checker: TS2528 fires on every default export beyond the first" {
    // Mirrors `multipleDefaultExports05.ts` upstream baseline: three
    // `export default` declarations produce three TS2528 anchors (one
    // per default), not just the first conflicting pair.
    const src =
        "export default class AA1 {}\n" ++
        "export default class BB1 {}\n" ++
        "export default class CC1 {}\n";
    const s = try newSetup(src);
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.multiple_default_exports) count += 1;
    }
    try T.expectEqual(@as(usize, 3), count);
}

test "checker: simpleDiagnosticTypeName renders undefined and null after non-nullish in union" {
    // Direct unit test on the union-shape renderer used by TS2345 /
    // TS2322 prose. Ensures `number | undefined` / `string | null`
    // are rendered with the nullish member LAST regardless of
    // interner-id ordering — `undefined`'s primitive TypeId (6) is
    // numerically lower than `number`'s (8), so naive iteration
    // order would produce `undefined | number`.
    const s = try newSetup(";");
    defer destroySetup(s);
    const union_a = try s.checker.interner.internUnion(&.{ types.Primitive.undefined_t, types.Primitive.number_t });
    const name_a = (try s.checker.simpleDiagnosticTypeName(union_a)) orelse return error.TestUnexpectedResult;
    try T.expectEqualStrings("number | undefined", name_a);

    const union_b = try s.checker.interner.internUnion(&.{ types.Primitive.null_t, types.Primitive.string_t });
    const name_b = (try s.checker.simpleDiagnosticTypeName(union_b)) orelse return error.TestUnexpectedResult;
    try T.expectEqualStrings("string | null", name_b);
}

test "checker: TS2365 renders type-rich form for boolean + number" {
    // Mirrors `logicalNotOperatorInvalidOperations.ts(8,16)` and the
    // `compoundAdditionAssignmentWithInvalidOperands.ts` cluster:
    // when neither operand of `+` is string-like or any-like and
    // both have a simple display name, the diagnostic includes the
    // operand type labels instead of falling back to the generic
    // `…to these operand types.` prose.
    const s = try newSetup(
        \\declare var b: number;
        \\var r = !b + b;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_rich = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.operator_cannot_be_applied) continue;
        if (std.mem.indexOf(u8, d.message, "Operator '+' cannot be applied to types 'boolean' and 'number'.") != null) {
            saw_rich = true;
        }
    }
    try T.expect(saw_rich);
}

test "checker: TS2365 renders type-rich form for boolean += number" {
    const s = try newSetup(
        \\var x: boolean = false;
        \\declare var n: number;
        \\x += n;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_rich = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.operator_cannot_be_applied) continue;
        if (std.mem.indexOf(u8, d.message, "Operator '+=' cannot be applied to types 'boolean' and 'number'.") != null) {
            saw_rich = true;
        }
    }
    try T.expect(saw_rich);
}

test "checker: TS2389 anchors on the implementation's name identifier" {
    // Mirror upstream `parserFunctionDeclaration4` — the diagnostic
    // underlines the function name, not the `function` keyword.
    const src = "function foo();\nfunction bar() { }\n";
    const s = try newSetup(src);
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found_pos: ?u32 = null;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.function_implementation_name_mismatch) {
            found_pos = s.checker.hir.spanOf(d.node).start;
            break;
        }
    }
    try T.expect(found_pos != null);
    // The `b` of `bar` sits at offset 25 within the source above
    // (`function foo();\n` is 16 bytes, then `function ` adds 9).
    try T.expectEqual(@as(u32, 25), found_pos.?);
}

test "checker: TS1108 is suppressed in ambient .d.ts files" {
    // `return;` inside a virtual `.d.ts` section gets TS1036 from the
    // parser for the ambient statement; emitting TS1108 on top of it
    // would double-report. Mirrors upstream `parserReturnStatement1.d`.
    // The `@filename: foo.d.ts` directive makes
    // `virtualSectionIsDeclarationFile` return true for the return.
    const src =
        \\// @filename: foo.d.ts
        \\return;
    ;
    const s = try newSetup(src);
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_1108: u32 = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.return_outside_function) saw_1108 += 1;
    }
    try T.expectEqual(@as(u32, 0), saw_1108);
}

test "checker: TS2347 suppressed when callee has TS2339" {
    // `this.super<T>(0)` — the `.super` access already gets TS2339
    // ("Property 'super' does not exist…"). tsc skips the cascading
    // TS2347 ("Untyped function calls may not accept type arguments.")
    // in that case. Mirrors upstream `parserSuperExpression3`.
    const s = try newSetup(
        \\class C {
        \\  M() {
        \\    this.super<number>(0);
        \\  }
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_2339: u32 = 0;
    var saw_2347: u32 = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.property_does_not_exist) saw_2339 += 1;
        if (d.code == TsCodes.untyped_function_type_args) saw_2347 += 1;
    }
    try T.expect(saw_2339 >= 1);
    try T.expectEqual(@as(u32, 0), saw_2347);
}

test "checker: class instance member access inherits Object prototype" {
    // `class C {}` instances pick up `toString`, `hasOwnProperty`, …
    // from `Object.prototype` — tsc accepts these without TS2339.
    // Mirrors upstream `classAppearsToHaveMembersOfObject`.
    const s = try newSetup(
        \\class C { foo: string; }
        \\var c: C;
        \\var r = c.toString();
        \\var r2 = c.hasOwnProperty('');
        \\var o: Object = c;
        \\var o2: {} = c;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var saw_tostring_2339 = false;
    var saw_hasown_2339 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.property_does_not_exist) {
            if (std.mem.indexOf(u8, d.message, "toString") != null) saw_tostring_2339 = true;
            if (std.mem.indexOf(u8, d.message, "hasOwnProperty") != null) saw_hasown_2339 = true;
        }
    }
    try T.expect(!saw_tostring_2339);
    try T.expect(!saw_hasown_2339);
}
